def _log(msg):
    logcat(f"[NFT_ARCH] {msg}")

# Shared reflection cache for hot profile/gift paths.
_field_cache = {}

def _dispatch_bg(callable_obj):
    """Best-effort dispatch of a heavy callable onto PLUGINS_QUEUE.

    Falls back to a lightweight Python thread if run_on_queue/PLUGINS_QUEUE
    are unavailable (older client_utils) so the call never blocks the
    caller's thread. All failures are swallowed; callers must be tolerant.
    """
    if callable_obj is None:
        return False
    try:
        if run_on_queue is not None and PLUGINS_QUEUE is not None:
            try:
                run_on_queue(callable_obj, PLUGINS_QUEUE)
                return True
            except TypeError:
                # Older signature: run_on_queue(callable) with implicit queue
                try:
                    run_on_queue(callable_obj)
                    return True
                except Exception:
                    pass
            except Exception:
                pass
    except Exception:
        pass
    try:
        t = threading.Thread(target=callable_obj, daemon=True)
        t.start()
        return True
    except Exception:
        try:
            callable_obj()
        except Exception:
            pass
        return False

def _cached_get_field(obj, field_name):
    if obj is None:
        return None
    try:
        cls = obj.getClass()
        key = (str(cls.getName() or ""), str(field_name or ""))
        cached = _field_cache.get(key, None)
        if cached is not None or key in _field_cache:
            return cached
        field = None
        try:
            field = cls.getField(field_name)
        except:
            try:
                field = cls.getDeclaredField(field_name)
                if field is not None:
                    try:
                        field.setAccessible(True)
                    except:
                        pass
            except:
                field = None
        _field_cache[key] = field
        return field
    except:
        return None

def to_java_int(val):
    val = val & 0xFFFFFFFF
    if val > 0x7FFFFFFF:
        val -= 0x100000000
    return val

def to_java_Integer(val):
    """Box a Python int as java.lang.Integer (NOT Long) for postNotificationName
    Object... varargs. Chaquopy by default autoboxes Python int -> java.lang.Long
    in Object[] context, which crashes recipients that cast args[0] to Integer
    (e.g. DialogsActivity.didReceivedNotification for updateInterfaces masks).
    """
    try:
        return jclass("java.lang.Integer")(int(to_java_int(val)))
    except Exception:
        return int(to_java_int(val))

def get_val(obj, name, default=None):
    if obj is None:
        return default
    try:
        return getattr(obj, name)
    except:
        pass
    try:
        f = _cached_get_field(obj, name)
        if f is not None:
            return f.get(obj)
    except:
        pass
    return default

def find_document_recursive(obj, depth=0):
    if obj is None or depth > 2:
        return None
    try:
        if "Document" in obj.getClass().getSimpleName():
            return obj
    except:
        return None
    doc = get_val(obj, "document")
    if doc:
        return doc
    try:
        for f in obj.getClass().getFields():
            if "Document" in f.getType().getSimpleName():
                val = f.get(obj)
                if val:
                    return val
    except:
        pass
    gift = get_val(obj, "gift")
    if gift:
        found = find_document_recursive(gift, depth + 1)
        if found:
            return found
    return None

def _saved_gift_has_inner_gift(obj):
    if obj is None:
        return False
    try:
        inner = get_val(obj, "gift", None)
    except:
        inner = None
    return inner is not None

def serialize_tl_object(obj):
    """Serialize a TLObject to base64 string using Telegram's built-in serialization."""
    data = None
    try:
        SerializedData = jclass("org.telegram.tgnet.SerializedData")
        try:
            size = int(obj.getObjectSize() or 0)
        except:
            size = 0
        for extra in [32, 256, 2048]:
            try:
                data = SerializedData(max(size + int(extra), 256))
                # TL objects write their own constructor inside serializeToStream().
                obj.serializeToStream(data)
                byte_arr = data.toByteArray()
                py_bytes = bytes(byte_arr)
                return base64.b64encode(py_bytes).decode('utf-8')
            except:
                try:
                    if data is not None:
                        data.cleanup()
                except:
                    pass
                data = None
                continue
        raise RuntimeError("serialize retries exhausted")
    except Exception as e:
        try:
            cls_name = str(obj.getClass().getName() or "")
        except:
            cls_name = "unknown"
        _log(f"Serialize error ({cls_name}): {e}\n{traceback.format_exc()}")
        return None
    finally:
        try:
            if data is not None:
                data.cleanup()
        except:
            pass

def deserialize_tl_saved_gift(b64_str):
    """Deserialize a TL_savedStarGift from base64 string."""
    data = None
    try:
        SerializedData = jclass("org.telegram.tgnet.SerializedData")

        raw = base64.b64decode(b64_str)

        JByte = jclass("java.lang.Byte").TYPE
        JArray = jclass("java.lang.reflect.Array")
        arr = JArray.newInstance(JByte, len(raw))
        for i, b in enumerate(raw):
            if b > 127:
                b = b - 256
            JArray.setByte(arr, i, b)

        data = SerializedData(arr)
        try:
            Saved = jclass("org.telegram.tgnet.tl.TL_stars$TL_savedStarGift")
            try:
                constructor = data.readInt32(False)
            except:
                constructor = 0
            try:
                obj = Saved.TLdeserialize(data, constructor, False)
                if obj is not None and _saved_gift_has_inner_gift(obj):
                    return obj
                if obj is not None:
                    _log("deserialize: gift field is null - discarding")
            except Exception as e0:
                _log(f"Static TLdeserialize failed: {e0}")
            try:
                data.cleanup()
            except:
                pass
            data = SerializedData(arr)
            try:
                _ = data.readInt32(False)
            except:
                pass
            obj = Saved()
            obj.readParams(data, False)
            if not _saved_gift_has_inner_gift(obj):
                _log("deserialize: gift field is null - discarding")
                return None
            return obj
        except Exception as e1:
            _log(f"Direct deserialize failed: {e1}")
        return None
    except Exception as e:
        _log(f"Deserialize error: {e}\n{traceback.format_exc()}")
        return None
    finally:
        try:
            if data is not None:
                data.cleanup()
        except:
            pass

def deserialize_fragment_collectible_info(b64_str):
    """Deserialize TL_fragment.TL_collectibleInfo from base64 string."""
    data = None
    try:
        SerializedData = jclass("org.telegram.tgnet.SerializedData")

        raw = base64.b64decode(b64_str)

        JByte = jclass("java.lang.Byte").TYPE
        JArray = jclass("java.lang.reflect.Array")
        arr = JArray.newInstance(JByte, len(raw))
        for i, b in enumerate(raw):
            if b > 127:
                b = b - 256
            JArray.setByte(arr, i, b)

        data = SerializedData(arr)
        Info = jclass("org.telegram.tgnet.tl.TL_fragment$TL_collectibleInfo")
        constructor = data.readInt32(False)
        try:
            obj = Info.TLdeserialize(data, constructor, False)
        except:
            obj = None
        if obj is not None:
            return obj
        try:
            data.cleanup()
        except:
            pass
        data = SerializedData(arr)
        try:
            _ = data.readInt32(False)
        except:
            pass
        obj = Info()
        obj.readParams(data, False)
        return obj
    except Exception as e:
        _log(f"Collectible deserialize error: {e}\n{traceback.format_exc()}")
        return None
    finally:
        try:
            if data is not None:
                data.cleanup()
        except:
            pass

def gen(java_class, method_name, return_value=False, default_value=None):
    def _run(instance, *java_args):
        try:
            return instance._fn(*java_args)
        except Exception:
            return default_value

    def __init__(self, fn, *args, **kwargs):
        self._fn = fn
        super(type(self), self).__init__()

    NewClass = type(
        'Proxy_' + java_class.__name__.replace('$', '_'),
        (dynamic_proxy(java_class),),
        {'__init__': __init__, method_name: _run},
    )
    return NewClass

