class ProfileConfigOpenHook(MethodHook):
    def __init__(self, plugin):
        super().__init__()
        self.plugin = plugin

    def before_hooked_method(self, param):
        try:
            message = param.args[0]
            if not message:
                return

            file_name = ""
            try:
                file_name = str(message.getFileName() or "")
            except:
                file_name = ""
            if not file_name.lower().endswith(PROFILE_CONFIG_FILE_EXTENSION):
                return

            try:
                method_name = str(param.method.getName() or "")
            except:
                method_name = ""
            try:
                if "openForView" in method_name:
                    param.setResult(True)
                else:
                    param.setResult(None)
            except:
                pass

            path = None
            try:
                path = message.messageOwner.attachPath
            except:
                path = None
            if not path or (not os.path.exists(str(path))):
                try:
                    loader = FileLoader.getInstance(message.currentAccount)
                    resolved = loader.getPathToMessage(message.messageOwner)
                    path = resolved.getAbsolutePath() if resolved is not None else None
                except:
                    path = None

            if path and os.path.exists(str(path)):
                run_on_ui_thread(lambda: self.plugin._handle_profile_file_open(str(path)))
            else:
                BulletinHelper.show_error("Файл ещё не загружен или не найден")
        except:
            pass

class AppResumeRefreshHook(MethodHook):
    def __init__(self, plugin):
        super().__init__()
        self.plugin = plugin

    def after_hooked_method(self, param):
        try:
            self.plugin._debug_state_snapshot("app_resume:before")
        except:
            pass
        try:
            self.plugin._ensure_user_context(force=False)
        except:
            pass
        try:
            self.plugin._prune_active_controller_refs()
        except:
            pass
        try:
            if self.plugin._is_local_rating_active() and self.plugin._is_my_profile_activity():
                self.plugin._refresh_visible_profile_boosts()
        except:
            pass
        try:
            if self.plugin.gift_library:
                self.plugin._rebuild_injection_payloads()
        except:
            pass
        try:
            self.plugin._prewarm_self_user_info_cache(force=False)
        except:
            pass
        try:
            if self.plugin._has_profile_overrides():
                self.plugin._patch_my_cached_user(patch_userconfig=False)
        except:
            pass
        try:
            if self.plugin._has_profile_overrides():
                self.plugin._patch_userconfig_current_user(force=True)
        except:
            pass
        try:
            if self.plugin._has_profile_overrides() or self.plugin._is_local_rating_active():
                self.plugin._post_local_profile_notifications(reason="app_resume", cooldown=0.25)
        except:
            pass
        # On app resume, schedule a staggered re-patch series so wear/identity state
        # survives any incoming server sync that fires right after the app becomes active
        try:
            if self.plugin._has_profile_overrides():
                self.plugin._schedule_cached_user_patch([0, 300, 900, 2500], patch_userconfig=True, key="resume_wear_patch")
        except:
            pass
        try:
            if self.plugin._has_local_gifts_overrides() and self.plugin._is_my_profile_activity():
                self.plugin._schedule_profile_gifts_refresh([180, 520], min_interval=0.65, force=False)
        except:
            pass
        try:
            self.plugin._debug_state_snapshot("app_resume:after")
        except:
            pass


class ChatActivityFakeIncomingHook(MethodHook):
    def __init__(self, plugin):
        super().__init__()
        self.plugin = plugin

    def after_hooked_method(self, param):
        try:
            chat_activity = getattr(param, "thisObject", None)
            if chat_activity is None:
                return
            try:
                method_name = str(param.method.getName() or "") if getattr(param, "method", None) is not None else ""
            except:
                method_name = ""
            if method_name not in ["createView", "onResume", "onFragmentCreate"]:
                return
            delays = [120, 420] if method_name == "createView" else [80, 260]
            self.plugin._schedule_fake_incoming_restore(chat_activity, delays=delays)
        except Exception as e:
            _log(f"ChatActivityFakeIncomingHook error: {e}")


class ResaleGridUpdateHook(MethodHook):
    def __init__(self, plugin):
        super().__init__()
        self.plugin = plugin

    def before_hooked_method(self, param):
        try:
            frag = param.thisObject
            valid = []
            for ctrl in (getattr(self.plugin, "active_catalog_controllers", None) or []):
                try:
                    if ctrl.fragment and ctrl.fragment.equals(frag):
                        valid.append(ctrl)
                        if bool(getattr(ctrl, "block_native_update", True)):
                            try:
                                _log("CatalogGrid.updateList: native update blocked for active controller")
                            except:
                                pass
                            param.setResult(None)
                            self.plugin.active_catalog_controllers = valid
                            return
                    elif ctrl.fragment:
                        valid.append(ctrl)
                except:
                    pass
            self.plugin.active_catalog_controllers = valid
        except:
            pass


def _iter_unique_plugin_controllers(plugin):
    seen = set()
    try:
        buckets = [
            getattr(plugin, "active_controllers", None) or [],
            getattr(plugin, "active_catalog_controllers", None) or [],
        ]
    except:
        buckets = []
    for bucket in buckets:
        try:
            for ctrl in list(bucket):
                if ctrl is None:
                    continue
                key = id(ctrl)
                if key in seen:
                    continue
                seen.add(key)
                yield ctrl
        except:
            continue


class ResaleGridFillItemsHook(MethodHook):
    def __init__(self, plugin):
        super().__init__()
        self.plugin = plugin

    def before_hooked_method(self, param):
        try:
            frag = param.thisObject
            for ctrl in _iter_unique_plugin_controllers(self.plugin):
                try:
                    if ctrl.fragment and ctrl.fragment.equals(frag):
                        if bool(getattr(ctrl, "use_official_render", False)):
                            return
                        param.setResult(None)
                        ctrl._fill_items(param.args[0], param.args[1])
                        return
                except:
                    continue
        except:
            pass


