class UpdateListHook(MethodHook):
    def __init__(self, plugin):
        super().__init__()
        self.plugin = plugin

    def before_hooked_method(self, param):
        try:
            frag = param.thisObject
            active_regular = []
            active_catalog = []
            matched = False

            for ctrl in list(getattr(self.plugin, "active_controllers", None) or []):
                try:
                    if ctrl.fragment:
                        active_regular.append(ctrl)
                        if ctrl.fragment.equals(frag):
                            matched = True
                            if bool(getattr(ctrl, "block_native_update", True)):
                                param.setResult(None)
                                self.plugin.active_controllers = active_regular
                                self.plugin.active_catalog_controllers = list(getattr(self.plugin, "active_catalog_controllers", None) or [])
                                return
                except:
                    pass

            for ctrl in list(getattr(self.plugin, "active_catalog_controllers", None) or []):
                try:
                    if ctrl.fragment:
                        active_catalog.append(ctrl)
                        if ctrl.fragment.equals(frag):
                            matched = True
                            if bool(getattr(ctrl, "block_native_update", True)):
                                param.setResult(None)
                                self.plugin.active_controllers = active_regular
                                self.plugin.active_catalog_controllers = active_catalog
                                return
                except:
                    pass

            self.plugin.active_controllers = active_regular
            self.plugin.active_catalog_controllers = active_catalog
            if matched:
                return
        except:
            pass


