    def _ensure_bg_executor(self):
        if getattr(self, "_bg_exec", None) is not None:
            return True
        try:
            Executors = jclass("java.util.concurrent.Executors")
            try:
                self._bg_timeunit = jclass("java.util.concurrent.TimeUnit")
            except:
                self._bg_timeunit = None
            try:
                self._bg_exec = Executors.newSingleThreadScheduledExecutor()
            except:
                self._bg_exec = Executors.newSingleThreadExecutor()
            return True
        except:
            self._bg_exec = None
            self._bg_timeunit = None
            return False

    def _bg_submit(self, fn, delay_ms=0):
        """
        Best-effort: run fn off the UI thread.
        Returns a Future when scheduled, otherwise None.
        """
        try:
            if bool(getattr(self, "_plugin_unloading", False)):
                return None
        except:
            pass
        try:
            delay_ms = int(delay_ms or 0)
        except:
            delay_ms = 0
        try:
            if not self._ensure_bg_executor():
                return None
        except:
            return None
        try:
            if delay_ms > 0 and self._bg_timeunit is not None and hasattr(self._bg_exec, "schedule"):
                return self._bg_exec.schedule(JRunnable(fn), int(delay_ms), self._bg_timeunit.MILLISECONDS)
        except:
            pass
        try:
            self._bg_exec.execute(JRunnable(fn))
        except:
            pass
        return None

    def _next_ui_batch_token(self, key):
        try:
            tokens = getattr(self, "_ui_batch_tokens", None)
            if not isinstance(tokens, dict):
                tokens = {}
                self._ui_batch_tokens = tokens
            tokens[key] = int(tokens.get(key, 0) or 0) + 1
            return int(tokens.get(key, 0) or 0)
        except:
            return 0

    def _invalidate_ui_batch(self, key):
        try:
            return int(self._next_ui_batch_token(key) or 0)
        except:
            return 0

    def _schedule_ui_batch(self, key, fn, delays):
        if fn is None:
            return False
        if not isinstance(delays, (list, tuple)):
            delays = [delays]
        token = self._next_ui_batch_token(key)
        scheduled = False
        seen = set()
        for delay in delays:
            try:
                d = int(delay or 0)
            except:
                d = 0
            if d < 0:
                d = 0
            if d in seen:
                continue
            seen.add(d)

            def _run(_token=token, _key=str(key or "")):
                try:
                    if bool(getattr(self, "_plugin_unloading", False)):
                        return
                    tokens = getattr(self, "_ui_batch_tokens", None)
                    if isinstance(tokens, dict) and int(tokens.get(_key, 0) or 0) != int(_token or 0):
                        return
                except:
                    pass
                try:
                    fn()
                except:
                    pass

            try:
                AndroidUtilities.runOnUIThread(JRunnable(_run), d)
                scheduled = True
            except:
                pass
        return scheduled

