    def _schedule_profile_activity_task(self, key, profile_activity, fn, delays):
        if fn is None or profile_activity is None:
            return False
        try:
            frag_key = int(profile_activity.hashCode())
        except:
            frag_key = 0
        try:
            session = int(getattr(self, "_profile_patch_session", 0) or 0)
        except:
            session = 0
        try:
            runtime_gen = int(getattr(self, "_profile_runtime_gen", 0) or 0)
        except:
            runtime_gen = 0

        def _run(_frag_key=frag_key, _session=session, _runtime_gen=runtime_gen):
            try:
                if bool(getattr(self, "_plugin_unloading", False)):
                    return
            except:
                pass
            try:
                if int(getattr(self, "_profile_patch_session", 0) or 0) != int(_session or 0):
                    return
            except:
                pass
            try:
                if int(getattr(self, "_profile_runtime_gen", 0) or 0) != int(_runtime_gen or 0):
                    return
            except:
                pass
            try:
                active = self._get_visible_profile_activity()
            except:
                active = None
            if active is None:
                return
            try:
                active_key = int(active.hashCode())
            except:
                active_key = 0
            if int(_frag_key or 0) > 0 and int(active_key or 0) != int(_frag_key or 0):
                return
            try:
                if not self._is_my_profile_activity(active):
                    return
            except:
                return
            try:
                fn(active)
            except:
                pass

        return self._schedule_ui_batch(
            f"{str(key or 'profile_task')}_{int(frag_key or 0)}",
            _run,
            delays,
        )

    def _schedule_cached_user_patch(self, delays=None, patch_userconfig=True, key="cached_user_patch"):
        if delays is None:
            delays = [0, 180, 560]
        def _cb():
            try:
                self._patch_my_cached_user(patch_userconfig=patch_userconfig)
            except:
                pass
            try:
                self._patch_my_cached_user_full()
            except:
                pass
        base_key = "cached_user_patch_uc" if patch_userconfig else "cached_user_patch_fast"
        try:
            suffix = str(key or "default")
        except:
            suffix = "default"
        token_key = f"{base_key}:{suffix}"
        return self._schedule_ui_batch(token_key, _cb, delays)

    def _get_visible_profile_activity(self):
        try:
            frag = get_last_fragment()
        except:
            frag = None
        if frag is None:
            return None
        try:
            frag_name = str(frag.getClass().getName() or "")
        except:
            frag_name = ""
        if "ProfileActivity" not in frag_name:
            return None
        return frag

    def _mark_profile_activity_open(self, profile_activity=None):
        pa = profile_activity if profile_activity is not None else self._get_visible_profile_activity()
        if pa is None:
            return 0
        try:
            frag_key = int(pa.hashCode())
        except:
            frag_key = 0
        if frag_key <= 0:
            return 0
        try:
            if int(getattr(self, "_profile_open_frag_key", 0) or 0) != frag_key:
                self._profile_open_frag_key = frag_key
                self._profile_open_last_ts = time.time()
        except:
            pass
        return frag_key

    def _is_profile_activity_cold_open(self, profile_activity=None, window_sec=0.38):
        pa = profile_activity if profile_activity is not None else self._get_visible_profile_activity()
        if pa is None:
            return False
        try:
            frag_key = int(pa.hashCode())
        except:
            frag_key = 0
        if frag_key <= 0:
            return False
        try:
            last_key = int(getattr(self, "_profile_open_frag_key", 0) or 0)
            last_ts = float(getattr(self, "_profile_open_last_ts", 0.0) or 0.0)
            return bool(last_key == frag_key and (time.time() - last_ts) < float(window_sec or 0.0))
        except:
            return False

    def _should_run_profile_open_heavy_pass(self, profile_activity=None, window_sec=0.9):
        pa = profile_activity if profile_activity is not None else self._get_visible_profile_activity()
        if pa is None:
            return False
        try:
            frag_key = int(pa.hashCode())
        except:
            frag_key = 0
        if frag_key <= 0:
            return True
        now = time.time()
        try:
            last_key = int(getattr(self, "_profile_open_heavy_frag_key", 0) or 0)
            last_ts = float(getattr(self, "_profile_open_heavy_last_ts", 0.0) or 0.0)
            if last_key == frag_key and (now - last_ts) < float(window_sec or 0.0):
                return False
        except:
            pass
        try:
            self._profile_open_heavy_frag_key = frag_key
            self._profile_open_heavy_last_ts = now
        except:
            pass
        return True

