    def _is_my_profile_activity(self, profile_activity=None):
        pa = profile_activity if profile_activity is not None else self._get_visible_profile_activity()
        if pa is None:
            return False
        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0
        if my_id <= 0:
            return False
        try:
            uid = int(self._get_profile_activity_user_id(pa) or 0)
        except:
            uid = 0
        return bool(uid > 0 and uid == my_id)

    def _prune_active_controller_refs(self, max_keep=4):
        try:
            merged = []
            seen = set()
            for bucket in [
                getattr(self, "active_catalog_controllers", None) or [],
                getattr(self, "active_controllers", None) or [],
            ]:
                for ctrl in list(bucket):
                    if ctrl is None:
                        continue
                    frag = getattr(ctrl, "fragment", None)
                    if frag is None:
                        continue
                    key = id(ctrl)
                    if key in seen:
                        continue
                    seen.add(key)
                    merged.append(ctrl)
            try:
                keep_n = max(int(max_keep or 0), 1)
            except:
                keep_n = 4
            if len(merged) > keep_n:
                merged = merged[-keep_n:]
            self.active_catalog_controllers = merged
            self.active_controllers = merged
            return len(merged)
        except:
            return 0

    def _recompute_gift_objects_limit(self):
        try:
            _ = len(self.gift_library or [])
        except:
            pass
        target = 12
        try:
            self._gift_objects_max = int(target)
        except:
            self._gift_objects_max = 12
        return int(getattr(self, "_gift_objects_max", 12) or 12)

    def _has_live_catalog_controller(self):
        try:
            self._prune_active_controller_refs()
        except:
            pass
        try:
            for ctrl in list(getattr(self, "active_catalog_controllers", None) or []):
                if ctrl is not None and getattr(ctrl, "fragment", None) is not None:
                    return True
        except:
            pass
        return False

    def _can_warm_catalog(self):
        try:
            if self._is_my_profile_activity():
                return True
        except:
            pass
        try:
            if self._has_live_catalog_controller():
                return True
        except:
            pass
        return False

    def _collect_saved_gift_lists(self, root, max_depth=2):
        found = []
        if root is None:
            return found

        visited = set()
        found_ids = set()

        def looks_like_list(obj):
            if obj is None:
                return False
            try:
                _ = obj.size()
                _ = obj.get
                return True
            except:
                return False

        def iter_fields(obj):
            out = []
            try:
                cls = obj.getClass()
            except:
                return out
            try:
                for f in cls.getDeclaredFields():
                    try:
                        f.setAccessible(True)
                    except:
                        pass
                    out.append(f)
            except:
                pass
            try:
                for f in cls.getFields():
                    out.append(f)
            except:
                pass
            return out

        def list_id(obj):
            try:
                return int(obj.hashCode())
            except:
                return id(obj)

        def remember_list(lst):
            if lst is None:
                return
            try:
                lid = list_id(lst)
            except:
                lid = id(lst)
            if lid in found_ids:
                return
            found_ids.add(lid)
            found.append(lst)

        def looks_like_saved_gifts_field(field_name, lst):
            try:
                if lst is not None and int(lst.size() or 0) > 0:
                    sample = lst.get(0)
                    if self._looks_like_saved_gift_wrapper(sample):
                        return True
            except:
                pass
            low = str(field_name or "").lower()
            return bool(("gift" in low and "saved" in low) or ("star" in low and "gift" in low))

        def walk(obj, depth):
            if obj is None or depth > max_depth:
                return
            try:
                oid = int(obj.hashCode())
            except:
                oid = id(obj)
            if oid in visited:
                return
            visited.add(oid)

            if looks_like_list(obj):
                try:
                    if int(obj.size() or 0) > 0 and self._looks_like_saved_gift_wrapper(obj.get(0)):
                        remember_list(obj)
                except:
                    pass
                return

            for f in iter_fields(obj):
                try:
                    name = str(f.getName() or "")
                except:
                    name = ""
                try:
                    val = f.get(obj)
                except:
                    continue
                if val is None:
                    continue
                if looks_like_list(val):
                    try:
                        if looks_like_saved_gifts_field(name, val):
                            remember_list(val)
                            continue
                    except:
                        pass
                try:
                    walk(val, depth + 1)
                except:
                    pass

        walk(root, 0)
        return found

    def _get_cached_profile_saved_lists(self, profile_activity, force_rescan=False):
        if profile_activity is None:
            return []
        try:
            frag_key = int(profile_activity.hashCode())
        except:
            frag_key = 0
        cached = []
        try:
            if (not force_rescan) and frag_key > 0 and int(getattr(self, "_profile_saved_lists_frag_key", 0) or 0) == frag_key:
                cached = list(getattr(self, "_profile_saved_lists", None) or [])
        except:
            cached = []

        live = []
        for lst in list(cached or []):
            try:
                _ = lst.size()
                _ = lst.get
                live.append(lst)
            except:
                continue
        if live:
            return live

        try:
            scanned = self._collect_saved_gift_lists(profile_activity, max_depth=2)
        except:
            scanned = []
        try:
            self._profile_saved_lists = list(scanned or [])
            self._profile_saved_lists_frag_key = int(frag_key or 0)
        except:
            pass
        return list(scanned or [])

    def _notify_profile_activity_adapters_light(self, profile_activity, cooldown=0.22, force=False):
        if profile_activity is None:
            return 0
        try:
            frag_key = int(profile_activity.hashCode())
        except:
            frag_key = 0
        if (not force) and frag_key > 0:
            try:
                now = time.time()
                last_key = int(getattr(self, "_profile_ui_notify_frag_key", 0) or 0)
                last_ts = float(getattr(self, "_profile_ui_notify_last_ts", 0.0) or 0.0)
                if last_key == frag_key and (now - last_ts) < float(cooldown or 0.0):
                    return 0
                self._profile_ui_notify_frag_key = frag_key
                self._profile_ui_notify_last_ts = now
            except:
                pass
        notified = 0
        seen = set()

        def _poke_adapter(adapter):
            nonlocal notified
            if adapter is None:
                return
            try:
                aid = int(adapter.hashCode())
            except:
                aid = id(adapter)
            if aid in seen:
                return
            seen.add(aid)
            try:
                if hasattr(adapter, "update") and callable(getattr(adapter, "update", None)):
                    adapter.update(False)
                    notified += 1
                    return
            except:
                pass
            try:
                if hasattr(adapter, "notifyDataSetChanged") and callable(getattr(adapter, "notifyDataSetChanged", None)):
                    adapter.notifyDataSetChanged()
                    notified += 1
                    return
            except:
                pass

        for name in ["listView", "recyclerListView", "giftsListView", "mediaListView", "sharedMediaLayout", "adapter", "giftsAdapter", "listAdapter"]:
            try:
                obj = get_val(profile_activity, name, None)
            except:
                obj = None
            if obj is None:
                continue
            try:
                _poke_adapter(obj.getAdapter() if hasattr(obj, "getAdapter") and callable(getattr(obj, "getAdapter", None)) else None)
            except:
                pass
            _poke_adapter(obj)
            try:
                if hasattr(obj, "invalidate") and callable(getattr(obj, "invalidate", None)):
                    obj.invalidate()
            except:
                pass
        for name in ["fragmentView", "avatarContainer", "actionsView"]:
            try:
                obj = get_val(profile_activity, name, None)
            except:
                obj = None
            if obj is None:
                continue
            try:
                if hasattr(obj, "invalidate") and callable(getattr(obj, "invalidate", None)):
                    obj.invalidate()
            except:
                pass
        return int(notified or 0)

    def _sync_saved_gifts_owner_count_fields(self, owner, gifts_list=None, field_names=None, desired_min=0):
        if owner is None:
            return 0
        if gifts_list is None:
            try:
                gifts_list = get_val(owner, "gifts", None)
            except:
                gifts_list = None
        if not self._is_java_list_like(gifts_list):
            return 0
        try:
            actual_size = int(gifts_list.size() or 0)
        except:
            actual_size = 0
        try:
            desired = max(int(desired_min or 0), int(actual_size or 0))
        except:
            desired = int(actual_size or 0)
        if desired <= 0:
            return 0
        names = [str(v) for v in list(field_names or []) if str(v or "").strip()]
        if not names:
            return 0
        current = 0
        for name in names:
            try:
                current = max(current, int(self._to_int(get_val(owner, name, 0), 0) or 0))
            except:
                pass
        new_value = max(int(current or 0), int(desired or 0))
        if new_value <= 0 or new_value == current:
            return 0
        changed = False
        for name in names:
            try:
                if self._set_field(owner, name, int(new_value)):
                    changed = True
            except:
                pass
            try:
                if int(self._to_int(get_val(owner, name, 0), 0) or 0) != int(new_value):
                    setattr(owner, name, int(new_value))
                    changed = True
            except:
                pass
        return int(1 if changed else 0)

    def _scan_object_and_sync_saved_gifts_counts(self, root, desired_min=0, max_depth=2):
        if root is None:
            return 0
        visited = set()
        patched = 0

        def walk(obj, depth):
            nonlocal patched
            if obj is None or depth > max_depth:
                return
            try:
                oid = int(obj.hashCode())
            except:
                oid = id(obj)
            if oid in visited:
                return
            visited.add(oid)
            try:
                gifts = get_val(obj, "gifts", None)
            except:
                gifts = None
            if self._is_java_list_like(gifts):
                try:
                    owner_name = str(obj.getClass().getName() or "").lower()
                except:
                    owner_name = ""
                try:
                    sample = gifts.get(0) if int(gifts.size() or 0) > 0 else None
                except:
                    sample = None
                looks_saved = bool(("gift" in owner_name) and ("list" in owner_name or "controller" in owner_name))
                if sample is not None:
                    looks_saved = self._looks_like_saved_gift_wrapper(sample)
                if not looks_saved and sample is not None:
                    try:
                        sample_name = str(sample.getClass().getName() or "").lower()
                    except:
                        sample_name = ""
                    looks_saved = bool("stargift" in sample_name)
                if looks_saved:
                    try:
                        patched += int(self._sync_saved_gifts_owner_count_fields(
                            obj,
                            gifts_list=gifts,
                            field_names=["totalCount", "count"],
                            desired_min=desired_min,
                        ) or 0)
                    except:
                        pass
            try:
                cls_name = str(obj.getClass().getName() or "")
            except:
                cls_name = ""
            if cls_name.startswith("android.") or cls_name.startswith("androidx."):
                try:
                    if hasattr(obj, "getAdapter") and callable(getattr(obj, "getAdapter", None)):
                        walk(obj.getAdapter(), depth + 1)
                except:
                    pass
                return
            for f in self._iter_object_fields(obj):
                try:
                    val = f.get(obj)
                except:
                    continue
                if val is None:
                    continue
                try:
                    walk(val, depth + 1)
                except:
                    pass

        walk(root, 0)
        return int(patched or 0)

    def _rebuild_profile_gifts_rows(self, profile_activity, animated=True):
        if profile_activity is None:
            return 0
        try:
            if not self._is_my_profile_activity(profile_activity):
                return 0
        except:
            return 0
        rebuilt = 0
        try:
            if hasattr(profile_activity, "updateRowsIds") and callable(getattr(profile_activity, "updateRowsIds", None)):
                profile_activity.updateRowsIds()
                rebuilt += 1
        except:
            pass
        try:
            if hasattr(profile_activity, "updateSelectedMediaTabText") and callable(getattr(profile_activity, "updateSelectedMediaTabText", None)):
                profile_activity.updateSelectedMediaTabText()
                rebuilt += 1
        except:
            pass
        try:
            list_adapter = get_val(profile_activity, "listAdapter", None)
        except:
            list_adapter = None
        if list_adapter is not None:
            try:
                if hasattr(list_adapter, "notifyDataSetChanged") and callable(getattr(list_adapter, "notifyDataSetChanged", None)):
                    list_adapter.notifyDataSetChanged()
                    rebuilt += 1
            except:
                pass
        try:
            shared_media = get_val(profile_activity, "sharedMediaLayout", None)
        except:
            shared_media = None
        if shared_media is not None:
            try:
                rebuilt += int(self._scan_object_and_sync_saved_gifts_counts(shared_media, desired_min=self._get_local_profile_gifts_count(), max_depth=2) or 0)
            except:
                pass
            try:
                if hasattr(shared_media, "updateTabs") and callable(getattr(shared_media, "updateTabs", None)):
                    shared_media.updateTabs(bool(animated))
                    rebuilt += 1
            except:
                pass
            try:
                if hasattr(shared_media, "updateAdapters") and callable(getattr(shared_media, "updateAdapters", None)):
                    shared_media.updateAdapters()
                    rebuilt += 1
            except:
                pass
        return int(rebuilt or 0)

    def _refresh_profile_activity_views_light(self, profile_activity, cooldown=0.28, force=False):
        if profile_activity is None:
            return 0
        try:
            frag_key = int(profile_activity.hashCode())
        except:
            frag_key = 0
        if (not force) and frag_key > 0:
            try:
                now = time.time()
                last_key = int(getattr(self, "_profile_ui_refresh_frag_key", 0) or 0)
                last_ts = float(getattr(self, "_profile_ui_refresh_last_ts", 0.0) or 0.0)
                if last_key == frag_key and (now - last_ts) < float(cooldown or 0.0):
                    return 0
                self._profile_ui_refresh_frag_key = frag_key
                self._profile_ui_refresh_last_ts = now
            except:
                pass
        refreshed = 0
        for name in ["fragmentView", "avatarContainer", "actionsView", "listView", "recyclerListView", "giftsListView"]:
            try:
                obj = get_val(profile_activity, name, None)
            except:
                obj = None
            if obj is None:
                continue
            try:
                if hasattr(obj, "invalidate") and callable(getattr(obj, "invalidate", None)):
                    obj.invalidate()
                    refreshed += 1
            except:
                pass
        return int(refreshed or 0)

    def _patch_profile_shared_media_layout(self, profile_activity, animated=True):
        if profile_activity is None:
            return 0
        try:
            if not self._is_my_profile_activity(profile_activity):
                return 0
        except:
            return 0
        try:
            shared_media = get_val(profile_activity, "sharedMediaLayout", None)
        except:
            shared_media = None
        if shared_media is None:
            return 0
        try:
            target_entity_id = int(self._get_profile_activity_entity_id(profile_activity) or 0)
        except:
            target_entity_id = 0
        try:
            desired_count = int(self._get_local_profile_gifts_count(target_entity_id) or 0)
        except:
            desired_count = 0
        user_info = None
        for field_name in ["userInfo", "userFull", "currentUserInfo", "currentUserFull"]:
            try:
                user_info = get_val(profile_activity, field_name, None)
            except:
                user_info = None
            if user_info is not None:
                break
        if user_info is None:
            return 0
        changed = 0
        try:
            current_user_info = get_val(shared_media, "userInfo", None)
        except:
            current_user_info = None
        try:
            if current_user_info is not user_info and self._set_field(shared_media, "userInfo", user_info):
                changed += 1
        except:
            pass
        try:
            changed += int(self._scan_object_and_sync_saved_gifts_counts(shared_media, desired_min=desired_count, max_depth=2) or 0)
        except:
            pass
        try:
            if hasattr(shared_media, "setUserInfo") and callable(getattr(shared_media, "setUserInfo", None)):
                shared_media.setUserInfo(user_info)
                changed += 1
            elif hasattr(shared_media, "updateTabs") and callable(getattr(shared_media, "updateTabs", None)):
                shared_media.updateTabs(bool(animated))
                changed += 1
        except:
            pass
        try:
            changed += int(self._rebuild_profile_gifts_rows(profile_activity, animated=animated) or 0)
        except:
            pass
        return int(changed or 0)

    def _schedule_profile_ui_repatch(self, profile_activity, delays=None):
        if profile_activity is None:
            return False
        try:
            frag_key = int(profile_activity.hashCode())
        except:
            frag_key = 0
        if frag_key > 0:
            try:
                now = time.time()
                last_key = int(getattr(self, "_profile_ui_repatch_frag_key", 0) or 0)
                last_ts = float(getattr(self, "_profile_ui_repatch_last_ts", 0.0) or 0.0)
                if last_key == frag_key and (now - last_ts) < 0.26:
                    return False
                self._profile_ui_repatch_frag_key = frag_key
                self._profile_ui_repatch_last_ts = now
            except:
                pass
        if delays is None:
            delays = [180, 420]
        try:
            delays = [d for d in list(delays or []) if int(d or 0) >= 0]
        except:
            delays = [180, 420]
        if len(delays) > 2:
            try:
                delays = sorted(set([int(d or 0) for d in delays if int(d or 0) >= 0]))[:2]
            except:
                delays = [180, 420]

        def _run_repatch(pa):
            changed = 0
            try:
                # Delayed repatch is meant to refresh lightweight profile state
                # after async userInfo callbacks; do not re-enter the expensive
                # major view-tree scan here or the profile will hitch every time
                # Telegram emits a follow-up notification.
                changed = int(self._patch_profile_activity_in_place(pa, notify=False, include_major_views=False) or 0)
            except:
                changed = 0
            if changed > 0:
                try:
                    self._refresh_profile_activity_views_light(pa, force=True)
                except:
                    pass

        return self._schedule_profile_activity_task(
            "profile_ui_repatch",
            profile_activity,
            _run_repatch,
            delays,
        )

    def _schedule_profile_gifts_refresh(self, delays=None, min_interval=0.55, force=False):
        if delays is None:
            delays = [120, 420]
        try:
            if not self._has_local_gifts_overrides():
                return False
        except:
            pass
        try:
            if not self._is_my_profile_activity():
                return False
        except:
            return False
        try:
            if bool(getattr(self, "_profile_gifts_refresh_busy", False)) and (not force):
                return False
        except:
            pass
        try:
            now = time.time()
            last = float(getattr(self, "_profile_gifts_refresh_last_ts", 0.0) or 0.0)
            if (not force) and (now - last) < float(min_interval or 0.0):
                return False
            self._profile_gifts_refresh_last_ts = now
        except:
            pass
        return self._schedule_ui_batch("profile_gifts_refresh", self._refresh_profile_gifts_ui, delays)

    def _heal_runtime_state(self, reason="", force=False):
        """
        Best-effort runtime self-heal for cases where slot context is unchanged,
        but Java-side cached objects were dropped after resume/account bounce.
        """
        healed = False
        try:
            has_library = bool(self.gift_library and len(self.gift_library) > 0)
        except:
            has_library = False

        try:
            needs_payloads = bool(has_library and ((not self.inject_active) or (not self.injection_payloads)))
        except:
            needs_payloads = bool(has_library)

        if needs_payloads:
            try:
                before = len(self.injection_payloads or [])
            except:
                before = 0
            try:
                self._rebuild_injection_payloads()
            except:
                pass
            try:
                after = len(self.injection_payloads or [])
            except:
                after = 0
            if after <= 0:
                try:
                    self._load_injection_cache(uid=self._get_cache_uid())
                except:
                    pass
                try:
                    self._rebuild_injection_payloads()
                except:
                    pass
                try:
                    after = len(self.injection_payloads or [])
                except:
                    after = 0
            if after > 0:
                try:
                    self.inject_active = True
                except:
                    pass
                try:
                    if self.injection_payload is None:
                        self.injection_payload = self.injection_payloads[0]
                except:
                    pass
                healed = bool(after != before or (not getattr(self, "inject_active", False)))

        try:
            if self._has_profile_overrides():
                # Runtime heal can be triggered by many unrelated requests while
                # the account context stays unchanged. Keep it delayed-only so
                # network activity does not immediately schedule UI work.
                self._schedule_cached_user_patch([180], key="runtime_state_heal_patch")
        except:
            pass

        try:
            if self._has_local_gifts_overrides() or has_library:
                self._schedule_profile_gifts_refresh([90, 320], min_interval=0.18, force=(force or healed))
        except:
            pass

        try:
            if healed:
                self._debug_state_snapshot("heal_runtime", f"reason={reason} force={1 if force else 0}")
        except:
            pass
        return bool(healed)

    def _shutdown_bg_executor(self):
        try:
            for attr in ["_cache_save_future", "_inj_save_future"]:
                fut = getattr(self, attr, None)
                if fut is not None:
                    try:
                        fut.cancel(False)
                    except:
                        pass
                try:
                    setattr(self, attr, None)
                except:
                    pass
        except:
            pass
        try:
            self._cache_pending = None
        except:
            pass
        exec_obj = getattr(self, "_bg_exec", None)
        if exec_obj is not None:
            try:
                if hasattr(exec_obj, "shutdownNow"):
                    exec_obj.shutdownNow()
                else:
                    exec_obj.shutdown()
            except:
                try:
                    exec_obj.shutdown()
                except:
                    pass
        try:
            self._bg_exec = None
            self._bg_timeunit = None
        except:
            pass

    def _hook_native_catalog_ui(self):
        try:
            JavaClass = jclass("java.lang.Class")
            frag_class = JavaClass.forName("org.telegram.ui.Gifts.ResaleGiftsFragment")
        except Exception as e:
            _log(f"Native catalog hook skipped: {e}")
            return

        hooked = 0
        try:
            for m in frag_class.getDeclaredMethods():
                try:
                    name = m.getName()
                except:
                    continue
                try:
                    m.setAccessible(True)
                except:
                    pass
                if name == "updateList":
                    self.hooks_refs.append(self.hook_method(m, UpdateListHook(self)))
                    hooked += 1
                elif name == "fillItems":
                    self.hooks_refs.append(self.hook_method(m, ResaleGridFillItemsHook(self)))
                    hooked += 1
                elif name == "onItemClick":
                    self.hooks_refs.append(self.hook_method(m, ResaleGridClickHook(self)))
                    hooked += 1
        except Exception as e:
            _log(f"Native catalog hook error: {e}")
            return

        if hooked:
            _log(f"Native catalog hooks installed: {hooked}")

