    def _commit_local_rating_settings(self, stars_value=None, level=None, next_goal=None, notify=True):
        for raw in [("rating", stars_value), ("level", level), ("goal", next_goal)]:
            key, value = raw
            if value is None:
                continue
            try:
                text = str(value).strip()
            except:
                text = ""
            if text and (not text.isdigit()):
                raise ValueError("Введите числовое значение")
        try:
            stars = self._get_local_rating_value()
        except:
            stars = 0
        try:
            lvl = self._get_local_rating_level()
        except:
            lvl = 1
        try:
            goal = self._get_local_rating_next_goal()
        except:
            goal = 5000

        if stars_value is not None:
            stars = self._sanitize_local_rating_value(stars_value)
        if level is not None:
            lvl = self._sanitize_local_rating_level(level)
        if next_goal is not None:
            goal = self._sanitize_local_rating_next_goal(next_goal, stars)
        else:
            goal = self._sanitize_local_rating_next_goal(goal, stars)

        self.local_rating_value = int(stars)
        self.local_rating_level = int(lvl)
        self.local_rating_next_goal = int(goal)
        self.local_rating_enabled = bool(stars > 0)

        try:
            self._save_cache()
        except:
            pass
        try:
            self._refresh_visible_profile_boosts()
        except:
            pass
        try:
            self._post_local_profile_notifications(reason="local_rating_commit", cooldown=0.15)
        except:
            pass

        if not notify:
            return
        try:
            if self.local_rating_enabled:
                BulletinHelper.show_success(f"Локальный рейтинг сохранен: {self._get_local_rating_label()}")
            else:
                BulletinHelper.show_success("Локальный рейтинг выключен")
        except:
            pass

