    def _has_local_profile_gifts_presence(self, target_user_id=0):
        try:
            uid = int(target_user_id or 0)
        except:
            uid = 0
        if uid <= 0:
            try:
                uid = int(self._get_my_user_id() or 0)
            except:
                uid = 0
        if uid <= 0:
            return False
        try:
            return bool(self._has_local_gifts_for_target_entity(uid))
        except:
            pass
        try:
            return bool(self.gift_library)
        except:
            return False

    def _get_local_profile_gifts_count(self, target_user_id=0):
        try:
            uid = int(target_user_id or 0)
        except:
            uid = 0
        if uid <= 0:
            try:
                uid = int(self._get_my_user_id() or 0)
            except:
                uid = 0
        if uid <= 0:
            return 0
        count = 0
        try:
            for entry in list(self.gift_library or []):
                if not isinstance(entry, dict):
                    continue
                try:
                    entry_uid = int(self._get_entry_target_entity_id(entry, fallback_to_self=True) or 0)
                except:
                    entry_uid = 0
                if entry_uid != uid:
                    continue
                count += 1
        except:
            count = 0
        if count <= 0:
            try:
                if self._has_local_profile_gifts_presence(uid):
                    return 1
            except:
                pass
        return int(count or 0)

    def _apply_local_profile_gifts_to_obj(self, obj, allow_profile_context_fallback=False):
        if obj is None:
            return False
        try:
            if not self._should_apply_self_profile_override(obj, allow_profile_context_fallback=allow_profile_context_fallback):
                return False
        except:
            return False
        try:
            target_uid = int(self._extract_user_id_from_obj(obj) or 0)
        except:
            target_uid = 0
        if target_uid <= 0:
            try:
                target_uid = int(self._get_my_user_id() or 0)
            except:
                target_uid = 0
        local_count = int(self._get_local_profile_gifts_count(target_uid) or 0)
        if local_count <= 0:
            return False
        try:
            cls_name = str(obj.getClass().getName() or "").lower()
        except:
            cls_name = ""
        field_names = set()
        try:
            field_names = set([str(f.getName() or "") for f in self._iter_object_fields(obj)])
        except:
            field_names = set()
        if ("userfull" not in cls_name) and ("chatfull" not in cls_name) and ("stargifts_count" not in field_names) and ("stargiftsCount" not in field_names):
            return False
        current = 0
        for name in ["stargifts_count", "stargiftsCount"]:
            try:
                current = int(self._to_int(get_val(obj, name, 0), 0) or 0)
            except:
                current = 0
            if current > 0:
                break
        desired = max(int(local_count), int(current or 0))
        if desired <= current:
            return False
        changed = False
        for name in ["stargifts_count", "stargiftsCount"]:
            try:
                if self._set_field(obj, name, int(desired)):
                    changed = True
            except:
                pass
            try:
                if getattr(obj, name) != int(desired):
                    setattr(obj, name, int(desired))
                    changed = True
            except:
                pass
        return bool(changed)

    def _get_object_cache_key(self, obj):
        if obj is None:
            return None
        try:
            key = int(obj.hashCode())
        except:
            try:
                key = id(obj)
            except:
                key = 0
        try:
            cls_name = str(obj.getClass().getName() or "")
        except:
            try:
                cls_name = str(type(obj) or "")
            except:
                cls_name = ""
        if key == 0 and not cls_name:
            return None
        return (int(key or 0), cls_name)

    def _profile_override_state_sig(self):
        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0
        try:
            verification_mode = int(self.local_verification_mode or 0)
        except:
            verification_mode = 0
        try:
            rating_value = int(self.local_rating_value or 0)
        except:
            rating_value = 0
        try:
            rating_level = int(self.local_rating_level or 0)
        except:
            rating_level = 0
        try:
            rating_goal = int(self.local_rating_next_goal or 0)
        except:
            rating_goal = 0
        try:
            username_token = str(self.nft_username or "")
        except:
            username_token = ""
        try:
            number_token = str(self.nft_number or "")
        except:
            number_token = ""
        try:
            wear_active = 1 if (self.wear_active and int(self.wear_collectible_id or 0) > 0) else 0
        except:
            wear_active = 0
        try:
            wear_id = int(self.wear_collectible_id or 0)
        except:
            wear_id = 0
        return (
            my_id,
            1 if self._is_local_verification_active() else 0,
            verification_mode,
            1 if self._is_nft_username_active() else 0,
            username_token,
            1 if self._is_nft_number_active() else 0,
            number_token,
            wear_active,
            wear_id,
            1 if self._is_local_rating_active() else 0,
            rating_value,
            rating_level,
            rating_goal,
        )

    def _get_cached_entity_id(self, obj):
        key = self._get_object_cache_key(obj)
        if key is None:
            return None
        try:
            cache = getattr(self, "_entity_id_cache", None)
            if not isinstance(cache, dict):
                cache = {}
                self._entity_id_cache = cache
            item = cache.get(key)
            if item is None:
                return None
            value, ts = item
            now = time.time()
            if (now - float(ts or 0.0)) > 30.0:
                try:
                    cache.pop(key, None)
                except:
                    pass
                return None
            return int(value or 0)
        except:
            return None

    def _store_cached_entity_id(self, obj, entity_id):
        key = self._get_object_cache_key(obj)
        if key is None:
            return
        try:
            cache = getattr(self, "_entity_id_cache", None)
            if not isinstance(cache, dict):
                cache = {}
                self._entity_id_cache = cache
            now = time.time()
            cache[key] = (int(entity_id or 0), now)
            if len(cache) > 4096:
                last_prune = float(getattr(self, "_entity_id_cache_prune_ts", 0.0) or 0.0)
                if (now - last_prune) > 3.0:
                    self._entity_id_cache_prune_ts = now
                    stale = [k for k, v in list(cache.items()) if (now - float((v[1] if isinstance(v, tuple) and len(v) > 1 else 0.0) or 0.0)) > 30.0]
                    for k in stale:
                        cache.pop(k, None)
                    if len(cache) > 3072:
                        try:
                            recent = sorted(cache.items(), key=lambda kv: float((kv[1][1] if isinstance(kv[1], tuple) and len(kv[1]) > 1 else 0.0) or 0.0), reverse=True)[:2048]
                            cache.clear()
                            for k, v in recent:
                                cache[k] = v
                        except:
                            pass
        except:
            pass

    def _should_skip_hot_get_override(self, obj, ttl=0.45):
        key = self._get_object_cache_key(obj)
        if key is None:
            return False, None
        try:
            cache = getattr(self, "_hot_get_override_cache", None)
            if not isinstance(cache, dict):
                cache = {}
                self._hot_get_override_cache = cache
            sig = self._profile_override_state_sig()
            # Telegram can mutate the same cached self-user object in-place
            # between consecutive getUser/getUserFull calls. For identity-style
            # overrides this makes a pure TTL cache unsafe and causes visible
            # blink / "every other time" drops, so always re-check them.
            try:
                identity_hot_override = bool(
                    (self.wear_active and int(self.wear_collectible_id or 0) > 0)
                    or self._is_nft_username_active()
                    or self._is_nft_number_active()
                )
            except:
                identity_hot_override = True
            if identity_hot_override:
                return False, sig
            now = time.time()
            item = cache.get(key)
            if item is not None:
                cached_sig, cached_ts = item
                if cached_sig == sig and (now - float(cached_ts or 0.0)) < float(ttl or 0.0):
                    return True, sig
            return False, sig
        except:
            return False, None

    def _mark_hot_get_override(self, obj, sig):
        if sig is None:
            return
        key = self._get_object_cache_key(obj)
        if key is None:
            return
        try:
            cache = getattr(self, "_hot_get_override_cache", None)
            if not isinstance(cache, dict):
                cache = {}
                self._hot_get_override_cache = cache
            now = time.time()
            cache[key] = (sig, now)
            if len(cache) > 4096:
                last_prune = float(getattr(self, "_hot_get_override_cache_prune_ts", 0.0) or 0.0)
                if (now - last_prune) > 1.0:
                    self._hot_get_override_cache_prune_ts = now
                    stale = [k for k, v in list(cache.items()) if (now - float((v[1] if isinstance(v, tuple) and len(v) > 1 else 0.0) or 0.0)) > 2.0]
                    for k in stale:
                        cache.pop(k, None)
                    if len(cache) > 3072:
                        try:
                            recent = sorted(cache.items(), key=lambda kv: float((kv[1][1] if isinstance(kv[1], tuple) and len(kv[1]) > 1 else 0.0) or 0.0), reverse=True)[:2048]
                            cache.clear()
                            for k, v in recent:
                                cache[k] = v
                        except:
                            pass
        except:
            pass

    def _should_apply_self_profile_override(self, obj, allow_profile_context_fallback=False):
        if obj is None:
            return False
        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0
        if my_id <= 0:
            return False

        try:
            obj_uid = int(self._extract_user_id_from_obj(obj) or 0)
        except:
            obj_uid = 0
        if obj_uid > 0:
            return bool(obj_uid == my_id)

        try:
            nested_user = get_val(obj, "user", None)
        except:
            nested_user = None
        if nested_user is not None:
            try:
                nested_uid = int(self._extract_user_id_from_obj(nested_user) or 0)
            except:
                nested_uid = 0
            if nested_uid > 0:
                return bool(nested_uid == my_id)

        if not allow_profile_context_fallback:
            return False
        try:
            return bool(self._is_my_profile_activity())
        except:
            return False

    def _apply_profile_overrides_to_obj(self, obj, allow_profile_context_fallback=False):
        if obj is None:
            return False
        try:
            if not self._should_apply_self_profile_override(obj, allow_profile_context_fallback=allow_profile_context_fallback):
                return False
        except:
            return False
        changed = False
        try:
            if self._is_local_verification_active() and self._apply_local_verification_to_full_obj(obj):
                changed = True
        except:
            pass
        try:
            if self._is_local_verification_active() and self._apply_local_verification_to_obj(obj):
                changed = True
        except:
            pass
        try:
            if self._is_local_rating_active() and self._apply_local_rating_to_obj(obj):
                changed = True
        except:
            pass
        try:
            if self._is_nft_username_active() and self._apply_nft_username_to_obj(obj):
                changed = True
        except:
            pass
        try:
            if self._is_nft_number_active() and self._apply_nft_number_to_obj(obj):
                changed = True
        except:
            pass
        try:
            if self.wear_active and int(self.wear_collectible_id or 0) > 0 and self._apply_wear_status_only_to_obj(obj):
                changed = True
        except:
            pass
        try:
            if self._apply_local_profile_gifts_to_obj(obj, allow_profile_context_fallback=allow_profile_context_fallback):
                changed = True
        except:
            pass
        return changed

    def _debug_gifts_brief(self, limit=3):
        try:
            out = []
            items = list(self.gift_library or [])
            for e in items[: max(int(limit or 0), 0)]:
                try:
                    out.append(
                        "{0}|inj={1}|owner={2}|uid={3}|sid={4}".format(
                            str(e.get("key", "") or ""),
                            1 if bool(e.get("inject", False)) else 0,
                            int(e.get("owner_user_id", 0) or 0),
                            int(e.get("unique_id", 0) or 0),
                            int(e.get("saved_id", 0) or 0),
                        )
                    )
                except:
                    continue
            return "; ".join(out)
        except:
            return ""

    def _debug_state_snapshot(self, reason, extra=""):
        try:
            acc = int(get_user_config().selectedAccount or 0)
        except:
            acc = -1
        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0
        try:
            ctx = int(getattr(self, "_context_user_id", 0) or 0)
        except:
            ctx = 0
        try:
            cache_uid = int(getattr(self, "_cache_file_user_id", 0) or 0)
        except:
            cache_uid = 0
        try:
            lib_count = len(self.gift_library or [])
        except:
            lib_count = 0
        try:
            payload_count = len(self.injection_payloads or [])
        except:
            payload_count = 0
        try:
            inject_active = 1 if bool(self.inject_active) else 0
        except:
            inject_active = 0
        try:
            uname_enabled = 1 if bool(self.nft_username_enabled) else 0
        except:
            uname_enabled = 0
        try:
            num_enabled = 1 if bool(self.nft_number_enabled) else 0
        except:
            num_enabled = 0
        try:
            unames = ",".join(list(self._get_nft_username_tokens() or [])[:3])
        except:
            unames = ""
        try:
            nums = ",".join(list(self._get_nft_number_tokens() or [])[:3])
        except:
            nums = ""
        try:
            brief = self._debug_gifts_brief(3)
        except:
            brief = ""
        try:
            msg = (
                f"DBG[{reason}] acc={acc} my={my_id} ctx={ctx} file_uid={cache_uid} "
                f"lib={lib_count} payloads={payload_count} inject={inject_active} "
                f"uname_en={uname_enabled} num_en={num_enabled} "
                f"unames=[{unames}] nums=[{nums}] gifts=[{brief}]"
            )
            if extra:
                msg += f" extra={extra}"
            _log(msg)
        except Exception as e:
            _log(f"DBG[{reason}] failed: {e}")

