    def _theme_color(self, attr_name, fallback=0xFF222222):
        try:
            key = getattr(Theme, attr_name, None)
            if key is not None:
                return int(Theme.getColor(key))
        except:
            pass
        try:
            return int(fallback)
        except:
            return 0xFF222222

    def _create_round_rect(self, color, radius_dp=18, stroke_color=0, stroke_dp=0):
        bg = GradientDrawable()
        try:
            bg.setCornerRadius(float(AndroidUtilities.dp(radius_dp)))
        except:
            pass
        try:
            bg.setColor(int(color))
        except:
            pass
        try:
            if int(stroke_dp or 0) > 0:
                bg.setStroke(AndroidUtilities.dp(int(stroke_dp)), int(stroke_color or 0))
        except:
            pass
        return bg

