    def _ui_text(self, value, fallback=""):
        try:
            text = str(value if value is not None else fallback)
        except:
            text = str(fallback or "")
        if not text:
            text = str(fallback or "")
        try:
            text = text.replace("\ufeff", "")
        except:
            pass

        def _noise_score(src):
            try:
                score = 0
                for token in ["Ã", "Ð", "Ñ", "â", "™"]:
                    score += src.count(token)
                return score
            except:
                return 0

        cur = text
        for _ in range(3):
            best = cur
            best_score = _noise_score(cur)
            for enc in ["latin-1", "cp1252"]:
                try:
                    cand = cur.encode(enc, errors="ignore").decode("utf-8", errors="ignore")
                except:
                    continue
                if not cand:
                    continue
                cand_score = _noise_score(cand)
                if cand_score < best_score:
                    best = cand
                    best_score = cand_score
            if best == cur:
                break
            cur = best

        try:
            replacements = {
                "â€¢": "\u2022",
                "â„–": "\u2116",
                "â€”": "-",
                "â€“": "-",
            }
            for src, dst in replacements.items():
                cur = cur.replace(src, dst)
        except:
            pass
        return cur



    def _show_action_menu(self, title, actions, negative_text="\u041d\u0430\u0437\u0430\u0434", context=None):
        try:
            ctx = self._get_menu_activity(context)
            if not ctx:
                return False

            labels = []
            callbacks = []
            for item in (actions or []):
                if not item:
                    continue
                try:
                    label, callback = item
                except:
                    continue
                label = self._ui_text(label).strip()
                if not label:
                    continue
                labels.append(label)
                callbacks.append(callback)

            if not labels:
                return False

            def _on_click(dialog, index):
                try:
                    dialog.dismiss()
                except:
                    pass
                if index < 0 or index >= len(callbacks):
                    return
                cb = callbacks[index]
                try:
                    if cb:
                        cb()
                except Exception as e:
                    BulletinHelper.show_error(f"\u041e\u0448\u0438\u0431\u043a\u0430 \u043c\u0435\u043d\u044e: {e}")

            builder = AlertDialogBuilder(ctx)
            builder.set_title(self._ui_text(title, "NFT Studio"))
            builder.set_items(labels, _on_click)
            builder.set_negative_button(self._ui_text(negative_text, "\u041d\u0430\u0437\u0430\u0434"), None)
            run_on_ui_thread(builder.show)
            return True
        except Exception as e:
            BulletinHelper.show_error(f"\u041e\u0448\u0438\u0431\u043a\u0430 \u043c\u0435\u043d\u044e: {e}")
            return False

    def _get_current_nft_summary(self):
        try:
            gift = self._resolve_active_gift()
        except:
            gift = None
        if gift is not None:
            try:
                title = self._ui_text(get_val(gift, "title", "NFT"), "NFT")
            except:
                title = "NFT"
            try:
                num = int(get_val(gift, "num", 0) or 0)
            except:
                num = 0
            if num > 0:
                return f"{title} #{num}"
            return title
        try:
            lib_count = len(self.gift_library or [])
        except:
            lib_count = 0
        if lib_count > 0:
            return f"\u0432 \u0431\u0438\u0431\u043b\u0438\u043e\u0442\u0435\u043a\u0435 {lib_count}"
        return "\u043d\u0438\u0447\u0435\u0433\u043e \u043d\u0435 \u0432\u044b\u0431\u0440\u0430\u043d\u043e"

    def _format_library_entry_label(self, entry):
        if not isinstance(entry, dict):
            return "NFT"
        title = self._ui_text(entry.get("title", "NFT"), "NFT")
        try:
            num = int(entry.get("num", 0) or 0)
        except:
            num = 0
        base = f"{title} #{num}" if num > 0 else title

        tags = []
        try:
            if bool(entry.get("inject", False)):
                tags.append("\u0430\u043a\u0442\u0438\u0432\u0435\u043d")
        except:
            pass
        try:
            kind_label = self._gift_kind_label(self._classify_gift_kind(entry=entry))
            if kind_label:
                tags.append(kind_label)
        except:
            pass
        try:
            unique_id = int(entry.get("unique_id", 0) or 0)
        except:
            unique_id = 0
        if self.wear_active and unique_id > 0 and unique_id == int(self.wear_collectible_id or 0):
            tags.append("wear")
        if tags:
            return f"{base} \u2022 {', '.join(tags)}"
        return base

    def _open_gift_library_menu(self, context=None):
        try:
            entries = list(self.gift_library or [])
            try:
                entries.sort(key=lambda e: (
                    0 if bool(e.get("inject", False)) else 1,
                    0 if (self.wear_active and int(e.get("unique_id", 0) or 0) == int(self.wear_collectible_id or 0)) else 1,
                    -int(e.get("created_at", 0) or 0)
                ))
            except:
                pass

            actions = []
            for entry in entries:
                key = entry.get("key")
                actions.append((self._format_library_entry_label(entry), lambda k=key: self._open_gift_actions_menu(k)))

            actions.extend([
                ("\u041e\u0442\u043a\u0440\u044b\u0442\u044c \u043a\u0430\u0442\u0430\u043b\u043e\u0433", lambda: self._open_catalog_nft_sheet()),
            ])

            title = f"\u0411\u0438\u0431\u043b\u0438\u043e\u0442\u0435\u043a\u0430 NFT \u2022 {len(entries)}" if entries else "\u0411\u0438\u0431\u043b\u0438\u043e\u0442\u0435\u043a\u0430 NFT \u2022 \u043f\u0443\u0441\u0442\u043e"
            self._show_action_menu(title, actions, negative_text="\u0417\u0430\u043a\u0440\u044b\u0442\u044c", context=context)
        except Exception as e:
            BulletinHelper.show_error(f"\u041e\u0448\u0438\u0431\u043a\u0430 \u0431\u0438\u0431\u043b\u0438\u043e\u0442\u0435\u043a\u0438: {e}")

