    def _is_visible_profile_name_text_view(self, view):
        if view is None or not self._is_local_major_verification_active():
            return False
        try:
            pa = self._get_visible_profile_activity()
        except:
            pa = None
        if pa is None or not self._is_my_profile_activity(pa):
            return False
        try:
            name_views = get_val(pa, "nameTextView", None)
        except:
            name_views = None
        if name_views is None:
            return False
        try:
            view_hash = int(view.hashCode())
        except:
            view_hash = 0
        for tv in self._iter_java_array_items(name_views):
            try:
                if tv is view:
                    return True
            except:
                pass
            try:
                if tv is not None and view_hash != 0 and int(tv.hashCode()) == view_hash:
                    return True
            except:
                pass
            try:
                if tv is not None and hasattr(tv, "equals") and tv.equals(view):
                    return True
            except:
                pass
        return False

    def _iter_java_array_items(self, arr):
        if arr is None:
            return
        try:
            ReflectArray = jclass("java.lang.reflect.Array")
            ln = int(ReflectArray.getLength(arr) or 0)
            for i in range(ln):
                try:
                    yield ReflectArray.get(arr, i)
                except:
                    continue
            return
        except:
            pass
        try:
            for item in arr:
                yield item
            return
        except:
            pass
        try:
            yield arr
        except:
            return

    def _iter_view_tree(self, root, max_depth=8, _depth=0):
        # Iterative BFS-ish walk (explicit stack) replaces recursive generator:
        # avoids Python frame allocations per child and deep recursion warnings,
        # and lets the JIT keep the hot JNI calls tight. Same yield semantics
        # as the previous implementation (root first, then descendants).
        if root is None:
            return
        try:
            max_d = int(max_depth or 0)
        except:
            max_d = 0
        try:
            start_d = int(_depth or 0)
        except:
            start_d = 0
        if start_d > max_d:
            return
        seen_ids = set()
        stack = [(root, start_d)]
        while stack:
            node, d = stack.pop()
            if node is None:
                continue
            # De-duplicate by Java hashCode to protect against pathological
            # cyclic / re-parented view graphs (rare but fatal if present).
            try:
                nid = int(node.hashCode())
            except:
                nid = id(node)
            if nid in seen_ids:
                continue
            seen_ids.add(nid)
            yield node
            if d >= max_d:
                continue
            try:
                if isinstance(node, ViewGroup):
                    try:
                        count = int(node.getChildCount() or 0)
                    except:
                        count = 0
                    # Push in reverse order so children are visited left-to-right
                    # (matches the previous recursive generator's order).
                    for i in range(count - 1, -1, -1):
                        try:
                            child = node.getChildAt(i)
                        except:
                            child = None
                        if child is not None:
                            stack.append((child, d + 1))
            except:
                continue

    def _patch_local_major_profile_views(self, profile_activity):
        if profile_activity is None or not self._is_local_major_verification_active():
            return 0
        if self._should_use_native_major_verification_emoji():
            return 0
        patched = 0
        try:
            heavy_pass = bool(self._should_run_major_profile_heavy_pass(profile_activity, window_sec=1.15))
        except:
            heavy_pass = True
        try:
            drawable = self._get_local_major_badge_drawable(17.0)
        except:
            drawable = None

        try:
            name_views = get_val(profile_activity, "nameTextView", None)
        except:
            name_views = None
        # Track views that actually changed so we can invalidate only the root
        # container once per pass (instead of per-view cascaded invalidate()
        # storms which trigger repeated layout passes / dropped frames).
        _deferred_invalidate_views = []
        if drawable is not None and name_views is not None:
            for tv in self._iter_java_array_items(name_views):
                if tv is None:
                    continue
                try:
                    if hasattr(tv, "setLeftDrawableOutside"):
                        tv.setLeftDrawableOutside(True)
                except:
                    pass
                tv_changed = False
                try:
                    if hasattr(tv, "setLeftDrawable"):
                        tv.setLeftDrawable(drawable)
                        patched += 1
                        tv_changed = True
                except:
                    pass
                if tv_changed:
                    _deferred_invalidate_views.append(tv)

        try:
            fragment_view = get_val(profile_activity, "fragmentView", None)
        except:
            fragment_view = None
        if heavy_pass and drawable is not None and fragment_view is not None:
            # Pre-bind attribute lookups outside the tight loop.
            _cs2txt = self._charsequence_to_plain_text
            _skip_texts = ("в сети", "online")
            for view in self._iter_view_tree(fragment_view, max_depth=9):
                if view is None:
                    continue
                try:
                    cls_name = str(view.getClass().getSimpleName() or "")
                except:
                    cls_name = ""
                if "SimpleTextView" not in cls_name:
                    continue
                try:
                    txt = _cs2txt(view.getText())
                except:
                    txt = ""
                txt_norm = str(txt or "").strip().lower()
                if (not txt_norm) or txt_norm in _skip_texts or "был" in txt_norm:
                    continue
                try:
                    if hasattr(view, "setLeftDrawableOutside"):
                        view.setLeftDrawableOutside(True)
                except:
                    pass
                v_changed = False
                try:
                    if hasattr(view, "setLeftDrawable"):
                        view.setLeftDrawable(drawable)
                        patched += 1
                        v_changed = True
                except:
                    pass
                if v_changed:
                    _deferred_invalidate_views.append(view)

        target = self._get_local_verification_description()
        if heavy_pass and target:
            replacement = self._build_local_major_badge_text(target, size_dp=15.0)
            roots = []
            for holder_name in ["listView", "recyclerListView", "fragmentView"]:
                try:
                    holder = get_val(profile_activity, holder_name, None)
                except:
                    holder = None
                if holder is not None:
                    roots.append(holder)
            seen_views = set()
            for root in roots:
                for child in self._iter_view_tree(root, max_depth=9):
                    if child is None:
                        continue
                    try:
                        key = int(child.hashCode())
                    except:
                        key = id(child)
                    if key in seen_views:
                        continue
                    seen_views.add(key)
                    try:
                        cls_name = str(child.getClass().getSimpleName() or "")
                    except:
                        cls_name = ""
                    text_view = None
                    cur_text = None
                    if "TextInfoPrivacyCell" in cls_name:
                        try:
                            cur_text = child.getText()
                        except:
                            cur_text = None
                        try:
                            text_view = child.getTextView()
                        except:
                            text_view = None
                    elif "TextView" in cls_name:
                        text_view = child
                        try:
                            cur_text = child.getText()
                        except:
                            cur_text = None
                    plain = self._charsequence_to_plain_text(cur_text)
                    if target not in plain:
                        continue
                    try:
                        if "TextInfoPrivacyCell" in cls_name and hasattr(child, "setText"):
                            child.setText(replacement)
                            patched += 1
                    except:
                        pass
                    if text_view is not None:
                        try:
                            text_view.setText(replacement)
                            patched += 1
                        except:
                            pass
                        if drawable is not None:
                            try:
                                text_view.setCompoundDrawablesWithIntrinsicBounds(drawable, None, None, None)
                            except:
                                try:
                                    text_view.setCompoundDrawables(drawable, None, None, None)
                                except:
                                    pass
                            try:
                                text_view.setCompoundDrawablePadding(AndroidUtilities.dp(6))
                            except:
                                pass
                    # Defer invalidate for this cell; the single trailing
                    # root invalidate at the bottom of this method covers it.
                    _deferred_invalidate_views.append(child)

        # Single consolidated invalidate pass. For most cases, invalidating
        # the fragmentView root is sufficient because Android propagates the
        # dirty rect to descendants - this avoids N separate invalidate()
        # calls each triggering a layout measurement (dropped-frame cause).
        if patched > 0:
            try:
                if fragment_view is not None:
                    fragment_view.invalidate()
                elif _deferred_invalidate_views:
                    # Fallback: invalidate the first changed view which will
                    # drag its parent's dirty rect up the chain.
                    try:
                        _deferred_invalidate_views[0].invalidate()
                    except:
                        pass
            except:
                pass
        return int(patched or 0)

    def _clear_local_verification_from_obj(self, obj):
        if obj is None:
            return False
        changed = False
        for field_name, value in [
            ("verified", False),
            ("fake", False),
            ("scam", False),
            ("bot_verification_icon", 0),
            ("bot_verification", None),
        ]:
            try:
                if self._set_field(obj, field_name, value):
                    changed = True
            except:
                pass
            try:
                if getattr(obj, field_name) != value:
                    setattr(obj, field_name, value)
                    changed = True
            except:
                pass
        return bool(changed)

    def _create_local_bot_verification(self, icon, description):
        try:
            if int(icon or 0) <= 0 and not str(description or "").strip():
                return None
            bot_verification = TL_bots.botVerification()
            try:
                bot_verification.bot_id = 0
            except:
                pass
            bot_verification.icon = int(icon or 0)
            bot_verification.description = str(description or "")
            return bot_verification
        except Exception as e:
            _log(f"Local bot verification create error: {e}")
            return None

    def _apply_local_verification_to_full_obj(self, obj):
        if obj is None or not self._is_local_verification_active():
            return False
        try:
            cls_name = str(obj.getClass().getName() or "").lower()
        except:
            cls_name = ""
        if ("userfull" not in cls_name) and ("chatfull" not in cls_name):
            return False

        try:
            if not self._should_apply_self_profile_override(obj, allow_profile_context_fallback=False):
                return False
        except:
            return False

        mode = self._get_local_verification_mode()
        if mode not in [1, 2]:
            try:
                return bool(self._clear_local_verification_from_obj(obj))
            except:
                return False
        icon = self._get_local_verification_icon()
        description = self._get_local_verification_description()
        bot_verification = self._create_local_bot_verification(icon, description)
        if bot_verification is None:
            return False

        changed = False
        try:
            current = get_val(obj, "bot_verification", None)
        except:
            current = None
        try:
            current_icon = int(get_val(current, "icon", 0) or 0) if current is not None else 0
        except:
            current_icon = 0
        try:
            current_desc = str(get_val(current, "description", "") or "") if current is not None else ""
        except:
            current_desc = ""
        try:
            if self._set_field(obj, "bot_verification", bot_verification):
                changed = True
        except:
            pass
        try:
            if current is None or current_icon != int(icon) or current_desc != str(description):
                obj.bot_verification = bot_verification
                changed = True
        except:
            pass
        return bool(changed)

    def _should_apply_local_verification_for_target(self, target_user_id=-1):
        if not self._is_local_verification_active():
            return False
        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0
        if my_id <= 0:
            return False
        try:
            uid = int(target_user_id)
        except:
            uid = -1
        if uid > 0:
            return bool(uid == my_id)
        try:
            return bool(self._is_my_profile_activity())
        except:
            return False

    def _apply_local_verification_to_obj(self, obj):
        if obj is None or not self._is_local_verification_active():
            return False
        try:
            if not self._should_apply_self_profile_override(obj, allow_profile_context_fallback=False):
                return False
        except:
            return False

        changed = False
        try:
            changed = bool(self._clear_local_verification_from_obj(obj) or changed)
        except:
            pass

        mode = self._get_local_verification_mode()
        if mode in [1, 2]:
            icon = self._get_local_verification_icon()
            description = self._get_local_verification_description()
            try:
                if self._set_field(obj, "bot_verification_icon", int(icon)):
                    changed = True
            except:
                pass
            try:
                if getattr(obj, "bot_verification_icon") != int(icon):
                    obj.bot_verification_icon = int(icon)
                    changed = True
            except:
                pass
            try:
                bot_verification = self._create_local_bot_verification(icon, description)
                if bot_verification is not None and self._set_field(obj, "bot_verification", bot_verification):
                    changed = True
            except:
                pass
            try:
                if self._set_field(obj, "verified", False):
                    changed = True
            except:
                pass
            try:
                if getattr(obj, "verified") is not False:
                    obj.verified = False
                    changed = True
            except:
                pass
            return bool(changed)

        identity_kind = self._get_local_fake_identity_kind()
        if identity_kind:
            is_scam = bool(identity_kind == "scam")
            is_fake = bool(identity_kind == "fake")
            for field_name, value in [
                ("verified", False),
                ("scam", is_scam),
                ("fake", is_fake),
                ("bot_verification_icon", 0),
                ("bot_verification", None),
            ]:
                try:
                    if self._set_field(obj, field_name, value):
                        changed = True
                except:
                    pass
                try:
                    if getattr(obj, field_name) != value:
                        setattr(obj, field_name, value)
                        changed = True
                except:
                    pass
            return bool(changed)

        return bool(changed)

    def _commit_local_verification_mode(self, mode, notify=True):
        self.local_verification_mode = self._sanitize_local_verification_mode(mode)
        try:
            self._save_cache()
        except:
            pass
        try:
            self._patch_my_cached_user()
        except:
            pass
        try:
            self._patch_my_cached_user_full()
        except:
            pass
        try:
            self._schedule_cached_user_patch([180, 420], patch_userconfig=True, key="verification_cached_user_patch")
        except:
            pass
        try:
            pa = self._get_visible_profile_activity()
            if pa is not None:
                self._patch_profile_activity_in_place(pa)
                self._notify_profile_activity_adapters_light(pa)
        except:
            pass
        try:
            self._post_local_profile_notifications(reason="verification_commit", cooldown=0.1)
        except:
            pass
        if notify:
            try:
                BulletinHelper.show_success(f"\u0412\u0435\u0440\u0438\u0444\u0438\u043a\u0430\u0446\u0438\u044f: {self._get_local_verification_label()}")
            except:
                pass

    def _patch_local_verification_in_response(self, response, req_name="", target_user_id=-1):
        if response is None or not self._is_local_verification_active():
            return 0
        try:
            if not self._should_apply_local_verification_for_target(target_user_id):
                return 0
        except:
            return 0

        patched = 0
        visited = set()

        def walk(obj, depth):
            nonlocal patched
            if obj is None or depth > 4:
                return
            try:
                oid = int(obj.hashCode())
            except:
                oid = id(obj)
            if oid in visited:
                return
            visited.add(oid)

            try:
                if self._apply_local_verification_to_obj(obj):
                    patched += 1
            except:
                pass

            if self._is_java_list_like(obj):
                try:
                    size = min(int(obj.size() or 0), 12)
                except:
                    size = 0
                for i in range(size):
                    try:
                        walk(obj.get(i), depth + 1)
                    except:
                        continue
                return

            for f in self._iter_object_fields(obj):
                try:
                    val = f.get(obj)
                except:
                    continue
                if val is None:
                    continue
                try:
                    typ = str(f.getType().getName() or "")
                except:
                    typ = ""
                if typ in ["int", "long", "boolean", "float", "double", "java.lang.String"]:
                    continue
                try:
                    walk(val, depth + 1)
                except:
                    continue

        walk(response, 0)

        if patched:
            try:
                _log(f"Local verification patched in response ({req_name}): {patched}")
            except:
                pass
        return int(patched or 0)

    def _get_local_rating_value(self):
        return self._sanitize_local_rating_value(getattr(self, "local_rating_value", 0))

    def _get_local_rating_level(self):
        return self._sanitize_local_rating_level(getattr(self, "local_rating_level", 1))

    def _get_local_rating_next_goal(self):
        return self._sanitize_local_rating_next_goal(
            getattr(self, "local_rating_next_goal", 5000),
            self._get_local_rating_value(),
        )

    def _is_local_rating_active(self):
        try:
            return bool(self.local_rating_enabled and self._get_local_rating_value() > 0)
        except:
            return False

    def _format_local_rating_points(self, value):
        try:
            amount = int(value or 0)
        except:
            amount = 0
        if amount >= 1000000:
            whole = float(amount) / 1000000.0
            text = f"{whole:.1f}M"
        elif amount >= 1000:
            whole = float(amount) / 1000.0
            text = f"{whole:.1f}K"
        else:
            text = str(amount)
        if text.endswith(".0K") or text.endswith(".0M"):
            text = text[:-3] + text[-1]
        return text

    def _get_local_rating_floor(self):
        level = self._get_local_rating_level()
        goal = self._get_local_rating_next_goal()
        if level <= 1 or goal <= 1:
            return 0
        step = max(int(goal / max(level, 1)), 1)
        floor = max(goal - step, 0)
        try:
            stars = self._get_local_rating_value()
            if floor > stars:
                floor = min(stars, floor)
        except:
            pass
        if floor >= goal:
            floor = max(goal - 1, 0)
        return int(floor)

    def _get_local_rating_label(self):
        if not self._is_local_rating_active():
            return "Выкл"
        return f"{self._format_local_rating_points(self._get_local_rating_value())} звезд • ур. {self._get_local_rating_level()}"

    def _get_local_rating_label(self):
        if not self._is_local_rating_active():
            return "Выкл"
        return f"{self._format_local_rating_points(self._get_local_rating_value())} очков • ур. {self._get_local_rating_level()}"

    def _get_local_stars_balance_value(self):
        return self._sanitize_local_stars_balance_value(getattr(self, "local_stars_balance_value", 0))

    def _is_local_stars_balance_active(self):
        try:
            return bool(getattr(self, "local_stars_balance_enabled", False) and self._get_local_stars_balance_value() > 0)
        except:
            return False

    def _get_local_stars_balance_label(self):
        if not self._is_local_stars_balance_active():
            return "Ð’Ñ‹ÐºÐ»"
        return f"{self._format_local_rating_points(self._get_local_stars_balance_value())} Ð·Ð²Ñ‘Ð·Ð´"

    def _create_local_stars_amount(self):
        try:
            StarsAmount = jclass("org.telegram.tgnet.tl.TL_stars$StarsAmount")
            return StarsAmount.ofStars(int(self._get_local_stars_balance_value() or 0))
        except Exception as e:
            _log(f"Local stars amount create error: {e}")
            return None

    def _create_local_stars_amount_value(self):
        try:
            local_amount = self._create_local_stars_amount()
            if local_amount is None:
                return None
            AmountUtils = jclass("org.telegram.messenger.utils.tlutils.AmountUtils$Amount")
            return AmountUtils.of(local_amount)
        except Exception as e:
            _log(f"Local stars amount value create error: {e}")
            return None

    def _get_stars_controller_instance(self):
        try:
            account = int(get_user_config().selectedAccount or 0)
        except:
            account = 0
        try:
            Ctrl = jclass("org.telegram.ui.Stars.StarsController")
            return Ctrl.getInstance(to_java_int(account))
        except Exception as e:
            _log(f"StarsController instance error: {e}")
            return None

    def _apply_local_stars_balance_to_controller(self, ctrl):
        if ctrl is None or not self._is_local_stars_balance_active():
            return False
        changed = False
        local_amount = self._create_local_stars_amount()
        if local_amount is None:
            return False
        for field_name, value in [
            ("balance", local_amount),
            ("minus", 0),
            ("balanceLoaded", True),
            ("balanceLoading", False),
        ]:
            try:
                if self._set_field(ctrl, field_name, value):
                    changed = True
            except:
                pass
        try:
            if self._set_field(ctrl, "lastBalanceLoaded", int(time.time() * 1000)):
                changed = True
        except:
            pass
        return bool(changed)

    def _notify_local_star_balance_changed(self):
        try:
            ctrl = self._get_stars_controller_instance()
            if ctrl is not None:
                if self._is_local_stars_balance_active():
                    self._apply_local_stars_balance_to_controller(ctrl)
                else:
                    try:
                        if hasattr(ctrl, "invalidateBalance"):
                            ctrl.invalidateBalance()
                    except:
                        pass
                    try:
                        self._set_field(ctrl, "balanceLoaded", False)
                    except:
                        pass
        except:
            pass
        try:
            account = int(get_user_config().selectedAccount or 0)
        except:
            account = 0
        try:
            NotificationCenter.getInstance(account).postNotificationName(NotificationCenter.starBalanceUpdated)
        except Exception as e:
            _log(f"Local star balance notify error: {e}")

    def _has_profile_fastpatch_overrides(self):
        try:
            if self._is_local_rating_active():
                return True
        except:
            pass
        try:
            if self._has_local_profile_gifts_presence():
                return True
        except:
            pass
        try:
            return bool(self._has_profile_overrides())
        except:
            return False

    def _refresh_local_profile_gifts_section(self, reason="local_profile_gifts"):
        if not self._has_local_profile_gifts_presence():
            return False
        changed = False
        try:
            self._prewarm_self_user_info_cache(force=True)
        except:
            pass
        try:
            if self._patch_my_cached_user_full():
                changed = True
        except:
            pass
        try:
            pa = self._get_visible_profile_activity()
        except:
            pa = None
        if pa is not None:
            try:
                if self._is_my_profile_activity(pa):
                    if self._patch_profile_activity_in_place(pa, notify=False, include_major_views=False):
                        changed = True
            except:
                pass
            try:
                if self._rebuild_profile_gifts_rows(pa, animated=True):
                    changed = True
            except:
                pass
            try:
                if self._patch_profile_shared_media_layout(pa, animated=True):
                    changed = True
            except:
                pass
            try:
                self._notify_profile_activity_adapters_light(pa, force=True)
            except:
                pass
            try:
                self._refresh_profile_activity_views_light(pa, force=True)
            except:
                pass
            try:
                self._schedule_profile_ui_repatch(pa, [80, 240])
            except:
                pass
        try:
            self._schedule_profile_gifts_refresh([60, 220], min_interval=0.12, force=True)
        except:
            pass
        try:
            self._post_local_profile_notifications(reason=reason, cooldown=0.08)
        except:
            pass
        return bool(changed)

    def _should_use_early_profile_data_mode(self, target_user_id=0):
        try:
            uid = int(target_user_id or 0)
        except:
            uid = 0
        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0
        if uid <= 0 or my_id <= 0 or uid != my_id:
            return False
        try:
            return bool(self._has_profile_fastpatch_overrides())
        except:
            return False

    def _touch_local_full_user_loaded_state(self, controller, user_id, full_obj=None):
        try:
            uid = int(user_id or 0)
        except:
            uid = 0
        if controller is None or uid <= 0:
            return False
        changed = False
        try:
            if full_obj is not None:
                full_users = get_val(controller, "fullUsers", None)
                if full_users is not None:
                    try:
                        existing = full_users.get(uid)
                    except:
                        existing = None
                    if existing is None or existing is not full_obj:
                        full_users.put(uid, full_obj)
                        changed = True
        except:
            pass
        try:
            loaded_full_users = get_val(controller, "loadedFullUsers", None)
            if loaded_full_users is not None:
                loaded_full_users.put(uid, int(time.time() * 1000))
                changed = True
        except:
            pass
        try:
            loading_full_users = get_val(controller, "loadingFullUsers", None)
            if loading_full_users is not None:
                try:
                    loading_full_users.remove(uid)
                    changed = True
                except:
                    pass
        except:
            pass
        return bool(changed)

    def _create_placeholder_self_user_full(self, user_obj=None):
        try:
            uid = int(self._extract_user_id_from_obj(user_obj) or 0) if user_obj is not None else 0
        except:
            uid = 0
        if uid <= 0:
            try:
                uid = int(self._get_my_user_id() or 0)
            except:
                uid = 0
        if uid <= 0 or not self._should_use_early_profile_data_mode(uid):
            return None
        try:
            FullCls = jclass("org.telegram.tgnet.TLRPC$TL_userFull")
            PeerSettingsCls = jclass("org.telegram.tgnet.TLRPC$TL_peerSettings")
            NotifySettingsCls = jclass("org.telegram.tgnet.TLRPC$TL_peerNotifySettings")
            full_obj = FullCls()
            try:
                full_obj.id = uid
            except:
                pass
            try:
                full_obj.user = user_obj
            except:
                try:
                    self._set_field(full_obj, "user", user_obj)
                except:
                    pass
            try:
                full_obj.flags = 0
            except:
                pass
            try:
                full_obj.flags2 = 0
            except:
                pass
            try:
                full_obj.common_chats_count = 0
            except:
                pass
            try:
                full_obj.settings = PeerSettingsCls()
            except:
                pass
            try:
                full_obj.notify_settings = NotifySettingsCls()
            except:
                pass
            try:
                self._apply_profile_overrides_to_obj(full_obj)
            except:
                pass
            try:
                if user_obj is not None:
                    self._apply_profile_overrides_to_obj(user_obj)
            except:
                pass
            return full_obj
        except Exception as e:
            _log(f"Create placeholder UserFull error: {e}")
            return None

    def _prewarm_self_user_info_cache(self, force=False):
        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0
        if my_id <= 0:
            return False
        try:
            if not self._should_use_early_profile_data_mode(my_id):
                return False
        except:
            return False
        try:
            now = time.time()
            last = float(getattr(self, "_self_userinfo_prewarm_last_ts", 0.0) or 0.0)
            if (not force) and (now - last) < 2.5:
                return False
            self._self_userinfo_prewarm_last_ts = now
        except:
            pass

        def _run():
            try:
                account = int(get_user_config().selectedAccount or 0)
                MC = jclass("org.telegram.messenger.MessagesController")
                ctrl = MC.getInstance(to_java_int(account))
                if ctrl is None:
                    return
                try:
                    user_obj = ctrl.getUser(my_id)
                except:
                    user_obj = None
                if user_obj is not None:
                    try:
                        self._apply_profile_overrides_to_obj(user_obj)
                    except:
                        pass
                    try:
                        try:
                            ctrl.putUser(user_obj, False, True)
                        except Exception:
                            ctrl.putUser(user_obj, False)
                    except:
                        pass
                try:
                    full_obj = ctrl.getUserFull(my_id)
                except:
                    full_obj = None
                if full_obj is None and user_obj is not None:
                    try:
                        full_obj = self._create_placeholder_self_user_full(user_obj)
                    except:
                        full_obj = None
                    if full_obj is not None:
                        try:
                            self._touch_local_full_user_loaded_state(ctrl, my_id, full_obj)
                        except:
                            pass
                        try:
                            ctrl.loadUserInfo(user_obj, False, 0)
                        except:
                            pass
                if full_obj is not None:
                    try:
                        self._apply_profile_overrides_to_obj(full_obj)
                    except:
                        pass
                    try:
                        nested_user = get_val(full_obj, "user", None)
                    except:
                        nested_user = None
                    if nested_user is None and user_obj is not None:
                        try:
                            self._set_field(full_obj, "user", user_obj)
                        except:
                            pass
                    self._touch_local_full_user_loaded_state(ctrl, my_id, full_obj)
                    return
                if user_obj is not None:
                    try:
                        ctrl.loadUserInfo(user_obj, False, 0)
                    except:
                        pass
            except Exception as e:
                _log(f"Self user info prewarm error: {e}")

        try:
            run_on_ui_thread(_run)
            return True
        except:
            try:
                _run()
                return True
            except:
                return False

    def _has_local_gifts_overrides(self):
        try:
            if self.inject_active or bool(self.gift_library):
                return True
        except:
            pass
        try:
            if bool(self.hide_official_gifts_local):
                return True
        except:
            pass
        try:
            if bool(getattr(self, "_hidden_official_gift_wrappers", None)):
                return True
        except:
            pass
        return False

    def _should_manage_self_saved_gifts(self, req_user_id=-1, owner_user_id=0, target_user_id=0):
        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0
        if my_id <= 0:
            return False

        parsed = []
        for raw in [target_user_id, owner_user_id, req_user_id]:
            try:
                parsed.append(int(raw))
            except:
                parsed.append(-1)

        for uid in parsed:
            if uid > 0 and uid == my_id:
                return True
        for uid in parsed:
            if uid > 0 and uid != my_id:
                return False
        try:
            return bool(self._is_my_profile_activity())
        except:
            return False

    def _get_entry_target_entity_id(self, entry, fallback_to_self=True):
        if not isinstance(entry, dict):
            return 0
        try:
            cfg = self._sanitize_identity_config(entry.get("identity_config", None))
        except:
            cfg = self._default_identity_config()
        for key in ["owner_user_id", "to_user_id"]:
            try:
                eid = int(cfg.get(key, 0) or 0)
            except:
                eid = 0
            if eid != 0:
                return int(eid)
        if not fallback_to_self:
            return 0
        try:
            return int(self._get_my_user_id() or 0)
        except:
            return 0

    def _entry_matches_target_entity(self, entry, target_entity_id):
        try:
            target = int(target_entity_id or 0)
        except:
            target = 0
        if target == 0:
            return False
        try:
            entry_target = int(self._get_entry_target_entity_id(entry, fallback_to_self=True) or 0)
        except:
            entry_target = 0
        return bool(entry_target != 0 and entry_target == target)

    def _has_local_gifts_for_target_entity(self, target_entity_id):
        try:
            target = int(target_entity_id or 0)
        except:
            target = 0
        if target == 0:
            return False
        for entry in list(self.gift_library or []):
            try:
                if bool(entry.get("inject", False)) and self._entry_matches_target_entity(entry, target):
                    return True
            except:
                continue
        return False

    def _should_manage_self_saved_gifts(self, req_user_id=-1, owner_user_id=0, target_user_id=0):
        parsed = []
        for raw in [target_user_id, owner_user_id, req_user_id]:
            try:
                eid = int(raw)
            except:
                eid = -1
            if eid not in [-1, 0]:
                parsed.append(eid)

        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0

        for eid in list(parsed or []):
            if my_id > 0 and eid == my_id:
                return True
            try:
                if self._has_local_gifts_for_target_entity(eid):
                    return True
            except:
                pass

        if parsed:
            return False

        try:
            visible_id = int(self._get_profile_activity_entity_id(self._get_visible_profile_activity()) or 0)
        except:
            visible_id = 0
        if visible_id != 0:
            if my_id > 0 and visible_id == my_id:
                return True
            try:
                return bool(self._has_local_gifts_for_target_entity(visible_id))
            except:
                return False
        return False

    def _should_apply_local_rating_for_target(self, target_user_id=-1):
        if not self._is_local_rating_active():
            return False
        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0
        if my_id <= 0:
            return False
        try:
            uid = int(target_user_id)
        except:
            uid = -1
        if uid > 0:
            return bool(uid == my_id)
        return False

    def _is_java_list_like(self, obj):
        if obj is None:
            return False
        try:
            _ = obj.size()
            _ = obj.get
            return True
        except:
            return False

    def _iter_object_fields(self, obj):
        if obj is None:
            return ()
        try:
            cls = obj.getClass()
            cls_name = str(cls.getName() or "")
        except:
            return ()
        try:
            cache = getattr(self, "_object_fields_cache", None)
            if not isinstance(cache, dict):
                cache = {}
                self._object_fields_cache = cache
            cached = cache.get(cls_name, None)
            if cached is not None:
                return cached
        except:
            cache = None
        out = []
        seen = set()
        for getter_name in ["getDeclaredFields", "getFields"]:
            try:
                getter = getattr(cls, getter_name, None)
                if getter is None:
                    continue
                for f in getter():
                    try:
                        name = str(f.getName() or "")
                    except:
                        name = ""
                    if not name or name in seen:
                        continue
                    seen.add(name)
                    try:
                        f.setAccessible(True)
                    except:
                        pass
                    out.append(f)
            except:
                continue
        result = tuple(out)
        try:
            if cache is not None:
                cache[cls_name] = result
        except:
            pass
        return result

    def _apply_local_rating_to_stars_rating(self, obj):
        if obj is None or not self._is_local_rating_active():
            return False
        try:
            cls_name = str(obj.getClass().getName() or "").lower()
        except:
            cls_name = ""
        field_names = set()
        try:
            field_names = set([str(f.getName() or "") for f in self._iter_object_fields(obj)])
        except:
            field_names = set()
        if ("starsrating" not in cls_name) and (not ({"level", "current_level_stars", "stars", "next_level_stars"} & field_names)):
            return False

        stars = self._get_local_rating_value()
        level = self._get_local_rating_level()
        current_floor = self._get_local_rating_floor()
        next_goal = self._get_local_rating_next_goal()
        changed = False
        field_values = [
            (["level"], level),
            (["current_level_stars", "currentLevelStars"], current_floor),
            (["stars"], stars),
            (["next_level_stars", "nextLevelStars"], next_goal),
        ]
        for names, value in field_values:
            for name in names:
                try:
                    if self._set_field(obj, name, value):
                        changed = True
                except:
                    pass
        try:
            flags = self._to_int(get_val(obj, "flags", 0), 0)
            wanted = int(flags | 1)
            if wanted != flags and self._set_field(obj, "flags", wanted):
                changed = True
        except:
            pass
        return bool(changed)

    def _create_local_stars_rating(self):
        if not self._is_local_rating_active():
            return None
        for cls_name in [
            "org.telegram.tgnet.tl.TL_stars$Tl_starsRating",
            "org.telegram.tgnet.tl.TL_stars$TL_starsRating",
            "org.telegram.tgnet.TLRPC$TL_starsRating",
        ]:
            try:
                obj = jclass(cls_name)()
                self._apply_local_rating_to_stars_rating(obj)
                return obj
            except:
                continue
        return None

    def _apply_local_rating_to_full_user(self, obj, target_user_id=-1):
        if obj is None or not self._is_local_rating_active():
            return False
        resolved_target_user_id = -1
        try:
            resolved_target_user_id = int(self._extract_user_id_from_obj(obj) or 0)
        except:
            resolved_target_user_id = 0
        if resolved_target_user_id <= 0:
            try:
                resolved_target_user_id = int(target_user_id)
            except:
                resolved_target_user_id = -1
        if not self._should_apply_local_rating_for_target(resolved_target_user_id):
            return False
        try:
            cls_name = str(obj.getClass().getName() or "").lower()
        except:
            cls_name = ""
        field_names = set()
        try:
            field_names = set([str(f.getName() or "") for f in self._iter_object_fields(obj)])
        except:
            field_names = set()
        if ("userfull" not in cls_name) and ("stars_rating" not in field_names) and ("starsRating" not in field_names):
            return False

        changed = False
        rating_obj = None
        for name in ["stars_rating", "starsRating"]:
            try:
                rating_obj = get_val(obj, name, None)
            except:
                rating_obj = None
            if rating_obj is not None:
                break

        if rating_obj is None:
            rating_obj = self._create_local_stars_rating()
            if rating_obj is not None:
                for name in ["stars_rating", "starsRating"]:
                    try:
                        if self._set_field(obj, name, rating_obj):
                            changed = True
                            break
                    except:
                        pass
        else:
            try:
                if self._apply_local_rating_to_stars_rating(rating_obj):
                    changed = True
            except:
                pass

        pending_obj = None
        for name in ["stars_my_pending_rating", "starsMyPendingRating"]:
            try:
                pending_obj = get_val(obj, name, None)
            except:
                pending_obj = None
            if pending_obj is not None:
                break
        if pending_obj is None:
            pending_obj = self._create_local_stars_rating()
            if pending_obj is not None:
                for name in ["stars_my_pending_rating", "starsMyPendingRating"]:
                    try:
                        if self._set_field(obj, name, pending_obj):
                            changed = True
                            break
                    except:
                        pass
        if pending_obj is not None:
            try:
                if self._apply_local_rating_to_stars_rating(pending_obj):
                    changed = True
            except:
                pass
            for name in ["stars_my_pending_rating_date", "starsMyPendingRatingDate"]:
                try:
                    if self._set_field(obj, name, 0):
                        changed = True
                except:
                    pass

        try:
            flags2 = self._to_int(get_val(obj, "flags2", 0), 0)
            wanted = int(flags2 | (1 << 17))
            if pending_obj is not None:
                wanted = int(wanted | (1 << 18))
            if wanted != flags2 and self._set_field(obj, "flags2", wanted):
                changed = True
        except:
            pass
        return bool(changed)

    def _apply_local_rating_to_obj(self, obj, target_user_id=-1):
        if not self._is_local_rating_active():
            return False
        resolved_target_user_id = -1
        try:
            resolved_target_user_id = int(self._extract_user_id_from_obj(obj) or 0)
        except:
            resolved_target_user_id = 0
        if resolved_target_user_id <= 0:
            try:
                resolved_target_user_id = int(target_user_id)
            except:
                resolved_target_user_id = -1
        if not self._should_apply_local_rating_for_target(resolved_target_user_id):
            return False
        changed = False
        try:
            if self._apply_local_rating_to_stars_rating(obj):
                changed = True
        except:
            pass
        try:
            if self._apply_local_rating_to_full_user(obj, resolved_target_user_id):
                changed = True
        except:
            pass
        return bool(changed)

    def _patch_local_rating_in_response(self, response, req_name="", target_user_id=-1):
        if response is None or not self._is_local_rating_active():
            return 0
        try:
            known_target_user_id = int(target_user_id)
        except:
            known_target_user_id = -1
        if known_target_user_id > 0 and not self._should_apply_local_rating_for_target(known_target_user_id):
            return 0

        patched = 0
        visited = set()

        def walk(obj, depth):
            nonlocal patched
            if obj is None or depth > 2:
                return
            try:
                oid = int(obj.hashCode())
            except:
                oid = id(obj)
            if oid in visited:
                return
            visited.add(oid)

            try:
                if self._apply_local_rating_to_obj(obj, known_target_user_id):
                    patched += 1
            except:
                pass

            if self._is_java_list_like(obj):
                try:
                    size = min(int(obj.size() or 0), 12)
                except:
                    size = 0
                for i in range(size):
                    try:
                        walk(obj.get(i), depth + 1)
                    except:
                        continue
                return

            for f in self._iter_object_fields(obj):
                try:
                    val = f.get(obj)
                except:
                    continue
                if val is None:
                    continue
                try:
                    fname = str(f.getName() or "").lower()
                except:
                    fname = ""
                try:
                    typ = str(f.getType().getName() or "")
                except:
                    typ = ""
                if typ in ["int", "long", "boolean", "float", "double", "java.lang.String"]:
                    continue
                if depth > 0 and fname and ("user" not in fname and "full" not in fname and "rating" not in fname and "peer" not in fname and "chat" not in fname):
                    continue
                try:
                    walk(val, depth + 1)
                except:
                    continue

        walk(response, 0)

        if patched:
            try:
                _log(f"Local rating patched in response ({req_name}): {patched}")
            except:
                pass
        return int(patched or 0)

    def _patch_profile_activity_boosts(self, profile_activity):
        if profile_activity is None or not self._is_local_rating_active():
            return 0
        try:
            if not self._is_my_profile_activity(profile_activity):
                return 0
        except:
            return 0
        try:
            target_user_id = int(self._get_profile_activity_user_id(profile_activity) or 0)
        except:
            target_user_id = 0
        if target_user_id <= 0:
            try:
                target_user_id = int(self._get_my_user_id() or 0)
            except:
                target_user_id = 0

        patched = 0
        rating_view_changed = False
        for name in ["userInfo", "userFull", "currentUserInfo", "currentUserFull"]:
            try:
                obj = get_val(profile_activity, name, None)
            except:
                obj = None
            if obj is None:
                continue
            try:
                if self._apply_local_rating_to_full_user(obj, target_user_id):
                    patched += 1
            except:
                pass

        try:
            rating_view = get_val(profile_activity, "ratingView", None)
        except:
            rating_view = None
        if rating_view is not None:
            for name in ["userInfo", "userFull", "currentUserInfo", "currentUserFull"]:
                try:
                    obj = get_val(profile_activity, name, None)
                except:
                    obj = None
                if obj is None:
                    continue
                try:
                    if get_val(rating_view, name, None) is not None and self._set_field(rating_view, name, obj):
                        patched += 1
                        rating_view_changed = True
                except:
                    pass
            if rating_view_changed or patched > 0:
                try:
                    rating_view.invalidate()
                except:
                    pass
                try:
                    if hasattr(rating_view, "getChildCount") and hasattr(rating_view, "getChildAt"):
                        child_count = min(int(rating_view.getChildCount() or 0), 12)
                        for i in range(child_count):
                            try:
                                child = rating_view.getChildAt(i)
                            except:
                                child = None
                            if child is None:
                                continue
                            try:
                                child.invalidate()
                            except:
                                pass
                    else:
                        pass
                except:
                        pass
        return int(patched or 0)

    def _resolve_profile_rating_obj(self, profile_activity, fallback=None):
        if fallback is not None:
            try:
                rating_obj = get_val(fallback, "stars_rating", None) or get_val(fallback, "starsRating", None)
            except:
                rating_obj = None
            if rating_obj is not None:
                return rating_obj
        if profile_activity is None:
            return None
        for name in ["userInfo", "userFull", "currentUserInfo", "currentUserFull"]:
            try:
                obj = get_val(profile_activity, name, None)
            except:
                obj = None
            if obj is None:
                continue
            try:
                rating_obj = get_val(obj, "stars_rating", None) or get_val(obj, "starsRating", None)
            except:
                rating_obj = None
            if rating_obj is not None:
                return rating_obj
        try:
            if self._is_local_rating_active() and self._is_my_profile_activity(profile_activity):
                return self._create_local_stars_rating()
        except:
            pass
        return None

    def _is_rating_view_header_visible(self, rating_view):
        if rating_view is None:
            return False
        try:
            if hasattr(rating_view, "getVisibility") and int(rating_view.getVisibility() or 8) != 0:
                return False
        except:
            pass
        try:
            if hasattr(rating_view, "getVisibilityFactor") and float(rating_view.getVisibilityFactor() or 0.0) <= 0.0:
                return False
        except:
            pass
        return True

    def _is_target_profile_rating_view(self, view):
        if view is None or not self._is_local_rating_active():
            return False
        try:
            pa = self._get_visible_profile_activity()
        except:
            pa = None
        if pa is None:
            return False
        try:
            if not self._is_my_profile_activity(pa):
                return False
        except:
            return False
        try:
            rating_view = get_val(pa, "ratingView", None)
        except:
            rating_view = None
        if rating_view is None:
            return False
        try:
            if rating_view is view:
                return True
        except:
            pass
        try:
            vh = int(view.hashCode())
            rh = int(rating_view.hashCode())
            if vh != 0 and vh == rh:
                return True
        except:
            pass
        try:
            if hasattr(rating_view, "equals") and rating_view.equals(view):
                return True
        except:
            pass
        return False

    def _force_star_rating_animator_hidden(self, view):
        if view is None:
            return False
        changed = False
        try:
            animator = get_val(view, "isVisibleAnimator", None)
        except:
            animator = None
        if animator is not None:
            try:
                animator.set(False, True)
                changed = True
            except:
                try:
                    for m in animator.getClass().getDeclaredMethods():
                        try:
                            if str(m.getName() or "") != "set":
                                continue
                            params = m.getParameterTypes()
                            if len(params) != 2:
                                continue
                            m.setAccessible(True)
                            m.invoke(animator, False, True)
                            changed = True
                            break
                        except:
                            continue
                except:
                    pass
        return bool(changed)

    def _suppress_star_rating_view_instance(self, view):
        if view is None or not self._is_target_profile_rating_view(view):
            return False
        changed = False
        for field_name, value in [("isVisibleInternal", False), ("isVisibleExternal", False), ("isVisible", False)]:
            try:
                if self._set_field(view, field_name, value):
                    changed = True
            except:
                pass
        try:
            if self._force_star_rating_animator_hidden(view):
                changed = True
        except:
            pass
        try:
            view.setEnabled(False)
            changed = True
        except:
            pass
        try:
            view.setClickable(False)
            changed = True
        except:
            pass
        if changed:
            try:
                view.invalidate()
            except:
                pass
        return bool(changed)

    def _suppress_profile_rating_header(self, profile_activity, rating_view=None, run_checker=True):
        if profile_activity is None or not self._is_local_rating_active():
            return False
        try:
            if not self._is_my_profile_activity(profile_activity):
                return False
        except:
            return False
        changed = False
        try:
            if self._set_field(profile_activity, "isStarRatingVisible1", False):
                changed = True
        except:
            pass
        if rating_view is None:
            try:
                rating_view = get_val(profile_activity, "ratingView", None)
            except:
                rating_view = None
        if rating_view is not None:
            try:
                if self._suppress_star_rating_view_instance(rating_view):
                    changed = True
            except:
                pass
        if run_checker:
            try:
                checker = getattr(profile_activity, "checkStarRatingVisible", None)
                if callable(checker):
                    checker()
                    changed = True
                else:
                    for m in profile_activity.getClass().getDeclaredMethods():
                        try:
                            if str(m.getName() or "") != "checkStarRatingVisible":
                                continue
                            if len(m.getParameterTypes()) != 0:
                                continue
                            m.setAccessible(True)
                            m.invoke(profile_activity)
                            changed = True
                            break
                        except:
                            continue
            except:
                pass
        return bool(changed)

    def _force_rating_view_refresh(self, profile_activity, source_obj=None):
        if profile_activity is None:
            return False
        try:
            rating_view = get_val(profile_activity, "ratingView", None)
        except:
            rating_view = None
        if rating_view is None:
            return False
        # Preserve the older behavior: do not surface the compact rating badge
        # near the online text unless Telegram already made it visible itself.
        if not self._is_rating_view_header_visible(rating_view):
            return False
        try:
            rating_obj = self._resolve_profile_rating_obj(profile_activity, fallback=source_obj)
        except:
            rating_obj = None
        changed = False
        if rating_obj is not None:
            try:
                rating_view.set(rating_obj)
                changed = True
            except:
                try:
                    for m in rating_view.getClass().getDeclaredMethods():
                        try:
                            if str(m.getName() or "") != "set":
                                continue
                            if len(m.getParameterTypes()) != 1:
                                continue
                            m.setAccessible(True)
                            m.invoke(rating_view, rating_obj)
                            changed = True
                            break
                        except:
                                continue
                except:
                    pass
        if changed:
            try:
                rating_view.invalidate()
            except:
                pass
        return bool(changed)

    def _force_profile_rating_visibility(self, profile_activity):
        if profile_activity is None or not self._is_local_rating_active():
            return False
        try:
            if not self._is_my_profile_activity(profile_activity):
                return False
        except:
            return False
        changed = False
        try:
            if self._set_field(profile_activity, "isStarRatingVisible1", True):
                changed = True
        except:
            pass
        try:
            rating_view = get_val(profile_activity, "ratingView", None)
        except:
            rating_view = None
        if rating_view is not None:
            try:
                rating_view.setVisibility(True)
                changed = True
            except:
                pass
            if changed:
                try:
                    rating_view.invalidate()
                except:
                    pass
        try:
            checker = getattr(profile_activity, "checkStarRatingVisible", None)
            if callable(checker):
                checker()
                changed = True
            else:
                for m in profile_activity.getClass().getDeclaredMethods():
                    try:
                        if str(m.getName() or "") != "checkStarRatingVisible":
                            continue
                        if len(m.getParameterTypes()) != 0:
                            continue
                        m.setAccessible(True)
                        m.invoke(profile_activity)
                        changed = True
                        break
                    except:
                        continue
        except:
            pass
        return bool(changed)

    def _get_notification_center_event_id(self, notification_center_cls, name):
        if notification_center_cls is None:
            return 0
        try:
            event_name = str(name or "")
        except:
            event_name = ""
        if not event_name:
            return 0
        try:
            cache = getattr(self, "_notification_event_id_cache", None)
            if not isinstance(cache, dict):
                cache = {}
                self._notification_event_id_cache = cache
            if event_name in cache:
                return int(cache.get(event_name, 0) or 0)
        except:
            cache = None
        event_id = 0
        try:
            event_id = int(getattr(notification_center_cls, event_name))
        except:
            try:
                field = notification_center_cls.getDeclaredField(event_name)
                field.setAccessible(True)
                event_id = int(field.getInt(None))
            except:
                event_id = 0
        try:
            if cache is not None:
                cache[event_name] = int(event_id or 0)
        except:
            pass
        return int(event_id or 0)

    def _post_local_profile_notifications(self, reason="profile_patch", cooldown=0.35):
        try:
            if bool(getattr(self, "_plugin_unloading", False)) or bool(getattr(self, "_patching_nc", False)):
                return 0
        except:
            pass
        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0
        if my_id <= 0:
            return 0
        try:
            notify_map = getattr(self, "_local_profile_notify_ts", None)
            if not isinstance(notify_map, dict):
                notify_map = {}
                self._local_profile_notify_ts = notify_map
            key = str(reason or "profile_patch")
            now = time.time()
            last = float(notify_map.get(key, 0.0) or 0.0)
            if (now - last) < float(cooldown or 0.0):
                return 0
            notify_map[key] = now
        except:
            pass

        def _emit():
            try:
                self._patching_nc = True
            except:
                pass
            try:
                try:
                    account = int(get_user_config().selectedAccount or 0)
                except:
                    account = 0
                try:
                    NC = jclass("org.telegram.messenger.NotificationCenter")
                    nc = NC.getInstance(to_java_int(account))
                    gnc = NC.getGlobalInstance()
                except:
                    NC = None
                    nc = None
                    gnc = None
                if NC is None or nc is None:
                    return

                def _event_id(name):
                    try:
                        return int(self._get_notification_center_event_id(NC, name) or 0)
                    except:
                        return 0

                def _post(name, *args):
                    eid = _event_id(name)
                    if eid <= 0:
                        return
                    try:
                        nc.postNotificationName(to_java_int(eid), *args)
                    except:
                        pass

                def _post_global(name, *args):
                    eid = _event_id(name)
                    if eid <= 0 or gnc is None:
                        return
                    try:
                        gnc.postNotificationName(to_java_int(eid), *args)
                    except:
                        pass
                try:
                    _post("mainUserInfoChanged")
                except:
                    pass
                try:
                    _post_global("emojiLoaded")
                except:
                    pass
                # Force ProfileActivity to re-render the wear status orbit and
                # name-row drawable: it listens to updateInterfaces with
                # UPDATE_MASK_EMOJI_STATUS|UPDATE_MASK_NAME (mask=524290).
                try:
                    if (getattr(self, "wear_active", False) and int(getattr(self, "wear_collectible_id", 0) or 0) > 0) \
                            or self._is_nft_username_active() or self._is_nft_number_active():
                        try:
                            MC = jclass("org.telegram.messenger.MessagesController")
                            try:
                                me = int(MC.UPDATE_MASK_EMOJI_STATUS)
                            except Exception:
                                me = 524288
                            try:
                                mn = int(MC.UPDATE_MASK_NAME)
                            except Exception:
                                mn = 2
                            mask = me | mn
                        except Exception:
                            mask = 524290
                        eid = _event_id("updateInterfaces")
                        if eid > 0:
                            try:
                                nc.postNotificationName(to_java_int(eid), to_java_Integer(mask))
                            except Exception:
                                pass
                except Exception:
                    pass
                # Per-user fast path so the avatar/name drawable picks up the
                # new emoji_status without waiting for the next interface sweep.
                try:
                    if getattr(self, "wear_active", False) and int(getattr(self, "wear_collectible_id", 0) or 0) > 0:
                        try:
                            ctrl = jclass("org.telegram.messenger.MessagesController").getInstance(to_java_int(account))
                            u = ctrl.getUser(int(my_id))
                        except Exception:
                            u = None
                        if u is not None:
                            eid = _event_id("userEmojiStatusUpdated")
                            if eid > 0:
                                try:
                                    nc.postNotificationName(to_java_int(eid), u)
                                except Exception:
                                    pass
                except Exception:
                    pass
            finally:
                try:
                    self._patching_nc = False
                except:
                    pass

        try:
            run_on_ui_thread(_emit)
            return 1
        except:
            try:
                _emit()
                return 1
            except:
                return 0

    def _refresh_visible_profile_boosts(self):
        try:
            pa = self._get_visible_profile_activity()
        except:
            pa = None
        if pa is None:
            return False
        try:
            if not self._is_my_profile_activity(pa):
                return False
        except:
            return False
        try:
            frag_key = int(pa.hashCode())
        except:
            frag_key = 0
        try:
            runtime_gen = int(getattr(self, "_profile_runtime_gen", 0) or 0)
        except:
            runtime_gen = 0
        try:
            now = time.time()
            last = float(getattr(self, "_local_rating_refresh_ts", 0.0) or 0.0)
            last_frag = int(getattr(self, "_local_rating_refresh_frag_key", 0) or 0)
            last_gen = int(getattr(self, "_local_rating_refresh_runtime_gen", -1) or -1)
            same_session = bool(last_frag == frag_key and last_gen == runtime_gen and frag_key != 0)
            if same_session and (now - last) < 0.12:
                return False
            self._local_rating_refresh_ts = now
            self._local_rating_refresh_frag_key = frag_key
            self._local_rating_refresh_runtime_gen = runtime_gen
        except:
            pass
        changed = False
        try:
            changed = bool(self._patch_profile_activity_boosts(pa))
        except:
            changed = False
        if changed:
            try:
                self._notify_profile_activity_adapters_light(pa)
            except:
                pass
        return bool(changed)

