    def _new_gift_key(self):
        return f"{int(time.time() * 1000)}-{random.randint(1000, 9999)}"

    def _get_cache_uid(self):
        """
        Stable cache namespace per Telegram account slot.
        Avoid switching between fallback/user_id while app is booting, which resets runtime state.
        """
        try:
            acc = int(get_user_config().selectedAccount or 0)
        except:
            acc = 0
        return int(10000000000 + acc)

    def _ensure_user_context(self, force=False):
        """
        Reload per-user cache when Telegram account changes.
        This prevents cross-account gift libraries and reduces leaked references.
        """
        uid = self._get_cache_uid()
        prev = int(getattr(self, "_context_user_id", 0) or 0)
        if not force and prev == uid and uid > 0:
            try:
                should_maintain = bool(
                    self.inject_active
                    or self.injection_payload
                    or self.injection_payloads
                    or self.gift_library
                    or self._has_profile_overrides()
                    or self._is_local_rating_active()
                    or self._has_local_gifts_overrides()
                )
            except:
                should_maintain = True
            if not should_maintain:
                return False
            try:
                now = time.time()
                last_same = float(getattr(self, "_ensure_user_context_same_uid_last_ts", 0.0) or 0.0)
                if (now - last_same) < 1.8:
                    return False
                self._ensure_user_context_same_uid_last_ts = now
            except:
                pass
            try:
                self._heal_runtime_state(reason="same_context", force=False)
            except:
                pass
            return False

        try:
            self._debug_state_snapshot("ensure_ctx:start", f"force={1 if force else 0} uid={uid} prev={prev}")
        except:
            pass
        self._context_user_id = uid
        try:
            self._ensure_user_context_same_uid_last_ts = time.time()
        except:
            pass

        # Drop runtime objects only when the account slot really changes. A forced
        # recheck of the same slot must not blank wear/identity before cache IO.
        if int(prev or 0) != int(uid or 0):
            # Reset load-state for the new slot — prevents the previous
            # account's "ok" state from authorizing writes against the new
            # account's possibly-unloaded cache.
            try:
                self._cache_load_state = "pending"
            except:
                pass
            self.stolen_gift_wrapper = None
            self.stolen_gift_inner = None
            self.injection_payload = None
            self.injection_payloads = []
            self.inject_active = False
            self.gift_library = []
            self.regular_gifts = []
            self._regular_gifts_seq = 0
            self.gift_objects = {}
            self._gift_objects_order = []
            self.editing_gift_key = None
            self.cached_gift_id = None

            self.wear_active = False
            self.wear_collectible_id = 0
            self.wear_status_data = {}
            self._pending_wear_override = None
            self._wear_status_sync_collectible_id = 0
            self._wear_status_sync_last_ts = 0.0
            self._wear_status_snapshot = {}
            self._wear_status_snapshot_collectible_id = 0
            self._wear_status_snapshot_last_ts = 0.0

            self.nft_username_enabled = False
            self.nft_usernames = []
            self.nft_username = ""
            self.nft_username_price_ton = "10.8"
            self.nft_username_price_usd = "14.68"
            self.nft_username_purchase_date = ""
            self.nft_collectible_template = None
            self.nft_collectible_template_b64 = ""

            self.nft_number_enabled = False
            self.nft_numbers = []
            self.nft_number = ""
            self.nft_number_price_ton = "10.8"
            self.nft_number_price_usd = "14.68"
            self.nft_number_purchase_date = ""
            self.nft_number_collectible_template = None
            self.nft_number_collectible_template_b64 = ""
            self.local_rating_enabled = False
            self.local_rating_value = 0
            self.local_rating_level = 1
            self.local_rating_next_goal = 5000
            self.local_stars_balance_enabled = False
            self.local_stars_balance_value = 0
            self.local_verification_mode = 0
            self.hide_official_gifts_local = False
            self._hidden_official_gift_wrappers = []

            self.build_config = {"model": 0, "pattern": 0, "backdrop": 0, "num": 1}
            self.identity_config = self._default_identity_config()
            self.value_config = self._default_value_config()
            self.gift_stars_config = self._default_gift_stars_config()
        self.gift_stars_config = self._default_gift_stars_config()

        self._load_cache(uid=uid)
        self._load_injection_cache(uid=uid)
        try:
            if self._is_local_stars_balance_active():
                self._notify_local_star_balance_changed()
        except:
            pass
        try:
            if self.gift_library:
                self._rebuild_injection_payloads()
        except:
            pass
        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0
        try:
            cached_uid = int(getattr(self, "_cache_file_user_id", 0) or 0)
        except:
            cached_uid = 0
        if my_id > 0 and cached_uid > 0 and cached_uid != my_id:
            probe_sig = f"{int(uid)}:{int(cached_uid)}:{int(my_id)}"
            try:
                probe = getattr(self, "_cache_mismatch_probe", None)
                probe_same = bool(isinstance(probe, dict) and str(probe.get("sig", "")) == probe_sig)
                probe_age = time.time() - float(probe.get("ts", 0.0) or 0.0) if probe_same else 0.0
            except:
                probe_same = False
                probe_age = 0.0
            _log(f"Cache user mismatch observed: file_user_id={cached_uid} current_user_id={my_id} slot={uid}")
            try:
                self._cache_mismatch_probe = {"sig": probe_sig, "ts": time.time()}
            except:
                pass
            if probe_same and probe_age >= 2.0:
                _log("Cache mismatch confirmed, but destructive reset is skipped to preserve slot data")
            try:
                self._schedule_ui_batch("user_context_recheck", lambda: self._ensure_user_context(force=True), [450, 1400])
            except:
                pass
        else:
            try:
                self._cache_mismatch_probe = None
            except:
                pass

        try:
            if self._has_profile_overrides():
                self._schedule_cached_user_patch([180, 420], key="user_context_patch")
        except:
            pass
        try:
            if self._is_local_rating_active() and self._is_my_profile_activity():
                self._refresh_visible_profile_boosts()
        except:
            pass
        try:
            if self._has_local_gifts_overrides():
                self._schedule_profile_gifts_refresh([120, 360], force=True)
        except:
            pass
        try:
            self._heal_runtime_state(reason="context_loaded", force=True)
        except:
            pass

        try:
            self._debug_state_snapshot("ensure_ctx:end", f"force={1 if force else 0} uid={uid} prev={prev}")
        except:
            pass

        _log(f"User context: {prev} -> {uid}")
        return True

    def _extract_wrapper_gift(self, wrapper):
        if wrapper is None:
            return None
        try:
            return get_val(wrapper, "gift", None) or wrapper.getClass().getField("gift").get(wrapper)
        except:
            return None

    def _gift_has_document(self, gift):
        if gift is None:
            return False
        try:
            doc = get_val(gift, "document", None)
            if doc is not None:
                return True
        except:
            pass
        try:
            doc = gift.getDocument()
            if doc is not None:
                return True
        except:
            pass
        try:
            doc = get_val(gift, "sticker", None)
            if doc is not None:
                return True
        except:
            pass
        return False

    def _repair_gift_document(self, gift, wrapper=None):
        if gift is None:
            return False
        try:
            if self._gift_has_document(gift):
                return True
        except:
            pass

        docs = []
        seen = set()

        def _doc_key(doc):
            try:
                did = int(self._extract_doc_id(doc) or 0)
            except:
                did = 0
            if did > 0:
                return f"id:{did}"
            try:
                return f"obj:{int(doc.hashCode())}"
            except:
                return f"py:{id(doc)}"

        def _push(doc):
            if doc is None:
                return
            try:
                key = _doc_key(doc)
            except:
                key = None
            if key is not None and key in seen:
                return
            if key is not None:
                seen.add(key)
            docs.append(doc)

        try:
            _push(get_val(gift, "document", None))
        except:
            pass
        try:
            _push(get_val(gift, "sticker", None))
        except:
            pass
        try:
            _push(find_document_recursive(gift))
        except:
            pass

        try:
            attrs = get_val(gift, "attributes", None)
            size = int(attrs.size() or 0) if attrs is not None else 0
        except:
            size = 0
        for i in range(min(size, 8)):
            try:
                attr = attrs.get(i)
            except:
                continue
            try:
                _push(get_val(attr, "document", None))
            except:
                pass
            try:
                _push(get_val(attr, "sticker", None))
            except:
                pass
            try:
                _push(find_document_recursive(attr))
            except:
                pass

        entry = None
        try:
            if wrapper is not None:
                sid = int(self._extract_saved_id_from_wrapper(wrapper) or 0)
                if sid > 0:
                    entry = self._library_find_entry_by_saved_id(sid)
        except:
            entry = None
        if entry is None:
            try:
                uid = int(self._to_int(get_val(gift, "id", 0), 0) or 0)
            except:
                uid = 0
            if uid > 0:
                try:
                    entry = self._library_find_entry_by_unique_id(uid)
                except:
                    entry = None
        if entry is None:
            try:
                slug = str(get_val(gift, "slug", "") or "")
            except:
                slug = ""
            if slug:
                try:
                    entry = self._library_find_entry_by_slug(slug)
                except:
                    entry = None

        base_gift_id = 0
        try:
            if entry is not None:
                base_gift_id = int(entry.get("base_gift_id", 0) or 0)
        except:
            base_gift_id = 0
        if base_gift_id <= 0:
            try:
                base_gift_id = int(self._get_gift_base_id(gift, fallback=0) or 0)
            except:
                base_gift_id = 0

        if base_gift_id > 0:
            try:
                cat = self._get_catalog_gift_by_id(base_gift_id)
            except:
                cat = None
            if cat is not None:
                try:
                    _push(get_val(cat, "sticker", None))
                except:
                    pass
                try:
                    _push(get_val(cat, "document", None))
                except:
                    pass
                try:
                    _push(find_document_recursive(cat))
                except:
                    pass

        try:
            stolen = getattr(self, "stolen_gift_inner", None)
        except:
            stolen = None
        if stolen is not None:
            try:
                _push(get_val(stolen, "sticker", None))
            except:
                pass
            try:
                _push(get_val(stolen, "document", None))
            except:
                pass

        chosen = None
        try:
            chosen = self._pick_best_doc_for_collectible_status(docs)
        except:
            chosen = None
        if chosen is None:
            return False

        changed = False
        try:
            if self._set_field(gift, "document", chosen):
                changed = True
        except:
            pass
        try:
            if self._set_field(gift, "sticker", chosen):
                changed = True
        except:
            pass
        if not changed:
            try:
                gift.document = chosen
                changed = True
            except:
                pass
            try:
                gift.sticker = chosen
                changed = True
            except:
                pass
        try:
            return bool(changed or self._gift_has_document(gift))
        except:
            return bool(changed)

    def _repair_saved_gift_wrapper(self, wrapper):
        if wrapper is None:
            return False
        gift = self._extract_wrapper_gift(wrapper)
        if gift is None:
            return False
        try:
            if self._gift_has_document(gift):
                return True
        except:
            pass
        try:
            self._repair_gift_document(gift, wrapper)
        except:
            pass
        try:
            return bool(self._gift_has_document(gift))
        except:
            return False

    def _is_valid_saved_gift_wrapper(self, wrapper):
        gift = self._extract_wrapper_gift(wrapper)
        if gift is None:
            return False
        try:
            if self._gift_has_document(gift):
                return True
        except:
            pass
        return bool(self._repair_saved_gift_wrapper(wrapper))

    def _sanitize_saved_gifts_list(self, gifts_list):
        removed = 0
        if gifts_list is None:
            return 0
        try:
            size = int(gifts_list.size() or 0)
        except:
            size = 0
        for i in range(size - 1, -1, -1):
            try:
                item = gifts_list.get(i)
            except:
                continue
            try:
                if self._is_valid_saved_gift_wrapper(item):
                    continue
            except:
                pass
            try:
                gifts_list.remove(i)
                removed += 1
            except:
                pass
        return int(removed)

    def _build_injection_wrappers_bundle(self):
        wrappers = []
        wrapper_ids = set()
        for w in list(self.injection_payloads or []):
            try:
                if not self._repair_saved_gift_wrapper(w):
                    continue
                try:
                    self._normalize_saved_gift_for_actions(
                        w,
                        force_pin=False,
                        update_date=False,
                        touch_unsaved=False,
                        touch_restrictions=False,
                    )
                except:
                    pass
                gift = self._extract_wrapper_gift(w)
                try:
                    if gift is not None:
                        self._ensure_unique_gift_availability(gift, base_gift_id=0)
                except:
                    pass
                gid = int(get_val(gift, "id", 0) or 0) if gift is not None else 0
                if gid > 0 and gid in wrapper_ids:
                    continue
                wrappers.append(w)
                if gid > 0:
                    wrapper_ids.add(gid)
            except:
                continue
        try:
            wrappers.sort(key=lambda ww: self._saved_gift_sort_key(ww))
        except:
            pass
        ordered_ids = []
        for w in list(wrappers or []):
            try:
                gift = self._extract_wrapper_gift(w)
                gid = int(get_val(gift, "id", 0) or 0) if gift is not None else 0
            except:
                gid = 0
            if gid > 0:
                ordered_ids.append(gid)
        return wrappers, wrapper_ids, ordered_ids

    def _build_injection_wrappers_bundle(self, target_entity_id=0):
        wrappers = []
        wrapper_ids = set()
        try:
            target_entity_id = int(target_entity_id or 0)
        except:
            target_entity_id = 0

        for entry in list(self.gift_library or []):
            try:
                if not isinstance(entry, dict) or (not bool(entry.get("inject", False))):
                    continue
                if target_entity_id != 0 and (not self._entry_matches_target_entity(entry, target_entity_id)):
                    continue
                w = self._library_get_wrapper(entry.get("key"))
                if w is None:
                    continue
                if not self._repair_saved_gift_wrapper(w):
                    continue
                try:
                    owner_eid = int(self._get_entry_target_entity_id(entry, fallback_to_self=True) or 0)
                except:
                    owner_eid = 0
                try:
                    self._normalize_saved_gift_for_actions(
                        w,
                        force_pin=False,
                        update_date=False,
                        touch_unsaved=False,
                        touch_restrictions=False,
                        owner_user_id=owner_eid,
                    )
                except:
                    pass
                gift = self._extract_wrapper_gift(w)
                try:
                    if gift is not None:
                        self._ensure_unique_gift_availability(gift, base_gift_id=0)
                except:
                    pass
                try:
                    gid = int(get_val(gift, "id", 0) or 0) if gift is not None else 0
                except:
                    gid = 0
                if gid > 0 and gid in wrapper_ids:
                    continue
                wrappers.append(w)
                if gid > 0:
                    wrapper_ids.add(gid)
            except:
                continue

        try:
            wrappers.sort(key=lambda ww: self._saved_gift_sort_key(ww))
        except:
            pass
        ordered_ids = []
        for w in list(wrappers or []):
            try:
                gift = self._extract_wrapper_gift(w)
                gid = int(get_val(gift, "id", 0) or 0) if gift is not None else 0
            except:
                gid = 0
            if gid > 0:
                ordered_ids.append(gid)
        return wrappers, wrapper_ids, ordered_ids

    def _collect_plugin_gift_ids_in_order(self, gifts_list, target_ids):
        if gifts_list is None or not target_ids:
            return [], False
        current_ids = []
        seen = set()
        has_duplicates = False
        try:
            size = int(gifts_list.size() or 0)
        except:
            size = 0
        for i in range(size):
            try:
                item = gifts_list.get(i)
                gift = get_val(item, "gift", None)
                gid = int(self._to_int(get_val(gift, "id", 0), 0) or 0) if gift is not None else 0
            except:
                gid = 0
            if gid <= 0 or gid not in target_ids:
                continue
            if gid in seen:
                has_duplicates = True
            else:
                seen.add(gid)
            current_ids.append(gid)
        return current_ids, bool(has_duplicates)

    def _patch_saved_gift_list_availability(self, gifts_list, limit=60, sanitize=True):
        if gifts_list is None:
            return 0
        patched = 0
        if sanitize:
            try:
                self._sanitize_saved_gifts_list(gifts_list)
            except:
                pass
        try:
            size = int(gifts_list.size() or 0)
        except:
            size = 0
        for i in range(min(size, int(limit or 0))):
            try:
                item = gifts_list.get(i)
                gift = get_val(item, "gift", None)
                if gift is None:
                    continue
                if self._ensure_unique_gift_availability(gift, base_gift_id=0):
                    patched += 1
            except:
                continue
        return int(patched or 0)

    def _is_valid_saved_gifts_list_ref(self, gifts_list):
        if gifts_list is None:
            return False
        try:
            _ = gifts_list.size()
            _ = gifts_list.get
            return True
        except:
            return False

    def _cache_profile_saved_gift_lists(self, frag, lists):
        valid = []
        seen = set()
        for gifts_list in list(lists or []):
            if not self._is_valid_saved_gifts_list_ref(gifts_list):
                continue
            try:
                key = int(gifts_list.hashCode())
            except:
                key = id(gifts_list)
            if key in seen:
                continue
            seen.add(key)
            valid.append(gifts_list)
        try:
            self._profile_saved_lists = valid
        except:
            self._profile_saved_lists = []
        try:
            self._profile_saved_lists_frag_key = int(frag.hashCode()) if frag is not None else 0
        except:
            self._profile_saved_lists_frag_key = 0
        return list(valid)

    def _get_cached_profile_saved_gift_lists(self, frag):
        try:
            frag_key = int(frag.hashCode()) if frag is not None else 0
        except:
            frag_key = 0
        try:
            cached_key = int(getattr(self, "_profile_saved_lists_frag_key", 0) or 0)
        except:
            cached_key = 0
        if frag_key <= 0 or frag_key != cached_key:
            return []
        out = []
        for gifts_list in list(getattr(self, "_profile_saved_lists", None) or []):
            if self._is_valid_saved_gifts_list_ref(gifts_list):
                out.append(gifts_list)
        try:
            self._profile_saved_lists = out
        except:
            pass
        return list(out)

    def _sanitize_profile_gifts_container_state(self, container, max_depth=2):
        if container is None:
            return 0
        removed = 0
        try:
            lists = self._discover_saved_gift_lists(container, max_depth=max_depth)
        except:
            lists = []
        for gifts_list in list(lists or []):
            try:
                removed += int(self._sanitize_saved_gifts_list(gifts_list) or 0)
            except:
                continue
        return int(removed or 0)

    def _discover_saved_gift_lists(self, root, max_depth=2):
        if root is None:
            return []

        visited = set()
        found = []
        found_ids = set()

        def looks_like_list(obj):
            return bool(self._is_java_list_like(obj))

        def looks_like_saved_gifts_field(field_name, lst):
            try:
                if lst is not None and int(lst.size() or 0) > 0:
                    sample = lst.get(0)
                    return bool(self._looks_like_saved_gift_wrapper(sample))
            except:
                pass
            low = str(field_name or "").lower()
            return bool(("gift" in low and "saved" in low) or ("star" in low and "gift" in low))

        def add_list(lst):
            if not self._is_valid_saved_gifts_list_ref(lst):
                return
            try:
                lid = int(lst.hashCode())
            except:
                lid = id(lst)
            if lid in found_ids:
                return
            found_ids.add(lid)
            found.append(lst)

        def walk(obj, depth):
            if obj is None or depth > max_depth:
                return
            try:
                oid = int(obj.hashCode())
            except:
                oid = id(obj)
            if oid in visited:
                return
            visited.add(oid)

            if looks_like_list(obj):
                try:
                    if int(obj.size() or 0) > 0 and self._looks_like_saved_gift_wrapper(obj.get(0)):
                        add_list(obj)
                except:
                    pass
                return

            try:
                cn = str(obj.getClass().getName() or "")
            except:
                cn = ""
            try:
                if ("android.view" in cn) or ("android.widget" in cn) or ("androidx.recyclerview" in cn):
                    try:
                        if hasattr(obj, "getAdapter") and callable(getattr(obj, "getAdapter", None)):
                            ad = obj.getAdapter()
                            if ad is not None:
                                walk(ad, depth + 1)
                    except:
                        pass
                    return
            except:
                pass

            for f in self._iter_object_fields(obj):
                try:
                    name = str(f.getName() or "")
                    val = f.get(obj)
                except:
                    continue
                if val is None:
                    continue
                if looks_like_list(val):
                    try:
                        if looks_like_saved_gifts_field(name, val):
                            add_list(val)
                            continue
                    except:
                        pass
                try:
                    walk(val, depth + 1)
                except:
                    pass

        walk(root, 0)
        return list(found)

    def _extract_gift_meta(self, wrapper, base_gift_id=0):
        gift = self._extract_wrapper_gift(wrapper)
        title = str(get_val(gift, "title", "NFT")) if gift else "NFT"
        slug = str(get_val(gift, "slug", "")) if gift else ""
        num = self._to_int(get_val(gift, "num", 0), 0) if gift else 0
        unique_id = self._to_int(get_val(gift, "id", 0), 0) if gift else 0
        bg = self._to_int(base_gift_id, 0)
        if bg <= 0 and gift is not None:
            bg = self._to_int(get_val(gift, "gift_id", 0), 0)
        return title, slug, num, bg, unique_id

    def _compute_wear_status_data_from_gift(self, gift):
        """Compute wearable collectible status fields from a TL_starGiftUnique gift."""
        if gift is None:
            return {}
        wear_data = {}
        try:
            wear_data["title"] = str(get_val(gift, "title", "NFT"))
            wear_data["slug"] = str(get_val(gift, "slug", ""))
            wear_data["collectible_id"] = int(self._to_int(get_val(gift, "id", 0), 0))
        except:
            pass

        try:
            doc_choice = self._pick_best_doc_for_collectible_status([
                get_val(gift, "sticker", None),
                get_val(gift, "document", None),
            ])
            doc_id = self._extract_doc_id(doc_choice)
            if doc_id > 0:
                wear_data["document_id"] = int(doc_id)
        except:
            pass

        attrs = get_val(gift, "attributes", None)
        if attrs is None:
            return wear_data

        model_doc_id = 0
        pattern_doc_id = 0

        try:
            size = attrs.size()
        except:
            size = 0

        for i in range(size):
            try:
                a = attrs.get(i)
            except:
                continue
            if a is None:
                continue

            for color_field in ["center_color", "edge_color", "pattern_color", "text_color"]:
                try:
                    val = get_val(a, color_field, None)
                    if val is not None and int(val) != 0:
                        wear_data[color_field] = int(val)
                except:
                    pass

            try:
                doc = get_val(a, "document", None)
                if not doc:
                    continue
                doc_id = self._to_int(get_val(doc, "id", 0), 0)
                if doc_id <= 0:
                    continue
                cls = ""
                try:
                    cls = a.getClass().getSimpleName().lower()
                except:
                    cls = ""
                if "pattern" in cls and pattern_doc_id <= 0:
                    pattern_doc_id = doc_id
                elif model_doc_id <= 0:
                    model_doc_id = doc_id
            except:
                pass

        if model_doc_id > 0 and not wear_data.get("document_id", 0):
            wear_data["document_id"] = int(model_doc_id)
        if pattern_doc_id > 0:
            wear_data["pattern_document_id"] = int(pattern_doc_id)

        return wear_data

    def _sync_wear_status_data_from_library(self, collectible_id):
        """Ensure wear_status_data matches currently worn collectible_id."""
        cid = self._to_int(collectible_id, 0)
        if cid <= 0:
            return False

        for e in (self.gift_library or []):
            try:
                if self._to_int(e.get("unique_id", 0), 0) != cid:
                    continue
                wd = e.get("wear_status_data", None)
                if isinstance(wd, dict) and wd:
                    try:
                        w = self._library_get_wrapper(e.get("key"))
                        g = self._extract_wrapper_gift(w) if w else None
                        wd2 = self._compute_wear_status_data_from_gift(g)
                        if isinstance(wd2, dict) and wd2:
                            d1 = self._to_int(wd.get("document_id", 0), 0)
                            d2 = self._to_int(wd2.get("document_id", 0), 0)
                            if d2 > 0 and d2 != d1:
                                wd["document_id"] = d2
                                e["wear_status_data"] = wd
                            if self._to_int(wd.get("pattern_document_id", 0), 0) <= 0 and self._to_int(wd2.get("pattern_document_id", 0), 0) > 0:
                                wd["pattern_document_id"] = int(wd2.get("pattern_document_id"))
                                e["wear_status_data"] = wd
                    except:
                        pass
                    self.wear_status_data = wd
                    try:
                        self._remember_wear_status_snapshot(wd, cid)
                    except:
                        pass
                    return True
            except:
                pass

        for w in list(self.injection_payloads or []):
            try:
                g = self._extract_wrapper_gift(w)
                gid = self._to_int(get_val(g, "id", 0), 0) if g else 0
                if gid == cid:
                    wd = self._compute_wear_status_data_from_gift(g)
                    if wd:
                        self.wear_status_data = wd
                        try:
                            self._remember_wear_status_snapshot(wd, cid)
                        except:
                            pass
                        return True
            except:
                pass

        for e in (self.gift_library or []):
            try:
                if self._to_int(e.get("unique_id", 0), 0) == cid:
                    wd = e.get("wear_status_data", None)
                    if isinstance(wd, dict) and wd:
                        self.wear_status_data = wd
                        try:
                            self._remember_wear_status_snapshot(wd, cid)
                        except:
                            pass
                        return True
                    w = self._library_get_wrapper(e.get("key"))
                    g = self._extract_wrapper_gift(w) if w else None
                    wd2 = self._compute_wear_status_data_from_gift(g)
                    if wd2:
                        e["wear_status_data"] = wd2
                        e["unique_id"] = cid
                        self.wear_status_data = wd2
                        try:
                            self._remember_wear_status_snapshot(wd2, cid)
                        except:
                            pass
                        return True
            except:
                pass

        try:
            g = self.stolen_gift_inner
            gid = self._to_int(get_val(g, "id", 0), 0) if g else 0
            if gid == cid:
                wd = self._compute_wear_status_data_from_gift(g)
                if wd:
                    self.wear_status_data = wd
                    try:
                        self._remember_wear_status_snapshot(wd, cid)
                    except:
                        pass
                    return True
        except:
            pass

        return False

    def _is_wear_status_data_complete(self, wearable_data=None, collectible_id=0):
        wd = wearable_data if isinstance(wearable_data, dict) else {}
        cid = self._to_int(collectible_id or wd.get("collectible_id", 0), 0)
        if cid <= 0:
            return False
        if self._to_int(wd.get("collectible_id", cid), 0) not in [0, cid]:
            return False
        if self._to_int(wd.get("document_id", 0), 0) <= 0:
            return False
        if not str(wd.get("title", "") or ""):
            return False
        if not str(wd.get("slug", "") or ""):
            return False
        for color_field in ["center_color", "edge_color", "pattern_color", "text_color"]:
            if self._to_int(wd.get(color_field, 0), 0) > 0:
                return True
        return False

    def _remember_wear_status_snapshot(self, wearable_data=None, collectible_id=0):
        wd = dict(wearable_data or {}) if isinstance(wearable_data, dict) else {}
        cid = self._to_int(collectible_id or wd.get("collectible_id", 0), 0)
        if not self._is_wear_status_data_complete(wd, cid):
            return False
        try:
            self._wear_status_snapshot = wd
            self._wear_status_snapshot_collectible_id = cid
            self._wear_status_snapshot_last_ts = time.time()
        except:
            return False
        return True

    def _get_stable_wear_status_data(self, collectible_id=0):
        cid = self._to_int(collectible_id or getattr(self, "wear_collectible_id", 0), 0)
        if cid <= 0:
            return {}
        try:
            current = self.wear_status_data if isinstance(self.wear_status_data, dict) else {}
        except:
            current = {}
        if self._is_wear_status_data_complete(current, cid):
            return current
        try:
            snap = getattr(self, "_wear_status_snapshot", None)
            snap_cid = self._to_int(getattr(self, "_wear_status_snapshot_collectible_id", 0), 0)
        except:
            snap = None
            snap_cid = 0
        if isinstance(snap, dict) and snap_cid == cid and self._is_wear_status_data_complete(snap, snap_cid):
            return snap
        return current

    def _ensure_current_wear_status_data(self, collectible_id=0, force=False, max_age=6.0):
        cid = self._to_int(collectible_id or getattr(self, "wear_collectible_id", 0), 0)
        if cid <= 0:
            return False
        try:
            current = self._get_stable_wear_status_data(cid)
        except:
            current = {}
        if self._is_wear_status_data_complete(current, cid) and (not force):
            try:
                last_cid = int(getattr(self, "_wear_status_sync_collectible_id", 0) or 0)
                last_ts = float(getattr(self, "_wear_status_sync_last_ts", 0.0) or 0.0)
                if last_cid == cid and (time.time() - last_ts) < float(max_age or 0.0):
                    return True
            except:
                return True
        ok = False
        try:
            ok = bool(self._sync_wear_status_data_from_library(cid))
        except:
            ok = False
        if not ok:
            try:
                ok = bool(self._is_wear_status_data_complete(self._get_stable_wear_status_data(cid), cid))
            except:
                ok = False
        if ok:
            try:
                self._wear_status_sync_collectible_id = cid
                self._wear_status_sync_last_ts = time.time()
            except:
                pass
            try:
                self._remember_wear_status_snapshot(self.wear_status_data, cid)
            except:
                pass
        return bool(ok)

    def _clear_cached_self_emoji_status(self, patch_userconfig=True):
        cleared_any = False
        my_id = self._to_int(self._get_my_user_id(), 0)
        if my_id <= 0:
            return False

        try:
            empty_status = self._create_empty_emoji_status()
        except:
            empty_status = None

        try:
            account = get_user_config().selectedAccount
            MC = jclass("org.telegram.messenger.MessagesController")
            ctrl = MC.getInstance(to_java_int(account))
            user_obj = ctrl.getUser(my_id)
            if user_obj is not None:
                changed = False
                try:
                    if self._set_field(user_obj, "emoji_status", empty_status):
                        changed = True
                except:
                    pass
                try:
                    if self._set_field(user_obj, "emoji_status", None):
                        changed = True
                except:
                    pass
                try:
                    if self._has_profile_overrides() or self._is_local_rating_active():
                        if self._apply_profile_overrides_to_obj(user_obj):
                            changed = True
                except:
                    pass
                if changed:
                    cleared_any = True
                    try:
                        ctrl.putUser(user_obj, False)
                    except:
                        pass
        except Exception as e:
            _log(f"_clear_cached_self_emoji_status(controller) error: {e}")

        if not patch_userconfig:
            return cleared_any

        try:
            targets = []
            try:
                targets.append(get_user_config())
            except:
                pass
            try:
                UC = jclass("org.telegram.messenger.UserConfig")
                inst = UC.getInstance(to_java_int(get_user_config().selectedAccount))
                if inst is not None:
                    targets.append(inst)
            except:
                pass

            seen = set()
            for uc in targets:
                if uc is None:
                    continue
                try:
                    uc_id = int(uc.hashCode())
                except:
                    uc_id = id(uc)
                if uc_id in seen:
                    continue
                seen.add(uc_id)

                for field_name in ["currentUser", "user"]:
                    try:
                        u = get_val(uc, field_name, None)
                    except:
                        u = None
                    if u is None:
                        continue
                    try:
                        uid = self._to_int(self._extract_user_id_from_obj(u), 0)
                    except:
                        uid = 0
                    if uid > 0 and uid != my_id:
                        continue
                    changed = False
                    try:
                        if self._set_field(u, "emoji_status", empty_status):
                            changed = True
                    except:
                        pass
                    try:
                        if self._set_field(u, "emoji_status", None):
                            changed = True
                    except:
                        pass
                    try:
                        if self._has_profile_overrides() or self._is_local_rating_active():
                            if self._apply_profile_overrides_to_obj(u):
                                changed = True
                    except:
                        pass
                    if changed:
                        cleared_any = True
                        try:
                            self._set_field(uc, field_name, u)
                        except:
                            pass
        except Exception as e:
            _log(f"_clear_cached_self_emoji_status(userconfig) error: {e}")

        return cleared_any

    def _schedule_clear_cached_self_emoji_status(self, delays=None):
        def _run_clear():
            try:
                self._clear_cached_self_emoji_status()
            except:
                pass
            return None
        for delay in list(delays or [0, 120, 360, 800]):
            try:
                AndroidUtilities.runOnUIThread(
                    JRunnable(_run_clear),
                    int(delay or 0)
                )
            except:
                pass

    def _create_empty_emoji_status(self):
        for cls_name in [
            "org.telegram.tgnet.TLRPC$TL_emojiStatusEmpty",
            "org.telegram.tgnet.tl.TL_emojiStatus$emojiStatusEmpty",
        ]:
            try:
                return jclass(cls_name)()
            except:
                continue
        return None

    def _send_clear_emoji_status_request(self):
        req = None
        for cls_name in [
            "org.telegram.tgnet.TLRPC$TL_account_updateEmojiStatus",
            "org.telegram.tgnet.tl.TL_account$updateEmojiStatus",
        ]:
            try:
                req = jclass(cls_name)()
                break
            except:
                continue
        if req is None:
            return False

        empty_status = self._create_empty_emoji_status()
        if empty_status is None:
            return False

        assigned = False
        for field_name in ["emoji_status", "status", "input_status"]:
            try:
                if self._set_field(req, field_name, empty_status):
                    assigned = True
                    break
            except:
                pass
        if not assigned:
            return False

        try:
            get_connections_manager().sendRequest(req, JRequestDelegate(lambda response, error: None))
            _log("WEAR CLEAR: clear emoji status request sent")
            return True
        except Exception as e:
            _log(f"_send_clear_emoji_status_request error: {e}")
            return False

    # Whitelisted reasons that may drop the worn-NFT state. Any other call must be
    # ignored — wear status is now iron-clad and only the user can clear it
    # (menu toggle / removing the NFT).
    _ALLOWED_WEAR_CLEAR_REASONS = (
        "menu_remove_wear",
        "library_remove",
        "user_action",
    )

    def _clear_wear_state(self, persist=True, clear_cached_status=True, request_server_clear=False, reason=""):
        # Hard guard: ignore any clear that is not an explicit user action. This
        # makes wear "rock-solid" — server pushes / sync / refresh paths cannot
        # silently strip it. Only the menu-remove and library-remove flows pass.
        try:
            reason_str = str(reason or "").strip().lower()
        except:
            reason_str = ""
        if reason_str not in self._ALLOWED_WEAR_CLEAR_REASONS:
            try:
                _log(f"WEAR CLEAR BLOCKED: unauthorized reason={reason_str or 'unknown'}")
            except:
                pass
            return False

        try:
            active_cid = self._to_int(getattr(self, "wear_collectible_id", 0), 0)
        except:
            active_cid = 0
        had_wear = bool(getattr(self, "wear_active", False) or active_cid > 0)

        self.wear_active = False
        self.wear_collectible_id = 0
        self.wear_ignore_clear_once = False
        self.wear_last_collectible_ts = 0.0
        self.wear_status_data = {}
        self._pending_wear_override = None
        self._wear_status_sync_collectible_id = 0
        self._wear_status_sync_last_ts = 0.0
        self._wear_status_snapshot = {}
        self._wear_status_snapshot_collectible_id = 0
        self._wear_status_snapshot_last_ts = 0.0

        if persist:
            try:
                self._save_cache()
            except:
                pass

        if clear_cached_status:
            try:
                self._clear_cached_self_emoji_status()
            except:
                pass
            try:
                self._schedule_clear_cached_self_emoji_status([0, 120, 360, 800])
            except:
                pass

        if request_server_clear and had_wear:
            try:
                self._send_clear_emoji_status_request()
            except:
                pass

        try:
            _log(f"WEAR CLEARED: collectible_id={active_cid}, reason={reason or 'unknown'}")
        except:
            pass
        return had_wear

    def _remove_library_gift_wear(self, key=None):
        try:
            e = self._library_find_entry(key) if key else None
        except:
            e = None
        try:
            entry_cid = int((e or {}).get("unique_id", 0) or 0)
        except:
            entry_cid = 0
        try:
            active_cid = int(self.wear_collectible_id or 0)
        except:
            active_cid = 0

        if self.wear_active and active_cid > 0 and (entry_cid <= 0 or entry_cid == active_cid):
            try:
                self._clear_wear_state(persist=True, clear_cached_status=True, request_server_clear=True, reason="menu_remove_wear")
            except Exception as e:
                BulletinHelper.show_error(f"\u041e\u0448\u0438\u0431\u043a\u0430 wear: {e}")
                return False
            BulletinHelper.show_success("\u0421\u0442\u0430\u0442\u0443\u0441 wear \u0441\u043d\u044f\u0442")
            return True

        BulletinHelper.show_info("\u042d\u0442\u043e\u0442 NFT \u0441\u0435\u0439\u0447\u0430\u0441 \u043d\u0435 \u043d\u0430\u0434\u0435\u0442 \u0432 wear")
        return False

    def _library_find_entry(self, key):
        if not key:
            return None
        for e in (self.gift_library or []):
            if str(e.get("key", "")) == str(key):
                return e
        return None

    def _library_find_entry_by_unique_id(self, unique_id):
        try:
            target = int(unique_id or 0)
        except:
            target = 0
        if target <= 0:
            return None
        for e in (self.gift_library or []):
            try:
                if int(e.get("unique_id", 0) or 0) == target:
                    return e
            except:
                continue
        return None

    def _library_find_entry_by_slug(self, slug):
        s = str(slug or "")
        if not s:
            return None
        for e in (self.gift_library or []):
            try:
                if str(e.get("slug", "")) == s:
                    return e
            except:
                continue
        return None

    def _library_find_entry_by_saved_id(self, saved_id):
        try:
            target = int(saved_id or 0)
        except:
            target = 0
        if target <= 0:
            return None
        for e in (self.gift_library or []):
            try:
                if int(e.get("saved_id", 0) or 0) == target:
                    return e
            except:
                continue
        return None

    def _is_plugin_saved_gift_wrapper(self, wrapper):
        if wrapper is None:
            return False
        try:
            sid = int(self._extract_saved_id_from_wrapper(wrapper) or 0)
        except:
            sid = 0
        if sid > 0:
            try:
                if self._library_find_entry_by_saved_id(sid) is not None:
                    return True
            except:
                pass
        try:
            gift = self._extract_wrapper_gift(wrapper)
        except:
            gift = None
        if gift is None:
            return False
        try:
            unique_id = int(self._to_int(get_val(gift, "id", 0), 0) or 0)
        except:
            unique_id = 0
        if unique_id > 0:
            try:
                if self._library_find_entry_by_unique_id(unique_id) is not None:
                    return True
            except:
                pass
        try:
            slug = str(get_val(gift, "slug", "") or "")
        except:
            slug = ""
        if slug:
            try:
                if self._library_find_entry_by_slug(slug) is not None:
                    return True
            except:
                pass
        return False

    def _filter_official_saved_gifts(self, gifts_list):
        if gifts_list is None:
            return 0
        removed = 0
        removed_wrappers = []
        try:
            for i in range(int(gifts_list.size() or 0) - 1, -1, -1):
                try:
                    item = gifts_list.get(i)
                except:
                    continue
                try:
                    if self._is_plugin_saved_gift_wrapper(item):
                        continue
                except:
                    pass
                try:
                    removed_wrappers.append(item)
                    gifts_list.remove(i)
                    removed += 1
                except:
                    continue
        except Exception as e:
            _log(f"Local official gifts filter error: {e}")
        if removed_wrappers:
            try:
                self._hidden_official_gift_wrappers = list(reversed(removed_wrappers))
            except:
                self._hidden_official_gift_wrappers = removed_wrappers
        return int(removed or 0)

    def _restore_hidden_official_gifts(self, gifts_list):
        if gifts_list is None:
            return 0
        try:
            wrappers = list(getattr(self, "_hidden_official_gift_wrappers", None) or [])
        except:
            wrappers = []
        if not wrappers:
            return int(changed or 0)

        present_saved_ids = set()
        present_gift_ids = set()
        try:
            for i in range(int(gifts_list.size() or 0)):
                try:
                    item = gifts_list.get(i)
                except:
                    continue
                try:
                    sid = int(self._extract_saved_id_from_wrapper(item) or 0)
                except:
                    sid = 0
                if sid > 0:
                    present_saved_ids.add(sid)
                try:
                    gift = self._extract_wrapper_gift(item)
                    gid = int(self._to_int(get_val(gift, "id", 0), 0) or 0) if gift is not None else 0
                except:
                    gid = 0
                if gid > 0:
                    present_gift_ids.add(gid)
        except:
            pass

        restored = 0
        try:
            wrappers.sort(key=lambda ww: self._saved_gift_sort_key(ww))
        except:
            pass
        for wrapper in wrappers:
            try:
                sid = int(self._extract_saved_id_from_wrapper(wrapper) or 0)
            except:
                sid = 0
            try:
                gift = self._extract_wrapper_gift(wrapper)
                gid = int(self._to_int(get_val(gift, "id", 0), 0) or 0) if gift is not None else 0
            except:
                gid = 0
            if (sid > 0 and sid in present_saved_ids) or (gid > 0 and gid in present_gift_ids):
                continue
            try:
                idx = self._find_insert_index_by_sort(gifts_list, wrapper)
                gifts_list.add(idx, wrapper)
                restored += 1
                if sid > 0:
                    present_saved_ids.add(sid)
                if gid > 0:
                    present_gift_ids.add(gid)
            except:
                continue
        return int(restored or 0)

    def _extract_saved_id_from_wrapper(self, wrapper):
        gift_uid = 0
        try:
            g = get_val(wrapper, "gift", None)
            gift_uid = self._to_int(get_val(g, "id", 0), 0) if g is not None else 0
        except:
            gift_uid = 0

        for name in ["saved_id", "savedId", "savedID", "saved_gift_id", "savedGiftId", "savedStarGiftId", "msg_id", "msgId", "message_id", "messageId"]:
            try:
                v = self._to_int(get_val(wrapper, name, 0), 0)
                if v > 0:
                    return int(v)
            except:
                continue
        # Some builds use plain "id" on TL_savedStarGift as the saved gift id. Avoid confusing it with gift.id.
        try:
            v = self._to_int(get_val(wrapper, "id", 0), 0)
            if v > 0 and (gift_uid <= 0 or v != gift_uid):
                return int(v)
        except:
            pass
        return 0

    def _set_saved_id_on_wrapper(self, wrapper, saved_id):
        try:
            sid = int(saved_id or 0)
        except:
            sid = 0
        if sid <= 0 or wrapper is None:
            return False
        ok = False
        for name in ["saved_id", "savedId", "savedID", "saved_gift_id", "savedGiftId", "savedStarGiftId", "msg_id", "msgId", "message_id", "messageId"]:
            try:
                if self._set_field(wrapper, name, sid):
                    ok = True
            except:
                pass
        # Also try "id" field if it looks like it's the saved gift id (not gift.id).
        try:
            gift_uid = 0
            try:
                g = get_val(wrapper, "gift", None)
                gift_uid = self._to_int(get_val(g, "id", 0), 0) if g is not None else 0
            except:
                gift_uid = 0
            cur_id = self._to_int(get_val(wrapper, "id", 0), 0)
            if cur_id <= 0 or (gift_uid <= 0 or cur_id != gift_uid):
                if self._set_field(wrapper, "id", sid):
                    ok = True
        except:
            pass
        return ok

    def _new_saved_id(self):
        used = set()
        try:
            for e in (self.gift_library or []):
                try:
                    v = int(e.get("saved_id", 0) or 0)
                    if v > 0:
                        used.add(v)
                except:
                    pass
        except:
            pass
        # Use a high 32-bit range to reduce collisions and stay compatible with int/long fields.
        for _ in range(20):
            sid = random.randint(1600000000, 2147483647)
            if sid not in used:
                return sid
        return (int(time.time() * 1000) % 2147483647) or 1600000000

    def _ensure_saved_id_for_entry(self, entry, wrapper=None):
        if entry is None:
            return 0
        try:
            sid = int(entry.get("saved_id", 0) or 0)
        except:
            sid = 0
        if sid <= 0 and wrapper is not None:
            sid = self._extract_saved_id_from_wrapper(wrapper)
        if sid <= 0:
            sid = self._new_saved_id()
        try:
            entry["saved_id"] = int(sid)
        except:
            pass
        if wrapper is not None:
            self._set_saved_id_on_wrapper(wrapper, sid)
        return int(sid)

    def _remember_wrapper(self, key, wrapper):
        if not key or wrapper is None:
            return
        try:
            k = str(key)
        except:
            k = key
        try:
            # LRU order
            try:
                if k in self._gift_objects_order:
                    self._gift_objects_order.remove(k)
            except:
                pass
            self._gift_objects_order.append(k)
            self.gift_objects[k] = wrapper
            try:
                max_n = int(self._recompute_gift_objects_limit() or getattr(self, "_gift_objects_max", 12) or 12)
            except:
                max_n = int(getattr(self, "_gift_objects_max", 12) or 12)
            while len(self._gift_objects_order) > max_n:
                old = self._gift_objects_order.pop(0)
                try:
                    if old in self.gift_objects:
                        del self.gift_objects[old]
                except:
                    pass
        except:
            # Best-effort; never break core flow.
            self.gift_objects[k] = wrapper

    def _library_get_wrapper(self, key):
        if not key:
            return None
        if key in self.gift_objects:
            obj = self.gift_objects.get(key)
            try:
                if not self._is_valid_saved_gift_wrapper(obj):
                    try:
                        del self.gift_objects[key]
                    except:
                        pass
                    return None
            except:
                return None
            # Touch LRU.
            try:
                self._remember_wrapper(key, obj)
            except:
                pass
            return obj
        e = self._library_find_entry(key)
        if not e:
            return None
        b64 = e.get("b64", "")
        if not b64:
            return None
        try:
            obj = deserialize_tl_saved_gift(str(b64))
            if obj is None:
                _log(f"_library_get_wrapper: corrupt b64 for key={key}, removing entry")
                try:
                    self.gift_library = [x for x in (self.gift_library or []) if x.get("key") != key]
                    self._library_dirty = True
                except:
                    pass
                return None
            try:
                if not self._is_valid_saved_gift_wrapper(obj):
                    _log(f"Library wrapper invalid for key={key}")
                    return None
            except:
                return None
            # Ensure saved_id is non-empty and stable (needed for hide/reorder actions).
            try:
                self._ensure_saved_id_for_entry(e, obj)
            except:
                pass
            # Re-apply persisted UI overrides (pin/hide/order) so injected gifts don't reset
            # when re-entering profile or after restart.
            try:
                pv = e.get("pinned_override", None)
                if pv is not None:
                        for fn in ["pinned_to_top", "pinnedToTop", "pinned", "is_pinned", "isPinned"]:
                            try:
                                self._set_field(obj, fn, bool(pv))
                            except:
                                pass
            except:
                pass
            try:
                hv = e.get("hidden_override", None)
                if hv is not None:
                    for fn in ["hidden", "is_hidden", "isHidden", "hidden_to_top", "isHiddenToTop"]:
                        try:
                            self._set_field(obj, fn, bool(hv))
                        except:
                            pass
                    # TL_savedStarGift has no `hidden` field — the actual
                    # hide-from-profile semantic lives on `unsaved`. Mirror
                    # hidden_override there so re-injected wrappers stay
                    # hidden after the user tapped TG's «Hide from profile».
                    try:
                        self._set_field(obj, "unsaved", bool(hv))
                    except:
                        pass
            except:
                pass
            try:
                oh = self._to_int(e.get("order_hint", 0), 0)
                if oh != 0:
                    for fn in ["order", "position", "sort", "sort_id", "sortId", "rank", "pinned_order", "pinnedOrder", "pinned_index", "pinnedIndex"]:
                        try:
                            self._set_field(obj, fn, int(oh))
                        except:
                            pass
            except:
                pass
                # Fix bogus availability totals (prevents "1 ÃƒÂÃ‚Â¸ÃƒÂÃ‚Â· 0" ribbons in UI).
            try:
                gift = self._extract_wrapper_gift(obj)
                if gift is not None:
                    if self._ensure_unique_gift_availability(gift, base_gift_id=int(e.get("base_gift_id", 0) or 0)):
                        # Persist patched wrapper snapshot so it stays consistent across restarts.
                        try:
                            new_b64 = serialize_tl_object(obj)
                            if new_b64 and len(new_b64) > 10:
                                e["b64"] = new_b64
                                self._library_dirty = True
                        except:
                            pass
            except:
                pass
            try:
                gift = self._extract_wrapper_gift(obj)
                self._apply_identity_config_to_objects(gift=gift, wrapper=obj, identity_config=e.get("identity_config", None))
            except:
                pass
            try:
                gift = self._extract_wrapper_gift(obj)
                self._apply_gift_stars_config_to_objects(gift=gift, wrapper=obj, stars_config=e.get("gift_stars_config", None))
            except:
                pass
            # «Мои подарки» V4: write custom_date / custom_comment overrides
            # into the wrapper so they show up in the native StarGiftSheet.
            # custom_from is routed separately through identity_config (handled
            # above by _apply_identity_config_to_objects) when the user types
            # a numeric uid.
            try:
                self._apply_my_gifts_meta_overrides_to_wrapper(obj, e)
            except Exception as _mgo_e:
                try:
                    _log(f"_apply_my_gifts_meta_overrides_to_wrapper: {_mgo_e}")
                except:
                    pass
            self._remember_wrapper(key, obj)
            return obj
        except Exception as ex:
            _log(f"Library deserialize error: {ex}")
            return None

    def _rebuild_injection_payloads(self):
        try:
            self._recompute_gift_objects_limit()
        except:
            pass
        try:
            my_id_for_filter = int(self._get_my_user_id() or 0)
        except Exception:
            my_id_for_filter = 0
        payloads = []
        skipped_gifted = 0
        for e in (self.gift_library or []):
            if not e.get("inject", False):
                continue
            # Skip entries marked as "gifted to someone else" — i.e. their
            # identity_config.to_user_id is set to a uid that is not us.
            # Without this gate the gift still appears in our own profile
            # snapshot (and local injection) even though the user explicitly
            # routed it to a different recipient.
            try:
                ic = e.get("identity_config") if isinstance(e.get("identity_config"), dict) else {}
                to_uid = int(ic.get("to_user_id", 0) or 0)
            except Exception:
                to_uid = 0
            if my_id_for_filter > 0 and to_uid > 0 and to_uid != my_id_for_filter:
                skipped_gifted += 1
                continue
            w = self._library_get_wrapper(e.get("key"))
            if w and self._repair_saved_gift_wrapper(w):
                payloads.append(w)
        self.injection_payloads = payloads
        self.inject_active = bool(payloads)
        self.injection_payload = payloads[0] if payloads else None
        if skipped_gifted:
            try:
                _log(f"_rebuild_injection_payloads: skipped {skipped_gifted} gifted-out entries")
            except Exception:
                pass
        try:
            self._debug_state_snapshot("rebuild_payloads", f"rebuilt={len(payloads or [])}")
        except:
            pass

    def _library_upsert_wrapper(self, wrapper, base_gift_id=0, key=None, inject=True, make_active=True, wear_override=None, build_config=None, identity_config=None, value_config=None, gift_stars_config=None):
        if wrapper is None:
            return None
        k = key or self._new_gift_key()
        e = self._library_find_entry(k)
        # saved_id must exist and be unique/stable for official TG actions (hide/reorder).
        try:
            self._ensure_saved_id_for_entry(e, wrapper) if e else None
        except:
            pass
        if e is None:
            # For new entries, assign a saved_id now so it gets serialized into b64.
            e_tmp = {"key": k}
            self._ensure_saved_id_for_entry(e_tmp, wrapper)
            e = None

        try:
            b64 = serialize_tl_object(wrapper)
        except:
            b64 = None
        if not b64:
            try:
                prev_b64 = str(e.get("b64", "")) if isinstance(e, dict) else ""
            except:
                prev_b64 = ""
            if prev_b64 and len(prev_b64) > 10:
                b64 = prev_b64
                _log(f"Upsert serialize fallback: reuse cached b64 for key={k}")
            else:
                _log(f"Upsert serialize skipped: no usable b64 for key={k}")
                return None

        title, slug, num, bg, unique_id = self._extract_gift_meta(wrapper, base_gift_id)
        gift = self._extract_wrapper_gift(wrapper)
        wd = self._compute_wear_status_data_from_gift(gift)
        try:
            if wear_override and isinstance(wear_override, dict):
                ocid = self._to_int(wear_override.get("collectible_id", 0), 0)
                if ocid > 0 and (unique_id == 0 or ocid == unique_id):
                    wd = wear_override
                    unique_id = ocid
        except:
            pass
        e = self._library_find_entry(k)
        my_id = self._get_my_user_id()
        cfg = build_config if isinstance(build_config, dict) else (self.build_config if isinstance(self.build_config, dict) else {})
        cfg_slim = {
            "model": int(cfg.get("model", 0) or 0),
            "pattern": int(cfg.get("pattern", 0) or 0),
            "backdrop": int(cfg.get("backdrop", 0) or 0),
            "num": int(cfg.get("num", 1) or 1),
        }
        existing_identity_cfg = e.get("identity_config", None) if isinstance(e, dict) else None
        raw_identity_cfg = identity_config if isinstance(identity_config, dict) else existing_identity_cfg
        if not isinstance(raw_identity_cfg, dict):
            raw_identity_cfg = getattr(self, "identity_config", None)
        identity_cfg_slim = self._sanitize_identity_config(raw_identity_cfg)
        existing_value_cfg = e.get("value_config", None) if isinstance(e, dict) else None
        raw_value_cfg = value_config if isinstance(value_config, dict) else existing_value_cfg
        if not isinstance(raw_value_cfg, dict):
            raw_value_cfg = getattr(self, "value_config", None)
        value_cfg_slim = self._sanitize_value_config(raw_value_cfg)
        existing_gift_stars_cfg = e.get("gift_stars_config", None) if isinstance(e, dict) else None
        raw_gift_stars_cfg = gift_stars_config if isinstance(gift_stars_config, dict) else existing_gift_stars_cfg
        if not isinstance(raw_gift_stars_cfg, dict):
            raw_gift_stars_cfg = getattr(self, "gift_stars_config", None)
        gift_stars_cfg_slim = self._sanitize_gift_stars_config(raw_gift_stars_cfg)
        try:
            sid2 = self._extract_saved_id_from_wrapper(wrapper)
        except:
            sid2 = 0
        if not e:
            e = {
                "key": k,
                "b64": b64,
                "title": title,
                "slug": slug,
                "num": int(num),
                "base_gift_id": int(bg),
                "unique_id": int(unique_id or 0),
                "saved_id": int(sid2 or 0),
                "wear_status_data": wd or {},
                "inject": bool(inject),
                "created_at": int(time.time()),
                "owner_user_id": int(my_id or 0),
                "build_config": cfg_slim,
                "identity_config": identity_cfg_slim,
                "value_config": value_cfg_slim,
                "gift_stars_config": gift_stars_cfg_slim,
            }
            try:
                has_pin, pin_val = self._saved_gift_pinned_value(wrapper)
                if has_pin:
                    e["pinned_override"] = bool(pin_val)
            except:
                pass
            try:
                e["hidden_override"] = bool(self._saved_gift_is_hidden(wrapper))
            except:
                pass
            try:
                e["order_hint"] = int(self._saved_gift_order_hint(wrapper) or 0)
            except:
                pass
            # Ensure saved_id exists for new entry and keep it on wrapper.
            self._ensure_saved_id_for_entry(e, wrapper)
            self.gift_library.append(e)
        else:
            e["b64"] = b64
            e["title"] = title
            e["slug"] = slug
            e["num"] = int(num)
            if bg:
                e["base_gift_id"] = int(bg)
            if unique_id:
                e["unique_id"] = int(unique_id)
            if wd:
                e["wear_status_data"] = wd
            e["inject"] = bool(inject)
            try:
                e["owner_user_id"] = int(e.get("owner_user_id", 0) or my_id or 0)
            except:
                pass
            e["build_config"] = cfg_slim
            e["identity_config"] = identity_cfg_slim
            e["value_config"] = value_cfg_slim
            e["gift_stars_config"] = gift_stars_cfg_slim
            try:
                has_pin, pin_val = self._saved_gift_pinned_value(wrapper)
                if has_pin:
                    e["pinned_override"] = bool(pin_val)
            except:
                pass
            try:
                e["hidden_override"] = bool(self._saved_gift_is_hidden(wrapper))
            except:
                pass
            try:
                e["order_hint"] = int(self._saved_gift_order_hint(wrapper) or 0)
            except:
                pass
            # Preserve existing saved_id; if missing, generate one.
            self._ensure_saved_id_for_entry(e, wrapper)

        try:
            self._recompute_gift_objects_limit()
        except:
            pass
        self._remember_wrapper(k, wrapper)
        self._rebuild_injection_payloads()

        if make_active:
            gift = self._extract_wrapper_gift(wrapper)
            if gift:
                self.stolen_gift_inner = gift
                self.stolen_gift_wrapper = wrapper
                self.cached_gift_id = int(bg or 0)
                try:
                    self.cls_saved = wrapper.getClass()
                    self.cls_unique = gift.getClass()
                except:
                    pass
        return k

    def _library_entry_matches_current_wear(self, entry=None, key=None):
        try:
            active_cid = int(self.wear_collectible_id or 0)
        except:
            active_cid = 0
        if not self.wear_active or active_cid <= 0:
            return False

        e = entry
        if e is None and key:
            try:
                e = self._library_find_entry(key)
            except:
                e = None
        if not e:
            return False

        try:
            entry_key = str(e.get("key", "") or "")
        except:
            entry_key = ""
        if key and entry_key and str(key) != entry_key:
            entry_key = str(key)

        try:
            active_entry = self._library_find_entry_by_unique_id(active_cid)
        except:
            active_entry = None
        try:
            if active_entry and entry_key and str(active_entry.get("key", "") or "") == entry_key:
                return True
        except:
            pass

        for raw_cid in [
            e.get("unique_id", 0),
            (e.get("wear_status_data", {}) or {}).get("collectible_id", 0) if isinstance(e.get("wear_status_data", None), dict) else 0,
        ]:
            try:
                if int(raw_cid or 0) == active_cid:
                    return True
            except:
                pass

        try:
            w = self._library_get_wrapper(entry_key or key)
            g = self._extract_wrapper_gift(w) if w else None
            if g is not None and int(self._to_int(get_val(g, "id", 0), 0) or 0) == active_cid:
                return True
        except:
            pass

        try:
            active_slug = str((self.wear_status_data or {}).get("slug", "") or "")
        except:
            active_slug = ""
        if not active_slug:
            try:
                ag = self._resolve_active_gift()
                active_slug = str(get_val(ag, "slug", "") or "") if ag is not None else ""
            except:
                active_slug = ""
        if active_slug:
            try:
                if str(e.get("slug", "") or "") == active_slug:
                    return True
            except:
                pass
            try:
                w = self._library_get_wrapper(entry_key or key)
                g = self._extract_wrapper_gift(w) if w else None
                if g is not None and str(get_val(g, "slug", "") or "") == active_slug:
                    return True
            except:
                pass

        return False

    def _library_remove(self, key):
        if not key:
            return
        try:
            e = self._library_find_entry(key)
        except:
            e = None
        if self._library_entry_matches_current_wear(e, key):
            try:
                self._clear_wear_state(persist=True, clear_cached_status=True, request_server_clear=True, reason="library_remove")
            except:
                pass
        self.gift_library = [e for e in (self.gift_library or []) if str(e.get("key", "")) != str(key)]
        try:
            if key in self.gift_objects:
                del self.gift_objects[key]
        except:
            pass
        if self.editing_gift_key == key:
            self.editing_gift_key = None
        self._rebuild_injection_payloads()

