    def _load_catalog_silent(self):
        """Trigger StarsController.loadStarGifts() without UI bulletin (best-effort)."""
        try:
            if not self._can_warm_catalog():
                return False
        except:
            return False
        try:
            now = time.time()
            last = float(getattr(self, "_catalog_silent_load_last_ts", 0.0) or 0.0)
            should_load = (now - last) >= 2.4
        except:
            should_load = True
        try:
            account = get_user_config().selectedAccount
            Ctrl = jclass("org.telegram.ui.Stars.StarsController")
            ctrl = Ctrl.getInstance(to_java_int(account))
            has_cached_catalog = False
            try:
                lst = self._get_catalog_gifts_from_memory()
                has_cached_catalog = bool(lst is not None and int(lst.size() or 0) > 0)
            except:
                has_cached_catalog = False
            try:
                if has_cached_catalog:
                    self._catalog_load_requested = False
            except:
                pass
            if should_load and (not has_cached_catalog):
                try:
                    if bool(getattr(self, "_catalog_load_requested", False)) and (now - last) < 3.2:
                        should_load = False
                except:
                    pass
            if should_load and (not has_cached_catalog):
                try:
                    self._invalidate_catalog_runtime_cache()
                except:
                    pass
                ctrl.loadStarGifts()
                try:
                    self._catalog_silent_load_last_ts = time.time()
                except:
                    pass
                try:
                    self._catalog_load_requested = True
                except:
                    pass
            if has_cached_catalog and self._is_my_profile_activity():
                self._schedule_profile_gifts_refresh([140, 360], min_interval=0.6, force=False)
            return True
        except:
            return False

    def _invalidate_catalog_runtime_cache(self):
        try:
            self._catalog_nft_cache_sig = ""
            self._catalog_nft_cache_items = []
            self._catalog_nft_cache_last_ts = 0.0
        except:
            pass
        try:
            self._catalog_gift_lookup_sig = ""
            self._catalog_gift_lookup = {}
        except:
            pass

    def _get_catalog_memory_signature(self, gifts_list, probe_limit=8):
        if gifts_list is None:
            return ""
        try:
            size = int(gifts_list.size() or 0)
        except:
            return ""
        if size <= 0:
            return "0"
        parts = [str(size)]
        try:
            limit = min(size, max(1, int(probe_limit or 0)))
        except:
            limit = min(size, 8)
        for i in range(limit):
            try:
                gift = gifts_list.get(i)
            except:
                continue
            gid = 0
            for name in ["id", "gift_id", "giftId", "giftID"]:
                try:
                    gid = self._to_int(get_val(gift, name, 0), 0)
                except:
                    gid = 0
                if gid > 0:
                    break
            if gid <= 0:
                try:
                    gid = int(gift.hashCode())
                except:
                    gid = i
            parts.append(str(int(gid)))
        return "|".join(parts)

    def _refresh_profile_gifts_ui(self):
        """Patch visible gifts list objects and notify adapters (best-effort, no user action required)."""
        try:
            now = time.time()
            last = float(getattr(self, "_profile_gifts_ui_last_ts", 0.0) or 0.0)
            if (now - last) < 0.65:
                return 0
            self._profile_gifts_ui_last_ts = now
        except:
            pass
        try:
            if bool(getattr(self, "_profile_gifts_refresh_busy", False)):
                return 0
        except:
            pass
        frag = self._get_visible_profile_activity()
        if frag is None:
            return 0
        if not self._is_my_profile_activity(frag):
            return 0
        try:
            self._profile_gifts_refresh_busy = True
        except:
            pass
        try:
            cold_open = bool(self._is_profile_activity_cold_open(frag, window_sec=0.42))
            removed_invalid = 0
            inserted = 0
            patched = 0
            try:
                frag_key = int(frag.hashCode())
            except:
                frag_key = 0
            try:
                saved_lists = self._get_cached_profile_saved_gift_lists(frag)
            except:
                saved_lists = []
            try:
                miss_key = int(getattr(self, "_profile_saved_lists_miss_frag_key", 0) or 0)
                miss_ts = float(getattr(self, "_profile_saved_lists_miss_last_ts", 0.0) or 0.0)
                recent_lists_miss = bool(
                    frag_key > 0 and miss_key == frag_key and (time.time() - miss_ts) < (0.95 if cold_open else 0.55)
                )
            except:
                recent_lists_miss = False
            if not saved_lists:
                if not recent_lists_miss:
                    try:
                        saved_lists = self._discover_saved_gift_lists(frag, max_depth=1)
                    except:
                        saved_lists = []
                if (not saved_lists) and cold_open:
                    try:
                        if frag_key > 0:
                            self._profile_saved_lists_miss_frag_key = frag_key
                            self._profile_saved_lists_miss_last_ts = time.time()
                    except:
                        pass
                    return 0
                if (not saved_lists) and frag_key > 0 and (not recent_lists_miss):
                    try:
                        last_deep = int(getattr(self, "_profile_gifts_deep_scan_key", 0) or 0)
                    except:
                        last_deep = 0
                    if frag_key != last_deep:
                        try:
                            saved_lists = self._discover_saved_gift_lists(frag, max_depth=2)
                        except:
                            saved_lists = []
                        try:
                            self._profile_gifts_deep_scan_key = frag_key
                        except:
                            pass
                if saved_lists:
                    try:
                        saved_lists = self._cache_profile_saved_gift_lists(frag, saved_lists)
                    except:
                        pass
                    try:
                        self._profile_saved_lists_miss_frag_key = 0
                        self._profile_saved_lists_miss_last_ts = 0.0
                    except:
                        pass
                elif frag_key > 0:
                    try:
                        self._profile_saved_lists_miss_frag_key = frag_key
                        self._profile_saved_lists_miss_last_ts = time.time()
                    except:
                        pass
            if saved_lists:
                for gifts_list in list(saved_lists or []):
                    try:
                        removed_invalid += int(self._sanitize_saved_gifts_list(gifts_list) or 0)
                    except:
                        pass
                    try:
                        if self._has_local_gifts_overrides():
                            inserted += int(self._inject_saved_gifts_into_list(gifts_list) or 0)
                    except:
                        pass
                    try:
                        patched += int(self._patch_saved_gift_list_availability(gifts_list, limit=60, sanitize=False) or 0)
                    except:
                        pass
            allow_root_scan = False
            try:
                allow_root_scan = (not cold_open) and self._should_run_profile_gifts_root_scan(frag, window_sec=1.45)
            except:
                allow_root_scan = (not cold_open)
            if (not saved_lists) and (not recent_lists_miss) and allow_root_scan:
                try:
                    if self._has_local_gifts_overrides():
                        inserted += int(self._scan_object_and_inject_saved_gifts(frag, max_depth=1) or 0)
                except:
                    pass
                try:
                    patched += int(self._scan_object_and_patch_gift_availability(frag, max_depth=1) or 0)
                except:
                    pass
            try:
                desired_count = int(self._get_local_profile_gifts_count(self._get_profile_activity_entity_id(frag)) or 0)
            except:
                desired_count = 0
            try:
                patched += int(self._scan_object_and_sync_saved_gifts_counts(frag, desired_min=desired_count, max_depth=2) or 0)
            except:
                pass
            try:
                if removed_invalid or inserted or patched:
                    try:
                        self._rebuild_profile_gifts_rows(frag, animated=True)
                    except:
                        pass
                    notified = int(self._notify_profile_activity_adapters_light(frag) or 0)
                    if notified <= 0:
                        self._scan_object_and_notify_adapters(frag, max_depth=1)
            except:
                pass
            try:
                self._debug_state_snapshot("profile_gifts_ui", f"removed={removed_invalid} inserted={inserted} patched={patched}")
            except:
                pass
            return int((removed_invalid or 0) + (inserted or 0) + (patched or 0))
        finally:
            try:
                self._profile_gifts_refresh_busy = False
            except:
                pass

    def _inject_saved_gifts_into_list(self, gifts_list):
        if gifts_list is None:
            return 0
        changed = 0
        try:
            changed += int(self._sanitize_saved_gifts_list(gifts_list) or 0)
        except:
            pass
        try:
            if bool(getattr(self, "hide_official_gifts_local", False)):
                changed += int(self._filter_official_saved_gifts(gifts_list) or 0)
            else:
                changed += int(self._restore_hidden_official_gifts(gifts_list) or 0)
        except:
            pass
        if not self.inject_active or not self.injection_payloads:
            return int(changed or 0)
        try:
            owner_entity_id = int(self._get_list_owner_user_id(gifts_list) or 0)
        except:
            owner_entity_id = 0
        try:
            target_entity_id = int(self._resolve_saved_gifts_target_user_id(0, owner_entity_id) or 0)
        except:
            target_entity_id = 0
        wrappers, wrapper_gift_ids, desired_ids = self._build_injection_wrappers_bundle(target_entity_id=target_entity_id)
        if not wrappers:
            return int(changed or 0)
        try:
            current_ids, has_duplicates = self._collect_plugin_gift_ids_in_order(gifts_list, wrapper_gift_ids)
        except:
            current_ids, has_duplicates = [], True
        if (not has_duplicates) and current_ids == desired_ids:
            return int(changed or 0)
        try:
            if wrapper_gift_ids:
                self._remove_existing_gifts_by_ids(gifts_list, wrapper_gift_ids)
        except:
            pass
        inserted = 0
        try:
            list_size_now = int(gifts_list.size() or 0)
        except:
            list_size_now = 0
        if list_size_now <= 0:
            for w in wrappers:
                try:
                    gifts_list.add(w)
                    inserted += 1
                except:
                    continue
            return int((changed or 0) + (inserted or 0))
        for w in wrappers:
            try:
                idx = self._find_insert_index_by_sort(gifts_list, w)
                gifts_list.add(idx, w)
                inserted += 1
            except:
                continue
        try:
            self._debug_state_snapshot("inject_saved_list", f"inserted={inserted} wrappers={len(wrappers or [])}")
        except:
            pass
        return int((changed or 0) + (inserted or 0))

    def _scan_object_and_inject_saved_gifts(self, root, max_depth=2):
        if root is None:
            return 0

        visited = set()
        inserted = 0

        def looks_like_list(obj):
            return bool(self._is_java_list_like(obj))

        def looks_like_saved_gifts_field(field_name, lst):
            try:
                if lst is not None and int(lst.size() or 0) > 0:
                    sample = lst.get(0)
                    return bool(self._looks_like_saved_gift_wrapper(sample))
            except:
                pass
            low = str(field_name or "").lower()
            return bool(("gift" in low and "saved" in low) or ("star" in low and "gift" in low))

        def walk(obj, depth):
            nonlocal inserted
            if obj is None or depth > max_depth:
                return
            try:
                oid = int(obj.hashCode())
            except:
                oid = id(obj)
            if oid in visited:
                return
            visited.add(oid)

            if looks_like_list(obj):
                try:
                    if int(obj.size() or 0) > 0 and self._looks_like_saved_gift_wrapper(obj.get(0)):
                        inserted += int(self._inject_saved_gifts_into_list(obj) or 0)
                except:
                    pass
                return

            try:
                cn = str(obj.getClass().getName() or "")
            except:
                cn = ""
            try:
                if ("android.view" in cn) or ("android.widget" in cn) or ("androidx.recyclerview" in cn):
                    try:
                        if hasattr(obj, "getAdapter") and callable(getattr(obj, "getAdapter", None)):
                            ad = obj.getAdapter()
                            if ad is not None:
                                walk(ad, depth + 1)
                    except:
                        pass
                    return
            except:
                pass

            for f in self._iter_object_fields(obj):
                try:
                    name = str(f.getName() or "")
                except:
                    name = ""
                try:
                    val = f.get(obj)
                except:
                    continue
                if val is None:
                    continue
                if looks_like_list(val):
                    try:
                        if looks_like_saved_gifts_field(name, val):
                            inserted += int(self._inject_saved_gifts_into_list(val) or 0)
                            continue
                    except:
                        pass
                try:
                    walk(val, depth + 1)
                except:
                    pass

        walk(root, 0)
        try:
            self._debug_state_snapshot("scan_inject_saved", f"inserted={inserted} depth={max_depth}")
        except:
            pass
        return int(inserted or 0)

    def _scan_object_and_patch_gift_availability(self, root, max_depth=2):
        """Walk object graph, find saved gift lists and patch gift availability totals in-place."""
        if root is None:
            return 0

        visited = set()
        patched = 0

        def looks_like_list(obj):
            if obj is None:
                return False
            try:
                _ = obj.size()
                _ = obj.get
                return True
            except:
                return False

        def patch_list(lst):
            nonlocal patched
            try:
                size = int(lst.size() or 0)
            except:
                return
            if size <= 0:
                return
            sample = None
            try:
                sample = lst.get(0)
            except:
                sample = None

            is_saved = self._looks_like_saved_gift_wrapper(sample)
            is_unique = False
            if not is_saved:
                try:
                    n = str(sample.getClass().getName() or "").lower()
                    if "stargift" in n and "unique" in n:
                        is_unique = True
                except:
                    is_unique = False

            if not is_saved and not is_unique:
                return

            lim = min(size, 60)
            for i in range(lim):
                try:
                    it = lst.get(i)
                except:
                    continue
                try:
                    g = get_val(it, "gift", None) if is_saved else it
                    if g is None:
                        continue
                    if self._ensure_unique_gift_availability(g, base_gift_id=0):
                        patched += 1
                except:
                    continue

        def walk(obj, depth):
            if obj is None or depth > max_depth:
                return
            try:
                oid = int(obj.hashCode())
            except:
                oid = id(obj)
            if oid in visited:
                return
            visited.add(oid)

            if looks_like_list(obj):
                patch_list(obj)
                return

            # If it's a View (e.g. RecyclerView), don't recurse through the whole tree.
            # Just try to reach its adapter and patch data there.
            try:
                cn = str(obj.getClass().getName() or "")
            except:
                cn = ""
            try:
                if ("android.view" in cn) or ("android.widget" in cn) or ("androidx.recyclerview" in cn):
                    try:
                        if hasattr(obj, "getAdapter") and callable(getattr(obj, "getAdapter", None)):
                            ad = obj.getAdapter()
                            if ad is not None:
                                walk(ad, depth + 1)
                    except:
                        pass
                    return
            except:
                pass

            for f in self._iter_object_fields(obj):
                try:
                    v = f.get(obj)
                except:
                    continue
                if v is None:
                    continue
                if looks_like_list(v):
                    patch_list(v)
                else:
                    walk(v, depth + 1)

        walk(root, 0)
        return int(patched or 0)

    def _get_catalog_gifts_from_memory(self):
        """Returns raw TL_starGift list from StarsController memory (best-effort)."""
        try:
            account = get_user_config().selectedAccount
            CtrlClass = jclass("org.telegram.ui.Stars.StarsController")
            ctrl = CtrlClass.getInstance(to_java_int(account))
            # Fast path: cached field.
            try:
                f0 = getattr(self, "_stars_catalog_list_field", None)
            except:
                f0 = None
            if f0 is not None:
                try:
                    try:
                        f0.setAccessible(True)
                    except:
                        pass
                    val = f0.get(ctrl)
                    if val is not None and "ArrayList" in str(val.getClass().getName() or ""):
                        return val
                except:
                    pass

            # Try cached candidates (cheap, avoids full reflection scan).
            try:
                cand = getattr(self, "_stars_catalog_list_candidates", None)
            except:
                cand = None
            if cand:
                fallback_val = None
                for f in list(cand):
                    try:
                        try:
                            f.setAccessible(True)
                        except:
                            pass
                        val = f.get(ctrl)
                        if val is None:
                            continue
                        if "ArrayList" not in str(val.getClass().getName() or ""):
                            continue
                        if fallback_val is None:
                            fallback_val = val
                        try:
                            if val.size() <= 0:
                                continue
                            first = val.get(0)
                            first_name_l = str(first.getClass().getName() or "").lower()
                            if ("stargift" in first_name_l) and ("saved" not in first_name_l):
                                try:
                                    self._stars_catalog_list_field = f
                                except:
                                    pass
                                return val
                        except:
                            continue
                    except:
                        continue
                # If everything is empty, still return the likely list to avoid re-scanning repeatedly.
                if fallback_val is not None:
                    return fallback_val

            # Throttle full scans while catalog is empty/loading.
            try:
                now_ts = time.time()
                last = float(getattr(self, "_stars_catalog_last_scan_ts", 0.0) or 0.0)
                if (now_ts - last) < 1.2:
                    return None
                self._stars_catalog_last_scan_ts = now_ts
            except:
                pass

            gifts_list = None
            candidates = []
            real_cls = ctrl.getClass()
            for f in real_cls.getDeclaredFields():
                try:
                    f.setAccessible(True)
                except:
                    pass
                try:
                    val = f.get(ctrl)
                except:
                    continue
                if val is None:
                    continue
                try:
                    if "ArrayList" not in val.getClass().getName():
                        continue
                except:
                    continue
                try:
                    fname_l = str(f.getName() or "").lower()
                    if ("gift" in fname_l) and ("saved" not in fname_l):
                        candidates.append(f)
                except:
                    pass
                try:
                    if val.size() <= 0:
                        continue
                    first = val.get(0)
                    first_name_l = str(first.getClass().getName() or "").lower()
                    if ("stargift" in first_name_l) and ("saved" not in first_name_l):
                        gifts_list = val
                        try:
                            self._stars_catalog_list_field = f
                        except:
                            pass
                        break
                except:
                    continue

            try:
                if candidates:
                    self._stars_catalog_list_candidates = candidates
            except:
                pass

            if gifts_list is not None:
                return gifts_list
            # If we only have candidates, return the first one (likely empty) to avoid constant rescans.
            try:
                if candidates:
                    return candidates[0].get(ctrl)
            except:
                pass
            return None
        except:
            return None

    def _get_catalog_gift_by_id(self, gift_id):
        """Return TL_starGift from StarsController cache by id (best-effort)."""
        try:
            gid = int(gift_id or 0)
        except:
            gid = 0
        if gid <= 0:
            return None

        # Prefer StarsController getter method when available (more reliable than scanning fields).
        try:
            account = get_user_config().selectedAccount
            CtrlClass = jclass("org.telegram.ui.Stars.StarsController")
            ctrl = CtrlClass.getInstance(to_java_int(account))
        except:
            ctrl = None

        if ctrl is not None:
            try:
                checked = bool(getattr(self, "_stars_get_gift_method_checked", False))
            except:
                checked = False
            if not checked:
                try:
                    self._stars_get_gift_method_checked = True
                except:
                    pass
                best = None
                best_score = -1
                try:
                    for m in ctrl.getClass().getDeclaredMethods():
                        try:
                            ret = str(m.getReturnType().getName() or "").lower()
                            if "stargift" not in ret:
                                continue
                            params = m.getParameterTypes()
                            if len(params) != 1:
                                continue
                            p0 = str(params[0].getName() or "")
                            if p0 not in ["int", "long", "java.lang.Integer", "java.lang.Long"]:
                                continue
                            name_l = str(m.getName() or "").lower()
                            if "gift" not in name_l:
                                continue
                            score = 0
                            if "get" in name_l:
                                score += 3
                            if "find" in name_l:
                                score += 2
                            if "by" in name_l or "id" in name_l:
                                score += 1
                            if score > best_score:
                                best_score = score
                                best = m
                        except:
                            continue
                except:
                    best = None
                if best is not None:
                    try:
                        best.setAccessible(True)
                    except:
                        pass
                try:
                    self._stars_get_gift_method = best
                except:
                    pass

            m = getattr(self, "_stars_get_gift_method", None)
            if m is not None:
                try:
                    p0 = str(m.getParameterTypes()[0].getName() or "")
                except:
                    p0 = "int"
                try:
                    if p0 in ["long", "java.lang.Long"]:
                        res = m.invoke(ctrl, int(gid))
                    else:
                        res = m.invoke(ctrl, to_java_int(int(gid)))
                    if res is not None:
                        return res
                except:
                    pass

        lst = self._get_catalog_gifts_from_memory()
        if not lst:
            return None
        try:
            sig = self._get_catalog_memory_signature(lst)
        except:
            sig = ""
        try:
            cached_sig = str(getattr(self, "_catalog_gift_lookup_sig", "") or "")
            lookup = getattr(self, "_catalog_gift_lookup", None)
            if isinstance(lookup, dict) and sig and cached_sig == sig:
                cached = lookup.get(int(gid))
                if cached is not None:
                    return cached
        except:
            lookup = None
        try:
            size = int(lst.size() or 0)
        except:
            return None
        lookup = {}
        for i in range(size):
            try:
                g = lst.get(i)
            except:
                continue
            try:
                for name in ["id", "gift_id", "giftId", "giftID"]:
                    cur_id = self._to_int(get_val(g, name, 0), 0)
                    if cur_id > 0:
                        lookup[int(cur_id)] = g
                        if cur_id == gid:
                            try:
                                if sig:
                                    self._catalog_gift_lookup_sig = sig
                                    self._catalog_gift_lookup = lookup
                            except:
                                pass
                            return g
                continue
            except:
                continue
        try:
            if sig:
                self._catalog_gift_lookup_sig = sig
                self._catalog_gift_lookup = lookup
        except:
            pass
        return None

    def _get_gift_base_id(self, gift, fallback=0):
        """Best-effort resolve base gift id for a unique gift instance."""
        if gift is None:
            return int(fallback or 0)
        for name in ["gift_id", "giftId", "giftID", "base_gift_id", "baseGiftId"]:
            try:
                v = self._to_int(get_val(gift, name, 0), 0)
                if v > 0:
                    return int(v)
            except:
                pass
        return int(fallback or 0)

    def _normalize_catalog_gift_availability(self, gift):
        if gift is None:
            return False

        changed = False

        def _get_any_int(obj, names):
            for n in names:
                try:
                    v = self._to_int(get_val(obj, n, 0), 0)
                    if v > 0:
                        return int(v)
                except:
                    pass
            return 0

        def _set_any_int(obj, names, value):
            ok = False
            for n in names:
                try:
                    if self._set_field(obj, n, int(value)):
                        ok = True
                except:
                    pass
            return ok

        total = _get_any_int(gift, ["availability_total", "availabilityTotal", "total", "total_count", "totalCount", "limited_count", "limitedCount", "max", "maxCount"])
        issued = _get_any_int(gift, ["availability_issued", "availabilityIssued", "issued", "issued_count", "issuedCount"])
        remaining = _get_any_int(gift, ["availability_remains", "availabilityRemains", "remaining", "remaining_count", "remainingCount", "left", "left_count", "leftCount"])

        if remaining <= 0:
            try:
                for f in gift.getClass().getFields():
                    try:
                        low = str(f.getName() or "").lower()
                        typ = f.getType().getName()
                    except:
                        continue
                    if typ not in ["int", "long"]:
                        continue
                    try:
                        val = int(f.getLong(gift) if typ == "long" else f.getInt(gift))
                    except:
                        continue
                    if val < 0:
                        continue
                    if total <= 0 and (("avail" in low or "limit" in low) and ("total" in low or "count" in low or "max" in low)):
                        total = val
                    if issued <= 0 and (("avail" in low or "availability" in low) and ("issued" in low or "sold" in low)):
                        issued = val
                    if remaining <= 0 and ("remain" in low or "left" in low or "available" in low):
                        remaining = val
            except:
                pass

        if issued <= 0 and total > 0 and remaining >= 0 and total >= remaining:
            issued = int(total - remaining)

        if issued <= 0:
            try:
                num = int(get_val(gift, "num", 0) or 0)
            except:
                num = 0
            if num > 0 and total > 0:
                issued = min(num, total)

        if total > 0 and _set_any_int(gift, ["availability_total", "availabilityTotal", "total", "total_count", "totalCount"], total):
            changed = True
        if issued > 0 and _set_any_int(gift, ["availability_issued", "availabilityIssued", "issued", "issued_count", "issuedCount"], issued):
            changed = True

        return bool(changed)

    def _ensure_unique_gift_availability(self, gift, base_gift_id=0):
        """
        Fix "X ÃƒÂÃ‚Â¸ÃƒÂÃ‚Â· 0" ribbons by ensuring availability_total / limited_count are filled from catalog.
        If we can't resolve totals, disable 'limited' flag so Telegram doesn't render bogus data.
        """
        if gift is None:
            return False

        changed = False
        try:
            bg = int(base_gift_id or 0)
        except:
            bg = 0
        if bg <= 0:
            try:
                bg = self._get_gift_base_id(gift, fallback=0)
            except:
                bg = 0
        if bg <= 0:
            return False

        def _get_any_int(obj, names):
            for n in names:
                try:
                    v = self._to_int(get_val(obj, n, 0), 0)
                    if v > 0:
                        return int(v)
                except:
                    pass
            return 0

        def _set_any_int(obj, names, value):
            ok = False
            for n in names:
                try:
                    if self._set_field(obj, n, int(value)):
                        ok = True
                except:
                    pass
            return ok

        def _set_any_bool(obj, names, value):
            ok = False
            for n in names:
                try:
                    if self._set_field(obj, n, bool(value)):
                        ok = True
                except:
                    pass
            return ok

        # Read current values.
        cur_total = _get_any_int(gift, ["availability_total", "availabilityTotal", "total", "total_count", "totalCount"])
        cur_issued = _get_any_int(gift, ["availability_issued", "availabilityIssued", "issued", "issued_count", "issuedCount"])
        cur_limited_count = _get_any_int(gift, ["limited_count", "limitedCount", "limit", "max", "max_count", "maxCount"])

        # Resolve from catalog.
        total = 0
        issued = 0
        limited_count = 0
        cat = self._get_catalog_gift_by_id(bg)
        if cat is None and (cur_total <= 0 and cur_limited_count <= 0):
            # Catalog may not be loaded yet. Request it once, then try again.
            try:
                if self._can_warm_catalog() and (not bool(getattr(self, "_catalog_load_requested", False))):
                    self._catalog_load_requested = True
                    self._load_catalog_silent()
            except:
                pass
            cat = self._get_catalog_gift_by_id(bg)
        if cat is not None:
            total = _get_any_int(cat, ["availability_total", "availabilityTotal", "total", "total_count", "totalCount", "limited_count", "limitedCount", "max", "max_count", "maxCount"])
            issued = _get_any_int(cat, ["availability_issued", "availabilityIssued", "issued", "issued_count", "issuedCount"])
            limited_count = _get_any_int(cat, ["limited_count", "limitedCount", "limit", "max", "max_count", "maxCount", "availability_total", "availabilityTotal", "totalCount", "total"])

            # Fallback: scan numeric fields by name if fork renamed them.
            try:
                for f in cat.getClass().getFields():
                    try:
                        name = str(f.getName() or "")
                        low = name.lower()
                        typ = f.getType().getName()
                    except:
                        continue
                    if typ not in ["int", "long"]:
                        continue
                    try:
                        v = int(f.getLong(cat) if typ == "long" else f.getInt(cat))
                    except:
                        continue
                    if v <= 0:
                        continue
                    if ("avail" in low or "availability" in low) and ("total" in low or low.endswith("total")) and total <= 0:
                        total = v
                    if ("avail" in low or "availability" in low) and ("issued" in low or "sold" in low) and issued <= 0:
                        issued = v
                    if ("limited" in low or "limit" in low) and ("count" in low or "total" in low or "max" in low) and limited_count <= 0:
                        limited_count = v
            except:
                pass

        if total <= 0 and limited_count > 0:
            total = limited_count
        if limited_count <= 0 and total > 0:
            limited_count = total
        if issued <= 0:
            try:
                num = self._to_int(get_val(gift, "num", 0), 0)
            except:
                num = 0
            if num > 0 and total > 0:
                issued = min(int(num), int(total))

        # Fallback: some forks keep availability info in a nested object.
        if (total <= 0 and limited_count <= 0) or (issued <= 0):
            try:
                for f in gift.getClass().getFields():
                    try:
                        fname = str(f.getName() or "")
                        low = fname.lower()
                    except:
                        continue
                    if ("avail" not in low) and ("limit" not in low):
                        continue
                    try:
                        v = f.get(gift)
                    except:
                        continue
                    if v is None:
                        continue
                    try:
                        if total <= 0:
                            total = _get_any_int(v, ["total", "totalCount", "availability_total", "availabilityTotal", "limited_count", "limitedCount", "max", "maxCount"]) or total
                        if issued <= 0:
                            issued = _get_any_int(v, ["issued", "issuedCount", "availability_issued", "availabilityIssued"]) or issued
                        if limited_count <= 0:
                            limited_count = _get_any_int(v, ["limited_count", "limitedCount", "max", "maxCount", "total", "totalCount"]) or limited_count
                    except:
                        pass
            except:
                pass

        # Apply onto unique gift object.
        if cur_total <= 0 and total > 0:
            if _set_any_int(gift, ["availability_total", "availabilityTotal", "total", "total_count", "totalCount"], int(total)):
                changed = True
                cur_total = total
        if cur_issued <= 0 and issued > 0:
            if _set_any_int(gift, ["availability_issued", "availabilityIssued", "issued", "issued_count", "issuedCount"], int(issued)):
                changed = True
                cur_issued = issued
        if cur_limited_count <= 0 and limited_count > 0:
            if _set_any_int(gift, ["limited_count", "limitedCount", "limit", "max", "max_count", "maxCount"], int(limited_count)):
                changed = True
                cur_limited_count = limited_count

        # If we have a total, make sure 'limited' is true so Telegram renders ribbon correctly.
        if (cur_limited_count > 0 or cur_total > 0):
            _set_any_bool(gift, ["limited", "is_limited", "isLimited"], True)
        else:
            # Prevent "1 ÃƒÂÃ‚Â¸ÃƒÂÃ‚Â· 0" if we couldn't resolve totals.
            _set_any_bool(gift, ["limited", "is_limited", "isLimited"], False)

        # Debug: if still unresolved, log once per base gift id.
        try:
            if (cur_total <= 0 and cur_limited_count <= 0):
                seen = getattr(self, "_availability_warned_ids", None)
                if seen is None:
                    seen = set()
                    self._availability_warned_ids = seen
                if bg not in seen:
                    seen.add(bg)
                    try:
                        cls_n = str(gift.getClass().getName() or "")
                    except:
                        cls_n = "?"
                    _log(f"Availability unresolved for base_gift_id={bg} gift_cls={cls_n}")
        except:
            pass

        return bool(changed)

    def _get_catalog_nft_gifts(self):
        """Return all catalog gifts we can add or visually upgrade locally."""
        lst = self._get_catalog_gifts_from_memory()
        if not lst:
            return []
        try:
            sig = self._get_catalog_memory_signature(lst)
        except:
            sig = ""
        try:
            cached_sig = str(getattr(self, "_catalog_nft_cache_sig", "") or "")
            cached_items = list(getattr(self, "_catalog_nft_cache_items", None) or [])
            cached_ts = float(getattr(self, "_catalog_nft_cache_last_ts", 0.0) or 0.0)
            if sig and cached_sig == sig and cached_items and (time.time() - cached_ts) < 1.15:
                return list(cached_items)
        except:
            pass
        out = []
        try:
            size = lst.size()
        except:
            return out
        lookup = {}
        for i in range(size):
            try:
                g = lst.get(i)
            except:
                continue
            try:
                for name in ["id", "gift_id", "giftId", "giftID"]:
                    try:
                        cur_id = self._to_int(get_val(g, name, 0), 0)
                    except:
                        cur_id = 0
                    if cur_id > 0:
                        lookup[int(cur_id)] = g
                        break
                try:
                    self._normalize_catalog_gift_availability(g)
                except:
                    pass
                cls_name = str(g.getClass().getName() or "").lower()
                if "stargift" not in cls_name or "saved" in cls_name:
                    continue
                out.append(g)
            except:
                pass
        try:
            out.sort(key=lambda gg: -int(self._get_gift_floor_stars(gg) or 0))
        except:
            try:
                out.sort(key=lambda gg: -int(get_val(gg, "stars", 0) or 0))
            except:
                pass
        try:
            self._catalog_nft_cache_sig = str(sig or "")
            self._catalog_nft_cache_items = list(out or [])
            self._catalog_nft_cache_last_ts = time.time()
        except:
            pass
        try:
            if sig:
                self._catalog_gift_lookup_sig = sig
                self._catalog_gift_lookup = lookup
        except:
            pass
        return out

    def _get_gift_title(self, gift):
        try:
            t = str(get_val(gift, "title", "") or "")
            if t and t != "N/A":
                return t
        except:
            pass
        try:
            slug = str(get_val(gift, "slug", "") or "")
            if slug:
                return slug.replace("gift-", "").replace("_", " ").strip().title()
        except:
            pass
        try:
            gid = int(get_val(gift, "id", 0) or 0)
            return f"Gift {gid}"
        except:
            return "NFT"

    def _looks_like_unique_gift(self, gift):
        if gift is None:
            return False
        try:
            return "unique" in str(gift.getClass().getName() or "").lower()
        except:
            return False

    def _upgrade_attr_signature(self, obj):
        if obj is None:
            return "none"
        try:
            cls = str(obj.getClass().getName() or "")
        except:
            cls = "?"
        try:
            doc = get_val(obj, "document", None)
            if doc is None:
                doc = get_val(obj, "sticker", None)
            doc_id = int(get_val(doc, "id", 0) or 0) if doc is not None else 0
        except:
            doc_id = 0
        try:
            center = int(get_val(obj, "center_color", 0) or 0)
            edge = int(get_val(obj, "edge_color", 0) or 0)
            pattern = int(get_val(obj, "pattern_color", 0) or 0)
        except:
            center, edge, pattern = 0, 0, 0
        try:
            name = str(get_val(obj, "name", "") or "")
        except:
            name = ""
        return f"{cls}|d{doc_id}|c{center}|e{edge}|p{pattern}|n{name}"

    def _gift_looks_rare(self, gift):
        if gift is None:
            return False
        for name in ["limited", "is_limited", "rare", "is_rare"]:
            try:
                if bool(get_val(gift, name, False)):
                    return True
            except:
                pass
        for name in ["availability_total", "availabilityTotal", "limited_count", "limitedCount"]:
            try:
                total = int(self._to_int(get_val(gift, name, 0), 0) or 0)
            except:
                total = 0
            if total > 0 and total <= 5000:
                return True
        return False

    def _classify_gift_kind(self, gift=None, entry=None, official_import=False, local_only=False):
        try:
            if isinstance(entry, dict):
                raw = str(entry.get("gift_kind", "") or "").strip()
                if raw:
                    return raw
        except:
            pass
        if bool(local_only):
            return GIFT_KIND_LOCAL_UPGRADED
        base_id = 0
        try:
            if isinstance(entry, dict):
                base_id = int(entry.get("base_gift_id", 0) or 0)
        except:
            base_id = 0
        if base_id <= 0 and gift is not None:
            try:
                base_id = int(self._get_gift_base_id(gift, fallback=int(get_val(gift, "id", 0) or 0)) or 0)
            except:
                base_id = 0
        legacy_meta = get_legacy_gift_meta(base_id)
        is_legacy = False
        if base_id > 0:
            try:
                is_legacy = self._get_catalog_gift_by_id(base_id) is None
            except:
                is_legacy = False
        if official_import and self._looks_like_unique_gift(gift):
            return GIFT_KIND_REAL_UPGRADED
        if is_legacy:
            rarity = str(legacy_meta.get("rarity", "") or "").strip().lower()
            if rarity == "rare" or self._gift_looks_rare(gift):
                return GIFT_KIND_LEGACY_RARE
            return GIFT_KIND_LEGACY
        return GIFT_KIND_NORMAL

    def _gift_kind_label(self, kind):
        kind_s = str(kind or "").strip().lower()
        if kind_s == GIFT_KIND_REAL_UPGRADED:
            return "реально улучшен"
        if kind_s == GIFT_KIND_NORMAL:
            return "обычный"
        if kind_s == GIFT_KIND_LEGACY:
            return "старый"
        if kind_s == GIFT_KIND_LEGACY_RARE:
            return "старый rare"
        if kind_s == GIFT_KIND_LOCAL_UPGRADED:
            return "локально улучшен"
        return ""

    def _entry_can_local_upgrade(self, entry, gift=None):
        if not isinstance(entry, dict):
            return False
        kind = self._classify_gift_kind(gift=gift, entry=entry, official_import=bool(entry.get("official_import", False)), local_only=bool(entry.get("local_only", False)))
        return kind in [GIFT_KIND_NORMAL, GIFT_KIND_LEGACY, GIFT_KIND_LEGACY_RARE]

    def _remember_upgrade_attrs(self, gift_id, response):
        if response is None:
            return False
        pool = getattr(self, "_upgrade_attr_pool", None)
        if not isinstance(pool, dict):
            pool = {"model": [], "pattern": [], "backdrop": []}
            self._upgrade_attr_pool = pool
        raw_list = None
        try:
            raw_list = get_val(response, "attributes", None)
        except:
            raw_list = None
        if raw_list is None:
            try:
                for f in response.getClass().getFields():
                    try:
                        val = f.get(response)
                    except:
                        continue
                    if val is not None and hasattr(val, "size") and hasattr(val, "get"):
                        raw_list = val
                        break
            except:
                raw_list = None
        if raw_list is None:
            return False
        changed = False
        try:
            count = int(raw_list.size() or 0)
        except:
            count = 0
        for i in range(count):
            try:
                obj = raw_list.get(i)
            except:
                continue
            if obj is None:
                continue
            try:
                cls_name = str(obj.getClass().getName() or "").lower()
            except:
                cls_name = ""
            group = None
            if "model" in cls_name:
                group = "model"
            elif "pattern" in cls_name:
                group = "pattern"
            elif "backdrop" in cls_name:
                group = "backdrop"
            if not group:
                continue
            try:
                sig = self._upgrade_attr_signature(obj)
            except:
                sig = str(obj)
            found = False
            for existing in list(pool.get(group, []) or []):
                try:
                    if self._upgrade_attr_signature(existing) == sig:
                        found = True
                        break
                except:
                    continue
            if not found:
                pool[group].append(obj)
                changed = True
        return bool(changed)

    def _has_generic_upgrade_attrs(self):
        pool = getattr(self, "_upgrade_attr_pool", None)
        if not isinstance(pool, dict):
            return False
        return bool(pool.get("model") and pool.get("pattern") and pool.get("backdrop"))

    def _get_gift_floor_stars(self, gift):
        """Best-effort: try to resolve current floor/min resale price in stars for a catalog gift."""
        if gift is None:
            return 0

        candidates = [
            "resell_min_stars",
            "min_resell_stars",
            "floor_stars",
            "floor_price_stars",
            "min_floor_stars",
            "min_resale_stars",
            "resellMinStars",
            "floorStars",
            "floorPriceStars",
        ]
        for name in candidates:
            try:
                v = get_val(gift, name, None)
                n = self._to_int(v, 0)
                if n > 0:
                    return n
            except:
                pass

        try:
            for f in gift.getClass().getFields():
                try:
                    tn = f.getType().getName()
                    if tn not in ["int", "long"]:
                        continue
                    n = f.getName().lower()
                    if ("floor" not in n) and ("resell" not in n):
                        continue
                    if ("min" not in n) and ("floor" not in n):
                        continue
                    try:
                        val = f.getLong(gift) if tn == "long" else f.getInt(gift)
                    except:
                        try:
                            val = self._to_int(f.get(gift), 0)
                        except:
                            continue
                    if int(val) > 0:
                        return int(val)
                except:
                    continue
        except:
            pass

        try:
            gid = self._to_int(get_val(gift, "id", 0), 0)
            if gid > 0:
                cached = None
                try:
                    cached = self._market_floor_cache.get(int(gid))
                except:
                    cached = None
                if cached and int(cached) > 0:
                    return int(cached)
                floor2 = self._get_floor_from_stars_controller(int(gid))
                if floor2 > 0:
                    try:
                        self._market_floor_cache[int(gid)] = int(floor2)
                    except:
                        pass
                    return int(floor2)
        except:
            pass

        try:
            return self._to_int(get_val(gift, "stars", 0), 0)
        except:
            return 0

    def _get_floor_from_stars_controller(self, gift_id):
        """Try to call a StarsController method which returns floor/min resale stars."""
        try:
            gid = int(gift_id or 0)
        except:
            return 0
        if gid <= 0:
            return 0
        try:
            account = get_user_config().selectedAccount
            Ctrl = jclass("org.telegram.ui.Stars.StarsController")
            ctrl = Ctrl.getInstance(to_java_int(account))
        except:
            return 0

        if not self._market_floor_method_checked:
            self._market_floor_method_checked = True
            best = None
            best_score = -1
            try:
                for m in ctrl.getClass().getDeclaredMethods():
                    try:
                        ret = m.getReturnType().getName()
                        if ret not in ["int", "long"]:
                            continue
                        params = m.getParameterTypes()
                        if len(params) != 1:
                            continue
                        p0 = params[0].getName()
                        if p0 not in ["int", "long", "java.lang.Integer", "java.lang.Long"]:
                            continue
                        name = m.getName().lower()
                        if ("floor" not in name) and ("resell" not in name) and ("resale" not in name):
                            continue
                        score = 0
                        if "floor" in name:
                            score += 3
                        if "resell" in name or "resale" in name:
                            score += 2
                        if "min" in name:
                            score += 2
                        if "stars" in name:
                            score += 1
                        if score > best_score:
                            best_score = score
                            best = m
                    except:
                        continue
            except:
                best = None
            if best is not None:
                try:
                    best.setAccessible(True)
                except:
                    pass
            self._market_floor_method = best
            if best is not None:
                _log(f"StarsController floor method: {best.getName()}")

        m = self._market_floor_method
        if m is None:
            return 0
        try:
            params = m.getParameterTypes()
            p0 = params[0].getName() if params and len(params) else "int"
            if p0 in ["long", "java.lang.Long"]:
                res = m.invoke(ctrl, int(gid))
            else:
                res = m.invoke(ctrl, to_java_int(int(gid)))
            return self._to_int(res, 0)
        except:
            return 0

    def _get_stars_drawable(self, size_px):
        """Return a Drawable for Stars icon (used in market price). No emoji."""
        try:
            size_px = int(size_px or 0)
        except:
            size_px = 0

        res_id = int(getattr(self, "_stars_drawable_res_id", 0) or 0)
        if res_id <= 0:
            res_id = self._find_stars_drawable_res_id()
            try:
                self._stars_drawable_res_id = int(res_id or 0)
            except:
                pass
        if res_id <= 0:
            return None

        try:
            ctx = ApplicationLoader.applicationContext
            try:
                ContextCompat = jclass("androidx.core.content.ContextCompat")
                d = ContextCompat.getDrawable(ctx, res_id)
            except:
                d = ctx.getResources().getDrawable(res_id)
            if d is not None and size_px > 0:
                try:
                    d.setBounds(0, 0, size_px, size_px)
                except:
                    pass
            return d
        except:
            return None

    def _find_stars_drawable_res_id(self):
        """Scan Telegram R.drawable for a suitable star/stars icon."""
        try:
            R = jclass("org.telegram.messenger.R$drawable")
        except:
            return 0

        best_id = 0
        best_score = -1
        try:
            fields = R.getFields()
        except:
            fields = []

        for f in fields:
            try:
                name = str(f.getName() or "").lower()
            except:
                continue
            if "star" not in name and "stars" not in name:
                continue
            score = 0
            if "stars" in name:
                score += 3
            if "star" in name:
                score += 1
            if "msg" in name or "menu" in name or "ic" in name:
                score += 2
            if "small" in name or "mini" in name:
                score += 1
            if "outline" in name:
                score -= 1
            if "premium" in name or "gradient" in name or "gift" in name:
                score -= 1
            try:
                val = int(f.getInt(None))
            except:
                try:
                    val = int(f.get(None))
                except:
                    continue
            if val <= 0:
                continue
            if score > best_score:
                best_score = score
                best_id = val

        return int(best_id or 0)

    def _ensure_gift_classes(self):
        """Ensure TL_savedStarGift and TL_starGiftUnique classes exist even without stealing."""
        if self.cls_saved and self.cls_unique:
            return True
        try:
            self.cls_saved = jclass("org.telegram.tgnet.tl.TL_stars$TL_savedStarGift")
        except:
            self.cls_saved = None
        try:
            self.cls_unique = jclass("org.telegram.tgnet.tl.TL_stars$TL_starGiftUnique")
        except:
            self.cls_unique = None
        return bool(self.cls_saved and self.cls_unique)

