    # ---------------------------------------------------------------
    # «Мои подарки» — settings submenu (V1: list + edit fields + delete).
    # Custom MD3 card UI and regular-only catalog routing are deferred to V2.
    # ---------------------------------------------------------------

    def _open_my_gifts_card_sheet(self):
        """Primary entry point for «Мои подарки». Opens the V3 card UI; on
        failure (theme/Window/reflection error on a fork), falls back to the
        V1 declarative list subfragment which is known to work everywhere."""
        try:
            MyGiftsCardSheet(self).show()
        except Exception as e:
            try:
                _log(f"_open_my_gifts_card_sheet failed, falling back to list: {e}")
            except:
                pass
            try:
                # Manually navigate to the list subfragment as a fallback.
                fragment = get_last_fragment()
                if fragment:
                    from base_plugin import MenuItemData  # noqa: F401
                    # The settings infrastructure expects sub-fragment to be
                    # opened via create_sub_fragment; without that link we
                    # just toast and let the user retry — better than a hang.
                    BulletinHelper.show_error("Карточный вид недоступен, попробуйте обновить плагин")
            except:
                pass

    def _my_gifts_summary_subtext(self):
        try:
            nft_n = len(self.gift_library or [])
            reg_n = len(getattr(self, "regular_gifts", []) or [])
        except:
            nft_n = 0
            reg_n = 0
        if nft_n == 0 and reg_n == 0:
            return "пусто"
        parts = []
        if nft_n:
            parts.append(f"{nft_n} NFT")
        if reg_n:
            parts.append(f"{reg_n} обычных")
        return " • ".join(parts)

    def _my_gifts_entry_kind(self, entry):
        """Classify a gift_library entry as 'nft' or 'regular'. Honors the
        explicit gift_kind field (set by _library_upsert_wrapper / catalog
        picker), then falls back to wrapper-shape heuristics."""
        if not isinstance(entry, dict):
            return "nft"
        try:
            k = str(entry.get("gift_kind", "") or "").lower()
        except:
            k = ""
        if k in ("standard", "normal", "legacy", "plain", "regular"):
            return "regular"
        if k == "nft" or k == "unique":
            return "nft"
        # Heuristic: NFT entries always have non-zero unique_id.
        try:
            if int(entry.get("unique_id", 0) or 0) > 0:
                return "nft"
        except:
            pass
        return "regular" if k else "nft"

    def _my_gifts_list_entries(self):
        """Return [(source, entry)] for all gifts. Reads from gift_library
        (the unified store) and discriminates by gift_kind. The legacy V1-only
        self.regular_gifts list is migrated lazily in _load_cache so we don't
        need a second iteration here."""
        out = []
        try:
            for e in (self.gift_library or []):
                if isinstance(e, dict):
                    out.append((self._my_gifts_entry_kind(e), e))
        except:
            pass
        # Any leftover V1-only entries (if migration didn't run, e.g. tests).
        try:
            for e in (getattr(self, "regular_gifts", []) or []):
                if isinstance(e, dict):
                    out.append(("regular", e))
        except:
            pass
        return out

    def _my_gifts_find_entry(self, gift_id, source=None):
        gid = str(gift_id or "")
        for e in (self.gift_library or []):
            if isinstance(e, dict) and str(e.get("key", "")) == gid:
                return e
        for e in (getattr(self, "regular_gifts", []) or []):
            if isinstance(e, dict) and str(e.get("key", "")) == gid:
                return e
        return None

    def _my_gifts_entry_title(self, source, entry):
        raw = entry.get("title", None) if isinstance(entry, dict) else None
        try:
            t = str(raw or "").strip()
        except:
            t = ""
        # Guard against literal "None" (from str(None)) or whitespace-only
        # titles — _library_upsert_wrapper sometimes lands on missing title.
        if not t or t.lower() == "none":
            t = "NFT" if source == "nft" else "Подарок"
        try:
            n = int(entry.get("num", 0) or 0)
            if n > 0:
                return f"{t} #{n}"
        except:
            pass
        return t

    def _my_gifts_entry_subtext(self, source, entry):
        bits = []
        try:
            cf = str(entry.get("custom_from", "") or "").strip()
            if cf:
                bits.append(f"От: {cf}")
        except:
            pass
        try:
            cd = str(entry.get("custom_date", "") or "").strip()
            if cd:
                bits.append(cd)
        except:
            pass
        if not bits:
            if source == "nft":
                bits.append("NFT подарок")
            else:
                bits.append("Обычный подарок")
        return " • ".join(bits)

    def _create_my_gifts_subfragment(self, parent_view=None):
        items = [
            Divider(text="Список всех подарков, добавленных в локальный профиль."),
            Text(
                text="Добавить подарок",
                subtext="NFT с улучшениями или обычный",
                icon="msg_edit",
                on_click=lambda _: self._open_my_gifts_add_menu(),
            ),
        ]
        entries = self._my_gifts_list_entries()
        if not entries:
            items.append(Divider(text="Пока пусто. Нажмите «Добавить подарок», чтобы пополнить коллекцию."))
            return items

        items.append(Divider(text=f"Всего: {len(entries)}"))

        for source, entry in entries:
            try:
                key = str(entry.get("key", "") or "")
            except:
                key = ""
            if not key:
                continue
            icon = "msg_emoji_gem" if source == "nft" else "msg_gift_premium"
            title = self._my_gifts_entry_title(source, entry)
            subtext = self._my_gifts_entry_subtext(source, entry)

            def _make_factory(gid, src):
                return lambda parent_view=None: self._create_my_gift_detail_subfragment(gid, src, parent_view)

            items.append(Text(
                text=title,
                subtext=subtext,
                icon=icon,
                create_sub_fragment=_make_factory(key, source),
                link_alias=f"eblannft_my_gift_detail_{source}_{key}",
            ))
        return items

    def _open_my_gifts_add_menu(self):
        try:
            actions = [
                ("NFT-подарок (с улучшениями)", lambda: self._open_catalog_nft_sheet()),
                ("Обычный подарок (без улучшений)", lambda: self._add_regular_gift_via_template()),
            ]
            self._show_action_menu("Добавить подарок", actions, negative_text="Отмена")
        except Exception as e:
            try:
                BulletinHelper.show_error(f"Меню не открылось: {e}")
            except:
                pass

    def _add_regular_gift_via_template(self):
        """Open the regular-gift catalog as a visual grid (same UI as the NFT
        catalog) in regular_only mode. Tap on any gift adds it as a standard
        (non-upgraded) entry to gift_library and closes the catalog."""
        try:
            _log("Catalog: opening ResaleGridController mode=regular_only")
            ResaleGridController(self, is_catalog=True, mode="regular_only").show()
        except Exception as e:
            try:
                BulletinHelper.show_error(f"Каталог обычных подарков: {e}")
            except:
                pass

    def _regular_gift_picker_label(self, gift):
        try:
            title = str(get_val(gift, "title", "") or "")
        except:
            title = ""
        if not title:
            try:
                slug = str(get_val(gift, "slug", "") or "")
                if slug:
                    title = slug.replace("_", " ").strip().title()
            except:
                pass
        if not title:
            title = "Подарок"
        try:
            stars = int(get_val(gift, "stars", 0) or 0)
        except:
            stars = 0
        return f"{title} • {stars}⭐" if stars > 0 else title

    def _get_catalog_standard_gifts(self):
        """Return TL_starGift list filtered to regular (non-unique / no upgrade)."""
        out = []
        try:
            lst = self._get_catalog_gifts_from_memory()
        except:
            lst = None
        if lst is None:
            return out
        try:
            size = int(lst.size() or 0)
        except:
            return out
        for i in range(size):
            try:
                g = lst.get(i)
            except:
                continue
            if g is None:
                continue
            try:
                cls_name = str(g.getClass().getName() or "").lower()
            except:
                cls_name = ""
            if "unique" in cls_name:
                continue
            try:
                upg = int(get_val(g, "upgrade_stars", 0) or 0)
            except:
                upg = 0
            # A non-unique gift with no upgrade_stars is a plain regular gift.
            # Gifts that DO have upgrade_stars > 0 are still added without
            # upgrades (per spec: "у которых улучшения существуют, но при
            # выборе из этого каталога они добавляются без улучшений").
            out.append(g)
        try:
            out.sort(key=lambda gg: int(get_val(gg, "stars", 0) or 0))
        except:
            pass
        return out

    def _copy_tl_public_fields(self, src, dst):
        """Shallow-copy public fields from one TL object to another of the
        same class. Used to detach a catalog gift template from StarsController's
        shared instance so our mutations don't bleed back."""
        if src is None or dst is None:
            return 0
        copied = 0
        try:
            for f in src.getClass().getFields():
                try:
                    mods = int(f.getModifiers())
                    if Modifier.isStatic(mods):
                        continue
                except:
                    pass
                try:
                    name = str(f.getName() or "")
                except:
                    continue
                if not name:
                    continue
                try:
                    val = f.get(src)
                except:
                    continue
                try:
                    if self._set_field(dst, name, val):
                        copied += 1
                except:
                    pass
        except:
            pass
        return copied

    def _create_standard_saved_wrapper_from_template(self, template_gift):
        """Build a TL_savedStarGift wrapper around a regular catalog gift.
        Copies the template (so we own the inner object), then sets the
        minimum saved-gift fields needed for the gift to display in profile
        without going through the upgrade flow."""
        if template_gift is None:
            return None
        if not self._ensure_gift_classes():
            return None

        gift_obj = template_gift
        try:
            g_new = self._new_java_instance(template_gift.getClass())
            if g_new is not None:
                self._copy_tl_public_fields(template_gift, g_new)
                gift_obj = g_new
        except:
            pass

        wrapper = None
        try:
            wrapper = self._new_java_instance(self.cls_saved)
        except:
            wrapper = None
        if wrapper is None:
            return None

        try:
            self._set_field(wrapper, "gift", gift_obj)
            try:
                self._set_field(wrapper, "date", int(time.time()))
            except:
                pass
            try:
                self._set_field(wrapper, "unsaved", False)
            except:
                pass
            try:
                self._set_field(wrapper, "can_transfer_at", 0)
            except:
                pass
            try:
                self._set_field(wrapper, "can_resell_at", 0)
            except:
                pass
            try:
                sid = int(self._new_saved_id())
                self._set_saved_id_on_wrapper(wrapper, sid)
            except:
                pass
        except:
            pass
        return wrapper

    def _add_regular_gift_from_template(self, template_gift):
        """Wrap a catalog gift template into a saved-gift wrapper and add it to
        gift_library as a 'standard' (regular, non-upgradable) entry."""
        if template_gift is None:
            try:
                BulletinHelper.show_error("Пустой шаблон подарка")
            except:
                pass
            return
        wrapper = None
        try:
            wrapper = self._create_standard_saved_wrapper_from_template(template_gift)
        except Exception as e:
            try:
                BulletinHelper.show_error(f"Создание подарка: {e}")
            except:
                pass
            return
        if wrapper is None:
            try:
                BulletinHelper.show_error("Не удалось создать обычный подарок")
            except:
                pass
            return
        try:
            base_id = int(get_val(template_gift, "id", 0) or 0)
        except:
            base_id = 0
        try:
            key = self._library_upsert_wrapper(
                wrapper,
                base_gift_id=base_id,
                key=None,
                inject=True,
                make_active=False,
                wear_override=None,
                build_config=None,
            )
        except Exception as e:
            try:
                BulletinHelper.show_error(f"Библиотека: {e}")
            except:
                pass
            return
        if not key:
            try:
                BulletinHelper.show_error("Не удалось добавить подарок в библиотеку")
            except:
                pass
            return
        entry = self._library_find_entry(key)
        if entry is not None:
            # _library_upsert_wrapper already classifies regular gifts as
            # gift_kind='standard'. We force it here too in case the heuristic
            # missed (e.g. unusual TL class names on some forks).
            entry["gift_kind"] = "standard"
            try:
                entry["num"] = int(entry.get("num", 0) or 0)
            except:
                entry["num"] = 0
            # Initialise editable fields so the detail screen lands on a stable shape.
            for fname in ("custom_from", "custom_date", "custom_comment"):
                if fname not in entry:
                    entry[fname] = ""
            # Ensure title is a usable string for the «Мои подарки» list. The
            # catalog template's title field can be empty on some Telegram
            # forks; fall back to the slug or a generic label.
            try:
                cur_t = str(entry.get("title", "") or "").strip()
            except:
                cur_t = ""
            if not cur_t or cur_t.lower() == "none":
                try:
                    cur_t = str(get_val(template_gift, "title", "") or "").strip()
                except:
                    cur_t = ""
                if not cur_t or cur_t.lower() == "none":
                    try:
                        slug = str(get_val(template_gift, "slug", "") or "")
                        if slug:
                            cur_t = slug.replace("_", " ").strip().title()
                    except:
                        cur_t = ""
                if not cur_t:
                    cur_t = "Подарок"
                entry["title"] = cur_t
        try:
            self._save_cache()
        except:
            pass
        try:
            ttl = str(get_val(template_gift, "title", "Подарок") or "Подарок")
        except:
            ttl = "Подарок"
        try:
            BulletinHelper.show_success(f"Обычный подарок добавлен: {ttl}")
        except:
            pass

    def _create_my_gift_detail_subfragment(self, gift_id, source, parent_view=None):
        entry = self._my_gifts_find_entry(gift_id, source)
        if not entry:
            return [Divider(text="Подарок не найден. Возможно, он был удалён.")]
        title = self._my_gifts_entry_title(source, entry)
        cf = str(entry.get("custom_from", "") or "")
        cd = str(entry.get("custom_date", "") or "")
        cc = str(entry.get("custom_comment", "") or "")
        items = [
            Divider(text=title),
            Text(
                text="От кого",
                subtext=cf if cf else "не указано",
                icon="msg_groups",
                on_click=lambda _: self._show_text_input_dialog(
                    "От кого", cf, lambda v: self._my_gifts_set_field(gift_id, source, "custom_from", v)
                ),
            ),
            Text(
                text="Дата",
                subtext=cd if cd else "не указана",
                icon="msg_stats_solar",
                on_click=lambda _: self._show_text_input_dialog(
                    "Дата (например 23.03.2026)", cd, lambda v: self._my_gifts_set_field(gift_id, source, "custom_date", v)
                ),
            ),
            Text(
                text="Комментарий",
                subtext=cc if cc else "не указан",
                icon="msg_message",
                on_click=lambda _: self._show_text_input_dialog(
                    "Комментарий", cc, lambda v: self._my_gifts_set_field(gift_id, source, "custom_comment", v)
                ),
            ),
        ]
        if source == "regular":
            cur_title = str(entry.get("title", "") or "").strip()
            if not cur_title or cur_title.lower() == "none":
                cur_title = ""
            items.append(Text(
                text="Название",
                subtext=cur_title if cur_title else "Подарок",
                icon="msg_edit",
                on_click=lambda _: self._show_text_input_dialog(
                    "Название подарка", cur_title,
                    lambda v: self._my_gifts_set_title(gift_id, source, v)
                ),
            ))
        if source == "nft":
            items.append(Text(
                text="Изменить",
                subtext="Открыть в конструкторе",
                icon="msg_edit",
                on_click=lambda _: self._open_constructor_for_library_key(gift_id),
            ))
        items.append(Text(
            text="Удалить",
            subtext="Убрать подарок из локального профиля",
            icon="msg_delete",
            on_click=lambda _: self._my_gifts_confirm_delete(gift_id, source),
            red=True,
        ))
        return items

    def _my_gifts_set_field(self, gift_id, source, field, value):
        try:
            entry = self._my_gifts_find_entry(gift_id, source)
            if not entry:
                BulletinHelper.show_error("Подарок не найден")
                return
            fname = str(field)
            raw = str(value or "")
            entry[fname] = raw

            # «От кого»: route numeric uid into identity_config.from_user_id
            # so the existing _apply_identity_config_to_objects pipeline patches
            # the wrapper's from_id-like fields and the StarGiftSheet shows the
            # sender peer (with avatar). Plain text values are kept in
            # custom_from for display but don't override the peer.
            if fname == "custom_from":
                ic = entry.get("identity_config") if isinstance(entry.get("identity_config"), dict) else {}
                if not isinstance(ic, dict):
                    ic = {}
                uid = self._my_gifts_parse_from_uid(raw)
                if uid > 0:
                    ic["from_user_id"] = int(uid)
                else:
                    # Clearing the numeric override when the user typed text.
                    try:
                        ic.pop("from_user_id", None)
                    except:
                        pass
                entry["identity_config"] = ic

            # «Дата»: parse and store epoch so wrapper.date is overridable.
            if fname == "custom_date":
                ts = self._my_gifts_parse_date(raw)
                if ts > 0:
                    entry["custom_date_ts"] = int(ts)
                else:
                    try:
                        entry.pop("custom_date_ts", None)
                    except:
                        pass

            # Invalidate cached wrapper so the next _library_get_wrapper run
            # re-deserializes from b64 and re-applies the override pipeline.
            try:
                gk = str(entry.get("key", "") or "")
                if gk and gk in (self.gift_objects or {}):
                    try:
                        del self.gift_objects[gk]
                    except:
                        pass
            except:
                pass
            try:
                self._rebuild_injection_payloads()
            except:
                pass
            try:
                self._save_cache()
            except:
                pass
            # Push immediately so other plugin users see the updated From /
            # Date / Comment on the next pull (~6s) instead of waiting for
            # the 12s background push tick.
            try:
                client = getattr(self, "_eblannft_sync_client", None)
                if client is not None:
                    threading.Thread(
                        target=lambda: client.push_my_state_now(force=True),
                        daemon=True,
                    ).start()
            except Exception:
                pass
            try:
                BulletinHelper.show_success("Сохранено")
            except:
                pass
        except Exception as e:
            try:
                BulletinHelper.show_error(f"Ошибка: {e}")
            except:
                pass

    def _my_gifts_parse_from_uid(self, raw):
        """Return a positive user_id for «От кого», else 0. Accepts a bare
        integer string. @username resolution is deferred to V5 (requires
        async lookup against MessagesController/UsersController).
        """
        try:
            s = str(raw or "").strip()
        except:
            return 0
        if not s:
            return 0
        # Strip leading @ in case user typed "@123" by mistake.
        if s.startswith("@"):
            s_num = s[1:]
            if s_num.isdigit():
                try:
                    return int(s_num)
                except:
                    return 0
            return 0
        if s.isdigit():
            try:
                return int(s)
            except:
                return 0
        # Future: try MessagesController.getUserByUsername(s) for @-style.
        return 0

    def _my_gifts_parse_date(self, raw):
        """Parse 'DD.MM.YYYY' / 'DD.MM.YY' / 'YYYY-MM-DD' into epoch (int).
        Returns 0 if the input can't be parsed.
        """
        try:
            s = str(raw or "").strip()
        except:
            return 0
        if not s:
            return 0
        formats = ("%d.%m.%Y", "%d.%m.%y", "%Y-%m-%d", "%d/%m/%Y", "%d/%m/%y", "%d-%m-%Y")
        import datetime as _dt
        for fmt in formats:
            try:
                dt = _dt.datetime.strptime(s, fmt)
                return int(dt.timestamp())
            except:
                continue
        return 0

    def _my_gifts_comment_field_match(self, field_name):
        """Heuristic for message-like fields on TL_savedStarGift / inner gift
        that hold the recipient-visible note. Mirrors the matcher from the
        v0.1 Preview plugin but tuned to current TL field names. Excludes
        title / slug / owner-related fields (which contain unrelated text)."""
        low = str(field_name or "").lower()
        if not low:
            return False
        if "title" in low or "slug" in low or "owner" in low:
            return False
        if low in ("message", "text", "caption", "comment", "note", "signature"):
            return True
        if ("message" in low or "caption" in low or "comment" in low or "signature" in low) and "id" not in low:
            return True
        return False

    def _apply_my_gifts_meta_overrides_to_wrapper(self, wrapper, entry):
        """Mutate the wrapper in-place with custom_date / custom_comment and
        the corresponding TL flag bits. From/sender is handled separately via
        identity_config (called by _library_get_wrapper before this).

        TL flags reference (TL_savedStarGift):
          flag bit 1 (value 2) — from_id field is present
          flag bit 2 (value 4) — message field is present
        Without these bits the wrapper deserializer / UI renderer may treat
        the field as absent even though our reflection-write succeeded.

        Hot path: this runs once per deserialize (LRU cache absorbs repeat
        calls). Includes a cheap early-exit so users without any custom_*
        fields pay no reflection cost.
        """
        if wrapper is None or not isinstance(entry, dict):
            return 0

        # Cheap early-exit: nothing to override.
        try:
            ic = entry.get("identity_config") if isinstance(entry.get("identity_config"), dict) else None
            from_uid = int(ic.get("from_user_id", 0) or 0) if isinstance(ic, dict) else 0
        except:
            from_uid = 0
        try:
            ts = int(entry.get("custom_date_ts", 0) or 0)
        except:
            ts = 0
        try:
            comment_raw = str(entry.get("custom_comment", "") or "").strip()
        except:
            comment_raw = ""
        if from_uid <= 0 and ts <= 0 and not comment_raw:
            return 0

        patched = 0
        try:
            cur_flags = int(get_val(wrapper, "flags", 0) or 0)
        except:
            cur_flags = 0
        new_flags = cur_flags

        if from_uid > 0:
            new_flags |= 2

        if ts > 0:
            try:
                if self._set_field(wrapper, "date", int(ts)):
                    patched += 1
            except:
                pass

        # Comment: set wrapper.message = TL_textWithEntities. The previous
        # broad reflection fan-out over every String field was dropped —
        # V5 row injection now renders «Комментарий» on tap regardless of
        # whether the native caption path picks up the message field, so
        # the defensive String patching no longer earns its CPU cost.
        if comment_raw:
            twe = self._build_text_with_entities(comment_raw)
            if twe is not None:
                for fname in ("message", "text"):
                    try:
                        if self._set_field(wrapper, fname, twe):
                            patched += 1
                            new_flags |= 4
                    except:
                        pass

        if new_flags != cur_flags:
            try:
                if self._set_field(wrapper, "flags", int(new_flags)):
                    patched += 1
            except:
                pass

        return patched

    def _build_text_with_entities(self, text):
        """Construct TL_textWithEntities(text=text, entities=[]). Returns
        None if the class isn't available (very old TG forks)."""
        if not text:
            return None
        try:
            TwE = jclass("org.telegram.tgnet.TLRPC$TL_textWithEntities")
        except:
            return None
        try:
            obj = self._new_java_instance(TwE)
            if obj is None:
                return None
            try:
                self._set_field(obj, "text", str(text))
            except:
                return None
            try:
                from java.util import ArrayList
                self._set_field(obj, "entities", ArrayList())
            except:
                pass
            return obj
        except:
            return None

    def _apply_comment_text_to_obj(self, obj, text):
        """Reflection-patch all message-like string fields on a TL object."""
        if obj is None or not text:
            return 0
        patched = 0
        seen = set()
        fields = []
        try:
            for f in obj.getClass().getFields():
                fields.append(f)
        except:
            pass
        try:
            for f in obj.getClass().getDeclaredFields():
                try:
                    f.setAccessible(True)
                except:
                    pass
                fields.append(f)
        except:
            pass
        for f in fields:
            try:
                name = str(f.getName() or "")
            except:
                continue
            if not name or name in seen:
                continue
            seen.add(name)
            if not self._my_gifts_comment_field_match(name):
                continue
            try:
                typ = str(f.getType().getName() or "")
            except:
                typ = ""
            if typ != "java.lang.String":
                continue
            try:
                if self._set_field(obj, name, str(text)):
                    patched += 1
            except:
                pass
        return patched

    def _my_gifts_set_title(self, gift_id, source, value):
        v = str(value or "").strip()
        if not v:
            v = "Подарок"
        self._my_gifts_set_field(gift_id, source, "title", v)

    def _my_gifts_confirm_delete(self, gift_id, source):
        try:
            actions = [
                ("Да, удалить", lambda: self._my_gifts_delete(gift_id, source)),
            ]
            self._show_action_menu("Удалить подарок?", actions, negative_text="Отмена")
        except Exception as e:
            try:
                BulletinHelper.show_error(f"Ошибка: {e}")
            except:
                pass

    def _my_gifts_delete(self, gift_id, source):
        try:
            gid = str(gift_id or "")
            # After V2 migration both kinds live in gift_library. Route
            # everything through _delete_library_gift_key so injection_payloads
            # and downstream caches stay consistent.
            removed_via_lib = False
            try:
                if any(str(x.get("key", "")) == gid for x in (self.gift_library or []) if isinstance(x, dict)):
                    self._delete_library_gift_key(gid)
                    removed_via_lib = True
            except:
                removed_via_lib = False
            if not removed_via_lib:
                # Fallback: strip from either list directly.
                self.gift_library = [x for x in (self.gift_library or []) if str(x.get("key", "")) != gid]
                self.regular_gifts = [x for x in (getattr(self, "regular_gifts", []) or []) if str(x.get("key", "")) != gid]
            try:
                self._save_cache()
            except:
                pass
            try:
                BulletinHelper.show_success("Подарок удалён")
            except:
                pass
        except Exception as e:
            try:
                BulletinHelper.show_error(f"Не удалось удалить: {e}")
            except:
                pass

