    def _profile_option_defs(self):
        return [
            ("nft_gifts", "Все NFT подарки", "Библиотека, активный локальный подарок и wear"),
            ("nft_usernames", "NFT юзернеймы", "Список username, выбранный username и шаблон"),
            ("nft_number", "NFT номер", "Список номеров, выбранный номер и шаблон"),
            ("local_rating", "Локальный рейтинг", "Очки, уровень и следующая цель"),
        ]

    def _profile_option_title(self, option_key):
        for key, title, _desc in self._profile_option_defs():
            if key == option_key:
                return title
        return str(option_key or "")

    def _get_profile_configs_dir(self):
        try:
            Environment = jclass("android.os.Environment")
            downloads = Environment.getExternalStoragePublicDirectory(
                Environment.DIRECTORY_DOWNLOADS
            ).getAbsolutePath()
            target = os.path.join(downloads, "eblanNFT")
            ensure_dir_exists(target)
            return target
        except Exception as e:
            _log(f"Profile dir error: {e}")
            try:
                target = os.path.join(_cache_dir(), "profiles")
                ensure_dir_exists(target)
                return target
            except:
                return None

    def _sanitize_profile_name(self, raw_name):
        try:
            name = str(raw_name or "").strip()
        except:
            name = ""
        if name.lower().endswith(PROFILE_CONFIG_FILE_EXTENSION):
            name = name[:-len(PROFILE_CONFIG_FILE_EXTENSION)]
        name = re.sub(r'[\\/:*?"<>|]+', "_", name)
        name = re.sub(r"\s+", " ", name).strip(" .")
        if not name:
            name = f"profile_{int(time.time())}"
        return name[:64]

    def _collect_profile_export_payload(self, profile_name, selected_keys):
        keys = [str(k) for k in list(selected_keys or []) if str(k or "").strip()]
        sections = {}
        if "nft_gifts" in keys:
            sections["nft_gifts"] = {
                "gift_library": list(getattr(self, "gift_library", None) or []),
                "inject_active": bool(getattr(self, "inject_active", False)),
                "wear_active": bool(getattr(self, "wear_active", False)),
                "wear_collectible_id": int(getattr(self, "wear_collectible_id", 0) or 0),
                "wear_status_data": dict(getattr(self, "wear_status_data", None) or {}),
                "cached_gift_id": int(getattr(self, "cached_gift_id", 0) or 0),
                "build_config": dict(getattr(self, "build_config", None) or {}),
                "identity_config": self._sanitize_identity_config(getattr(self, "identity_config", None)),
                "value_config": self._sanitize_value_config(getattr(self, "value_config", None)),
                "gift_stars_config": self._sanitize_gift_stars_config(getattr(self, "gift_stars_config", None)),
            }
        if "nft_usernames" in keys:
            sections["nft_usernames"] = {
                "enabled": bool(getattr(self, "nft_username_enabled", False)),
                "tokens": self._get_nft_username_tokens(),
                "selected": str(getattr(self, "nft_username", "") or ""),
                "price_ton": str(getattr(self, "nft_username_price_ton", "10.8") or "10.8"),
                "price_usd": str(getattr(self, "nft_username_price_usd", "14.68") or "14.68"),
                "purchase_date": str(getattr(self, "nft_username_purchase_date", "") or ""),
                "template_b64": str(getattr(self, "nft_collectible_template_b64", "") or ""),
            }
        if "nft_number" in keys:
            sections["nft_number"] = {
                "enabled": bool(getattr(self, "nft_number_enabled", False)),
                "tokens": self._get_nft_number_tokens(),
                "selected": str(getattr(self, "nft_number", "") or ""),
                "price_ton": str(getattr(self, "nft_number_price_ton", "10.8") or "10.8"),
                "price_usd": str(getattr(self, "nft_number_price_usd", "14.68") or "14.68"),
                "purchase_date": str(getattr(self, "nft_number_purchase_date", "") or ""),
                "template_b64": str(getattr(self, "nft_number_collectible_template_b64", "") or ""),
            }
        if "local_rating" in keys:
            sections["local_rating"] = {
                "enabled": bool(getattr(self, "local_rating_enabled", False)),
                "value": int(self._get_local_rating_value() or 0),
                "level": int(self._get_local_rating_level() or 1),
                "next_goal": int(self._get_local_rating_next_goal() or 5000),
            }
        if "local_stars_balance" in keys:
            sections["local_stars_balance"] = {
                "enabled": bool(getattr(self, "local_stars_balance_enabled", False)),
                "value": int(self._get_local_stars_balance_value() or 0),
            }
        return {
            "version": PROFILE_CONFIG_VERSION,
            "plugin_id": __id__,
            "plugin_version": __version__,
            "timestamp": int(time.time()),
            "profile_name": self._sanitize_profile_name(profile_name),
            "sections": sections,
        }

    def _write_profile_config_file(self, profile_name, selected_keys):
        payload = self._collect_profile_export_payload(profile_name, selected_keys)
        if not payload.get("sections"):
            BulletinHelper.show_error("Выберите хотя бы один пункт")
            return False
        config_dir = self._get_profile_configs_dir()
        if not config_dir:
            BulletinHelper.show_error("Не удалось подготовить папку для профилей")
            return False
        safe_name = self._sanitize_profile_name(profile_name)
        filename = f"{safe_name}{PROFILE_CONFIG_FILE_EXTENSION}"
        filepath = os.path.join(config_dir, filename)
        try:
            raw_json = json.dumps(payload, indent=2, ensure_ascii=False)
            raw_b64 = base64.b64encode(raw_json.encode("utf-8")).decode("utf-8")
            content = (
                f"# eblanNFT profile\n"
                f"# {time.strftime('%Y-%m-%d %H:%M:%S')}\n"
                f"# sections: {', '.join(sorted(payload.get('sections', {}).keys()))}\n\n"
                f"{raw_b64}"
            )
            write_file(filepath, content)
            self._show_profile_saved_sheet(filepath, filename)
            return True
        except Exception as e:
            BulletinHelper.show_error(f"Ошибка экспорта: {e}")
            return False

    def _load_profile_config_file(self, filepath):
        try:
            raw = read_file(filepath)
            if not raw:
                return None
            data_lines = [line for line in str(raw).split("\n") if line.strip() and (not str(line).startswith("#"))]
            if not data_lines:
                return None
            decoded = base64.b64decode("".join(data_lines)).decode("utf-8")
            data = json.loads(decoded)
            if not isinstance(data, dict):
                return None
            sections = data.get("sections", None)
            if not isinstance(sections, dict):
                return None
            return data
        except Exception as e:
            _log(f"Profile load error ({filepath}): {e}")
            return None

    def _handle_profile_file_open(self, filepath):
        data = self._load_profile_config_file(filepath)
        if not data:
            BulletinHelper.show_error("Не удалось прочитать .profile")
            return
        filename = ""
        try:
            filename = os.path.basename(filepath)
        except:
            filename = ".profile"
        self._show_profile_import_sheet(data, filename)

    def _get_profile_available_option_keys(self, profile_data):
        sections = profile_data.get("sections", {}) if isinstance(profile_data, dict) else {}
        available = []
        for key, _title, _desc in self._profile_option_defs():
            if key in sections:
                available.append(key)
        return available

    def _show_profile_saved_sheet(self, filepath, filename):
        try:
            fragment = get_last_fragment()
            if not fragment:
                BulletinHelper.show_success(f"Профиль сохранён: {filename}")
                return
            activity = fragment.getParentActivity()
            if not activity:
                BulletinHelper.show_success(f"Профиль сохранён: {filename}")
                return

            container = LinearLayout(activity)
            container.setOrientation(LinearLayout.VERTICAL)
            container.setPadding(AndroidUtilities.dp(20), AndroidUtilities.dp(20), AndroidUtilities.dp(20), AndroidUtilities.dp(12))

            title_view = TextView(activity)
            title_view.setText("Профиль экспортирован")
            title_view.setTextColor(Theme.getColor(Theme.key_dialogTextBlack))
            title_view.setTypeface(AndroidUtilities.bold())
            title_view.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 18)
            container.addView(title_view)

            file_view = TextView(activity)
            file_view.setText(filename)
            file_view.setTextColor(Theme.getColor(Theme.key_windowBackgroundWhiteBlueText))
            file_view.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 15)
            lp_file = LinearLayout.LayoutParams(-1, -2)
            lp_file.topMargin = AndroidUtilities.dp(8)
            container.addView(file_view, lp_file)

            path_view = TextView(activity)
            path_view.setText(str(filepath or ""))
            path_view.setTextColor(Theme.getColor(Theme.key_windowBackgroundWhiteGrayText2))
            path_view.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 12)
            lp_path = LinearLayout.LayoutParams(-1, -2)
            lp_path.topMargin = AndroidUtilities.dp(6)
            container.addView(path_view, lp_path)

            builder = AlertDialogBuilder(activity)
            builder.set_title("Экспорт .profile")
            builder.set_view(container)
            builder.set_positive_button("Поделиться", lambda d, w: self._share_profile_file(filepath, activity))
            builder.set_negative_button("Закрыть", None)
            run_on_ui_thread(builder.show)
        except Exception as e:
            _log(f"Profile saved sheet error: {e}")
            BulletinHelper.show_success(f"Профиль сохранён: {filename}")

    def _share_profile_file(self, filepath, activity):
        try:
            Intent = jclass("android.content.Intent")
            File = jclass("java.io.File")
            FileProvider = jclass("androidx.core.content.FileProvider")
            file_obj = File(filepath)
            uri = FileProvider.getUriForFile(
                activity,
                ApplicationLoader.getApplicationId() + ".provider",
                file_obj,
            )
            intent = Intent(Intent.ACTION_SEND)
            intent.setType("application/octet-stream")
            intent.putExtra(Intent.EXTRA_STREAM, uri)
            intent.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
            chooser = Intent.createChooser(intent, "Share profile")
            activity.startActivity(chooser)
        except Exception as e:
            BulletinHelper.show_error(f"Не удалось открыть шаринг: {e}")

    def _show_profile_selection_sheet(self, sheet_title, subtitle, option_keys, default_selected, confirm_text, on_confirm):
        try:
            fragment = get_last_fragment()
            if not fragment:
                return False
            activity = fragment.getParentActivity()
            if not activity:
                return False

            available = [key for key in list(option_keys or []) if str(key or "").strip()]
            if not available:
                BulletinHelper.show_error("Нет доступных пунктов")
                return False

            BottomSheetCls = jclass("org.telegram.ui.ActionBar.BottomSheet")
            TextCheckCell = jclass("org.telegram.ui.Cells.TextCheckCell")

            sheet = BottomSheetCls(activity, False)
            root = LinearLayout(activity)
            root.setOrientation(LinearLayout.VERTICAL)
            root.setPadding(AndroidUtilities.dp(16), AndroidUtilities.dp(18), AndroidUtilities.dp(16), AndroidUtilities.dp(12))

            title_view = TextView(activity)
            title_view.setText(str(sheet_title or "Профиль"))
            title_view.setTextColor(Theme.getColor(Theme.key_dialogTextBlack))
            title_view.setTypeface(AndroidUtilities.bold())
            title_view.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 18)
            root.addView(title_view)

            if subtitle:
                sub_view = TextView(activity)
                sub_view.setText(str(subtitle))
                sub_view.setTextColor(Theme.getColor(Theme.key_windowBackgroundWhiteGrayText2))
                sub_view.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 13)
                lp_sub = LinearLayout.LayoutParams(-1, -2)
                lp_sub.topMargin = AndroidUtilities.dp(6)
                root.addView(sub_view, lp_sub)

            scroll = ScrollView(activity)
            cells_wrap = LinearLayout(activity)
            cells_wrap.setOrientation(LinearLayout.VERTICAL)
            lp_scroll = LinearLayout.LayoutParams(-1, AndroidUtilities.dp(320))
            lp_scroll.topMargin = AndroidUtilities.dp(16)

            selected = {}
            for key in available:
                selected[key] = bool(default_selected.get(key, True)) if isinstance(default_selected, dict) else True

            for index, key in enumerate(available):
                title = self._profile_option_title(key)
                desc = ""
                for opt_key, _title, opt_desc in self._profile_option_defs():
                    if opt_key == key:
                        desc = opt_desc
                        break
                cell = TextCheckCell(activity, 21, True)
                cell.setTextAndValueAndCheck(title, desc, bool(selected.get(key, True)), True, index != len(available) - 1)

                def _toggle(_view=None, _cell=cell, _key=key):
                    try:
                        new_value = not bool(selected.get(_key, True))
                        selected[_key] = new_value
                        _cell.setChecked(new_value)
                    except:
                        pass

                cell.setOnClickListener(JOnClickListener(_toggle))
                cells_wrap.addView(cell)

            scroll.addView(cells_wrap)
            root.addView(scroll, lp_scroll)

            buttons = LinearLayout(activity)
            buttons.setOrientation(LinearLayout.HORIZONTAL)
            lp_buttons = LinearLayout.LayoutParams(-1, -2)
            lp_buttons.topMargin = AndroidUtilities.dp(14)

            cancel_btn = TextView(activity)
            cancel_btn.setText("Отмена")
            cancel_btn.setGravity(Gravity.CENTER)
            cancel_btn.setTypeface(AndroidUtilities.bold())
            cancel_btn.setTextColor(Theme.getColor(Theme.key_featuredStickers_addButton))
            cancel_btn.setBackgroundColor(0)
            cancel_btn.setPadding(AndroidUtilities.dp(8), AndroidUtilities.dp(14), AndroidUtilities.dp(8), AndroidUtilities.dp(14))

            apply_btn = TextView(activity)
            apply_btn.setText(str(confirm_text or "Готово"))
            apply_btn.setGravity(Gravity.CENTER)
            apply_btn.setTypeface(AndroidUtilities.bold())
            apply_btn.setTextColor(-1)
            bg = GradientDrawable()
            bg.setCornerRadius(AndroidUtilities.dp(10))
            bg.setColor(Theme.getColor(Theme.key_featuredStickers_addButton))
            apply_btn.setBackground(bg)
            apply_btn.setPadding(AndroidUtilities.dp(8), AndroidUtilities.dp(14), AndroidUtilities.dp(8), AndroidUtilities.dp(14))

            def _cancel(_view=None):
                try:
                    sheet.dismiss()
                except:
                    pass

            def _apply(_view=None):
                chosen = [key for key in available if bool(selected.get(key, False))]
                if not chosen:
                    BulletinHelper.show_error("Выберите хотя бы один пункт")
                    return
                try:
                    sheet.dismiss()
                except:
                    pass
                try:
                    on_confirm(chosen)
                except Exception as e:
                    BulletinHelper.show_error(f"Ошибка применения: {e}")

            cancel_btn.setOnClickListener(JOnClickListener(_cancel))
            apply_btn.setOnClickListener(JOnClickListener(_apply))
            buttons.addView(cancel_btn, LinearLayout.LayoutParams(0, -2, 1.0))
            lp_apply = LinearLayout.LayoutParams(0, -2, 1.0)
            lp_apply.leftMargin = AndroidUtilities.dp(8)
            buttons.addView(apply_btn, lp_apply)
            root.addView(buttons, lp_buttons)

            sheet.setCustomView(root)
            sheet.show()
            return True
        except Exception as e:
            BulletinHelper.show_error(f"Ошибка окна профиля: {e}")
            return False

    def _open_profile_export_name_dialog(self):
        current_name = time.strftime("profile_%Y%m%d_%H%M%S")
        self._show_text_input_dialog(
            "Имя конфига",
            current_name,
            lambda raw: self._show_profile_export_sheet(raw),
            numeric=False,
        )

    def _show_profile_export_sheet(self, profile_name):
        safe_name = self._sanitize_profile_name(profile_name)
        defaults = {key: True for key, _title, _desc in self._profile_option_defs()}
        self._show_profile_selection_sheet(
            f"Экспорт {safe_name}{PROFILE_CONFIG_FILE_EXTENSION}",
            "Отметьте, что нужно положить в конфиг",
            [key for key, _title, _desc in self._profile_option_defs()],
            defaults,
            "Экспортировать",
            lambda selected_keys: self._write_profile_config_file(safe_name, selected_keys),
        )

    def _show_profile_import_dialog(self):
        try:
            config_dir = self._get_profile_configs_dir()
            if not config_dir or (not os.path.exists(config_dir)):
                BulletinHelper.show_error("Папка с профилями не найдена")
                return
            files = [name for name in os.listdir(config_dir) if str(name).lower().endswith(PROFILE_CONFIG_FILE_EXTENSION)]
            files.sort(reverse=True)
            if not files:
                BulletinHelper.show_info("Нет сохранённых .profile")
                return

            ctx = self._get_menu_activity()
            if not ctx:
                return

            def _open_selected(dialog, index):
                try:
                    dialog.dismiss()
                except:
                    pass
                if index < 0 or index >= len(files):
                    return
                filepath = os.path.join(config_dir, files[index])
                data = self._load_profile_config_file(filepath)
                if not data:
                    BulletinHelper.show_error("Не удалось прочитать конфиг")
                    return
                self._show_profile_import_sheet(data, files[index])

            builder = AlertDialogBuilder(ctx)
            builder.set_title("Выберите .profile")
            builder.set_items(files, _open_selected)
            builder.set_negative_button("Отмена", None)
            run_on_ui_thread(builder.show)
        except Exception as e:
            BulletinHelper.show_error(f"Ошибка импорта: {e}")

    def _show_profile_import_sheet(self, profile_data, filename):
        available = self._get_profile_available_option_keys(profile_data)
        if not available:
            BulletinHelper.show_error("В профиле нет поддерживаемых данных")
            return
        profile_name = str(profile_data.get("profile_name", "") or "").strip()
        subtitle_parts = []
        if profile_name:
            subtitle_parts.append(profile_name)
        if filename:
            subtitle_parts.append(str(filename))
        self._show_profile_selection_sheet(
            "Импорт .profile",
            " • ".join(subtitle_parts),
            available,
            {key: True for key in available},
            "Импортировать",
            lambda selected_keys: self._import_profile_config(profile_data, selected_keys),
        )

    def _import_profile_config(self, profile_data, selected_keys):
        try:
            sections = profile_data.get("sections", {}) if isinstance(profile_data, dict) else {}
            imported = []
            skipped_legacy = []
            for key in list(selected_keys or []):
                if key not in sections:
                    continue
                data = sections.get(key, {})
                if key == "nft_gifts":
                    lib = data.get("gift_library", [])
                    self.gift_library = list(lib) if isinstance(lib, list) else []
                    self.inject_active = bool(data.get("inject_active", False))
                    self.wear_active = bool(data.get("wear_active", False))
                    self.wear_collectible_id = self._to_int(data.get("wear_collectible_id", 0), 0)
                    self.wear_status_data = dict(data.get("wear_status_data", {}) or {})
                    self.cached_gift_id = self._to_int(data.get("cached_gift_id", 0), 0)
                    self.build_config = dict(data.get("build_config", {}) or {})
                    self.identity_config = self._sanitize_identity_config(data.get("identity_config", None))
                    self.value_config = self._sanitize_value_config(data.get("value_config", None))
                    self.gift_stars_config = self._sanitize_gift_stars_config(data.get("gift_stars_config", None))
                    self.gift_objects = {}
                    self._gift_objects_order = []
                    self._profile_saved_lists = []
                    self._profile_saved_lists_frag_key = 0
                    try:
                        self._rebuild_injection_payloads()
                    except:
                        self.injection_payloads = []
                        self.injection_payload = None
                    imported.append(key)
                elif key == "nft_usernames":
                    self.nft_username_enabled = bool(data.get("enabled", False))
                    self._set_nft_username_tokens(data.get("tokens", []))
                    self.nft_username = self._normalize_nft_username(data.get("selected", ""))
                    self.nft_username_price_ton = str(data.get("price_ton", "10.8") or "10.8")
                    self.nft_username_price_usd = str(data.get("price_usd", "14.68") or "14.68")
                    self.nft_username_purchase_date = str(data.get("purchase_date", "") or "")
                    self.nft_collectible_template_b64 = str(data.get("template_b64", "") or "")
                    self.nft_collectible_template = None
                    imported.append(key)
                elif key == "nft_number":
                    self.nft_number_enabled = bool(data.get("enabled", False))
                    self._set_nft_number_tokens(data.get("tokens", []))
                    self.nft_number = self._normalize_nft_number(data.get("selected", ""))
                    self.nft_number_price_ton = str(data.get("price_ton", "10.8") or "10.8")
                    self.nft_number_price_usd = str(data.get("price_usd", "14.68") or "14.68")
                    self.nft_number_purchase_date = str(data.get("purchase_date", "") or "")
                    self.nft_number_collectible_template_b64 = str(data.get("template_b64", "") or "")
                    self.nft_number_collectible_template = None
                    imported.append(key)
                elif key == "local_rating":
                    self.local_rating_value = self._sanitize_local_rating_value(data.get("value", 0))
                    self.local_rating_level = self._sanitize_local_rating_level(data.get("level", 1))
                    self.local_rating_next_goal = self._sanitize_local_rating_next_goal(
                        data.get("next_goal", 5000),
                        self.local_rating_value,
                    )
                    self.local_rating_enabled = bool(data.get("enabled", False)) and bool(self.local_rating_value > 0)
                    imported.append(key)
                elif key == "local_stars_balance":
                    self.local_stars_balance_value = self._sanitize_local_stars_balance_value(data.get("value", 0))
                    self.local_stars_balance_enabled = bool(data.get("enabled", False)) and bool(self.local_stars_balance_value > 0)
                    imported.append(key)
                elif key == "local_verification":
                    skipped_legacy.append(key)
            if not imported:
                if skipped_legacy:
                    BulletinHelper.show_info("Секция локальной верификации больше не поддерживается и была пропущена")
                    return True
                BulletinHelper.show_error("Не удалось импортировать выбранные пункты")
                return False

            try:
                self._save_cache(delay_ms=0)
            except:
                pass
            try:
                self._save_injection_cache()
            except:
                pass
            try:
                self._patch_my_cached_user()
            except:
                pass
            try:
                self._patch_my_cached_user_full()
            except:
                pass
            try:
                self._schedule_cached_user_patch([0, 180, 560], patch_userconfig=True, key="profile_import")
            except:
                pass
            try:
                self._post_local_profile_notifications(reason="profile_import", cooldown=0.08)
            except:
                pass
            try:
                if "local_stars_balance" in imported:
                    self._notify_local_star_balance_changed()
            except:
                pass
            try:
                self._refresh_visible_profile_boosts()
            except:
                pass
            try:
                if self._is_my_profile_activity():
                    self._schedule_profile_gifts_refresh([60, 220], min_interval=0.12, force=True)
                    self._schedule_profile_ui_repatch(self._get_visible_profile_activity(), [0, 180])
            except:
                pass

            labels = ", ".join([self._profile_option_title(key) for key in imported])
            BulletinHelper.show_success(f"Импортировано: {labels}")
            return True
        except Exception as e:
            BulletinHelper.show_error(f"Ошибка импорта: {e}")
            return False

    def _show_text_input_dialog(self, title, prefill, on_submit, numeric=False):
        try:
            fragment = get_last_fragment()
            if not fragment:
                return
            ctx = fragment.getParentActivity()
            if not ctx:
                return

            container = FrameLayout(ctx)
            et = EditText(ctx)
            et.setText(str(prefill or ""))
            if numeric:
                et.setInputType(2)

            params = FrameLayout.LayoutParams(-1, -2)
            margin = AndroidUtilities.dp(20)
            params.leftMargin = margin
            params.rightMargin = margin
            et.setLayoutParams(params)
            container.addView(et)

            builder = AlertDialogBuilder(ctx)
            builder.set_title(self._ui_text(title))
            builder.set_view(container)

            def _ok(dialog, which):
                try:
                    on_submit(str(et.getText()))
                except Exception as e:
                    BulletinHelper.show_error(f"\u041e\u0448\u0438\u0431\u043a\u0430 \u0432\u0432\u043e\u0434\u0430: {e}")

            builder.set_positive_button("\u0421\u043e\u0445\u0440\u0430\u043d\u0438\u0442\u044c", _ok)
            builder.set_negative_button("\u041e\u0442\u043c\u0435\u043d\u0430", None)
            run_on_ui_thread(builder.show)
        except Exception as e:
            BulletinHelper.show_error(f"Dialog Err: {e}")

    def _open_fake_incoming_menu(self, context=None):
        account, dialog_id = self._resolve_fake_incoming_target(context)
        if dialog_id == 0:
            BulletinHelper.show_error("\u041d\u0435 \u0443\u0434\u0430\u043b\u043e\u0441\u044c \u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0438\u0442\u044c \u0434\u0438\u0430\u043b\u043e\u0433")
            return
        run_on_ui_thread(lambda: self._show_fake_incoming_dialog(account, dialog_id))

    def _show_fake_incoming_dialog(self, account, dialog_id):
        try:
            fragment = get_last_fragment()
            if not fragment:
                BulletinHelper.show_error("\u0427\u0430\u0442 \u043d\u0435 \u043d\u0430\u0439\u0434\u0435\u043d")
                return
            ctx = fragment.getParentActivity()
            if not ctx:
                BulletinHelper.show_error("\u041a\u043e\u043d\u0442\u0435\u043a\u0441\u0442 \u043d\u0435\u0434\u043e\u0441\u0442\u0443\u043f\u0435\u043d")
                return

            InputType = jclass("android.text.InputType")
            layout = LinearLayout(ctx)
            layout.setOrientation(LinearLayout.VERTICAL)
            pad_h = AndroidUtilities.dp(20)
            layout.setPadding(pad_h, AndroidUtilities.dp(10), pad_h, AndroidUtilities.dp(4))
            fields = {}

            def _add_input(key, label, default_value, input_type):
                title = TextView(ctx)
                title.setText(self._ui_text(label))
                try:
                    title.setTextColor(Theme.getColor(Theme.key_windowBackgroundWhiteBlueHeader))
                except:
                    pass
                layout.addView(title)

                edit = EditText(ctx)
                edit.setText(str(default_value or ""))
                edit.setInputType(input_type)
                layout.addView(edit)
                fields[key] = edit

            _add_input(
                "msg_text",
                "\u0422\u0435\u043a\u0441\u0442 \u0432\u0445\u043e\u0434\u044f\u0449\u0435\u0433\u043e \u0441\u043e\u043e\u0431\u0449\u0435\u043d\u0438\u044f",
                getattr(self, "fake_incoming_text", "\u041f\u0440\u0438\u0432\u0435\u0442! \u041a\u0430\u043a \u0434\u0435\u043b\u0430?"),
                int(InputType.TYPE_CLASS_TEXT | InputType.TYPE_TEXT_FLAG_MULTI_LINE | InputType.TYPE_TEXT_FLAG_CAP_SENTENCES)
            )
            _add_input(
                "delay",
                "\u0417\u0430\u0434\u0435\u0440\u0436\u043a\u0430 \u043f\u0435\u0440\u0435\u0434 \u043f\u043e\u044f\u0432\u043b\u0435\u043d\u0438\u0435\u043c (\u0441\u0435\u043a)",
                getattr(self, "fake_incoming_delay", "3"),
                int(InputType.TYPE_CLASS_NUMBER)
            )

            builder = AlertDialogBuilder(ctx)
            builder.set_title(self._ui_text("\u0412\u0445\u043e\u0434\u044f\u0449\u0435\u0435 \u0441\u043e\u043e\u0431\u0449\u0435\u043d\u0438\u0435"))
            builder.set_view(layout)

            def _submit(dialog, which):
                try:
                    raw_text = str(fields["msg_text"].getText() or "")
                except:
                    raw_text = ""
                try:
                    raw_delay = str(fields["delay"].getText() or "")
                except:
                    raw_delay = "0"
                self._queue_fake_incoming_message(account, dialog_id, raw_text, raw_delay)

            builder.set_positive_button(self._ui_text("\u0421\u043e\u0437\u0434\u0430\u0442\u044c"), _submit)
            builder.set_negative_button(self._ui_text("\u041e\u0442\u043c\u0435\u043d\u0430"), None)
            builder.show()
        except Exception as e:
            BulletinHelper.show_error(f"Fake incoming dialog err: {e}")

    def _queue_fake_incoming_message(self, account, dialog_id, raw_text, raw_delay):
        text = str(raw_text or "").strip()
        if not text:
            BulletinHelper.show_error("\u0412\u0432\u0435\u0434\u0438\u0442\u0435 \u0442\u0435\u043a\u0441\u0442 \u0441\u043e\u043e\u0431\u0449\u0435\u043d\u0438\u044f")
            return
        if len(text) > 4096:
            text = text[:4096]
        try:
            delay = int(str(raw_delay or "0").strip() or "0")
        except:
            delay = 0
        if delay < 0:
            delay = 0
        if delay > 86400:
            delay = 86400

        self.fake_incoming_text = text
        self.fake_incoming_delay = str(delay)
        try:
            record = self._upsert_fake_incoming_record({
                "dialog_id": int(dialog_id or 0),
                "message_id": int(self._allocate_fake_incoming_message_id() or 0),
                "text": text,
                "date": int(time.time()) + int(delay or 0),
                "unread": True,
            })
        except Exception as e:
            BulletinHelper.show_error(f"Fake incoming save err: {e}")
            return
        if not record:
            BulletinHelper.show_error("\u041d\u0435 \u0443\u0434\u0430\u043b\u043e\u0441\u044c \u0441\u043e\u0445\u0440\u0430\u043d\u0438\u0442\u044c \u0441\u043e\u043e\u0431\u0449\u0435\u043d\u0438\u0435")
            return
        try:
            self._save_cache(delay_ms=0)
        except:
            pass

        def _execute():
            run_on_ui_thread(lambda: self._apply_persistent_fake_messages_to_dialog(account, dialog_id, force=True))

        if delay > 0:
            BulletinHelper.show_success(f"\u0421\u043e\u043e\u0431\u0449\u0435\u043d\u0438\u0435 \u043f\u043e\u044f\u0432\u0438\u0442\u0441\u044f \u0447\u0435\u0440\u0435\u0437 {delay} \u0441\u0435\u043a.")
            threading.Timer(delay, _execute).start()
        else:
            _execute()

    def _inject_fake_incoming_message(self, account, dialog_id, text):
        try:
            dialog_id = int(dialog_id or 0)
        except:
            dialog_id = 0
        if dialog_id == 0:
            BulletinHelper.show_error("\u041d\u0435 \u0443\u0434\u0430\u043b\u043e\u0441\u044c \u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0438\u0442\u044c \u0434\u0438\u0430\u043b\u043e\u0433")
            return
        try:
            account = int(account or 0)
        except:
            account = 0

        try:
            TL_message = jclass("org.telegram.tgnet.TLRPC$TL_message")
            msg = TL_message()
            msg.id = UserConfig.getInstance(account).getNewMessageId()
            msg.peer_id = self._build_peer_for_entity(dialog_id)
            msg.from_id = self._build_peer_for_entity(dialog_id)
            msg.dialog_id = int(dialog_id)
            msg.message = str(text or "")
            msg.date = int(time.time())
            msg.out = False
            msg.unread = True
            msg.flags = 256

            if msg.peer_id is None or msg.from_id is None:
                BulletinHelper.show_error("\u042d\u0442\u043e\u0442 \u0442\u0438\u043f \u0434\u0438\u0430\u043b\u043e\u0433\u0430 \u043f\u043e\u043a\u0430 \u043d\u0435 \u043f\u043e\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442\u0441\u044f")
                return

            obj = MessageObject(account, msg, False, True)
            obj_list = ArrayList()
            obj_list.add(obj)

            mc = MessagesController.getInstance(account)
            mc.updateInterfaceWithMessages(int(dialog_id), obj_list, 0)
            try:
                NotificationCenter.getInstance(account).postNotificationName(NotificationCenter.dialogsNeedReload)
            except:
                pass
            BulletinHelper.show_success("\u0412\u0445\u043e\u0434\u044f\u0449\u0435\u0435 \u0441\u043e\u043e\u0431\u0449\u0435\u043d\u0438\u0435 \u0434\u043e\u0431\u0430\u0432\u043b\u0435\u043d\u043e \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u043e")
        except Exception as e:
            BulletinHelper.show_error(f"Fake incoming err: {e}")

