    def _clear_all_nft_numbers(self):
        self._set_nft_number_tokens([])
        self.nft_number_enabled = False
        self._save_cache()
        self._patch_my_cached_user()
        BulletinHelper.show_success("\u0412\u0441\u0435 NFT Number \u043e\u0447\u0438\u0449\u0435\u043d\u044b")

    def _open_remove_nft_username_menu(self):
        tokens = self._get_nft_username_tokens()
        if not tokens:
            BulletinHelper.show_error("\u0421\u043f\u0438\u0441\u043e\u043a \u044e\u0437\u0435\u0440\u043d\u0435\u0439\u043c\u043e\u0432 \u043f\u0443\u0441\u0442")
            return
        try:
            actions = []
            for token in tokens:
                actions.append((f"@{token}", lambda t=token: self._remove_nft_username_token(t)))
            self._show_action_menu("\u0423\u0434\u0430\u043b\u0438\u0442\u044c NFT Username", actions, negative_text="\u041e\u0442\u043c\u0435\u043d\u0430")
        except Exception as e:
            BulletinHelper.show_error(f"\u041e\u0448\u0438\u0431\u043a\u0430 \u0443\u0434\u0430\u043b\u0435\u043d\u0438\u044f: {e}")

    def _remove_nft_username_token(self, token):
        tokens = self._get_nft_username_tokens()
        new_tokens = [t for t in tokens if t.lower() != str(token or "").lower()]
        self._set_nft_username_tokens(new_tokens)
        self._save_cache()
        self._patch_my_cached_user()
        BulletinHelper.show_success(f"\u0423\u0434\u0430\u043b\u0435\u043d: @{token}")

    def _open_nft_username_menu(self, context=None):
        try:
            tokens = self._get_nft_username_tokens()
            actions = [
                ("\u0414\u043e\u0431\u0430\u0432\u0438\u0442\u044c", lambda: self._show_text_input_dialog("Username (\u0431\u0435\u0437 @)", "", self._add_nft_username)),
                (f"\u041f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0442\u044c \u2022 {self._state_short_text(self.nft_username_enabled)}", self._toggle_nft_username_enabled),
                (f"\u0421\u043f\u0438\u0441\u043e\u043a \u2022 {len(tokens)}", self._show_username_tokens_info),
                ("\u0414\u0435\u0442\u0430\u043b\u0438", self._open_nft_username_details_menu),
            ]
            if tokens:
                actions.append(("\u0423\u0434\u0430\u043b\u0438\u0442\u044c", self._open_remove_nft_username_menu))
                actions.append(("\u041e\u0447\u0438\u0441\u0442\u0438\u0442\u044c \u0432\u0441\u0451", self._clear_all_nft_usernames))
            self._show_action_menu("Username", actions, negative_text="\u0417\u0430\u043a\u0440\u044b\u0442\u044c", context=context)
        except Exception as e:
            BulletinHelper.show_error(f"\u041e\u0448\u0438\u0431\u043a\u0430 \u043c\u0435\u043d\u044e: {e}")

    def _toggle_nft_username_enabled(self):
        self.nft_username_enabled = not self.nft_username_enabled
        self._save_cache()
        self._patch_my_cached_user()
        BulletinHelper.show_success(f"NFT Username: {self._state_full_text(self.nft_username_enabled)}")

    def _add_nft_username(self, value):
        uname = self._normalize_nft_username(value)
        if not uname:
            BulletinHelper.show_error("\u041d\u0435\u043a\u043e\u0440\u0440\u0435\u043a\u0442\u043d\u044b\u0439 \u044e\u0437\u0435\u0440\u043d\u0435\u0439\u043c")
            return
        tokens = self._get_nft_username_tokens()
        if uname.lower() in [t.lower() for t in tokens]:
            BulletinHelper.show_info(f"\u0423\u0436\u0435 \u0434\u043e\u0431\u0430\u0432\u043b\u0435\u043d: @{uname}")
            return
        tokens.append(uname)
        self._set_nft_username_tokens(tokens)
        self.nft_username_enabled = True
        self._save_cache()
        self._patch_my_cached_user()
        BulletinHelper.show_success(f"NFT Username \u0434\u043e\u0431\u0430\u0432\u043b\u0435\u043d: @{uname}")

    def _open_nft_username_details_menu(self):
        try:
            date_text = self.nft_username_purchase_date if self.nft_username_purchase_date else "\u043d\u0435 \u0437\u0430\u0434\u0430\u043d\u0430"
            actions = [
                (f"TON \u2022 {self.nft_username_price_ton}", lambda: self._show_text_input_dialog("\u0426\u0435\u043d\u0430 \u0432 TON", self.nft_username_price_ton, lambda text: self._save_nft_username_detail("ton", text))),
                (f"USD \u2022 {self.nft_username_price_usd}", lambda: self._show_text_input_dialog("\u0426\u0435\u043d\u0430 \u0432 USD", self.nft_username_price_usd, lambda text: self._save_nft_username_detail("usd", text))),
                (f"\u0414\u0430\u0442\u0430 \u2022 {date_text}", lambda: self._show_text_input_dialog("\u0414\u0430\u0442\u0430 \u043f\u043e\u043a\u0443\u043f\u043a\u0438", self.nft_username_purchase_date, lambda text: self._save_nft_username_detail("date", text))),
            ]
            self._show_action_menu("Username \u2022 \u0414\u0435\u0442\u0430\u043b\u0438", actions, negative_text="\u0417\u0430\u043a\u0440\u044b\u0442\u044c")
        except Exception as e:
            BulletinHelper.show_error(f"\u041e\u0448\u0438\u0431\u043a\u0430 \u0434\u0435\u0442\u0430\u043b\u0435\u0439: {e}")

    def _save_nft_username_detail(self, key, value):
        text = str(value or "").strip().replace(",", ".")
        if key in ["ton", "usd"]:
            text = re.sub(r"[^0-9.\\-]+", "", text)
            if text in ["", "-", "."]:
                text = "0"
        if key == "ton":
            self.nft_username_price_ton = text if text else "0"
        elif key == "usd":
            self.nft_username_price_usd = text if text else "0"
        elif key == "date":
            self.nft_username_purchase_date = text
        self._save_cache()
        BulletinHelper.show_success("\u0414\u0435\u0442\u0430\u043b\u0438 NFT Username \u0441\u043e\u0445\u0440\u0430\u043d\u0435\u043d\u044b")

    def _open_remove_nft_number_menu(self):
        tokens = self._get_nft_number_tokens()
        if not tokens:
            BulletinHelper.show_error("\u0421\u043f\u0438\u0441\u043e\u043a \u043d\u043e\u043c\u0435\u0440\u043e\u0432 \u043f\u0443\u0441\u0442")
            return
        try:
            actions = []
            for token in tokens:
                actions.append((self._format_nft_number(token), lambda t=token: self._remove_nft_number_token(t)))
            self._show_action_menu("\u0423\u0434\u0430\u043b\u0438\u0442\u044c NFT Number", actions, negative_text="\u041e\u0442\u043c\u0435\u043d\u0430")
        except Exception as e:
            BulletinHelper.show_error(f"\u041e\u0448\u0438\u0431\u043a\u0430 \u0443\u0434\u0430\u043b\u0435\u043d\u0438\u044f: {e}")

    def _remove_nft_number_token(self, token):
        tokens = self._get_nft_number_tokens()
        new_tokens = [t for t in tokens if t != token]
        self._set_nft_number_tokens(new_tokens)
        self._save_cache()
        self._patch_my_cached_user()
        BulletinHelper.show_success(f"\u0423\u0434\u0430\u043b\u0435\u043d: {self._format_nft_number(token)}")

    def _open_nft_number_menu(self, context=None):
        try:
            tokens = self._get_nft_number_tokens()
            actions = [
                ("\u0414\u043e\u0431\u0430\u0432\u0438\u0442\u044c", lambda: self._show_text_input_dialog("Number (\u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440 +888 0413 6929)", "", self._add_nft_number)),
                (f"\u041f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0442\u044c \u2022 {self._state_short_text(self.nft_number_enabled)}", self._toggle_nft_number_enabled),
                (f"\u0421\u043f\u0438\u0441\u043e\u043a \u2022 {len(tokens)}", self._show_number_tokens_info),
                ("\u0414\u0435\u0442\u0430\u043b\u0438", self._open_nft_number_details_menu),
            ]
            if tokens:
                actions.append(("\u0423\u0434\u0430\u043b\u0438\u0442\u044c", self._open_remove_nft_number_menu))
                actions.append(("\u041e\u0447\u0438\u0441\u0442\u0438\u0442\u044c \u0432\u0441\u0451", self._clear_all_nft_numbers))
            self._show_action_menu("Number", actions, negative_text="\u0417\u0430\u043a\u0440\u044b\u0442\u044c", context=context)
        except Exception as e:
            BulletinHelper.show_error(f"\u041e\u0448\u0438\u0431\u043a\u0430 \u043c\u0435\u043d\u044e: {e}")

    def _toggle_nft_number_enabled(self):
        self.nft_number_enabled = not self.nft_number_enabled
        self._save_cache()
        self._patch_my_cached_user()
        BulletinHelper.show_success(f"NFT Number: {self._state_full_text(self.nft_number_enabled)}")

    def _add_nft_number(self, value):
        num = self._normalize_nft_number(value)
        if not num:
            BulletinHelper.show_error("\u041d\u0435\u043a\u043e\u0440\u0440\u0435\u043a\u0442\u043d\u044b\u0439 \u043d\u043e\u043c\u0435\u0440 (\u043d\u0443\u0436\u0435\u043d +888...)")
            return
        tokens = self._get_nft_number_tokens()
        if num in tokens:
            BulletinHelper.show_info("\u041d\u043e\u043c\u0435\u0440 \u0443\u0436\u0435 \u0432 \u0441\u043f\u0438\u0441\u043a\u0435")
            return
        tokens.append(num)
        self._set_nft_number_tokens(tokens)
        self.nft_number_enabled = True
        self._save_cache()
        self._patch_my_cached_user()
        BulletinHelper.show_success(f"NFT Number \u0434\u043e\u0431\u0430\u0432\u043b\u0435\u043d: {self._format_nft_number(num)}")

    def _open_nft_number_details_menu(self):
        try:
            date_text = self.nft_number_purchase_date if self.nft_number_purchase_date else "\u043d\u0435 \u0437\u0430\u0434\u0430\u043d\u0430"
            actions = [
                (f"TON \u2022 {self.nft_number_price_ton}", lambda: self._show_text_input_dialog("\u0426\u0435\u043d\u0430 \u0432 TON", self.nft_number_price_ton, lambda text: self._save_nft_number_detail("ton", text))),
                (f"USD \u2022 {self.nft_number_price_usd}", lambda: self._show_text_input_dialog("\u0426\u0435\u043d\u0430 \u0432 USD", self.nft_number_price_usd, lambda text: self._save_nft_number_detail("usd", text))),
                (f"\u0414\u0430\u0442\u0430 \u2022 {date_text}", lambda: self._show_text_input_dialog("\u0414\u0430\u0442\u0430 \u043f\u043e\u043a\u0443\u043f\u043a\u0438", self.nft_number_purchase_date, lambda text: self._save_nft_number_detail("date", text))),
            ]
            self._show_action_menu("Number \u2022 \u0414\u0435\u0442\u0430\u043b\u0438", actions, negative_text="\u0417\u0430\u043a\u0440\u044b\u0442\u044c")
        except Exception as e:
            BulletinHelper.show_error(f"\u041e\u0448\u0438\u0431\u043a\u0430 \u0434\u0435\u0442\u0430\u043b\u0435\u0439: {e}")

    def _save_nft_number_detail(self, key, value):
        text = str(value or "").strip().replace(",", ".")
        if key in ["ton", "usd"]:
            text = re.sub(r"[^0-9.\\-]+", "", text)
            if text in ["", "-", "."]:
                text = "0"
        if key == "ton":
            self.nft_number_price_ton = text if text else "0"
        elif key == "usd":
            self.nft_number_price_usd = text if text else "0"
        elif key == "date":
            self.nft_number_purchase_date = text
        self._save_cache()
        BulletinHelper.show_success("\u0414\u0435\u0442\u0430\u043b\u0438 NFT Number \u0441\u043e\u0445\u0440\u0430\u043d\u0435\u043d\u044b")

    def _create_sheet_action_row(self, ctx, title, subtitle, on_click, accent=False):
        row = LinearLayout(ctx)
        try:
            row.setOrientation(LinearLayout.VERTICAL)
            row.setClickable(True)
            row.setFocusable(True)
            row.setPadding(AndroidUtilities.dp(14), AndroidUtilities.dp(14), AndroidUtilities.dp(14), AndroidUtilities.dp(14))
            bg_color = self._theme_color("key_featuredStickers_addButton", 0xFF4E62FF) if accent else self._theme_color("key_dialogBackground", 0xFF1F1F1F)
            stroke_color = 0x00000000 if accent else self._theme_color("key_windowBackgroundWhiteGrayText2", 0x33222222)
            row.setBackground(self._create_round_rect(bg_color, radius_dp=16, stroke_color=stroke_color, stroke_dp=(0 if accent else 1)))
        except:
            pass

        title_view = TextView(ctx)
        try:
            title_view.setText(self._ui_text(title))
            title_view.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 16.0)
            title_view.setTextColor(self._theme_color("key_featuredStickers_buttonText", 0xFFFFFFFF) if accent else self._theme_color("key_windowBackgroundWhiteBlackText", 0xFFFFFFFF))
        except:
            pass
        try:
            row.addView(title_view)
        except:
            pass

        if subtitle:
            subtitle_view = TextView(ctx)
            try:
                subtitle_view.setText(self._ui_text(subtitle))
                subtitle_view.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 13.0)
                subtitle_view.setTextColor(self._theme_color("key_featuredStickers_buttonText", 0xFFFFFFFF) if accent else self._theme_color("key_windowBackgroundWhiteGrayText", 0xFF9A9A9A))
            except:
                pass
            try:
                lp_sub = LinearLayout.LayoutParams(LinearLayout.LayoutParams.WRAP_CONTENT, LinearLayout.LayoutParams.WRAP_CONTENT)
                lp_sub.topMargin = AndroidUtilities.dp(4)
                row.addView(subtitle_view, lp_sub)
            except:
                try:
                    row.addView(subtitle_view)
                except:
                    pass

        if on_click is not None:
            def _on_row_click(v):
                try:
                    self._dismiss_main_menu_sheet()
                except:
                    pass
                try:
                    on_click()
                except Exception as e:
                    BulletinHelper.show_error(f"\u041e\u0448\u0438\u0431\u043a\u0430 \u043c\u0435\u043d\u044e: {e}")
            try:
                row.setOnClickListener(JOnClickListener(_on_row_click))
            except:
                pass
        return row

    def _create_sheet_section_label(self, ctx, text):
        tv = TextView(ctx)
