    def _open_plugin_settings(self):
        try:
            def _show():
                try:
                    fragment = None
                    plugin = None
                    try:
                        fragment = get_last_fragment()
                    except:
                        fragment = None
                    try:
                        controller = PluginsController.getInstance()
                        plugin = controller.plugins.get(self.id) if controller else None
                    except:
                        plugin = None
                    if fragment is None or plugin is None:
                        return
                    fragment.presentFragment(PluginSettingsActivity(plugin))
                except Exception as inner_e:
                    _log(f"open plugin settings fail: {inner_e}")
            run_on_ui_thread(_show)
        except Exception as e:
            _log(f"open plugin settings fail: {e}")

    def _build_install_welcome_pattern_bitmap(self, width_px, height_px):
        try:
            w = max(1, int(width_px or 1))
            h = max(1, int(height_px or 1))
            bmp = Bitmap.createBitmap(w, h, Bitmap.Config.ARGB_8888)
            canvas = Canvas(bmp)
            try:
                canvas.drawColor(Color.parseColor("#07140C"))
            except:
                canvas.drawColor(0xFF07140C)
            paint = Paint()
            try:
                paint.setAntiAlias(True)
            except:
                pass
            try:
                paint.setColor(Color.parseColor("#5FA12B"))
            except:
                paint.setColor(0xFF5FA12B)
            try:
                paint.setTextSize(float(AndroidUtilities.dp(34)))
            except:
                paint.setTextSize(34.0)
            try:
                paint.setFakeBoldText(True)
            except:
                pass
            try:
                paint.setAlpha(108)
            except:
                pass
            try:
                paint.setTypeface(AndroidUtilities.getTypeface("fonts/rmedium.ttf"))
            except:
                pass
            try:
                canvas.save()
                canvas.rotate(-18.0, float(w) / 2.0, float(h) / 2.0)
            except:
                pass
            step_x = max(1, AndroidUtilities.dp(132))
            step_y = max(1, AndroidUtilities.dp(78))
            offset = 0
            y = -step_y
            while y < h + step_y * 2:
                x = -step_x * 2 + offset
                while x < w + step_x * 2:
                    try:
                        canvas.drawText("eblannft", float(x), float(y), paint)
                    except:
                        pass
                    x += step_x
                offset = AndroidUtilities.dp(34) if offset == 0 else 0
                y += step_y
            try:
                canvas.restore()
            except:
                pass
            return bmp
        except Exception as e:
            _log(f"welcome pattern bitmap fail: {e}")
            return None

    def _enable_welcome_sticker_animation(self, sticker_view):
        try:
            receiver = sticker_view.getImageReceiver() if sticker_view is not None and hasattr(sticker_view, "getImageReceiver") else None
        except:
            receiver = None
        if receiver is None:
            return
        try:
            if hasattr(receiver, "setAllowStartAnimation"):
                receiver.setAllowStartAnimation(True)
        except:
            pass
        try:
            if hasattr(receiver, "setAutoRepeat"):
                receiver.setAutoRepeat(1)
        except:
            pass
        try:
            if hasattr(receiver, "startAnimation"):
                receiver.startAnimation()
        except:
            pass

    def _apply_welcome_sticker_document(self, sticker_view, document):
        try:
            if sticker_view is None or document is None or not hasattr(sticker_view, "setImage"):
                return False
            image_location = ImageLocation.getForDocument(document)
            if image_location is None:
                return False
            sticker_view.setImage(image_location, "160_160", None, 0, document)
            self._enable_welcome_sticker_animation(sticker_view)
            try:
                self._welcome_sticker_document_cache = document
            except:
                pass
            return True
        except Exception as e:
            _log(f"apply welcome sticker fail: {e}")
            return False

    def _bind_welcome_pepe_sticker(self, sticker_view):
        if sticker_view is None:
            return False
        try:
            cached = getattr(self, "_welcome_sticker_document_cache", None)
        except:
            cached = None
        if cached is not None and self._apply_welcome_sticker_document(sticker_view, cached):
            return True
        try:
            account = int(UserConfig.selectedAccount)
        except:
            account = 0
        try:
            media_controller = MediaDataController.getInstance(account)
        except:
            media_controller = None
        if media_controller is None:
            return False
        try:
            sticker_set = media_controller.getStickerSetByName(EBLANNFT_WELCOME_STICKER_SET)
        except:
            sticker_set = None
        try:
            if sticker_set and sticker_set.documents and sticker_set.documents.size() > EBLANNFT_WELCOME_STICKER_INDEX:
                doc = sticker_set.documents.get(EBLANNFT_WELCOME_STICKER_INDEX)
                if self._apply_welcome_sticker_document(sticker_view, doc):
                    return True
        except:
            pass
        try:
            input_set = TLRPC.TL_inputStickerSetShortName()
            input_set.short_name = EBLANNFT_WELCOME_STICKER_SET
            plugin_self = self
            target_view = sticker_view

            class _StickerSetCallback(dynamic_proxy(jclass("org.telegram.messenger.Utilities$Callback"))):
                def run(self_obj, result):
                    try:
                        if result and result.documents and result.documents.size() > EBLANNFT_WELCOME_STICKER_INDEX:
                            doc = result.documents.get(EBLANNFT_WELCOME_STICKER_INDEX)
                            try:
                                run_on_ui_thread(lambda: plugin_self._apply_welcome_sticker_document(target_view, doc))
                            except:
                                plugin_self._apply_welcome_sticker_document(target_view, doc)
                    except Exception as inner_e:
                        try:
                            _log(f"welcome sticker callback fail: {inner_e}")
                        except:
                            pass

            media_controller.getStickerSet(input_set, None, False, _StickerSetCallback())
        except Exception as e:
            _log(f"bind welcome sticker fail: {e}")
        return False

    def _style_install_welcome_sheet_surface(self, sheet):
        try:
            if sheet is None:
                return
            targets = []
            try:
                c = sheet.getContainer()
                if c is not None and c not in targets:
                    targets.append(c)
            except:
                pass
            for fname in ("containerView", "container", "sheetContainer", "sheetView"):
                try:
                    v = getattr(sheet, fname, None)
                except:
                    v = None
                if v is not None and v not in targets:
                    targets.append(v)
            for v in targets:
                try:
                    try:
                        v.setBackgroundColor(0x00000000)
                    except:
                        pass
                    try:
                        v.setBackground(None)
                    except:
                        pass
                    try:
                        v.setPadding(0, 0, 0, 0)
                    except:
                        pass
                except:
                    pass
            try:
                w = sheet.getWindow()
            except:
                w = None
            if w is None:
                return
            try:
                w.setBackgroundDrawable(None)
            except:
                pass
            try:
                w.setDimAmount(0.0)
            except:
                pass
            try:
                w.clearFlags(WindowManager.LayoutParams.FLAG_DIM_BEHIND)
            except:
                pass
        except Exception as e:
            _log(f"welcome sheet style fail: {e}")

