    def _save_cache(self, delay_ms=180):
        try:
            uid = self._get_cache_uid()
            data = {}
            data["cache_user_id"] = int(self._get_my_user_id() or 0)
            if self.stolen_gift_inner:
                data["gift_id"] = int(get_val(self.stolen_gift_inner, "gift_id", 0))
                data["title"] = str(get_val(self.stolen_gift_inner, "title", ""))
                data["slug"] = str(get_val(self.stolen_gift_inner, "slug", ""))
                data["num"] = int(get_val(self.stolen_gift_inner, "num", 1))
            if self.build_config:
                data["build_config"] = self.build_config
            data["identity_config"] = self._sanitize_identity_config(getattr(self, "identity_config", None))
            data["value_config"] = self._sanitize_value_config(getattr(self, "value_config", None))
            data["gift_stars_config"] = self._sanitize_gift_stars_config(getattr(self, "gift_stars_config", None))
            data["inject_active"] = self.inject_active
            data["wear_active"] = bool(self.wear_active)
            data["wear_collectible_id"] = int(self.wear_collectible_id or 0)
            data["wear_status_data"] = self.wear_status_data if self.wear_status_data else {}
            data["nft_username_enabled"] = bool(self.nft_username_enabled)
            data["nft_usernames"] = self._get_nft_username_tokens()
            data["nft_username"] = self.nft_username or ""
            data["nft_username_price_ton"] = self.nft_username_price_ton or "0"
            data["nft_username_price_usd"] = self.nft_username_price_usd or "0"
            data["nft_username_purchase_date"] = self.nft_username_purchase_date or ""
            data["nft_collectible_template_b64"] = str(getattr(self, "nft_collectible_template_b64", "") or "")
            data["nft_number_enabled"] = bool(self.nft_number_enabled)
            data["nft_numbers"] = self._get_nft_number_tokens()
            data["nft_number"] = self.nft_number or ""
            data["nft_number_price_ton"] = self.nft_number_price_ton or "0"
            data["nft_number_price_usd"] = self.nft_number_price_usd or "0"
            data["nft_number_purchase_date"] = self.nft_number_purchase_date or ""
            data["nft_number_collectible_template_b64"] = str(getattr(self, "nft_number_collectible_template_b64", "") or "")
            data["local_rating_enabled"] = bool(getattr(self, "local_rating_enabled", False))
            data["local_rating_value"] = int(self._get_local_rating_value() or 0)
            data["local_rating_level"] = int(self._get_local_rating_level() or 1)
            data["local_rating_next_goal"] = int(self._get_local_rating_next_goal() or 5000)
            data["local_stars_balance_enabled"] = bool(getattr(self, "local_stars_balance_enabled", False))
            data["local_stars_balance_value"] = int(self._get_local_stars_balance_value() or 0)
            data["hide_official_gifts_local"] = bool(getattr(self, "hide_official_gifts_local", False))
            data["gift_library"] = self.gift_library or []
            try:
                data["regular_gifts"] = list(self.regular_gifts or [])
            except:
                data["regular_gifts"] = []
            try:
                data["_regular_gifts_seq"] = int(getattr(self, "_regular_gifts_seq", 0) or 0)
            except:
                data["_regular_gifts_seq"] = 0

            try:
                self._cache_pending = (uid, data)
            except:
                pass

            # Cancel prior scheduled write (coalesce frequent saves).
            try:
                fut = getattr(self, "_cache_save_future", None)
                if fut is not None:
                    try:
                        fut.cancel(False)
                    except:
                        pass
            except:
                pass

            def _write():
                try:
                    def _atomic_write_json(path, payload):
                        # Keep a sibling .bak of the *previous* good payload so
                        # we can recover if the main file gets corrupted (truncated
                        # write, FS error, etc.) — wear must never silently fall
                        # off because of a bad read.
                        try:
                            if os.path.exists(path):
                                try:
                                    prev_raw = read_file(path)
                                except:
                                    prev_raw = None
                                if prev_raw:
                                    try:
                                        # Only refresh .bak when the old file is
                                        # still parseable — never replace a good
                                        # backup with a corrupt one.
                                        json.loads(prev_raw)
                                        bak_path = path + ".bak"
                                        bak_tmp = bak_path + ".tmp"
                                        try:
                                            write_file(bak_tmp, prev_raw)
                                            try:
                                                os.replace(bak_tmp, bak_path)
                                            except:
                                                write_file(bak_path, prev_raw)
                                        except:
                                            try:
                                                write_file(bak_path, prev_raw)
                                            except:
                                                pass
                                    except:
                                        pass
                        except:
                            pass

                        tmp_path = path + ".tmp"
                        try:
                            write_file(tmp_path, payload)
                            try:
                                os.replace(tmp_path, path)
                            except:
                                write_file(path, payload)
                        except:
                            write_file(path, payload)

                    # Drain latest snapshot; if more snapshots arrive during IO, write again.
                    while True:
                        pending = getattr(self, "_cache_pending", None)
                        try:
                            self._cache_pending = None
                        except:
                            pass
                        if not pending:
                            break
                        uid2, data2 = pending
                        # Iron-clad wear: if a previous load failed to parse the
                        # on-disk cache, do NOT clobber it with a fresh (possibly
                        # blanked) payload. Persist into a recovery sidecar
                        # instead so the next successful load can pick up either
                        # the old good file or the recovery one.
                        try:
                            load_state = str(getattr(self, "_cache_load_state", "") or "")
                        except:
                            load_state = ""
                        if load_state in ("failed", "pending"):
                            # A "pending" load means we haven't successfully
                            # loaded yet — never overwrite a possibly-good disk
                            # file with our (likely empty) in-memory state.
                            try:
                                payload = json.dumps(data2)
                                rec_path = _cache_path(uid2) + ".recover"
                                _atomic_write_json(rec_path, payload)
                                _log(f"Cache save deferred to recovery (load_state={load_state}): {rec_path}")
                            except Exception as e:
                                _log(f"Cache recovery save error: {e}")
                            continue
                        payload = json.dumps(data2)
                        _atomic_write_json(_cache_path(uid2), payload)
                        if int(uid2 or 0) > 0:
                            try:
                                _atomic_write_json(_cache_path(), payload)
                            except:
                                pass
                        _log("Cache saved")
                except Exception as e:
                    _log(f"Cache save error: {e}")

            try:
                d = int(delay_ms or 0)
            except:
                d = 0
            if d <= 0:
                self._cache_save_future = None
                self._bg_submit(_write, delay_ms=0)
            else:
                self._cache_save_future = self._bg_submit(_write, delay_ms=d)
        except Exception as e:
            _log(f"Cache save error: {e}")

    def _load_cache(self, uid=None):
        try:
            uid = self._get_cache_uid() if uid is None else uid
            primary_path = _cache_path(uid)
            raw = read_file(primary_path)
            loaded_legacy = False
            loaded_from_backup = False
            primary_existed = bool(raw)
            if (not raw) and uid:
                # Backward-compatible: import shared cache once into user-specific file.
                raw = read_file(_cache_path())
                loaded_legacy = bool(raw)
                if loaded_legacy:
                    primary_existed = True
            data = None
            if raw:
                try:
                    data = json.loads(raw)
                except Exception as parse_err:
                    _log(f"Cache parse error on primary: {parse_err}; trying .bak")
                    data = None
            if data is None and primary_existed:
                # Attempt recovery from sibling .bak (created by _save_cache).
                # This makes wear truly iron-clad: a single bad write cannot
                # silently erase the persisted equip state.
                for cand in [primary_path + ".bak", _cache_path() + ".bak"]:
                    try:
                        bak_raw = read_file(cand)
                    except:
                        bak_raw = None
                    if not bak_raw:
                        continue
                    try:
                        data = json.loads(bak_raw)
                        raw = bak_raw
                        loaded_from_backup = True
                        _log(f"Cache recovered from backup: {cand}")
                        break
                    except Exception as e:
                        _log(f"Cache .bak parse error ({cand}): {e}")
                        continue
                if data is None:
                    # Mark the load as failed so subsequent saves do not blow
                    # away the (still possibly recoverable) on-disk file.
                    try:
                        self._cache_load_state = "failed"
                    except:
                        pass
                    _log("Cache load failed; subsequent saves will write to .recover instead of overwriting main")
                    return
            if data is not None:
                try:
                    self._cache_file_user_id = int(data.get("cache_user_id", 0) or 0)
                except:
                    self._cache_file_user_id = 0
                self.cached_gift_id = data.get("gift_id", None)
                cfg = data.get("build_config", None)
                if cfg:
                    self.build_config = cfg
                self.identity_config = self._sanitize_identity_config(data.get("identity_config", None))
                self.value_config = self._sanitize_value_config(data.get("value_config", None))
                self.gift_stars_config = self._sanitize_gift_stars_config(data.get("gift_stars_config", None))
                self.inject_active = data.get("inject_active", False)
                self.wear_active = bool(data.get("wear_active", False))
                self.wear_collectible_id = self._to_int(data.get("wear_collectible_id", 0), 0)
                self.wear_status_data = data.get("wear_status_data", {})
                try:
                    if self.wear_active and self.wear_collectible_id > 0:
                        self._remember_wear_status_snapshot(self.wear_status_data, self.wear_collectible_id)
                except:
                    pass
                self.nft_username_enabled = bool(data.get("nft_username_enabled", False))
                cached_tokens = data.get("nft_usernames", [])
                if not isinstance(cached_tokens, list):
                    cached_tokens = []
                legacy_token = self._normalize_nft_username(data.get("nft_username", ""))
                if legacy_token:
                    cached_tokens.append(legacy_token)
                self._set_nft_username_tokens(cached_tokens)
                self.nft_username_price_ton = str(data.get("nft_username_price_ton", "10.8"))
                self.nft_username_price_usd = str(data.get("nft_username_price_usd", "14.68"))
                self.nft_username_purchase_date = str(data.get("nft_username_purchase_date", ""))
                self.nft_collectible_template_b64 = str(data.get("nft_collectible_template_b64", "") or "")
                self.nft_collectible_template = None

                self.nft_number_enabled = bool(data.get("nft_number_enabled", False))
                cached_nums = data.get("nft_numbers", [])
                if not isinstance(cached_nums, list):
                    cached_nums = []
                legacy_num = self._normalize_nft_number(data.get("nft_number", ""))
                if legacy_num:
                    cached_nums.append(legacy_num)
                self._set_nft_number_tokens(cached_nums)
                self.nft_number_price_ton = str(data.get("nft_number_price_ton", "10.8"))
                self.nft_number_price_usd = str(data.get("nft_number_price_usd", "14.68"))
                self.nft_number_purchase_date = str(data.get("nft_number_purchase_date", ""))
                self.nft_number_collectible_template_b64 = str(data.get("nft_number_collectible_template_b64", "") or "")
                self.nft_number_collectible_template = None
                self.local_rating_enabled = bool(data.get("local_rating_enabled", False))
                self.local_rating_value = self._sanitize_local_rating_value(data.get("local_rating_value", 0))
                self.local_rating_level = self._sanitize_local_rating_level(data.get("local_rating_level", 1))
                self.local_rating_next_goal = self._sanitize_local_rating_next_goal(
                    data.get("local_rating_next_goal", 5000),
                    self.local_rating_value,
                )
                self.local_stars_balance_enabled = bool(data.get("local_stars_balance_enabled", False))
                self.local_stars_balance_value = self._sanitize_local_stars_balance_value(
                    data.get("local_stars_balance_value", 0)
                )
                self.local_verification_mode = 0
                self.hide_official_gifts_local = bool(data.get("hide_official_gifts_local", False))
                self.fake_incoming_text = str(data.get("fake_incoming_text", "Привет! Как дела?") or "Привет! Как дела?")
                self.fake_incoming_delay = "3"
                self.fake_incoming_text = "Привет! Как дела?"
                self.fake_incoming_next_id = -2100000000
                self.fake_incoming_messages = []
                self.channel_data = {}

                lib = data.get("gift_library", [])
                if isinstance(lib, list):
                    self.gift_library = lib
                else:
                    self.gift_library = []
                try:
                    reg = data.get("regular_gifts", [])
                    self.regular_gifts = [r for r in reg if isinstance(r, dict)] if isinstance(reg, list) else []
                except:
                    self.regular_gifts = []
                try:
                    self._regular_gifts_seq = int(data.get("_regular_gifts_seq", 0) or 0)
                except:
                    self._regular_gifts_seq = 0
                # V1 → V2 migration: V1 stored regular gifts in a separate list,
                # detached from gift_library. V2 unifies storage under
                # gift_library with gift_kind='standard'. Move any pre-V2 entries
                # over so the user sees them in the new picker output too.
                try:
                    if self.regular_gifts:
                        migrated = 0
                        for r in list(self.regular_gifts):
                            if not isinstance(r, dict):
                                continue
                            rk = str(r.get("key", "") or "")
                            if rk and any(str(x.get("key", "")) == rk for x in (self.gift_library or []) if isinstance(x, dict)):
                                continue
                            r["gift_kind"] = "standard"
                            r.setdefault("custom_from", "")
                            r.setdefault("custom_date", "")
                            r.setdefault("custom_comment", "")
                            r.setdefault("inject", False)
                            self.gift_library.append(r)
                            migrated += 1
                        if migrated:
                            self.regular_gifts = []
                            _log(f"[my_gifts] migrated {migrated} V1 regular_gifts to gift_library")
                except Exception as _mig_e:
                    try:
                        _log(f"[my_gifts] regular_gifts migration failed: {_mig_e}")
                    except:
                        pass
                # V3 → V4 backfill: route already-saved custom_from values into
                # identity_config.from_user_id (so the existing pipeline patches
                # the StarGiftSheet from peer) and parse custom_date into
                # custom_date_ts. Idempotent.
                try:
                    bf_from = 0
                    bf_date = 0
                    for e in (self.gift_library or []):
                        if not isinstance(e, dict):
                            continue
                        try:
                            cf = str(e.get("custom_from", "") or "").strip()
                        except:
                            cf = ""
                        if cf:
                            ic = e.get("identity_config") if isinstance(e.get("identity_config"), dict) else {}
                            if not isinstance(ic, dict):
                                ic = {}
                            try:
                                cur = int(ic.get("from_user_id", 0) or 0)
                            except:
                                cur = 0
                            if cur <= 0:
                                uid = self._my_gifts_parse_from_uid(cf)
                                if uid > 0:
                                    ic["from_user_id"] = int(uid)
                                    e["identity_config"] = ic
                                    bf_from += 1
                        try:
                            cd = str(e.get("custom_date", "") or "").strip()
                            cdts = int(e.get("custom_date_ts", 0) or 0)
                        except:
                            cd = ""
                            cdts = 0
                        if cd and cdts <= 0:
                            ts = self._my_gifts_parse_date(cd)
                            if ts > 0:
                                e["custom_date_ts"] = int(ts)
                                bf_date += 1
                    if bf_from or bf_date:
                        _log(f"[my_gifts] V4 backfill: from_uid={bf_from} date_ts={bf_date}")
                except Exception as _bf_e:
                    try:
                        _log(f"[my_gifts] V4 backfill failed: {_bf_e}")
                    except:
                        pass
                self.gift_objects = {}
                self._gift_objects_order = []
                self._profile_saved_lists = []
                self._profile_saved_lists_frag_key = 0
                try:
                    self._recompute_gift_objects_limit()
                except:
                    pass
                self._rebuild_injection_payloads()
                if self.wear_active and self.wear_collectible_id > 0:
                    try:
                        if self._sync_wear_status_data_from_library(self.wear_collectible_id):
                            pass
                    except:
                        pass
                    try:
                        self._remember_wear_status_snapshot(self.wear_status_data, self.wear_collectible_id)
                    except:
                        pass
                try:
                    self._cache_load_state = "ok"
                except:
                    pass
                _log(f"Cache loaded: gift_id={self.cached_gift_id}, inject_active={self.inject_active}, wear_active={self.wear_active}, wear_collectible_id={self.wear_collectible_id}, wear_status_data_keys={list(self.wear_status_data.keys())}, from_backup={1 if loaded_from_backup else 0}")
                try:
                    self._debug_state_snapshot("load_cache", f"uid={uid} legacy={1 if loaded_legacy else 0} bak={1 if loaded_from_backup else 0}")
                except:
                    pass
                if loaded_legacy and uid:
                    try:
                        write_file(_cache_path(uid), json.dumps(data))
                        _log(f"Legacy cache imported -> {_cache_path(uid)}")
                    except:
                        pass
                if loaded_from_backup:
                    # Re-stamp the main file from the recovered backup so the
                    # next load goes through the fast path instead of falling
                    # back through .bak again.
                    try:
                        write_file(_cache_path(uid), json.dumps(data))
                        _log("Main cache restored from backup")
                    except Exception as e:
                        _log(f"Main cache restore from backup failed: {e}")
                # If a previous failed-load wrote a .recover sidecar, drop it now
                # — main is good again.
                try:
                    rec_path = _cache_path(uid) + ".recover"
                    if os.path.exists(rec_path):
                        os.remove(rec_path)
                except:
                    pass
            else:
                # File missing entirely — fresh slot. Mark state as "missing"
                # so writes are allowed (this is a new install, not a corrupted
                # cache).
                try:
                    self._cache_load_state = "missing"
                except:
                    pass
        except Exception as e:
            _log(f"Cache load error: {e}")
            try:
                # Unknown failure inside the load block — treat as failed so we
                # don't blow the disk away on next save.
                self._cache_load_state = "failed"
            except:
                pass

    def _save_injection_cache(self):
        """Serialize the injection payload (TL_savedStarGift) to disk."""
        try:
            uid = self._get_cache_uid()
        except:
            uid = 0
        payload = self.injection_payload
        path = _injection_cache_path(uid)

        # Cancel prior scheduled write (coalesce).
        try:
            fut = getattr(self, "_inj_save_future", None)
            if fut is not None:
                try:
                    fut.cancel(False)
                except:
                    pass
        except:
            pass

        def _write():
            try:
                if not payload:
                    # Avoid resurrecting deleted gifts via legacy injection cache import.
                    try:
                        if os.path.exists(path):
                            os.remove(path)
                    except:
                        pass
                    try:
                        legacy_path = _injection_cache_path()
                        if legacy_path != path and os.path.exists(legacy_path):
                            os.remove(legacy_path)
                    except:
                        pass
                    return
                b64 = serialize_tl_object(payload)
                if b64:
                    tmp_path = path + ".tmp"
                    try:
                        write_file(tmp_path, b64)
                        try:
                            os.replace(tmp_path, path)
                        except:
                            write_file(path, b64)
                    except:
                        write_file(path, b64)
                    if int(uid or 0) > 0:
                        try:
                            legacy_path = _injection_cache_path()
                            legacy_tmp = legacy_path + ".tmp"
                            try:
                                write_file(legacy_tmp, b64)
                                try:
                                    os.replace(legacy_tmp, legacy_path)
                                except:
                                    write_file(legacy_path, b64)
                            except:
                                write_file(legacy_path, b64)
                        except:
                            pass
                    _log(f"Injection cache saved ({len(b64)} chars)")
            except Exception as e:
                _log(f"Injection cache save error: {e}")

        # Injection cache is written rarely; do it ASAP in background.
        self._inj_save_future = self._bg_submit(_write, delay_ms=0)

    def _load_injection_cache(self, uid=None):
        """Deserialize the injection payload from disk on startup."""
        try:
            uid = self._get_cache_uid() if uid is None else uid
            raw = read_file(_injection_cache_path(uid))
            loaded_legacy = False
            if (not raw) and uid:
                raw = read_file(_injection_cache_path())
                loaded_legacy = bool(raw)
            if raw and len(raw) > 10:
                obj = deserialize_tl_saved_gift(raw.strip())
                if obj:
                    gift = self._extract_wrapper_gift(obj)
                    slug = str(get_val(gift, "slug", "")) if gift else ""
                    exists = False
                    for e in (self.gift_library or []):
                        if slug and str(e.get("slug", "")) == slug:
                            exists = True
                            break
                    if not exists:
                        self._normalize_saved_gift_for_actions(obj, force_pin=True, update_date=False)
                        self._library_upsert_wrapper(obj, base_gift_id=self.cached_gift_id or 0, key=None, inject=True, make_active=False)
                        self._save_cache()
                        _log("Legacy injection imported to library")
                    if loaded_legacy and uid:
                        try:
                            write_file(_injection_cache_path(uid), raw)
                            _log(f"Legacy injection imported -> {_injection_cache_path(uid)}")
                        except:
                            pass
                else:
                    _log("Injection cache: deserialization returned None")
        except Exception as e:
            _log(f"Injection cache load error: {e}")

    def _clear_cache(self):
        self.stolen_gift_wrapper = None
        self.stolen_gift_inner = None
        self.cls_saved = None
        self.cls_unique = None
        self.injection_payload = None
        self.injection_payloads = []
        self.inject_active = False
        self.gift_library = []
        self.regular_gifts = []
        self._regular_gifts_seq = 0
        self.gift_objects = {}
        self._gift_objects_order = []
        self._gift_objects_max = 12
        self._profile_saved_lists = []
        self._profile_saved_lists_frag_key = 0
        self.editing_gift_key = None
        self.wear_active = False
        self.wear_collectible_id = 0
        self.wear_status_data = {}
        self._wear_status_sync_collectible_id = 0
        self._wear_status_sync_last_ts = 0.0
        self._wear_status_snapshot = {}
        self._wear_status_snapshot_collectible_id = 0
        self._wear_status_snapshot_last_ts = 0.0
        self.cached_gift_id = None
        self.nft_username_enabled = False
        self.nft_usernames = []
        self.nft_username = ""
        self.nft_username_price_ton = "10.8"
        self.nft_username_price_usd = "14.68"
        self.nft_username_purchase_date = ""
        self.nft_collectible_template = None
        self.nft_collectible_template_b64 = ""
        self.nft_number_enabled = False
        self.nft_numbers = []
        self.nft_number = ""
        self.nft_number_price_ton = "10.8"
        self.nft_number_price_usd = "14.68"
        self.nft_number_purchase_date = ""
        self.nft_number_collectible_template = None
        self.nft_number_collectible_template_b64 = ""
        self.local_rating_enabled = False
        self.local_rating_value = 0
        self.local_rating_level = 1
        self.local_rating_next_goal = 5000
        self.local_stars_balance_enabled = False
        self.local_stars_balance_value = 0
        self.hide_official_gifts_local = False
        self._hidden_official_gift_wrappers = []
        self.build_config = {"model": 0, "pattern": 0, "backdrop": 0, "num": 1}
        self.identity_config = self._default_identity_config()
        self.value_config = self._default_value_config()
        self.gift_stars_config = self._default_gift_stars_config()
        try:
            uid = self._get_cache_uid()
            base_paths = [_cache_path(uid), _injection_cache_path(uid)]
            # Also nuke the per-user cache sidecars (.bak / .recover / .tmp)
            # so the iron-clad recovery path can't quietly resurrect state.
            sidecar_paths = []
            for p in base_paths:
                for suffix in (".bak", ".recover", ".tmp"):
                    sidecar_paths.append(p + suffix)
            for p in base_paths + sidecar_paths:
                try:
                    if os.path.exists(p):
                        os.remove(p)
                except:
                    pass
        except:
            pass
        # Treat the user-driven reset as an authoritative clean slate so the
        # subsequent _save_cache call (if any) is allowed through.
        try:
            self._cache_load_state = "missing"
        except:
            pass
        BulletinHelper.show_success("\u041a\u044d\u0448 \u0441\u0431\u0440\u043e\u0448\u0435\u043d")

