    def _patch_profile_overrides_in_user_response(self, response, req_name="", target_user_id=-1):
        if response is None:
            return 0
        try:
            known_target_user_id = int(target_user_id)
        except:
            known_target_user_id = -1

        need_verification = bool(self._is_local_verification_active())
        need_rating = bool(self._is_local_rating_active())
        need_username = bool(self._is_nft_username_active())
        need_number = bool(self._is_nft_number_active())
        need_wear = bool(self.wear_active and int(self.wear_collectible_id or 0) > 0)
        if not (need_verification or need_rating or need_username or need_number or need_wear):
            return 0

        try:
            should_manage_self = bool(
                known_target_user_id <= 0 or self._should_manage_self_saved_gifts(req_user_id=known_target_user_id)
            )
        except:
            should_manage_self = bool(known_target_user_id <= 0)
        try:
            should_apply_rating = bool(
                need_rating and (
                    known_target_user_id <= 0 or self._should_apply_local_rating_for_target(known_target_user_id)
                )
            )
        except:
            should_apply_rating = bool(need_rating and known_target_user_id <= 0)
        if (not should_manage_self) and (not should_apply_rating):
            return 0

        patched = 0
        visited = set()

        def walk(obj, depth):
            nonlocal patched
            if obj is None or depth > 3:
                return
            try:
                oid = int(obj.hashCode())
            except:
                oid = id(obj)
            if oid in visited:
                return
            visited.add(oid)

            changed = False
            if should_manage_self:
                try:
                    if need_verification and self._apply_local_verification_to_full_obj(obj):
                        changed = True
                except:
                    pass
                try:
                    if need_verification and self._apply_local_verification_to_obj(obj):
                        changed = True
                except:
                    pass
                try:
                    if need_username and self._apply_nft_username_to_obj(obj):
                        changed = True
                except:
                    pass
                try:
                    if need_number and self._apply_nft_number_to_obj(obj):
                        changed = True
                except:
                    pass
                try:
                    if need_wear and self._apply_wear_status_only_to_obj(obj):
                        changed = True
                except:
                    pass
            if should_apply_rating:
                try:
                    if self._apply_local_rating_to_obj(obj, known_target_user_id):
                        changed = True
                except:
                    pass
            if changed:
                patched += 1

            if self._is_java_list_like(obj):
                try:
                    size = min(int(obj.size() or 0), 12)
                except:
                    size = 0
                for i in range(size):
                    try:
                        walk(obj.get(i), depth + 1)
                    except:
                        continue
                return

            for f in self._iter_object_fields(obj):
                try:
                    val = f.get(obj)
                except:
                    continue
                if val is None:
                    continue
                try:
                    fname = str(f.getName() or "").lower()
                except:
                    fname = ""
                try:
                    typ = str(f.getType().getName() or "")
                except:
                    typ = ""
                if typ in ["int", "long", "boolean", "float", "double", "java.lang.String"]:
                    continue
                if depth > 0 and fname and ("user" not in fname and "full" not in fname and "rating" not in fname and "peer" not in fname and "chat" not in fname and "emoji" not in fname and "status" not in fname and "username" not in fname and "phone" not in fname and "number" not in fname):
                    continue
                try:
                    walk(val, depth + 1)
                except:
                    continue

        walk(response, 0)
        if patched:
            try:
                _log(f"User response overrides patched ({req_name}): {patched}")
            except:
                pass
        return int(patched or 0)

    def _build_my_peer_user(self):
        try:
            my_id = self._get_my_user_id()
            if my_id <= 0:
                return None
            PeerUser = jclass("org.telegram.tgnet.TLRPC$TL_peerUser")
            peer = PeerUser()
            peer.user_id = my_id
            return peer
        except:
            return None

    def _build_peer_user(self, user_id):
        try:
            uid = int(user_id or 0)
        except:
            uid = 0
        if uid <= 0:
            return None
        try:
            PeerUser = jclass("org.telegram.tgnet.TLRPC$TL_peerUser")
            peer = PeerUser()
            peer.user_id = uid
            return peer
        except:
            return None

    def _resolve_identity_user_id(self, raw_uid, fallback_uid=0):
        try:
            uid = int(raw_uid or 0)
        except:
            uid = 0
        if uid > 0:
            return uid
        try:
            fb = int(fallback_uid or 0)
        except:
            fb = 0
        if fb > 0:
            return fb
        return int(self._get_my_user_id() or 0)

    def _set_user_ref_fields(self, obj, field_names, user_id):
        if obj is None:
            return False
        try:
            uid = int(user_id or 0)
        except:
            uid = 0
        if uid <= 0:
            return False
        peer = self._build_peer_user(uid)
        ok = False
        for name in field_names or []:
            try:
                if peer is not None and self._set_field(obj, name, peer):
                    ok = True
                    continue
            except:
                pass
            try:
                if self._set_field(obj, name, int(uid)):
                    ok = True
            except:
                pass
        return ok

    def _extract_identity_config_from_objects(self, gift=None, wrapper=None):
        cfg = self._default_identity_config()

        def _pick_uid(obj, field_names):
            for field_name in field_names:
                try:
                    val = get_val(obj, field_name, None)
                except:
                    val = None
                uid = self._extract_user_id_from_obj(val)
                if uid > 0:
                    return uid
            return 0

        try:
            owner_uid = _pick_uid(gift, ["owner_id", "owner", "ownerId"])
            cfg["owner_user_id"] = self._normalize_identity_uid_for_storage(owner_uid)
        except:
            pass
        try:
            from_uid = _pick_uid(wrapper, ["from_id", "fromId", "saved_from_id", "savedFromId", "sender_id", "senderId", "sender"])
            cfg["from_user_id"] = self._normalize_identity_uid_for_storage(from_uid)
        except:
            pass
        try:
            to_uid = _pick_uid(wrapper, ["to_id", "toId", "peer", "peer_id", "peerId", "recipient", "recipient_id", "recipientId"])
            if to_uid <= 0:
                try:
                    to_uid = owner_uid
                except:
                    to_uid = 0
            cfg["to_user_id"] = self._normalize_identity_uid_for_storage(to_uid)
        except:
            pass
        return self._sanitize_identity_config(cfg)

    def _apply_identity_config_to_objects(self, gift=None, wrapper=None, identity_config=None):
        cfg = self._sanitize_identity_config(identity_config)
        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0

        owner_uid = self._resolve_identity_user_id(cfg.get("owner_user_id", 0), fallback_uid=my_id)
        from_uid = self._resolve_identity_user_id(cfg.get("from_user_id", 0), fallback_uid=my_id)
        to_uid = self._resolve_identity_user_id(cfg.get("to_user_id", 0), fallback_uid=owner_uid or my_id)

        try:
            self._set_user_ref_fields(gift, ["owner_id", "owner", "ownerId"], owner_uid)
        except:
            pass
        try:
            self._set_user_ref_fields(wrapper, ["owner_id", "owner", "ownerId"], owner_uid)
        except:
            pass
        try:
            self._set_user_ref_fields(wrapper, ["from_id", "fromId", "saved_from_id", "savedFromId", "sender_id", "senderId", "sender"], from_uid)
        except:
            pass
        try:
            self._set_user_ref_fields(wrapper, ["to_id", "toId", "peer", "peer_id", "peerId", "recipient", "recipient_id", "recipientId"], to_uid)
        except:
            pass

        return {
            "owner_user_id": self._normalize_identity_uid_for_storage(cfg.get("owner_user_id", 0)),
            "from_user_id": self._normalize_identity_uid_for_storage(cfg.get("from_user_id", 0)),
            "to_user_id": self._normalize_identity_uid_for_storage(cfg.get("to_user_id", 0)),
        }

    def _convert_entity_to_chat_id(self, entity_id):
        try:
            eid = int(entity_id or 0)
        except:
            eid = 0
        if eid >= 0:
            return 0
        if str(eid).startswith("-100"):
            return abs(eid) - 1000000000000
        return abs(eid)

    def _build_peer_channel(self, entity_id):
        try:
            chat_id = int(self._convert_entity_to_chat_id(entity_id) or 0)
        except:
            chat_id = 0
        if chat_id <= 0:
            return None
        try:
            PeerChannel = jclass("org.telegram.tgnet.TLRPC$TL_peerChannel")
            peer = PeerChannel()
            peer.channel_id = chat_id
            return peer
        except:
            return None

    def _build_peer_chat(self, entity_id):
        try:
            chat_id = int(self._convert_entity_to_chat_id(entity_id) or 0)
        except:
            chat_id = 0
        if chat_id <= 0:
            return None
        try:
            PeerChat = jclass("org.telegram.tgnet.TLRPC$TL_peerChat")
            peer = PeerChat()
            peer.chat_id = chat_id
            return peer
        except:
            return None

    def _build_peer_for_entity(self, entity_id):
        try:
            eid = int(entity_id or 0)
        except:
            eid = 0
        if eid > 0:
            return self._build_peer_user(eid)
        if eid <= -1000000000000:
            return self._build_peer_channel(eid)
        if eid < 0:
            return self._build_peer_chat(eid)
        return None

    def _sanitize_fake_incoming_records(self, records):
        return []
        out = []
        seen = set()
        for raw in list(records or []):
            try:
                dialog_id = int(getattr(raw, "get", lambda *_: 0)("dialog_id", 0) if isinstance(raw, dict) else 0)
            except:
                try:
                    dialog_id = int(raw.get("dialog_id", 0))
                except:
                    dialog_id = 0
            try:
                message_id = int(raw.get("message_id", 0))
            except:
                message_id = 0
            text = str(raw.get("text", "") or "").strip() if isinstance(raw, dict) else ""
            try:
                date = int(raw.get("date", 0))
            except:
                date = 0
            try:
                unread = bool(raw.get("unread", True))
            except:
                unread = True
            if dialog_id == 0 or message_id == 0 or not text:
                continue
            if len(text) > 4096:
                text = text[:4096]
            if date <= 0:
                try:
                    date = int(time.time())
                except:
                    date = 0
            key = f"{int(dialog_id)}:{int(message_id)}"
            if key in seen:
                continue
            seen.add(key)
            out.append({
                "dialog_id": int(dialog_id),
                "message_id": int(message_id),
                "text": text,
                "date": int(date),
                "unread": bool(unread),
            })
        out.sort(key=lambda item: (int(item.get("date", 0) or 0), int(item.get("message_id", 0) or 0)))
        if len(out) > 200:
            out = out[-200:]
        return out

    def _allocate_fake_incoming_message_id(self):
        try:
            current = int(getattr(self, "fake_incoming_next_id", -2100000000) or -2100000000)
        except:
            current = -2100000000
        if current >= -1 or current <= -2147483000:
            current = -2100000000
        try:
            self.fake_incoming_next_id = int(current) - 1
        except:
            self.fake_incoming_next_id = -2100000001
        return int(current)

    def _upsert_fake_incoming_record(self, record):
        current = self._sanitize_fake_incoming_records(getattr(self, "fake_incoming_messages", None))
        normalized = self._sanitize_fake_incoming_records([record])
        if not normalized:
            return None
        rec = normalized[0]
        key = f"{int(rec.get('dialog_id', 0))}:{int(rec.get('message_id', 0))}"
        merged = [item for item in current if f"{int(item.get('dialog_id', 0))}:{int(item.get('message_id', 0))}" != key]
        merged.append(rec)
        self.fake_incoming_messages = self._sanitize_fake_incoming_records(merged)
        return rec

    def _get_fake_incoming_records_for_dialog(self, dialog_id, due_only=True):
        try:
            did = int(dialog_id or 0)
        except:
            did = 0
        if did == 0:
            return []
        now_ts = int(time.time())
        out = []
        for item in self._sanitize_fake_incoming_records(getattr(self, "fake_incoming_messages", None)):
            try:
                item_did = int(item.get("dialog_id", 0) or 0)
            except:
                item_did = 0
            if item_did != did:
                continue
            try:
                item_date = int(item.get("date", 0) or 0)
            except:
                item_date = 0
            if due_only and item_date > now_ts:
                continue
            out.append(item)
        return out

    def _build_fake_incoming_message_object(self, account, record):
        try:
            dialog_id = int(record.get("dialog_id", 0) or 0)
            message_id = int(record.get("message_id", 0) or 0)
        except:
            return None
        if dialog_id == 0 or message_id == 0:
            return None
        try:
            peer = self._build_peer_for_entity(dialog_id)
        except:
            peer = None
        if peer is None:
            return None
        try:
            TL_message = jclass("org.telegram.tgnet.TLRPC$TL_message")
            msg = TL_message()
            msg.id = int(message_id)
            msg.peer_id = peer
            msg.from_id = self._build_peer_for_entity(dialog_id)
            msg.dialog_id = int(dialog_id)
            msg.message = str(record.get("text", "") or "")
            msg.date = int(record.get("date", int(time.time())) or int(time.time()))
            msg.out = False
            msg.unread = bool(record.get("unread", True))
            msg.flags = 256
            if msg.from_id is None:
                return None
            return MessageObject(int(account or 0), msg, False, True)
        except Exception as e:
            _log(f"build fake incoming object error: {e}")
            return None

    def _is_chat_activity_fragment(self, fragment):
        if fragment is None:
            return False
        try:
            name = str(fragment.getClass().getName() or "")
        except:
            name = ""
        return bool("ChatActivity" in name)

    def _get_chat_activity_dialog_id(self, chat_activity=None):
        frag = chat_activity if chat_activity is not None else get_last_fragment()
        if frag is None or not self._is_chat_activity_fragment(frag):
            return 0
        try:
            return int(frag.getDialogId() or 0)
        except:
            pass
        try:
            return int(get_val(frag, "dialog_id", 0) or 0)
        except:
            return 0

    def _get_chat_activity_account(self, chat_activity=None):
        frag = chat_activity if chat_activity is not None else get_last_fragment()
        try:
            return int(get_val(frag, "currentAccount", get_user_config().selectedAccount) or 0)
        except:
            try:
                return int(UserConfig.selectedAccount)
            except:
                return 0

    def _apply_persistent_fake_messages_to_dialog(self, account, dialog_id, force=False):
        try:
            dialog_id = int(dialog_id or 0)
        except:
            dialog_id = 0
        if dialog_id == 0:
            return False
        try:
            account = int(account or 0)
        except:
            account = 0
        key = f"{int(account)}:{int(dialog_id)}"
        now_ts = time.time()
        if not force:
            try:
                last_ts = float((getattr(self, "_fake_incoming_restore_last", None) or {}).get(key, 0.0) or 0.0)
            except:
                last_ts = 0.0
            if (now_ts - last_ts) < 0.16:
                return False
        items = self._get_fake_incoming_records_for_dialog(dialog_id, due_only=True)
        if not items:
            return False
        obj_list = ArrayList()
        added = 0
        for item in items:
            obj = self._build_fake_incoming_message_object(account, item)
            if obj is None:
                continue
            obj_list.add(obj)
            added += 1
        if added <= 0:
            return False
        try:
            MessagesController.getInstance(account).updateInterfaceWithMessages(int(dialog_id), obj_list, 0)
            try:
                NotificationCenter.getInstance(account).postNotificationName(NotificationCenter.dialogsNeedReload)
            except:
                pass
            try:
                restore_map = getattr(self, "_fake_incoming_restore_last", None)
                if not isinstance(restore_map, dict):
                    restore_map = {}
                    self._fake_incoming_restore_last = restore_map
                restore_map[key] = now_ts
            except:
                pass
            return True
        except Exception as e:
            _log(f"apply fake incoming dialog error: {e}")
            return False

    def _schedule_fake_incoming_restore(self, chat_activity=None, delays=None):
        frag = chat_activity if chat_activity is not None else get_last_fragment()
        if frag is None or not self._is_chat_activity_fragment(frag):
            return False
        dialog_id = self._get_chat_activity_dialog_id(frag)
        if dialog_id == 0:
            return False
        account = self._get_chat_activity_account(frag)
        try:
            frag_key = int(frag.hashCode())
        except:
            frag_key = 0

        def _run(_dialog_id=dialog_id, _account=account, _frag_key=frag_key):
            try:
                active = get_last_fragment()
            except:
                active = None
            if active is None or not self._is_chat_activity_fragment(active):
                return
            try:
                active_key = int(active.hashCode())
            except:
                active_key = 0
            if int(_frag_key or 0) > 0 and int(active_key or 0) != int(_frag_key or 0):
                return
            if int(self._get_chat_activity_dialog_id(active) or 0) != int(_dialog_id or 0):
                return
            self._apply_persistent_fake_messages_to_dialog(_account, _dialog_id, force=False)

        return self._schedule_ui_batch(
            f"fake_incoming_restore_{int(frag_key or 0)}_{int(dialog_id or 0)}",
            _run,
            [0, 120, 420] if delays is None else delays,
        )

    def _resolve_fake_incoming_target(self, context=None):
        ctx = context if isinstance(context, dict) else {}
        try:
            account = int(ctx.get("account"))
        except:
            account = None
        if account is None:
            try:
                account = int(get_user_config().selectedAccount)
            except:
                try:
                    account = int(UserConfig.selectedAccount)
                except:
                    account = 0

        dialog_id = 0
        for key in ["dialog_id", "dialogId", "peer_id", "peerId", "peer"]:
            try:
                raw = ctx.get(key)
            except:
                raw = None
            try:
                raw = int(raw or 0)
            except:
                raw = 0
            if raw:
                dialog_id = raw
                break

        if not dialog_id:
            try:
                frag = ctx.get("fragment") or get_last_fragment()
            except:
                frag = None
            try:
                dialog_id = int(frag.getDialogId() or 0) if frag is not None else 0
            except:
                dialog_id = 0

        return int(account or 0), int(dialog_id or 0)

    def _resolve_entity_display_name(self, entity_id, account=None):
        try:
            eid = int(entity_id or 0)
        except:
            eid = 0
        try:
            acc = int(get_user_config().selectedAccount if account is None else account)
        except:
            acc = 0
        try:
            mc = MessagesController.getInstance(acc)
        except:
            mc = None
        if mc is not None and eid > 0:
            try:
                user = mc.getUser(int(eid))
            except:
                user = None
            if user is not None:
                try:
                    first_name = str(get_val(user, "first_name", "") or get_val(user, "firstName", "") or "").strip()
                    last_name = str(get_val(user, "last_name", "") or get_val(user, "lastName", "") or "").strip()
                    full_name = (first_name + " " + last_name).strip()
                    if full_name:
                        return full_name
                except:
                    pass
                try:
                    username = str(get_val(user, "username", "") or "").strip()
                    if username:
                        return username
                except:
                    pass
        if mc is not None and eid < 0:
            try:
                chat_id = int(self._convert_entity_to_chat_id(eid) or 0)
            except:
                chat_id = 0
            if chat_id > 0:
                try:
                    chat = mc.getChat(chat_id)
                except:
                    chat = None
                if chat is not None:
                    try:
                        title = str(get_val(chat, "title", "") or get_val(chat, "name", "") or "").strip()
                        if title:
                            return title
                    except:
                        pass
        return "Пользователь" if eid > 0 else "Чат"

    def _resolve_identity_entity_id(self, raw_uid, fallback_uid=0):
        try:
            uid = int(raw_uid or 0)
        except:
            uid = 0
        if uid != 0:
            return uid
        try:
            fb = int(fallback_uid or 0)
        except:
            fb = 0
        if fb != 0:
            return fb
        return int(self._get_my_user_id() or 0)

    def _resolve_identity_user_id(self, raw_uid, fallback_uid=0):
        try:
            uid = int(self._resolve_identity_entity_id(raw_uid, fallback_uid=fallback_uid) or 0)
        except:
            uid = 0
        if uid > 0:
            return uid
        try:
            fb = int(fallback_uid or 0)
        except:
            fb = 0
        if fb > 0:
            return fb
        return int(self._get_my_user_id() or 0)

    def _set_user_ref_fields(self, obj, field_names, user_id):
        if obj is None:
            return False
        try:
            eid = int(user_id or 0)
        except:
            eid = 0
        if eid == 0:
            return False
        peer = self._build_peer_for_entity(eid)
        ok = False
        for name in field_names or []:
            try:
                if peer is not None and self._set_field(obj, name, peer):
                    ok = True
                    continue
            except:
                pass
            try:
                if self._set_field(obj, name, int(eid)):
                    ok = True
            except:
                pass
        return ok

    def _extract_identity_config_from_objects(self, gift=None, wrapper=None):
        cfg = self._default_identity_config()

        def _pick_uid(obj, field_names):
            for field_name in field_names:
                try:
                    val = get_val(obj, field_name, None)
                except:
                    val = None
                uid = self._extract_entity_id_from_obj(val)
                if uid != 0:
                    return uid
            return 0

        owner_uid = 0
        try:
            owner_uid = _pick_uid(gift, ["owner_id", "owner", "ownerId"])
            cfg["owner_user_id"] = self._normalize_identity_uid_for_storage(owner_uid)
        except:
            pass
        try:
            from_uid = _pick_uid(wrapper, ["from_id", "fromId", "saved_from_id", "savedFromId", "sender_id", "senderId", "sender"])
            cfg["from_user_id"] = self._normalize_identity_uid_for_storage(from_uid)
        except:
            pass
        try:
            to_uid = _pick_uid(wrapper, ["to_id", "toId", "peer", "peer_id", "peerId", "recipient", "recipient_id", "recipientId"])
            if to_uid == 0:
                to_uid = owner_uid
            cfg["to_user_id"] = self._normalize_identity_uid_for_storage(to_uid)
        except:
            pass
        return self._sanitize_identity_config(cfg)

    def _apply_identity_config_to_objects(self, gift=None, wrapper=None, identity_config=None):
        cfg = self._sanitize_identity_config(identity_config)
        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0

        owner_uid = self._resolve_identity_entity_id(cfg.get("owner_user_id", 0), fallback_uid=my_id)
        from_uid = self._resolve_identity_entity_id(cfg.get("from_user_id", 0), fallback_uid=my_id)
        to_uid = self._resolve_identity_entity_id(cfg.get("to_user_id", 0), fallback_uid=owner_uid or my_id)

        try:
            self._set_user_ref_fields(gift, ["owner_id", "owner", "ownerId"], owner_uid)
        except:
            pass
        try:
            self._set_user_ref_fields(wrapper, ["owner_id", "owner", "ownerId"], owner_uid)
        except:
            pass
        try:
            self._set_user_ref_fields(wrapper, ["from_id", "fromId", "saved_from_id", "savedFromId", "sender_id", "senderId", "sender"], from_uid)
        except:
            pass
        try:
            self._set_user_ref_fields(wrapper, ["to_id", "toId", "peer", "peer_id", "peerId", "recipient", "recipient_id", "recipientId"], to_uid)
        except:
            pass

        return {
            "owner_user_id": self._normalize_identity_uid_for_storage(cfg.get("owner_user_id", 0)),
            "from_user_id": self._normalize_identity_uid_for_storage(cfg.get("from_user_id", 0)),
            "to_user_id": self._normalize_identity_uid_for_storage(cfg.get("to_user_id", 0)),
        }

    def _apply_gift_stars_config_to_objects(self, gift=None, wrapper=None, stars_config=None):
        cfg = self._sanitize_gift_stars_config(stars_config)
        amount = int(cfg.get("amount", 0) or 0)
        if amount <= 0:
            return cfg

        targets = [
            (gift, ["stars", "upgrade_stars", "resell_min_stars", "offer_min_stars"]),
            (wrapper, ["upgrade_stars", "transfer_stars", "convert_stars", "resell_min_stars", "resell_amount"]),
        ]
        for obj, names in targets:
            if obj is None:
                continue
            for field_name in names:
                try:
                    self._set_field(obj, field_name, int(amount))
                except:
                    pass
                try:
                    if hasattr(obj, field_name):
                        setattr(obj, field_name, int(amount))
                except:
                    pass
        return cfg

    def _get_my_user_object(self):
        try:
            my_id = self._get_my_user_id()
            if my_id <= 0:
                return None
            account = to_java_int(get_user_config().selectedAccount)
            MessagesController = jclass("org.telegram.messenger.MessagesController")
            ctrl = MessagesController.getInstance(account)
            return ctrl.getUser(my_id)
        except:
            return None

    def _extract_collectible_request_token(self, req):
        if req is None:
            return ""
        managed = [t.lower() for t in self._get_nft_username_tokens()]
        visited = set()

        def _pick_from_raw(raw):
            token = self._normalize_nft_username(raw)
            if not token:
                return ""
            if managed and token.lower() in managed:
                return token
            return token

        def _walk(obj, depth=0):
            if obj is None or depth > 3:
                return ""
            try:
                oid = int(obj.hashCode())
            except:
                oid = id(obj)
            if oid in visited:
                return ""
            visited.add(oid)

            try:
                cls_name_l = str(obj.getClass().getSimpleName() or "").lower()
            except:
                cls_name_l = ""
            if "inputcollectibleusername" in cls_name_l:
                for direct_name in ["username", "slug", "name", "value", "text"]:
                    try:
                        token = _pick_from_raw(get_val(obj, direct_name, None))
                    except:
                        token = ""
                    if token:
                        return token
            elif ("inputcollectiblephone" in cls_name_l) or ("inputcollectiblenumber" in cls_name_l):
                return ""

            try:
                nested_collectible = get_val(obj, "collectible", None)
            except:
                nested_collectible = None
            if nested_collectible is not None and depth < 3:
                token = _walk(nested_collectible, depth + 1)
                if token:
                    return token

            for field_name in ["username", "slug", "name", "query", "value", "text"]:
                try:
                    raw = get_val(obj, field_name, None)
                    if raw is None:
                        continue
                    token = _pick_from_raw(raw)
                    if token:
                        return token
                except:
                    pass
            try:
                for f in self._iter_object_fields(obj):
                    try:
                        f_type = str(f.getType().getName() or "")
                        raw = f.get(obj)
                    except:
                        continue
                    if raw is None:
                        continue
                    if f_type == "java.lang.String":
                        token = _pick_from_raw(raw)
                        if token:
                            return token
                        continue
                    if depth >= 3:
                        continue
                    try:
                        if hasattr(raw, "size") and hasattr(raw, "get"):
                            size = min(int(raw.size() or 0), 8)
                            for i in range(size):
                                try:
                                    token = _walk(raw.get(i), depth + 1)
                                except:
                                    token = ""
                                if token:
                                    return token
                            continue
                    except:
                        pass
                    low_type = f_type.lower()
                    if "org.telegram" in low_type or "tlrpc" in low_type or "fragment" in low_type:
                        token = _walk(raw, depth + 1)
                        if token:
                            return token
            except:
                pass
            return ""

        token = _walk(req, 0)
        if token:
            return token
        return ""

    def _extract_collectible_request_kind_and_token(self, req):
        """
        Best-effort detection for Fragment collectible info requests.
        Returns ("username", token) or ("number", digits) or ("", "").
        """
        if req is None:
            return ("", "")

        visited = set()

        def _iter_strings(obj, depth=0):
            if obj is None or depth > 3:
                return
            try:
                oid = int(obj.hashCode())
            except:
                oid = id(obj)
            if oid in visited:
                return
            visited.add(oid)

            try:
                cls_name_l = str(obj.getClass().getSimpleName() or "").lower()
            except:
                cls_name_l = ""
            if "inputcollectiblephone" in cls_name_l:
                for direct_name in ["phone", "phone_number", "number", "value", "text"]:
                    try:
                        raw = get_val(obj, direct_name, None)
                    except:
                        raw = None
                    if raw is not None:
                        yield (direct_name, raw)
                return
            if "inputcollectibleusername" in cls_name_l:
                for direct_name in ["username", "slug", "name", "value", "text"]:
                    try:
                        raw = get_val(obj, direct_name, None)
                    except:
                        raw = None
                    if raw is not None:
                        yield ("username", raw)
                return

            try:
                nested_collectible = get_val(obj, "collectible", None)
            except:
                nested_collectible = None
            if nested_collectible is not None and depth < 3:
                for item in _iter_strings(nested_collectible, depth + 1):
                    yield item

            # Prefer common field names first.
            for field_name in ["phone", "phone_number", "number", "username", "slug", "name", "query", "value", "text"]:
                try:
                    raw = get_val(obj, field_name, None)
                    if raw is not None:
                        yield (field_name, raw)
                except:
                    pass
            try:
                for f in self._iter_object_fields(obj):
                    try:
                        f_name = str(f.getName() or "")
                        f_type = str(f.getType().getName() or "")
                    except:
                        continue
                    try:
                        raw = f.get(obj)
                    except:
                        continue
                    if raw is None:
                        continue
                    if f_type == "java.lang.String":
                        yield (f_name, raw)
                        continue
                    if depth >= 3:
                        continue
                    low_type = f_type.lower()
                    low_name = f_name.lower()
                    if "org.telegram" in low_type or "tlrpc" in low_type or "fragment" in low_type or "username" in low_name or "phone" in low_name or "query" in low_name:
                        for item in _iter_strings(raw, depth + 1):
                            yield item
                        continue
                    try:
                        if hasattr(raw, "size") and hasattr(raw, "get"):
                            size = min(int(raw.size() or 0), 8)
                            for i in range(size):
                                try:
                                    nested = raw.get(i)
                                except:
                                    continue
                                for item in _iter_strings(nested, depth + 1):
                                    yield item
                    except:
                        pass
            except:
                pass

        # 1) Phone-like candidates (field name hint).
        for field_name, raw in _iter_strings(req, 0):
            try:
                low = str(field_name or "").lower()
            except:
                low = ""
            if ("phone" in low) or (low == "number") or ("phone_number" in low):
                num = self._normalize_nft_number(raw)
                if num:
                    return ("number", num)

        # 2) Username-like candidates (field name hint).
        for field_name, raw in _iter_strings(req):
            try:
                low = str(field_name or "").lower()
            except:
                low = ""
            if ("user" in low) or (low in ["username", "slug", "name", "query"]):
                token = self._normalize_nft_username(raw)
                if token and re.search(r"[A-Za-z_]", token):
                    return ("username", token)

        # 3) Fallback: scan any string values.
        for _, raw in _iter_strings(req, 0):
            num = self._normalize_nft_number(raw)
            if num:
                return ("number", num)
            token = self._normalize_nft_username(raw)
            if token and re.search(r"[A-Za-z_]", token):
                return ("username", token)

        return ("", "")

    def _create_fake_collectible_response(self, token):
        token = self._normalize_nft_username(token)
        if not token:
            return None

        raw_b64 = str(getattr(self, "nft_collectible_template_b64", "") or "").strip()
        if raw_b64:
            try:
                cloned = deserialize_fragment_collectible_info(raw_b64)
            except:
                cloned = None
            if cloned is not None:
                return cloned
        if self.nft_collectible_template is not None:
            try:
                raw_b64 = serialize_tl_object(self.nft_collectible_template)
            except:
                raw_b64 = None
            if raw_b64:
                try:
                    self.nft_collectible_template_b64 = str(raw_b64)
                except:
                    pass
                try:
                    cloned = deserialize_fragment_collectible_info(raw_b64)
                except:
                    cloned = None
                if cloned is not None:
                    return cloned
            return self.nft_collectible_template

        candidates = [
            "org.telegram.tgnet.tl.TL_fragment$TL_collectibleInfo",
            "org.telegram.tgnet.tl.TL_fragment$TL_collectible_info",
            "org.telegram.tgnet.tl.TL_fragment$TL_fragmentCollectibleInfo",
            "org.telegram.tgnet.tl.TL_fragment$TL_fragment_collectibleInfo",
        ]
        for cls_name in candidates:
            try:
                cls = jclass(cls_name)
                obj = cls()
                return obj
            except:
                pass
        return None

