    def _get_profile_activity_user_id(self, profile_activity):
        """Best-effort resolve target user_id for ProfileActivity instance."""
        if profile_activity is None:
            return 0
        for name in ["userId", "user_id", "uid", "currentUserId", "current_user_id", "dialogId", "dialog_id", "peerId", "peer_id"]:
            try:
                v = get_val(profile_activity, name, None)
                if v is None:
                    continue
                uid = self._to_int(v, 0)
                if uid > 0:
                    return uid
            except:
                pass
        for name in ["user", "currentUser", "userInfo", "userFull"]:
            try:
                u = get_val(profile_activity, name, None)
                if u is None:
                    continue
                try:
                    nested = get_val(u, "user", None)
                    if nested is not None:
                        u = nested
                except:
                    pass
                uid = self._to_int(get_val(u, "id", 0), 0)
                if uid > 0:
                    return uid
            except:
                pass
        return 0

    def _get_profile_activity_entity_id(self, profile_activity):
        if profile_activity is None:
            return 0
        for name in ["dialogId", "dialog_id", "peerId", "peer_id", "chatId", "chat_id", "userId", "user_id", "uid", "currentUserId", "current_user_id"]:
            try:
                v = get_val(profile_activity, name, None)
            except:
                v = None
            if v is None:
                continue
            try:
                eid = int(self._to_int(v, 0) or 0)
            except:
                eid = 0
            if eid != 0:
                return eid
        for name in ["user", "currentUser", "userInfo", "userFull", "chat", "currentChat", "chatInfo", "chatFull"]:
            try:
                obj = get_val(profile_activity, name, None)
            except:
                obj = None
            if obj is None:
                continue
            try:
                nested = get_val(obj, "user", None) or get_val(obj, "chat", None)
                if nested is not None:
                    obj = nested
            except:
                pass
            try:
                eid = int(self._extract_entity_id_from_obj(obj) or 0)
            except:
                eid = 0
            if eid != 0:
                return eid
        return 0

    def _get_profile_activity_user_id(self, profile_activity):
        try:
            eid = int(self._get_profile_activity_entity_id(profile_activity) or 0)
        except:
            eid = 0
        if eid > 0:
            return eid
        return 0

    def _patch_profile_activity_in_place(self, profile_activity, notify=True, include_major_views=True):
        """Patch ProfileActivity fields directly to avoid 'blink' on first render."""
        if profile_activity is None:
            return 0
        try:
            is_my_profile = bool(self._is_my_profile_activity(profile_activity))
        except:
            is_my_profile = False
        if not is_my_profile:
            return 0
        allow_profile_context_fallback = True
        patched = 0
        for name in ["user", "currentUser", "userInfo", "userFull", "currentUserInfo", "currentUserFull", "chat", "currentChat", "chatInfo", "chatFull", "currentChatInfo", "currentChatFull"]:
            try:
                obj = get_val(profile_activity, name, None)
                if obj is None:
                    continue
                if self._apply_profile_overrides_to_obj(obj, allow_profile_context_fallback=allow_profile_context_fallback):
                    patched += 1
                try:
                    nested = get_val(obj, "user", None)
                    if nested is not None and self._apply_profile_overrides_to_obj(nested, allow_profile_context_fallback=allow_profile_context_fallback):
                        patched += 1
                except:
                    pass
            except:
                pass
        try:
            patched += int(self._patch_profile_activity_boosts(profile_activity) or 0)
        except:
            pass
        try:
            patched += int(self._patch_profile_shared_media_layout(profile_activity, animated=False) or 0)
        except:
            pass
        try:
            if include_major_views:
                patched += int(self._patch_local_major_profile_views(profile_activity) or 0)
        except:
            pass
        try:
            if patched and notify:
                self._notify_profile_activity_adapters_light(profile_activity)
        except:
            pass
        return patched

