    def _open_local_gift_value_menu(self, key, sheet=None, context=None):
        e = self._library_find_entry(key)
        if not e:
            BulletinHelper.show_error("Подарок не найден")
            return False
        cfg = self._sanitize_value_config(e.get("value_config", None))
        stars_cfg = self._sanitize_gift_stars_config(e.get("gift_stars_config", None))
        stars_subtitle = self._format_gift_stars_text(stars_cfg, placeholder="не заданы")
        title = "Локальная ценность"
        subtitle = self._format_local_value_text(cfg, placeholder="не задана", include_tilde=True, include_code=True)

        def _open_constructor():
            def _run():
                try:
                    if sheet is not None:
                        sheet.dismiss()
                except:
                    pass
                try:
                    self._open_constructor_for_library_key(key)
                except Exception as ex:
                    BulletinHelper.show_error(f"Не удалось открыть конструктор: {ex}")

            try:
                AndroidUtilities.runOnUIThread(JRunnable(_run), 90)
            except:
                _run()

        actions = [
            (f"Текущее значение • {subtitle}", _open_constructor),
            (f"Локальные звёзды • {stars_subtitle}", lambda: self._open_local_gift_stars_dialog(key)),
            ("Изменить в конструкторе", _open_constructor),
        ]
        if self._is_gift_stars_config_active(stars_cfg):
            actions.append(("Сбросить локальные звёзды", lambda: self._save_library_gift_stars_config(key, "0")))
        self._show_action_menu(title, actions, negative_text="Назад", context=context)
        return True

    def _inject_local_gift_value_row(self, sheet, gift=None):
        if sheet is None:
            return False
        key = None
        try:
            key = self._resolve_library_key_from_gift_sheet(sheet)
        except:
            key = None
        if not key and gift is not None:
            try:
                key = self._resolve_library_key_for_gift(gift)
            except:
                key = None
        e = self._library_find_entry(key) if key else None
        is_remote = False
        if not e and gift is not None:
            try:
                e = self._get_remote_gift_meta_for_gift(gift)
            except Exception:
                e = None
            if e:
                is_remote = True
        if not e:
            try:
                gid_dbg = int(get_val(gift, "id", 0) or 0) if gift is not None else 0
                slug_dbg = str(get_val(gift, "slug", "") or "") if gift is not None else ""
                _log(f"value row skip: no entry resolved (key={key!r}, gid={gid_dbg}, slug={slug_dbg!r})")
            except Exception:
                pass
            return False
        # tableView is normally a direct field on StarGiftSheet, but on some
        # Telegram-fork builds the field name is mangled (R8 keep rules vary).
        # Walk a small allowlist of likely names, then fall back to scanning
        # declared fields for the first TableView-typed one. Without this the
        # «Ценность» row silently vanished on certain installs and the only
        # symptom was an officially-formatted gift with no Value row.
        table = None
        for tv_name in ("tableView", "table", "infoTable", "tableViewBottom"):
            try:
                v = get_val(sheet, tv_name, None)
            except Exception:
                v = None
            if v is None:
                continue
            try:
                cls_name = str(v.getClass().getName() or "")
            except Exception:
                cls_name = ""
            if "TableView" in cls_name or hasattr(v, "addRow"):
                table = v
                break
        if table is None:
            try:
                cls = sheet.getClass()
                while cls is not None:
                    for f in cls.getDeclaredFields():
                        try:
                            f.setAccessible(True)
                            v = f.get(sheet)
                        except Exception:
                            continue
                        if v is None:
                            continue
                        try:
                            cls_name = str(v.getClass().getName() or "")
                        except Exception:
                            cls_name = ""
                        if "TableView" in cls_name and hasattr(v, "addRow"):
                            table = v
                            break
                    if table is not None:
                        break
                    try:
                        cls = cls.getSuperclass()
                    except Exception:
                        cls = None
            except Exception:
                pass
        if table is None:
            try:
                _log("value row skip: tableView not found on StarGiftSheet")
            except Exception:
                pass
            return False
        cfg = self._sanitize_value_config(e.get("value_config", None))
        stars_cfg = self._sanitize_gift_stars_config(e.get("gift_stars_config", None))
        # If our before-hook successfully wrote native value fields the
        # gift's `flags & 256` is set and `slug` is non-empty — Telegram's
        # own GiftValue2 row at StarGiftSheet:4194 will render, so the
        # plugin row would just be a duplicate ("Value ~€1,337 learn more"
        # immediately followed by "Ценность ~1 337 € подробнее"). Skip
        # ours when the native one is going to render and there is no
        # extra info we add (custom stars line). The custom-stars case
        # still goes through our row since native one only shows currency.
        try:
            native_value_amount = int(self._to_int(get_val(gift, "value_amount", 0), 0) or 0) if gift is not None else 0
        except Exception:
            native_value_amount = 0
        try:
            native_flags = int(self._to_int(get_val(gift, "flags", 0), 0) or 0) if gift is not None else 0
        except Exception:
            native_flags = 0
        try:
            native_slug = str(get_val(gift, "slug", "") or "") if gift is not None else ""
        except Exception:
            native_slug = ""
        native_will_render = bool(
            native_slug
            and (native_flags & 256)
            and native_value_amount > 0
        )
        stars_active = self._is_gift_stars_config_active(stars_cfg)
        if native_will_render and not stars_active:
            try:
                _log(
                    f"value row skipped (native will render): value_amount={native_value_amount} "
                    f"slug={native_slug!r} flags&256={bool(native_flags & 256)}"
                )
            except Exception:
                pass
            return False
        value_text = self._format_local_value_text(cfg, placeholder="не задана")
        if stars_active:
            value_text = f"{value_text} • {self._format_gift_stars_text(stars_cfg)}"
        button_text = "подробнее"

        def _open_menu():
            try:
                self._open_local_gift_value_menu(key, sheet=sheet)
            except Exception as ex:
                BulletinHelper.show_error(f"Не удалось открыть меню ценности: {ex}")

        try:
            if is_remote:
                value_active = self._is_value_config_active(cfg)
                if not value_active and not stars_active:
                    try:
                        _log(f"remote gift value row skipped (empty cfg): value_cfg={cfg} stars_cfg={stars_cfg}")
                    except Exception:
                        pass
                    return False
                table.addRow(self._ui_text("Ценность"), self._ui_text(value_text))
                try:
                    _log(f"remote gift value row added: text={value_text!r}")
                except Exception:
                    pass
            else:
                table.addRow(self._ui_text("Ценность"), self._ui_text(value_text), self._ui_text(button_text), JRunnable(_open_menu))
            return True
        except Exception as e:
            _log(f"Local gift value row inject error: {e}")
            return False

    def _inject_local_gift_my_gifts_rows(self, sheet, gift=None):
        """«Мои подарки» V5: add «От» and «Комментарий» rows to the
        StarGiftSheet table when the gift has user-set custom_from /
        custom_comment overrides. Native sheet doesn't always render
        from_id correctly (Hidden User fallback) and never shows a
        comment field at all — these rows are the durable channel.

        Works for both locally-owned gifts (entry resolved via
        gift_library) and foreign gifts received via sync (entry
        resolved via _get_remote_gift_meta_for_gift)."""
        if sheet is None:
            return False
        key = None
        try:
            key = self._resolve_library_key_from_gift_sheet(sheet)
        except:
            key = None
        if not key and gift is not None:
            try:
                key = self._resolve_library_key_for_gift(gift)
            except:
                key = None
        e = self._library_find_entry(key) if key else None
        # V6 sync: fall back to the remote meta cache so foreign-profile
        # viewers also see the owner's «От» / «Комментарий» rows. Try the
        # raw arg first (works for TL_starGiftUnique whose .id key matches
        # the cache), then unwrap to the inner gift (regular savedStarGift
        # wrappers have no .id of their own — the cache is keyed on the
        # inner TL_starGift.id).
        if not e and gift is not None:
            try:
                e = self._get_remote_gift_meta_for_gift(gift)
            except Exception:
                e = None
            if not e:
                try:
                    inner = self._extract_wrapper_gift(gift)
                    if inner is not None and inner is not gift:
                        e = self._get_remote_gift_meta_for_gift(inner)
                except Exception:
                    e = None
        if not e:
            return False
        # Cheap early-out before touching reflection: most gifts have no
        # custom overrides set, and this hook fires on every sheet open.
        try:
            cf_raw = str(e.get("custom_from", "") or "").strip()
        except:
            cf_raw = ""
        try:
            cc_raw = str(e.get("custom_comment", "") or "").strip()
        except:
            cc_raw = ""
        try:
            ic = e.get("identity_config") if isinstance(e.get("identity_config"), dict) else {}
            from_uid = int(ic.get("from_user_id", 0) or 0) if isinstance(ic, dict) else 0
        except:
            from_uid = 0
        if not cf_raw and not cc_raw and from_uid <= 0:
            return False
        # De-dup: this hook now fires from all three sheet-set variants
        # (A/B/C), so the same StarGiftSheet instance may pass through us
        # multiple times in one user tap. Track which sheet we've already
        # injected into and bail on repeats — otherwise the table grows
        # «От» / «Комментарий» rows on each variant.
        try:
            already = getattr(self, "_my_gifts_rows_injected_sheets", None)
            if not isinstance(already, dict):
                already = {}
                self._my_gifts_rows_injected_sheets = already
            sheet_key = id(sheet)
            now_ts = time.time()
            # Stale entries get pruned eventually — drop anything older than
            # 5 seconds so a fresh re-open of the same Python id() works.
            for _k in list(already.keys()):
                if now_ts - already.get(_k, 0.0) > 5.0:
                    try:
                        del already[_k]
                    except:
                        pass
            if sheet_key in already:
                return False
            already[sheet_key] = now_ts
        except Exception:
            pass
        # Locate the table view (same allowlist + reflection walk pattern
        # used by _inject_local_gift_value_row).
        table = None
        for tv_name in ("tableView", "table", "infoTable", "tableViewBottom"):
            try:
                v = get_val(sheet, tv_name, None)
            except:
                v = None
            if v is None:
                continue
            try:
                cls_name = str(v.getClass().getName() or "")
            except:
                cls_name = ""
            if "TableView" in cls_name or hasattr(v, "addRow"):
                table = v
                break
        if table is None:
            try:
                cls = sheet.getClass()
                while cls is not None:
                    for f in cls.getDeclaredFields():
                        try:
                            f.setAccessible(True)
                            v = f.get(sheet)
                        except:
                            continue
                        if v is None:
                            continue
                        try:
                            cls_name = str(v.getClass().getName() or "")
                        except:
                            cls_name = ""
                        if "TableView" in cls_name and hasattr(v, "addRow"):
                            table = v
                            break
                    if table is not None:
                        break
                    try:
                        cls = cls.getSuperclass()
                    except:
                        cls = None
            except:
                pass
        if table is None:
            return False

        added = 0
        # «От» — display the user-typed value (or a clean uid label as fallback).
        from_text = ""
        if cf_raw and not cf_raw.isdigit():
            from_text = cf_raw
        elif from_uid > 0:
            try:
                ctrl = MessagesController.getInstance(to_java_int(get_user_config().selectedAccount))
                u = ctrl.getUser(to_java_int(from_uid))
                first = str(get_val(u, "first_name", "") or "") if u is not None else ""
                last = str(get_val(u, "last_name", "") or "") if u is not None else ""
                un = str(get_val(u, "username", "") or "") if u is not None else ""
                if first or last:
                    from_text = (first + " " + last).strip()
                elif un:
                    from_text = "@" + un
            except:
                from_text = ""
            if not from_text:
                from_text = f"id:{from_uid}"
        elif cf_raw:
            from_text = cf_raw

        if from_text:
            try:
                table.addRow(self._ui_text("От"), self._ui_text(from_text))
                added += 1
            except Exception as ex:
                _log(f"my-gifts «От» row inject error: {ex}")

        if cc_raw:
            try:
                table.addRow(self._ui_text("Комментарий"), self._ui_text(cc_raw))
                added += 1
            except Exception as ex:
                _log(f"my-gifts «Комментарий» row inject error: {ex}")

        return added > 0

    def _inject_local_gift_ton_owner_row(self, sheet, gift=None):
        if sheet is None:
            return False
        key = None
        try:
            key = self._resolve_library_key_from_gift_sheet(sheet)
        except:
            key = None
        if not key and gift is not None:
            try:
                key = self._resolve_library_key_for_gift(gift)
            except:
                key = None
        e = self._library_find_entry(key) if key else None
        if not e and gift is not None:
            try:
                e = self._get_remote_gift_meta_for_gift(gift)
            except Exception:
                e = None
        if not e:
            return False
        ton_cfg = self._sanitize_ton_display_config(e.get("ton_display_config", None))
        if not bool(ton_cfg.get("enabled", False)):
            return False
        try:
            table = get_val(sheet, "tableView", None)
        except:
            table = None
        if table is None:
            return False
        try:
            table.addRow(self._ui_text("Владелец"), self._ui_text(self._format_visual_ton_owner_text(e, ton_cfg)))
            return True
        except Exception as ex:
            _log(f"Local TON owner row inject error: {ex}")
            return False

    def _apply_local_ton_blockchain_line(self, sheet, gift=None):
        if sheet is None:
            return False
        key = None
        try:
            key = self._resolve_library_key_from_gift_sheet(sheet)
        except:
            key = None
        if not key and gift is not None:
            try:
                key = self._resolve_library_key_for_gift(gift)
            except:
                key = None
        e = self._library_find_entry(key) if key else None
        if not e and gift is not None:
            try:
                e = self._get_remote_gift_meta_for_gift(gift)
            except Exception:
                e = None
        if not e:
            return False
        ton_cfg = self._sanitize_ton_display_config(e.get("ton_display_config", None))
        enabled = bool(ton_cfg.get("enabled", False))
        try:
            after_view = get_val(sheet, "afterTableTextView", None)
        except:
            after_view = None
        try:
            before_view = get_val(sheet, "beforeTableTextView", None)
        except:
            before_view = None
        if after_view is None:
            return False
        try:
            if enabled:
                after_view.setText("Подарок хранится в блокчейне TON. Посмотреть ›")
                after_view.setVisibility(View.VISIBLE)
                try:
                    after_view.setTextColor(Theme.getColor(Theme.key_featuredStickers_addButton))
                except:
                    pass
                gift_address = self._get_visual_ton_gift_address(e, ton_cfg)
                if gift_address:
                    def _open_blockchain(v, address=gift_address):
                        try:
                            account = get_user_config().selectedAccount
                            base = str(MessagesController.getInstance(to_java_int(account)).tonBlockchainExplorerUrl or "")
                        except:
                            base = ""
                        try:
                            Browser.openUrlInSystemBrowser(v.getContext(), "{0}{1}".format(base, address) if base else address)
                        except:
                            pass
                    after_view.setOnClickListener(JOnClickListener(_open_blockchain))
                if before_view is not None:
                    try:
                        before_view.setVisibility(View.GONE)
                    except:
                        pass
            else:
                after_view.setVisibility(View.GONE)
        except Exception as ex:
            _log(f"Local TON blockchain line error: {ex}")
            return False
        return True

    def _resolve_local_gift_release_badge_text(self, entry=None, gift=None):
        ton_cfg = self._sanitize_ton_display_config(entry.get("ton_display_config", None) if isinstance(entry, dict) else None)
        if bool(ton_cfg.get("enabled", False)):
            return "Подарок хранится в блокчейне TON. Посмотреть ›"
        probes = []
        if isinstance(entry, dict):
            try:
                probes.append(str(entry.get("title", "") or ""))
            except:
                pass
            try:
                probes.append(str(entry.get("slug", "") or ""))
            except:
                pass
        if gift is not None:
            try:
                probes.append(str(get_val(gift, "title", "") or ""))
            except:
                pass
            try:
                probes.append(str(get_val(gift, "slug", "") or ""))
            except:
                pass

        haystack = " ".join([p.strip().lower() for p in probes if p]).strip()
        if not haystack:
            return None

        if any(token in haystack for token in ["snoop", "dogg", "low rider", "lowrider"]):
            try:
                text = "Выпущен @snoopdogg"
                username = "@snoopdogg"
                start = text.find(username)
                if start < 0:
                    return text
                end = start + len(username)
                ssb = SpannableStringBuilder(text)

                class _SnoopLink(ClickableSpan):
                    def __init__(self):
                        super().__init__()

                    def updateDrawState(self, ds):
                        try:
                            ds.setUnderlineText(False)
                            ds.setColor(0xFFFFFFFF)
                        except:
                            pass

                    def onClick(self, view):
                        try:
                            frag = get_last_fragment()
                        except:
                            frag = None
                        try:
                            Browser.openUrl(frag if frag is not None else view.getContext(), "https://t.me/snoopdogg")
                        except:
                            pass

                ssb.setSpan(_SnoopLink(), start, end, 0)
                return ssb
            except:
                return "Выпущен @snoopdogg"
        return None

    def _inject_local_gift_release_badge(self, sheet, gift=None):
        if sheet is None:
            return False
        key = None
        try:
            key = self._resolve_library_key_from_gift_sheet(sheet)
        except:
            key = None
        if not key and gift is not None:
            try:
                key = self._resolve_library_key_for_gift(gift)
            except:
                key = None
        if not key:
            return False
        e = self._library_find_entry(key)
        if not e:
            return False

        text = self._resolve_local_gift_release_badge_text(e, gift=gift)
        if not text:
            return False

        try:
            top_view = get_val(sheet, "topView", None)
        except:
            top_view = None
        if top_view is None:
            return False

        try:
            released_view = get_val(top_view, "releasedView", None)
        except:
            released_view = None
        try:
            collection_released_view = get_val(top_view, "collectionReleasedView", None)
        except:
            collection_released_view = None
        try:
            subtitle_container = get_val(top_view, "subtitleContainer", None)
        except:
            subtitle_container = None
        try:
            subtitle_views = get_val(top_view, "subtitleView", None)
        except:
            subtitle_views = None

        if collection_released_view is None:
            return False

        try:
            collection_released_view.setText(text)
        except Exception as e:
            _log(f"Local gift release badge text error: {e}")
            return False

        try:
            collection_released_view.setVisibility(View.VISIBLE)
        except:
            pass
        try:
            if released_view is not None:
                released_view.setVisibility(View.GONE)
        except:
            pass
        try:
            if subtitle_container is not None:
                subtitle_container.setVisibility(View.GONE)
        except:
            pass
        try:
            if subtitle_views is not None:
                subtitle_view = subtitle_views[0]
                if subtitle_view is not None:
                    subtitle_view.setVisibility(View.GONE)
        except:
            pass
        return True

    def _open_constructor_for_library_key(self, key):
        e = self._library_find_entry(key)
        if not e:
            BulletinHelper.show_error("\u041f\u043e\u0434\u0430\u0440\u043e\u043a \u043d\u0435 \u043d\u0430\u0439\u0434\u0435\u043d")
            return False
        self.editing_gift_key = str(key)
        self.cached_gift_id = int(e.get("base_gift_id", 0) or 0)
        try:
            cfg = e.get("build_config", None)
            if isinstance(cfg, dict):
                self.build_config = {
                    "model": int(cfg.get("model", 0) or 0),
                    "pattern": int(cfg.get("pattern", 0) or 0),
                    "backdrop": int(cfg.get("backdrop", 0) or 0),
                    "num": int(cfg.get("num", e.get("num", 1) or 1) or 1),
                }
        except:
            pass
        try:
            self.identity_config = self._sanitize_identity_config(e.get("identity_config", None))
        except:
            self.identity_config = self._default_identity_config()
        try:
            self.value_config = self._sanitize_value_config(e.get("value_config", None))
        except:
            self.value_config = self._default_value_config()
        try:
            self.gift_stars_config = self._sanitize_gift_stars_config(e.get("gift_stars_config", None))
        except:
            self.gift_stars_config = self._default_gift_stars_config()
        w = self._library_get_wrapper(key)
        g = self._extract_wrapper_gift(w) if w else None
        if w and g:
            self.stolen_gift_wrapper = w
            self.stolen_gift_inner = g
            try:
                if not any(int(v or 0) for v in self.identity_config.values()):
                    self.identity_config = self._extract_identity_config_from_objects(g, w)
            except:
                pass
            try:
                self.cls_saved = w.getClass()
                self.cls_unique = g.getClass()
            except:
                pass
        self._open_constructor(None)
        return True

    def _delete_library_gift_key(self, key):
        e = self._library_find_entry(key)
        if not e:
            BulletinHelper.show_error("\u041f\u043e\u0434\u0430\u0440\u043e\u043a \u043d\u0435 \u043d\u0430\u0439\u0434\u0435\u043d")
            return False
        sid = 0
        try:
            sid = int(e.get("saved_id", 0) or 0)
        except:
            sid = 0
        if sid <= 0:
            try:
                w = self._library_get_wrapper(key)
                sid = int(self._extract_saved_id_from_wrapper(w) or 0) if w else 0
            except:
                sid = 0
        self._library_remove(key)
        self._save_cache()
        try:
            self._save_injection_cache()
        except:
            pass
        try:
            self._try_refresh_saved_gifts_ui_after_delete(sid)
        except:
            pass
        BulletinHelper.show_success("\u041f\u043e\u0434\u0430\u0440\u043e\u043a \u0443\u0434\u0430\u043b\u0435\u043d")
        return True

    def _try_refresh_saved_gifts_ui_after_delete(self, saved_id):
        """
        Best-effort remove deleted injected gift from currently visible UI list,
        so user doesn't need to re-open profile.
        """
        try:
            sid = int(saved_id or 0)
        except:
            sid = 0
        if sid <= 0:
            return 0

        try:
            frag = get_last_fragment()
        except:
            frag = None
        if frag is None:
            return 0

        removed = 0
        try:
            removed += int(self._scan_object_and_remove_saved_gift(frag, sid, max_depth=2) or 0)
        except:
            pass

        # Notify adapters / list views if possible.
        try:
            self._scan_object_and_notify_adapters(frag, max_depth=2)
        except:
            pass

        # Close the gift sheet if still open (avoids showing deleted item).
        try:
            sheet = getattr(self, "_gift_menu_sheet_ref", None)
        except:
            sheet = None
        if sheet is not None:
            try:
                sheet.dismiss()
            except:
                pass
            try:
                self._gift_menu_sheet_ref = None
            except:
                pass

        return int(removed or 0)

    def _scan_object_and_remove_saved_gift(self, root, saved_id, max_depth=2):
        try:
            sid = int(saved_id or 0)
        except:
            sid = 0
        if sid <= 0 or root is None:
            return 0

        visited = set()

        def looks_like_list(obj):
            if obj is None:
                return False
            try:
                _ = obj.size()
                _ = obj.get
                return True
            except:
                return False

        def iter_fields(obj):
            out = []
            try:
                cls = obj.getClass()
            except:
                return out
            try:
                for f in cls.getDeclaredFields():
                    try:
                        f.setAccessible(True)
                    except:
                        pass
                    out.append(f)
            except:
                pass
            try:
                for f in cls.getFields():
                    out.append(f)
            except:
                pass
            return out

        def remove_from_list(lst):
            r = 0
            try:
                size = int(lst.size() or 0)
            except:
                return 0
            if size <= 0:
                return 0
            for i in range(size - 1, -1, -1):
                try:
                    it = lst.get(i)
                except:
                    continue
                if not self._looks_like_saved_gift_wrapper(it):
                    continue
                try:
                    it_sid = int(self._extract_saved_id_from_wrapper(it) or 0)
                except:
                    it_sid = 0
                if it_sid == sid:
                    try:
                        lst.remove(i)
                        r += 1
                    except:
                        pass
            return r

        def walk(obj, depth):
            if obj is None or depth > max_depth:
                return 0
            try:
                oid = int(obj.hashCode())
            except:
                oid = id(obj)
            if oid in visited:
                return 0
            visited.add(oid)

            total = 0

            if looks_like_list(obj):
                # Only mutate lists that actually contain saved gift wrappers.
                try:
                    if int(obj.size() or 0) > 0:
                        sample = obj.get(0)
                        if self._looks_like_saved_gift_wrapper(sample):
                            total += remove_from_list(obj)
                except:
                    pass

            for f in iter_fields(obj):
                try:
                    v = f.get(obj)
                except:
                    continue
                # Avoid recursing into Views; huge graphs.
                try:
                    if v is not None and "android.view" in str(v.getClass().getName() or ""):
                        continue
                except:
                    pass
                if looks_like_list(v):
                    total += remove_from_list(v)
                else:
                    total += walk(v, depth + 1)
            return total

        return int(walk(root, 0) or 0)

    def _scan_object_and_notify_adapters(self, root, max_depth=2):
        if root is None:
            return 0
        visited = set()
        notified = 0

        def has_method(obj, name):
            try:
                m = getattr(obj, name, None)
                return callable(m)
            except:
                return False

        def walk(obj, depth):
            nonlocal notified
            if obj is None or depth > max_depth:
                return
            try:
                oid = int(obj.hashCode())
            except:
                oid = id(obj)
            if oid in visited:
                return
            visited.add(oid)

            # Try notifyDataSetChanged on adapters.
            if has_method(obj, "notifyDataSetChanged"):
                try:
                    obj.notifyDataSetChanged()
                    notified += 1
                except:
                    pass
            # Telegram's custom adapters sometimes expose update(boolean).
            if has_method(obj, "update"):
                try:
                    obj.update(True)
                    notified += 1
                except:
                    pass

            # List views / recycler views: getAdapter().notifyDataSetChanged()
            if has_method(obj, "getAdapter"):
                try:
                    ad = obj.getAdapter()
                    if ad is not None and has_method(ad, "notifyDataSetChanged"):
                        ad.notifyDataSetChanged()
                        notified += 1
                except:
                    pass

            # If it's a View, don't recurse through its internal children; too large.
            try:
                cn = str(obj.getClass().getName() or "")
                if ("android.view" in cn) or ("android.widget" in cn) or ("androidx.recyclerview" in cn):
                    return
            except:
                pass

            for f in self._iter_object_fields(obj):
                try:
                    v = f.get(obj)
                except:
                    continue
                walk(v, depth + 1)

        walk(root, 0)
        return int(notified or 0)

    def _to_int(self, value, default=0):
        try:
            if value is None:
                return default
            if isinstance(value, bool):
                return default
            return int(value)
        except:
            try:
                return int(str(value))
            except:
                return default

    def _field_value_matches(self, current, wanted):
        try:
            if current is wanted:
                return True
        except:
            pass
        try:
            if current == wanted:
                return True
        except:
            pass
        try:
            if isinstance(current, bool) or isinstance(wanted, bool):
                return bool(current) == bool(wanted)
        except:
            pass
        try:
            if isinstance(current, (int, float)) or isinstance(wanted, (int, float)):
                return self._to_int(current, 0) == self._to_int(wanted, 0)
        except:
            pass
        try:
            if current is None or wanted is None:
                return current is wanted
        except:
            pass
        return False

    def _set_field(self, obj, field_name, value):
        if obj is None:
            return False
        try:
            current = getattr(obj, field_name)
        except:
            current = None
        try:
            if self._field_value_matches(current, value):
                return False
        except:
            pass
        try:
            setattr(obj, field_name, value)
            return True
        except:
            pass
        try:
            f = _cached_get_field(obj, field_name)
            if f is None:
                return False
            t_name = f.getType().getName()
            if t_name == "int":
                new_value = self._to_int(value, 0)
                try:
                    if self._to_int(f.getInt(obj), 0) == new_value:
                        return False
                except:
                    pass
                f.setInt(obj, new_value)
            elif t_name == "long":
                new_value = self._to_int(value, 0)
                try:
                    if self._to_int(f.getLong(obj), 0) == new_value:
                        return False
                except:
                    pass
                f.setLong(obj, new_value)
            elif t_name == "boolean":
                new_value = bool(value)
                try:
                    if bool(f.getBoolean(obj)) == new_value:
                        return False
                except:
                    pass
                f.setBoolean(obj, new_value)
            else:
                try:
                    if self._field_value_matches(f.get(obj), value):
                        return False
                except:
                    pass
                f.set(obj, value)
            return True
        except:
            return False

    def _extract_doc_id(self, doc):
        try:
            if doc is None:
                return 0
            return self._to_int(get_val(doc, "id", 0), 0)
        except:
            return 0

    def _doc_has_custom_emoji_attr(self, doc):
        """Best-effort check if a Document is a custom emoji (needed for animated emoji status)."""
        if doc is None:
            return False
        try:
            attrs = get_val(doc, "attributes", None)
            if attrs is None:
                return False
            try:
                size = attrs.size()
            except:
                size = 0
            for i in range(size):
                try:
                    a = attrs.get(i)
                except:
                    continue
                if a is None:
                    continue
                try:
                    n = a.getClass().getSimpleName().lower()
                    if "customemoji" in n or "custom_emoji" in n:
                        return True
                except:
                    pass
        except:
            pass
        return False

    def _pick_best_doc_for_collectible_status(self, docs):
        """Pick a Document which is most likely to animate as a collectible emoji status."""
        if not docs:
            return None
        for d in docs:
            try:
                if d is not None and self._doc_has_custom_emoji_attr(d) and self._extract_doc_id(d) > 0:
                    return d
            except:
                pass
        for d in docs:
            try:
                if d is not None and self._extract_doc_id(d) > 0:
                    return d
            except:
                pass
        return None

    def _new_java_instance(self, cls_or_ctor):
        """Create Java object from either java.lang.Class (newInstance) or Chaquopy JavaClass (callable)."""
        if cls_or_ctor is None:
            return None
        try:
            return cls_or_ctor.newInstance()
        except:
            pass
        try:
            return cls_or_ctor()
        except:
            pass
        try:
            name = cls_or_ctor.getName()
            return jclass(str(name))()
        except:
            pass
        return None

    def _new_tl_instance(self, *candidates):
        for candidate in candidates or []:
            if candidate is None:
                continue
            try:
                if isinstance(candidate, str):
                    obj = self._new_java_instance(jclass(candidate))
                else:
                    obj = self._new_java_instance(candidate)
                if obj is not None:
                    return obj
            except:
                continue
        return None

    def _set_first_field(self, obj, field_names, value):
        if obj is None:
            return False
        for field_name in field_names or []:
            try:
                if self._set_field(obj, field_name, value):
                    return True
            except:
                continue
        return False

    def _sanitize_slug_chunk(self, text):
        if text is None:
            return ""
        s = str(text).strip()
        if not s:
            return ""

        s = s.split("?", 1)[0].split("#", 1)[0]
        if "/" in s:
            s = s.rsplit("/", 1)[-1]

        s = re.sub(r"[^A-Za-z0-9_-]+", "", s)
        s = s.strip("-_")
        return s

    def _title_to_slug_base(self, title):
        parts = re.findall(r"[A-Za-z0-9]+", str(title or ""))
        if not parts:
            return "NFT"
        return "".join(p[0].upper() + p[1:] if p else "" for p in parts)

    def _slug_base_for_custom_link(self, gift_obj):
        if gift_obj is None:
            return ""

        slug = self._sanitize_slug_chunk(get_val(gift_obj, "slug", ""))
        if slug:
            m = re.match(r"^(.*?)-(\d+)$", slug)
            if m and m.group(1):
                return self._sanitize_slug_chunk(m.group(1))
            return slug

        title = get_val(gift_obj, "title", "NFT")
        return self._sanitize_slug_chunk(self._title_to_slug_base(title))

    def _build_custom_slug(self, gift_obj, number):
        base = self._slug_base_for_custom_link(gift_obj)
        if not base:
            base = "NFT"
        num = self._to_int(number, 0)
        if num > 0:
            return f"{base}-{num}"
        return base

    def _resolve_active_gift(self):
        gift = None
        try:
            if self.injection_payload:
                gift = get_val(self.injection_payload, "gift", None)
                if gift:
                    return gift
        except:
            pass
        if self.stolen_gift_inner:
            return self.stolen_gift_inner
        return None

    def _get_my_user_id(self):
        try:
            cfg = get_user_config()
            return self._to_int(cfg.clientUserId, 0)
        except:
            return 0

    def _extract_user_id_from_obj(self, obj, depth=0):
        if obj is None or depth > 3:
            return 0

        direct_id = self._to_int(obj, 0)
        if direct_id > 0:
            return direct_id

        try:
            cls_name = obj.getClass().getSimpleName().lower()
            if "inputuserself" in cls_name or "inputpeerself" in cls_name:
                return self._get_my_user_id()
        except:
            return 0

        for field_name in ["user_id", "peer_id", "dialog_id"]:
            try:
                uid = self._to_int(get_val(obj, field_name, 0), 0)
                if uid > 0:
                    return uid
            except:
                pass

        for field_name in ["peer", "user", "from_id", "to_id", "id"]:
            try:
                nested = get_val(obj, field_name, None)
                if nested is None:
                    continue
                uid = self._extract_user_id_from_obj(nested, depth + 1)
                if uid > 0:
                    return uid
            except:
                pass

        try:
            for f in obj.getClass().getFields():
                name = f.getName().lower()
                if "user" not in name and "peer" not in name and name not in ["id", "from_id", "to_id"]:
                    continue
                try:
                    nested = f.get(obj)
                    if nested is None:
                        continue
                    uid = self._extract_user_id_from_obj(nested, depth + 1)
                    if uid > 0:
                        return uid
                except:
                    pass
        except:
            pass

        return 0

    def _extract_request_user_id(self, req):
        if req is None:
            return -1

        req_name = ""
        try:
            req_name = req.getClass().getSimpleName().lower()
        except:
            pass

        has_target_field = False

        for field_name in ["user_id", "peer", "user", "from_id", "to_id"]:
            try:
                val = get_val(req, field_name, None)
                if val is None:
                    continue
                has_target_field = True
                uid = self._extract_user_id_from_obj(val)
                if uid > 0:
                    return uid
            except:
                pass

        try:
            for f in req.getClass().getFields():
                name = f.getName().lower()
                if "user" not in name and "peer" not in name and name not in ["from_id", "to_id"]:
                    continue
                has_target_field = True
                try:
                    val = f.get(req)
                    uid = self._extract_user_id_from_obj(val)
                    if uid > 0:
                        return uid
                except:
                    pass
        except:
            pass

        if "saved" in req_name and "gift" in req_name and not has_target_field:
            return 0
        return -1

    def _is_non_first_saved_gifts_page(self, req):
        """Detect pagination in getSavedStarGifts-like requests to avoid injecting duplicates into appended pages."""
        if req is None:
            return False

        for name in [
            "offset",
            "offset_id",
            "offset_date",
            "offset_peer",
            "offsetPeer",
            "offsetId",
            "offsetDate",
            "cursor",
            "page",
        ]:
            try:
                v = get_val(req, name, None)
            except:
                v = None
            if v is None:
                continue
            try:
                if isinstance(v, str):
                    if v.strip():
                        return True
                    continue
            except:
                pass
            try:
                n = self._to_int(v, 0)
                if n != 0:
                    return True
                continue
            except:
                pass
            # Be conservative with object offsets like InputPeerEmpty/self/default peers.
            try:
                cls_name = str(v.getClass().getSimpleName() or "").lower()
            except:
                cls_name = ""
            if cls_name and ("empty" in cls_name or "self" in cls_name):
                continue
            try:
                obj_uid = int(self._extract_entity_id_from_obj(v) or 0)
            except:
                obj_uid = 0
            if obj_uid != 0:
                return True

        try:
            fields = []
            try:
                fields.extend(list(req.getClass().getFields()))
            except:
                pass
            try:
                for f in req.getClass().getDeclaredFields():
                    try:
                        f.setAccessible(True)
                    except:
                        pass
                    fields.append(f)
            except:
                pass

            seen = set()
            for f in fields:
                try:
                    fname = str(f.getName() or "")
                except:
                    continue
                if fname in seen:
                    continue
                seen.add(fname)
                low = fname.lower()
                if "offset" not in low and low not in ["cursor", "page"]:
                    continue
                try:
                    t = f.getType().getName()
                except:
                    t = ""
                try:
                    if t == "int":
                        if int(f.getInt(req)) != 0:
                            return True
                        continue
                    if t == "long":
                        if int(f.getLong(req)) != 0:
                            return True
                        continue
                    if t == "java.lang.String":
                        vv = f.get(req)
                        if vv is not None and str(vv).strip():
                            return True
                        continue
                    vv = f.get(req)
                    if vv is None:
                        continue
                    try:
                        cls_name = str(vv.getClass().getSimpleName() or "").lower()
                    except:
                        cls_name = ""
                    if cls_name and ("empty" in cls_name or "self" in cls_name):
                        continue
                    try:
                        obj_uid = int(self._extract_entity_id_from_obj(vv) or 0)
                    except:
                        obj_uid = 0
                    if obj_uid != 0:
                        return True
                except:
                    continue
        except:
            pass

        return False

    def _resolve_saved_gifts_list(self, response):
        fallback_empty = None
        resp_name_l = response.getClass().getSimpleName().lower()

        for f in response.getClass().getFields():
            if f.getType() != ArrayList:
                continue
            try:
                val = f.get(response)
            except:
                continue

            if val is None:
                continue

            size = 0
            try:
                size = val.size()
            except:
                continue

            field_name = f.getName().lower()

            if size <= 0:
                if "saved" in resp_name_l and "gift" in resp_name_l and "collection" not in resp_name_l and "gift" in field_name:
                    fallback_empty = val
                continue

            try:
                item = val.get(0)
                item_name = item.getClass().getSimpleName()
                item_name_l = item_name.lower()
                _log(f"  Found ArrayList: field='{f.getName()}', item[0]={item_name}")
            except:
                continue

            if "collection" in item_name_l:
                continue
            if "saved" in item_name_l and "gift" in item_name_l:
                return val, item

        if fallback_empty is not None:
            _log("  Found empty saved gifts list")
            return fallback_empty, None
        return None, None

    def _get_list_owner_user_id(self, gifts_list):
        if gifts_list is None:
            return 0
        try:
            if gifts_list.size() <= 0:
                return 0
            item = gifts_list.get(0)
            gift = get_val(item, "gift", None)
            if not gift:
                return 0
            owner = get_val(gift, "owner_id", None)
            return self._extract_user_id_from_obj(owner)
        except:
            return 0

    def _resolve_saved_gifts_target_user_id(self, req_user_id, owner_user_id):
        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0
        try:
            owner_id = int(owner_user_id or 0)
        except:
            owner_id = 0
        if owner_id > 0:
            return owner_id
        try:
            req_id = int(req_user_id)
        except:
            req_id = -1
        if req_id > 0:
            return req_id
        if req_id == 0 and my_id > 0:
            return my_id
        try:
            if my_id > 0 and self._is_my_profile_context():
                return my_id
        except:
            pass
        try:
            if my_id > 0 and self.inject_active:
                return my_id
        except:
            pass
        return 0

    def _extract_entity_id_from_obj(self, obj, depth=0):
        if obj is None or depth > 4:
            return 0
        if depth <= 1:
            try:
                cached = self._get_cached_entity_id(obj)
            except:
                cached = None
            if cached is not None:
                return int(cached or 0)

        result = 0

        try:
            direct_id = int(self._to_int(obj, 0) or 0)
        except:
            direct_id = 0
        if direct_id != 0:
            result = int(direct_id)
        else:
            try:
                cls_name = str(obj.getClass().getSimpleName() or "").lower()
            except:
                cls_name = ""

            if "inputuserself" in cls_name or "inputpeerself" in cls_name:
                result = int(self._get_my_user_id() or 0)
            else:
                for field_name in ["user_id", "userId"]:
                    try:
                        uid = int(self._to_int(get_val(obj, field_name, 0), 0) or 0)
                    except:
                        uid = 0
                    if uid > 0:
                        result = uid
                        break

                if result == 0:
                    for field_name in ["channel_id", "channelId"]:
                        try:
                            cid = int(self._to_int(get_val(obj, field_name, 0), 0) or 0)
                        except:
                            cid = 0
                        if cid > 0:
                            result = int(-(1000000000000 + cid))
                            break

                if result == 0:
                    for field_name in ["chat_id", "chatId"]:
                        try:
                            cid = int(self._to_int(get_val(obj, field_name, 0), 0) or 0)
                        except:
                            cid = 0
                        if cid > 0:
                            result = int(-cid)
                            break

                if result == 0:
                    for field_name in ["peer_id", "peerId", "dialog_id", "dialogId", "id"]:
                        try:
                            eid = int(self._to_int(get_val(obj, field_name, 0), 0) or 0)
                        except:
                            eid = 0
                        if eid != 0:
                            if "channel" in cls_name and eid > 0:
                                result = int(-(1000000000000 + eid))
                            elif "chat" in cls_name and eid > 0:
                                result = int(-eid)
                            else:
                                result = int(eid)
                            break

                if result == 0:
                    for field_name in ["peer", "user", "chat", "channel", "owner", "from_id", "to_id", "from", "to", "recipient"]:
                        try:
                            nested = get_val(obj, field_name, None)
                        except:
                            nested = None
                        if nested is None:
                            continue
                        try:
                            result = int(self._extract_entity_id_from_obj(nested, depth + 1) or 0)
                        except:
                            result = 0
                        if result != 0:
                            break

                if result == 0:
                    try:
                        for f in obj.getClass().getFields():
                            try:
                                name = str(f.getName() or "").lower()
                            except:
                                name = ""
                            if (
                                "user" not in name
                                and "peer" not in name
                                and "chat" not in name
                                and "channel" not in name
                                and name not in ["id", "from_id", "to_id", "dialog_id", "peer_id"]
                            ):
                                continue
                            try:
                                nested = f.get(obj)
                            except:
                                nested = None
                            if nested is None:
                                continue
                            try:
                                result = int(self._extract_entity_id_from_obj(nested, depth + 1) or 0)
                            except:
                                result = 0
                            if result != 0:
                                break
                    except:
                        pass

        if depth <= 1:
            try:
                self._store_cached_entity_id(obj, int(result or 0))
            except:
                pass
        return int(result or 0)

    def _extract_user_id_from_obj(self, obj, depth=0):
        try:
            eid = int(self._extract_entity_id_from_obj(obj, depth=depth) or 0)
        except:
            eid = 0
        if eid > 0:
            return eid
        return 0

    def _extract_request_user_id(self, req):
        if req is None:
            return -1

        req_name = ""
        try:
            req_name = req.getClass().getSimpleName().lower()
        except:
            pass

        has_target_field = False
        for field_name in ["user_id", "peer", "user", "chat", "channel", "from_id", "to_id", "dialog_id", "dialogId", "peer_id", "peerId"]:
            try:
                val = get_val(req, field_name, None)
            except:
                val = None
            if val is None:
                continue
            has_target_field = True
            eid = self._extract_entity_id_from_obj(val)
            if eid != 0:
                return int(eid)

        try:
            for f in req.getClass().getFields():
                try:
                    name = str(f.getName() or "").lower()
                except:
                    name = ""
                if (
                    "user" not in name
                    and "peer" not in name
                    and "chat" not in name
                    and "channel" not in name
                    and name not in ["from_id", "to_id", "dialog_id", "peer_id"]
                ):
                    continue
                has_target_field = True
                try:
                    val = f.get(req)
                except:
                    val = None
                eid = self._extract_entity_id_from_obj(val)
                if eid != 0:
                    return int(eid)
        except:
            pass

        if "saved" in req_name and "gift" in req_name and not has_target_field:
            return 0
        return -1

    def _get_list_owner_user_id(self, gifts_list):
        if gifts_list is None:
            return 0
        try:
            if gifts_list.size() <= 0:
                return 0
            item = gifts_list.get(0)
            gift = get_val(item, "gift", None)
            if not gift:
                return 0
            owner = get_val(gift, "owner_id", None)
            return int(self._extract_entity_id_from_obj(owner) or 0)
        except:
            return 0

    def _resolve_saved_gifts_target_user_id(self, req_user_id, owner_user_id):
        try:
            owner_id = int(owner_user_id or 0)
        except:
            owner_id = 0
        if owner_id != 0:
            return owner_id
        try:
            req_id = int(req_user_id)
        except:
            req_id = -1
        if req_id not in [-1, 0]:
            return req_id
        try:
            visible_id = int(self._get_profile_activity_entity_id(self._get_visible_profile_activity()) or 0)
        except:
            visible_id = 0
        if visible_id != 0:
            return visible_id
        try:
            my_id = int(self._get_my_user_id() or 0)
        except:
            my_id = 0
        if req_id == 0 and my_id > 0:
            return my_id
        if my_id > 0 and self.inject_active:
            return my_id
        return 0

    def _normalize_saved_gift_for_actions(self, wrapper=None, force_pin=True, update_date=True, touch_unsaved=True, touch_restrictions=True, owner_user_id=0):
        wrapper_obj = wrapper if wrapper else self.injection_payload
        if not wrapper_obj:
            return

        now_ts = int(time.time())
        my_id = self._get_my_user_id()

        gift = get_val(wrapper_obj, "gift", None)
        if gift is None:
            try:
                gift = wrapper_obj.getClass().getField("gift").get(wrapper_obj)
            except:
                gift = None

        if gift:
            try:
                cur_owner_uid = 0
                for owner_field in ["owner_id", "owner", "ownerId"]:
                    try:
                        cur_owner_uid = self._extract_user_id_from_obj(get_val(gift, owner_field, None))
                    except:
                        cur_owner_uid = 0
                    if cur_owner_uid > 0:
                        break
                target_owner_uid = cur_owner_uid if cur_owner_uid != 0 else self._resolve_identity_entity_id(owner_user_id, fallback_uid=my_id)
                if target_owner_uid != 0:
                    self._set_user_ref_fields(gift, ["owner_id", "owner", "ownerId"], target_owner_uid)
            except Exception as e:
                _log(f"Owner normalize failed: {e}")

        if update_date:
            self._set_field(wrapper_obj, "date", now_ts)
        if force_pin:
            for fn in ["pinned_to_top", "pinnedToTop", "pinned", "is_pinned", "isPinned"]:
                try:
                    self._set_field(wrapper_obj, fn, True)
                except:
                    pass
        if touch_unsaved:
            try:
                self._set_field(wrapper_obj, "unsaved", False)
            except:
                pass

        try:
            saved_id = self._extract_saved_id_from_wrapper(wrapper_obj)
        except:
            saved_id = 0
        if saved_id <= 0:
            try:
                saved_id = self._new_saved_id()
            except:
                saved_id = random.randint(1600000000, 2147483647)
            self._set_saved_id_on_wrapper(wrapper_obj, saved_id)

        if touch_restrictions:
            self._set_field(wrapper_obj, "can_transfer_at", 0)
            self._set_field(wrapper_obj, "can_resell_at", 0)
            self._set_field(wrapper_obj, "can_upgrade", True)

            transfer_stars = self._to_int(get_val(wrapper_obj, "transfer_stars", 0), 0)
            if transfer_stars <= 0:
                self._set_field(wrapper_obj, "transfer_stars", 1)

            resell_min = self._to_int(get_val(wrapper_obj, "resell_min_stars", 0), 0)
            if resell_min <= 0:
                resell_min = 1
                self._set_field(wrapper_obj, "resell_min_stars", resell_min)

            resell_amount = self._to_int(get_val(wrapper_obj, "resell_amount", 0), 0)
            if resell_amount <= 0:
                self._set_field(wrapper_obj, "resell_amount", resell_min)

    def _remove_existing_gift_by_id(self, gifts_list, target_wrapper):
        """Remove any gift from list that matches target_wrapper's ID."""
        if not gifts_list or not target_wrapper:
            return
        
        target_id = 0
        try:
            target_gift = get_val(target_wrapper, "gift", None)
            target_id = self._to_int(get_val(target_gift, "id", 0), 0)
        except:
            pass
            
        if target_id <= 0:
            return

        try:
            for i in range(gifts_list.size() - 1, -1, -1):
                try:
                    item = gifts_list.get(i)
                    gift = get_val(item, "gift", None)
                    if not gift: continue
                    
                    curr_id = self._to_int(get_val(gift, "id", 0), 0)
                    if curr_id == target_id:
                        gifts_list.remove(i)
                        _log(f"  Removed duplicate gift index={i} id={target_id}")
                except:
                    pass
        except Exception as e:
            _log(f"  Deduplication error: {e}")

    def _remove_existing_gifts_by_ids(self, gifts_list, target_ids):
        if not gifts_list or not target_ids:
            return 0
        removed = 0
        try:
            ids = set()
            for v in list(target_ids or []):
                try:
                    gid = int(v or 0)
                except:
                    gid = 0
                if gid > 0:
                    ids.add(gid)
            if not ids:
                return 0
        except:
            return 0

        try:
            for i in range(int(gifts_list.size() or 0) - 1, -1, -1):
                try:
                    item = gifts_list.get(i)
                    gift = get_val(item, "gift", None)
                    if not gift:
                        continue
                    curr_id = self._to_int(get_val(gift, "id", 0), 0)
                    if curr_id in ids:
                        gifts_list.remove(i)
                        removed += 1
                except:
                    continue
        except Exception as e:
            _log(f"  Bulk deduplication error: {e}")
        return int(removed)

    def _saved_gift_is_hidden(self, wrapper):
        for name in ["hidden", "is_hidden", "isHidden", "hidden_to_top", "isHiddenToTop"]:
            try:
                v = get_val(wrapper, name, None)
                if v is None:
                    continue
                return bool(v)
            except:
                continue
        return False

    def _saved_gift_pinned_value(self, wrapper):
        """
        Return (has_value, pinned_bool). Some builds store pin state under different field names.
        """
        for fn in ["pinned_to_top", "pinnedToTop", "pinned", "is_pinned", "isPinned"]:
            try:
                v = get_val(wrapper, fn, None)
                if v is None:
                    continue
                return True, bool(v)
            except:
                continue
        return False, False

    def _saved_gift_order_hint(self, wrapper):
        # Best-effort: Telegram may store manual ordering here.
        candidates = [
            "order",
            "position",
            "sort",
            "sort_id",
            "sortId",
            "rank",
            "pinned_order",
            "pinnedOrder",
            "pinned_index",
            "pinnedIndex",
        ]
        for name in candidates:
            try:
                v = self._to_int(get_val(wrapper, name, 0), 0)
                if v != 0:
                    return int(v)
            except:
                continue
        return 0

    def _saved_gift_sort_key(self, wrapper):
        # Lower key = earlier in list.
        try:
            _, pinned = self._saved_gift_pinned_value(wrapper)
        except:
            pinned = False
        try:
            hidden = bool(self._saved_gift_is_hidden(wrapper))
        except:
            hidden = False
        try:
            date = int(self._to_int(get_val(wrapper, "date", 0), 0))
        except:
            date = 0
        hint = 0
        try:
            hint = int(self._saved_gift_order_hint(wrapper) or 0)
        except:
            hint = 0
        # If hint is 0, push it after items with explicit order.
        hint_norm = hint if hint != 0 else 1000000000
        # Keep hidden items after visible ones but still stable inside their group.
        return (0 if pinned else 1, 1 if hidden else 0, hint_norm, -int(date))

    def _find_insert_index_by_sort(self, gifts_list, wrapper):
        try:
            w_key = self._saved_gift_sort_key(wrapper)
        except:
            w_key = (0, 1000000000, 0)
        try:
            sz = gifts_list.size()
        except:
            sz = 0
        for i in range(sz):
            try:
                it = gifts_list.get(i)
            except:
                continue
            try:
                it_key = self._saved_gift_sort_key(it)
            except:
                continue
            # Insert before the first item that should go after us.
            try:
                if it_key > w_key:
                    return i
            except:
                continue
        return sz

    def _sync_library_entry_from_wrapper(self, wrapper):
        """
        Persist runtime changes (pin/unpin/hide/order/date) back into library cache,
        so they don't revert after screen re-open or app restart.
        """
        try:
            gift = self._extract_wrapper_gift(wrapper)
            slug = str(get_val(gift, "slug", "")) if gift else ""
            unique_id = int(self._to_int(get_val(gift, "id", 0), 0)) if gift else 0
            entry = None
            if unique_id > 0:
                entry = self._library_find_entry_by_unique_id(unique_id)
            if entry is None and slug:
                entry = self._library_find_entry_by_slug(slug)
            if entry is None:
                return False
            b64 = serialize_tl_object(wrapper)
            changed = False
            try:
                prev_b64 = str(entry.get("b64", ""))
            except:
                prev_b64 = ""
            if b64 and prev_b64 != str(b64):
                entry["b64"] = b64
                changed = True

            # Keep meta in sync too; pin/hide/order can be stored outside TL b64 on some forks.
            title, slug2, num, bg, uid2 = self._extract_gift_meta(wrapper, entry.get("base_gift_id", 0))
            try:
                if str(entry.get("title", "")) != str(title):
                    entry["title"] = title
                    changed = True
            except:
                entry["title"] = title
                changed = True
            try:
                if str(entry.get("slug", "")) != str(slug2):
                    entry["slug"] = slug2
                    changed = True
            except:
                entry["slug"] = slug2
                changed = True
            try:
                if int(entry.get("num", 0) or 0) != int(num):
                    entry["num"] = int(num)
                    changed = True
            except:
                entry["num"] = int(num)
                changed = True
            if bg:
                try:
                    if int(entry.get("base_gift_id", 0) or 0) != int(bg):
                        entry["base_gift_id"] = int(bg)
                        changed = True
                except:
                    entry["base_gift_id"] = int(bg)
                    changed = True
            if uid2:
                try:
                    if int(entry.get("unique_id", 0) or 0) != int(uid2):
                        entry["unique_id"] = int(uid2)
                        changed = True
                except:
                    entry["unique_id"] = int(uid2)
                    changed = True

            # Persist UI state overrides so pin/unpin/hide don't reset across profile re-open
            # even when TL schema differs across forks/builds.
            try:
                has_pin, pin_val = self._saved_gift_pinned_value(wrapper)
                if has_pin and (entry.get("pinned_override", None) != bool(pin_val)):
                    entry["pinned_override"] = bool(pin_val)
                    changed = True
            except:
                pass
            try:
                hv = bool(self._saved_gift_is_hidden(wrapper))
                if entry.get("hidden_override", None) != hv:
                    entry["hidden_override"] = hv
                    changed = True
            except:
                pass
            try:
                oh = int(self._saved_gift_order_hint(wrapper) or 0)
                if int(entry.get("order_hint", 0) or 0) != int(oh):
                    entry["order_hint"] = int(oh)
                    changed = True
            except:
                pass

            try:
                sid = self._extract_saved_id_from_wrapper(wrapper)
                if sid > 0:
                    prev_sid = int(entry.get("saved_id", 0) or 0)
                    if prev_sid <= 0:
                        entry["saved_id"] = int(sid)
                        changed = True
            except:
                pass

            if not changed:
                return False

            entry["updated_at"] = int(time.time())
            self._library_dirty = True
            return True
        except:
            return False

    def _extract_saved_id_from_req(self, req):
        if req is None:
            return 0
        for name in ["saved_id", "savedId", "savedID", "saved_gift_id", "savedGiftId"]:
            try:
                v = self._to_int(get_val(req, name, 0), 0)
                if v > 0:
                    return int(v)
            except:
                pass
        # Some request variants use plain "id" for saved gift id.
        try:
            v = self._to_int(get_val(req, "id", 0), 0)
            # Our injected saved_id is intentionally a large 32-bit int; use threshold to avoid false positives.
            if v >= 1000000000:
                return int(v)
        except:
            pass
        # Best-effort scan
        try:
            fields = []
            try:
                fields.extend(list(req.getClass().getFields()))
            except:
                pass
            try:
                for f in req.getClass().getDeclaredFields():
                    try:
                        f.setAccessible(True)
                    except:
                        pass
                    fields.append(f)
            except:
                pass
            seen = set()
            for f in fields:
                try:
                    n = str(f.getName() or "")
                except:
                    continue
                if n in seen:
                    continue
                seen.add(n)
                low = n.lower()
                if "saved" not in low or "id" not in low:
                    continue
                try:
                    v = f.get(req)
                    sid = self._to_int(v, 0)
                    if sid > 0:
                        return int(sid)
                except:
                    continue
        except:
            pass
        return 0

    def _extract_unique_id_from_req(self, req):
        if req is None:
            return 0
        for name in ["collectible_id", "unique_id", "gift_unique_id", "giftUniqueId"]:
            try:
                v = self._to_int(get_val(req, name, 0), 0)
                if v > 0:
                    return int(v)
            except:
                pass
        return 0

    def _resolve_library_entry_for_saved_action(self, req):
        sid = self._extract_saved_id_from_req(req)
        if sid > 0:
            e = self._library_find_entry_by_saved_id(sid)
            if e:
                return e
        uid = self._extract_unique_id_from_req(req)
        if uid > 0:
            e = self._library_find_entry_by_unique_id(uid)
            if e:
                return e
        try:
            slug = str(get_val(req, "slug", "") or "")
        except:
            slug = ""
        if slug:
            e = self._library_find_entry_by_slug(slug)
            if e:
                return e
        return None

    def _collect_input_saved_gift_tokens(self, req):
        """
        Extract identifiers from batched InputSavedStarGift vectors used by
        toggleStarGiftsPinnedToTop / updateStarGiftCollection requests.
        Returns (list_present, saved_ids:set[int], slugs:set[str], unique_ids:set[int]).
        """
        list_present = False
        saved_ids = set()
        slugs = set()
        unique_ids = set()
        if req is None:
            return list_present, saved_ids, slugs, unique_ids

        candidates = []
        for field_name in ["stargift", "stargifts", "order", "gifts"]:
            try:
                val = get_val(req, field_name, None)
            except:
                val = None
            if val is not None:
                candidates.append(val)

        for container in candidates:
            try:
                size = int(container.size() or 0)
                list_present = True
            except:
                continue
            for i in range(size):
                try:
                    item = container.get(i)
                except:
                    continue
                if item is None:
                    continue
                for name in ["saved_id", "savedId", "savedID", "saved_gift_id", "savedGiftId", "msg_id", "msgId"]:
                    try:
                        v = int(self._to_int(get_val(item, name, 0), 0) or 0)
                    except:
                        v = 0
                    if v > 0:
                        saved_ids.add(v)
                try:
                    slug = str(get_val(item, "slug", "") or "").strip()
                except:
                    slug = ""
                if slug:
                    slugs.add(slug)
                for name in ["collectible_id", "unique_id", "gift_unique_id", "giftUniqueId", "id"]:
                    try:
                        v = int(self._to_int(get_val(item, name, 0), 0) or 0)
                    except:
                        v = 0
                    if v > 0:
                        unique_ids.add(v)
        return list_present, saved_ids, slugs, unique_ids

    def _apply_pinned_overrides_from_toggle_req(self, req, req_name_l=""):
        """
        Persist full pinned-state snapshots sent by toggleStarGiftsPinnedToTop.
        Telegram sends the resulting pinned set, not a single pin/unpin flag.
        """
        if req is None:
            return []
        req_name_l = str(req_name_l or "").lower()
        if ("toggle" not in req_name_l) or ("pin" not in req_name_l):
            return []

        list_present, saved_ids, slugs, unique_ids = self._collect_input_saved_gift_tokens(req)
        if not list_present:
            return []

        try:
            target_entity_id = int(self._extract_request_user_id(req) or 0)
        except:
            target_entity_id = 0

        changed_keys = []
        changed = False
        for entry in list(self.gift_library or []):
            try:
                if not isinstance(entry, dict) or (not bool(entry.get("inject", False))):
                    continue
                if target_entity_id != 0 and (not self._entry_matches_target_entity(entry, target_entity_id)):
                    continue
            except:
                continue

            should_pin = False
            try:
                sid = int(entry.get("saved_id", 0) or 0)
            except:
                sid = 0
            if sid > 0 and sid in saved_ids:
                should_pin = True
            if (not should_pin) and slugs:
                try:
                    should_pin = str(entry.get("slug", "") or "") in slugs
                except:
                    should_pin = False
            if (not should_pin) and unique_ids:
                try:
                    should_pin = int(entry.get("unique_id", 0) or 0) in unique_ids
                except:
                    should_pin = False

            try:
                prev_override = entry.get("pinned_override", None)
            except:
                prev_override = None
            if prev_override is not None and bool(prev_override) == bool(should_pin):
                continue

            try:
                entry["pinned_override"] = bool(should_pin)
                entry["updated_at"] = int(time.time())
                self._library_dirty = True
                changed = True
                changed_keys.append(str(entry.get("key") or ""))
            except:
                continue

            try:
                key = entry.get("key")
                wrapper = self._library_get_wrapper(key)
                if wrapper is not None:
                    for fn in ["pinned_to_top", "pinnedToTop", "pinned", "is_pinned", "isPinned"]:
                        try:
                            self._set_field(wrapper, fn, bool(should_pin))
                        except:
                            pass
                    self._sync_library_entry_from_wrapper(wrapper)
            except:
                pass

        if changed:
            try:
                self._flush_library_if_dirty(min_interval_sec=0.0)
            except:
                pass
        return [k for k in changed_keys if k]

    def _apply_saved_action_from_req(self, req, entry, req_name_l=""):
        if req is None or entry is None:
            return None
        if not bool(entry.get("inject", False)):
            return None
        key = entry.get("key")
        prev_pinned_override = entry.get("pinned_override", None)
        prev_hidden_override = entry.get("hidden_override", None)
        prev_order_hint = entry.get("order_hint", None)
        w = None
        # Prefer live instance from injection_payloads (UI may have already mutated it).
        try:
            sid = self._extract_saved_id_from_req(req)
        except:
            sid = 0
        if sid > 0:
            try:
                for ww in list(self.injection_payloads or []):
                    try:
                        if self._extract_saved_id_from_wrapper(ww) == sid:
                            w = ww
                            break
                    except:
                        continue
            except:
                w = None
        if w is None:
            w = self._library_get_wrapper(key)
        if not w:
            return None

        # Ensure ids are present before TG builds follow-up actions.
        try:
            self._ensure_saved_id_for_entry(entry, w)
        except:
            pass

        # Copy common action fields if request contains them.
        pinned_from_req = None
        hidden_from_req = None
        for name in [
            "pinned_to_top",
            "pinnedToTop",
            "pinned",
            "is_pinned",
            "isPinned",
            "hidden",
            "is_hidden",
            "isHidden",
            "unsaved",
            "deleted",
        ]:
            try:
                v = get_val(req, name, None)
                if v is not None:
                    self._set_field(w, name, bool(v) if isinstance(v, bool) else v)
                    if pinned_from_req is None and name in ["pinned_to_top", "pinnedToTop", "pinned", "is_pinned", "isPinned"]:
                        pinned_from_req = bool(v)
                    if hidden_from_req is None and name in ["hidden", "is_hidden", "isHidden"]:
                        hidden_from_req = bool(v)
            except:
                pass
        # payments.saveStarGift carries the toggle in an `unsave` boolean
        # (true = hide from profile, false = show on profile). Treat it
        # as the hidden flag and also write through to wrapper.unsaved so
        # the gift list re-renders correctly on the next profile open.
        try:
            unsave_v = get_val(req, "unsave", None)
            if unsave_v is not None:
                un = bool(unsave_v)
                try:
                    self._set_field(w, "unsaved", un)
                except:
                    pass
                if hidden_from_req is None:
                    hidden_from_req = un
        except:
            pass
        # Persist explicit action state as overrides too (helps across forks / TL schema differences).
        try:
            if pinned_from_req is not None:
                entry["pinned_override"] = bool(pinned_from_req)
        except:
            pass
        try:
            if hidden_from_req is not None:
                entry["hidden_override"] = bool(hidden_from_req)
        except:
            pass

        # Heuristic based on request name (when explicit fields are missing).
        try:
            if ("hide" in req_name_l) or ("hidden" in req_name_l) or ("unsave" in req_name_l) or ("remove" in req_name_l):
                # Prefer wrapper's existing hidden field name.
                if get_val(w, "hidden", None) is not None:
                    self._set_field(w, "hidden", True)
                elif get_val(w, "is_hidden", None) is not None:
                    self._set_field(w, "is_hidden", True)
                if get_val(w, "unsaved", None) is not None and ("unsave" in req_name_l or "remove" in req_name_l):
                    self._set_field(w, "unsaved", True)
            if "unhide" in req_name_l or ("show" in req_name_l and "hide" not in req_name_l):
                if get_val(w, "hidden", None) is not None:
                    self._set_field(w, "hidden", False)
                elif get_val(w, "is_hidden", None) is not None:
                    self._set_field(w, "is_hidden", False)
                if get_val(w, "unsaved", None) is not None:
                    self._set_field(w, "unsaved", False)

            # Pin/unpin sometimes comes without a pinned_to_top field; infer from request name.
            if ("pin" in req_name_l) and ("unpin" not in req_name_l):
                for fn in ["pinned_to_top", "pinnedToTop", "pinned", "is_pinned", "isPinned"]:
                    try:
                        self._set_field(w, fn, True)
                    except:
                        pass
                try:
                    entry["pinned_override"] = True
                except:
                    pass
            if "unpin" in req_name_l:
                for fn in ["pinned_to_top", "pinnedToTop", "pinned", "is_pinned", "isPinned"]:
                    try:
                        self._set_field(w, fn, False)
                    except:
                        pass
                try:
                    entry["pinned_override"] = False
                except:
                    pass
        except:
            pass

        # If we changed overrides directly (without TL b64 change), force a save so state persists.
        try:
            if (entry.get("pinned_override", None) != prev_pinned_override) or (entry.get("hidden_override", None) != prev_hidden_override) or (entry.get("order_hint", None) != prev_order_hint):
                entry["updated_at"] = int(time.time())
                self._library_dirty = True
        except:
            pass

        # Persist current wrapper snapshot (so state doesn't revert on profile reopen).
        try:
            self._sync_library_entry_from_wrapper(w)
        except:
            pass
        try:
            self._flush_library_if_dirty()
        except:
            pass
        return str(key) if key else None

    def _flush_library_if_dirty(self, min_interval_sec=2.0):
        try:
            if not self._library_dirty:
                return
            now = time.time()
            last = float(getattr(self, "_library_last_save_ts", 0.0) or 0.0)
            if (now - last) < float(min_interval_sec):
                return
            self._library_last_save_ts = now
            self._library_dirty = False
            # Save immediately (but off the UI thread).
            self._save_cache(delay_ms=0)
        except:
            pass

    # ─────────────────────────────────────────────────────────────────────────
    # CHANNEL FEATURES – NFT gifts, subscriber count
    # ─────────────────────────────────────────────────────────────────────────

    def _get_channel_key(self, dialog_id_or_chat_id):
        """Convert a NEGATIVE dialog_id to a positive chat_id string key.
        Returns None for user dialogs (positive ids) or if conversion fails."""
        try:
            eid = int(dialog_id_or_chat_id or 0)
        except:
            eid = 0
        if eid >= 0:
            # Positive = user dialog, 0 = unknown → not a channel
            return None
        # Negative dialog_id → convert to positive chat_id
        key = self._convert_entity_to_chat_id(eid)
        try:
            key_int = int(key or 0)
        except:
            key_int = 0
        if key_int <= 0:
            return None
        return str(key_int)

    def _get_channel_data(self, key):
        """Return the channel override dict (or {}) for the given key."""
        return {}

    def _set_channel_data_field(self, key, field, value):
        """Safely update one field inside channel_data[key] and save."""
        if not isinstance(getattr(self, "channel_data", None), dict):
            self.channel_data = {}
        cd = dict(self.channel_data.get(str(key), {}))
        cd[field] = value
        self.channel_data[str(key)] = cd
        self._save_cache()

    def _has_channel_gifts(self, key):
        """Return True if there are local gifts in the channel's own library."""
        cd = self._get_channel_data(key)
        return bool(cd.get("gift_library"))

    def _resolve_channel_from_context(self, context=None):
        """Return (dialog_id, channel_key) from menu context.
        Uses the same resolution logic as fake_incoming for reliability.
        Returns (0, None) when the target is not a channel/group."""
        _, dialog_id = self._resolve_fake_incoming_target(context)
        if not dialog_id:
            return 0, None
        key = self._get_channel_key(dialog_id)
        return int(dialog_id), key

    def _apply_channel_overrides_to_chat(self, chat_obj):
        """Patch TLRPC$Chat with subscriber count override."""
        if chat_obj is None:
            return False
        try:
            chat_id = int(get_val(chat_obj, "id", 0) or 0)
        except:
            return False
        if chat_id <= 0:
            return False
        cd = self._get_channel_data(str(chat_id))
        if not cd:
            return False
        changed = False

        # ── Subscriber count ─────────────────────────────────────────────
        try:
            subs = int(cd.get("subscribers", 0) or 0)
            if subs > 0:
                try:
                    chat_obj.participants_count = subs
                    changed = True
                except:
                    pass
                try:
                    self._set_field(chat_obj, "participants_count", subs)
                    changed = True
                except:
                    pass
        except:
            pass

        return changed

    def _apply_channel_overrides_to_full(self, full_obj):
        """Patch TL_channelFull / TL_chatFull participants_count."""
        if full_obj is None:
            return False
        changed = False
        # Try to find the associated chat_id from the full object
        try:
            chat_id = int(get_val(full_obj, "id", 0) or 0)
        except:
            chat_id = 0
        if chat_id <= 0:
            # Walk common field names
            for fname in ["channel_id", "channelId", "chat_id", "chatId"]:
                try:
                    chat_id = int(get_val(full_obj, fname, 0) or 0)
                    if chat_id > 0:
                        break
                except:
                    pass
        if chat_id <= 0:
            return False
        cd = self._get_channel_data(str(chat_id))
        try:
            subs = int(cd.get("subscribers", 0) or 0)
            if subs > 0:
                try:
                    full_obj.participants_count = subs
                    changed = True
                except:
                    pass
                try:
                    self._set_field(full_obj, "participants_count", subs)
                    changed = True
                except:
                    pass
        except:
            pass
        return changed

    def _repatch_channel_chats(self):
        """Force-apply overrides to all tracked channels in MessagesController cache."""
        try:
            if not isinstance(getattr(self, "channel_data", None), dict):
                return
            if not self.channel_data:
                return
            try:
                account = int(get_user_config().selectedAccount)
            except:
                account = 0
            try:
                mc = MessagesController.getInstance(account)
            except:
                mc = None
            if mc is None:
                return
            for key in list(self.channel_data.keys()):
                try:
                    chat_id = int(key)
                except:
                    continue
                if chat_id <= 0:
                    continue
                try:
                    chat = mc.getChat(chat_id)
                    if chat is not None:
                        self._apply_channel_overrides_to_chat(chat)
                except:
                    continue
                # Also try to patch chatFull / channelFull
                for mname in ["getChatFull", "getChatInfo"]:
                    try:
                        getter = getattr(mc, mname, None)
                        if getter:
                            full = getter(chat_id)
                            if full is not None:
                                self._apply_channel_overrides_to_full(full)
                    except:
                        pass
            # Trigger chat list redraw
            # Use dialogsNeedReload (no extra args needed) - safe across versions
            try:
                nc = NotificationCenter.getInstance(account)
                try:
                    nc.postNotificationName(NotificationCenter.dialogsNeedReload)
                except:
                    pass
                try:
                    nc.postNotificationName(NotificationCenter.updateInterfaces,
                                            to_java_int(0))
                except:
                    pass
            except:
                pass
        except Exception as e:
            _log(f"repatch_channel_chats error: {e}")

    def _inject_channel_gifts_into_response(self, response, channel_key):
        """Inject channel-specific gifts (from channel's own library) into response."""
        try:
            cd = self._get_channel_data(channel_key)
            ch_lib = list(cd.get("gift_library", []) or [])
            if not ch_lib:
                return
            gifts_list, _ = self._resolve_saved_gifts_list(response)
            if gifts_list is None:
                return
            wrappers = []
            wrapper_gift_ids = set()
            for entry in ch_lib:
                try:
                    b64 = entry.get("bin", "")
                    if not b64:
                        continue
                    w = deserialize_tl_saved_gift(b64)
                    if w is None:
                        continue
                    try:
                        self._repair_saved_gift_wrapper(w)
                    except:
                        pass
                    gift = self._extract_wrapper_gift(w)
                    gid = int(get_val(gift, "id", 0) or 0) if gift else 0
                    if gid > 0 and gid in wrapper_gift_ids:
                        continue
                    wrappers.append(w)
                    if gid > 0:
                        wrapper_gift_ids.add(gid)
                except:
                    continue
            if not wrappers:
                return
            try:
                self._remove_existing_gifts_by_ids(gifts_list, wrapper_gift_ids)
            except:
                pass
            for w in reversed(wrappers):
                try:
                    gifts_list.add(0, w)
                except:
                    try:
                        gifts_list.add(w)
                    except:
                        pass
            _log(f"Channel gifts injected: {len(wrappers)} for key={channel_key}")
        except Exception as e:
            _log(f"inject_channel_gifts error: {e}")

    # ── Channel NFT Gifts (independent library) ──────────────────────────────

    def _open_channel_gifts_menu(self, context=None):
        """Show channel gift management menu (fully independent library)."""
        _, key = self._resolve_channel_from_context(context)
        if not key:
            BulletinHelper.show_error("Это меню только для каналов и групп")
            return
        cd = self._get_channel_data(key)
        ch_lib = list(cd.get("gift_library", []) or [])

        actions = []
        # Existing channel gifts (each can be removed)
        for entry in ch_lib:
            try:
                title = str(entry.get("title", "NFT") or "NFT")
                num = int(entry.get("num", 0) or 0)
                label = f"{title} #{num}" if num else title
                ek = str(entry.get("key", "") or "")

                def _make_remove(entry_key=ek):
                    def _rm():
                        self._remove_channel_gift_entry(key, entry_key)
                    return _rm

                actions.append((f"✕ {label}", _make_remove()))
            except:
                continue

        # Add from profile library
        actions.append(("＋ Добавить из профиля", lambda: self._open_channel_gift_picker(key)))
        # Clear all
        if ch_lib:
            actions.append(("⊘ Очистить все", lambda: self._clear_channel_gifts(key)))

        run_on_ui_thread(lambda: self._show_action_menu("NFT Gifts канала", actions))

    def _open_channel_gift_picker(self, channel_key):
        """Let user pick a gift from the profile library to copy to this channel."""
        lib = self.gift_library or []
        if not lib:
            BulletinHelper.show_error(
                "Профильная библиотека пуста. "
                "Постройте подарки через NFT Gifts в профиле."
            )
            return
        actions = []
        for entry in lib:
            try:
                label = self._format_library_entry_label(entry)
                gkey = str(entry.get("key", "") or "")
                if not gkey:
                    continue

                def _make_copy(ek=gkey):
                    def _do():
                        self._copy_profile_gift_to_channel(channel_key, ek)
                    return _do

                actions.append((label, _make_copy()))
            except:
                continue
        if not actions:
            BulletinHelper.show_error("Нет подарков для копирования")
            return
        run_on_ui_thread(lambda: self._show_action_menu("Выбрать подарок", actions))

    def _copy_profile_gift_to_channel(self, channel_key, profile_gift_key):
        """Serialize a profile library gift and store it independently in the channel."""
        try:
            w = self._library_get_wrapper(profile_gift_key)
            if w is None:
                BulletinHelper.show_error("Подарок не найден в профиле")
                return
            b64 = serialize_tl_object(w)
            if not b64:
                BulletinHelper.show_error("Не удалось сериализовать подарок")
                return
            # Build independent entry
            entry_src = self._library_find_entry(profile_gift_key)
            title = str(entry_src.get("title", "NFT") or "NFT") if entry_src else "NFT"
            num = int(entry_src.get("num", 0) or 0) if entry_src else 0
            new_key = f"ch_{channel_key}_{profile_gift_key}_{int(time.time())}"
            new_entry = {"key": new_key, "title": title, "num": num, "bin": b64}
            # Append to channel library
            if not isinstance(getattr(self, "channel_data", None), dict):
                self.channel_data = {}
            cd = dict(self.channel_data.get(str(channel_key), {}))
            ch_lib = list(cd.get("gift_library", []) or [])
            ch_lib.append(new_entry)
            cd["gift_library"] = ch_lib
            self.channel_data[str(channel_key)] = cd
            self._save_cache()
            lbl = f"{title} #{num}" if num else title
            BulletinHelper.show_success(f"Добавлен в канал: {lbl}")
        except Exception as e:
            BulletinHelper.show_error(f"Ошибка копирования: {e}")

    def _remove_channel_gift_entry(self, channel_key, entry_key):
        """Remove one gift entry from the channel's library."""
        try:
            if not isinstance(getattr(self, "channel_data", None), dict):
                self.channel_data = {}
            cd = dict(self.channel_data.get(str(channel_key), {}))
            ch_lib = [e for e in list(cd.get("gift_library", []) or [])
                      if str(e.get("key", "")) != entry_key]
            cd["gift_library"] = ch_lib
            self.channel_data[str(channel_key)] = cd
            self._save_cache()
            BulletinHelper.show_info("Подарок удалён из канала")
        except Exception as e:
            BulletinHelper.show_error(f"Ошибка: {e}")

    def _clear_channel_gifts(self, channel_key):
        """Remove all gifts from a channel's library."""
        self._set_channel_data_field(channel_key, "gift_library", [])
        BulletinHelper.show_info("Подарки канала очищены")

    # ── Channel Subscribers dialog ───────────────────────────────────────────

    def _open_channel_subscribers_dialog(self, context=None):
        """Open local subscriber count dialog for a channel."""
        _, key = self._resolve_channel_from_context(context)
        if not key:
            BulletinHelper.show_error("Это меню только для каналов и групп")
            return
        cd = self._get_channel_data(key)
        current_subs = int(cd.get("subscribers", 0) or 0)

        def _show_ui():
            try:
                ctx = self._get_menu_activity()
                if not ctx:
                    return
                InputType = jclass("android.text.InputType")
                layout = LinearLayout(ctx)
                layout.setOrientation(LinearLayout.VERTICAL)
                ph = AndroidUtilities.dp(20)
                layout.setPadding(ph, AndroidUtilities.dp(10), ph, AndroidUtilities.dp(4))

                lbl = TextView(ctx)
                lbl.setText("Количество подписчиков")
                try:
                    lbl.setTextColor(Theme.getColor(Theme.key_windowBackgroundWhiteBlueHeader))
                except:
                    pass
                layout.addView(lbl)

                note = TextView(ctx)
                note.setText("Локально. Видно только вам. 0 = выключить.")
                note.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 12)
                try:
                    note.setTextColor(Theme.getColor(Theme.key_windowBackgroundWhiteGrayText2))
                except:
                    pass
                lp = LinearLayout.LayoutParams(
                    LinearLayout.LayoutParams.MATCH_PARENT,
                    LinearLayout.LayoutParams.WRAP_CONTENT,
                )
                lp.topMargin = AndroidUtilities.dp(2)
                layout.addView(note, lp)

                edit = EditText(ctx)
                edit.setText(str(current_subs) if current_subs > 0 else "")
                try:
                    edit.setHint("Пример: 1500000")
                except:
                    pass
                edit.setInputType(int(InputType.TYPE_CLASS_NUMBER))
                lp2 = LinearLayout.LayoutParams(
                    LinearLayout.LayoutParams.MATCH_PARENT,
                    LinearLayout.LayoutParams.WRAP_CONTENT,
                )
                lp2.topMargin = AndroidUtilities.dp(8)
                layout.addView(edit, lp2)

                builder = AlertDialogBuilder(ctx)
                builder.set_title("Подписчики (локально)")
                builder.set_view(layout)

                def _submit(d, w):
                    try:
                        raw = str(edit.getText() or "0").strip().replace(" ", "").replace(",", "")
                        val = int(raw or "0")
                    except:
                        val = 0
                    self._commit_channel_subscribers(key, val)

                builder.set_positive_button("Сохранить", _submit)
                builder.set_negative_button("Отмена", None)
                builder.show()
            except Exception as e:
                BulletinHelper.show_error(f"Подписчики диалог: {e}")

        run_on_ui_thread(_show_ui)

    def _commit_channel_subscribers(self, key, count):
        try:
            count = max(0, int(count or 0))
            self._set_channel_data_field(key, "subscribers", count)
            run_on_ui_thread(self._repatch_channel_chats)
            if count > 0:
                BulletinHelper.show_success(f"Подписчики: {count:,}")
            else:
                BulletinHelper.show_info("Подписчики сброшены")
        except Exception as e:
            BulletinHelper.show_error(f"Ошибка: {e}")

    # ── Channel hooks ────────────────────────────────────────────────────────

    def _hook_channel_data(self):
        """Apply initial channel overrides via direct cache patch (no getChat/putChats hooks).
        Hooking getChat/putChats crosses JVM-Python bridge on every call and blocks
        Telegram's update pipeline → infinite loading across all dialogs. Instead we
        patch the MessagesController cache directly via _repatch_channel_chats()."""
        try:
            # Delay initial patch so MessagesController is fully initialised
            def _do_initial_patch():
                try:
                    self._repatch_channel_chats()
                except Exception as e:
                    _log(f"Channel initial repatch: {e}")
            try:
                AndroidUtilities = jclass("org.telegram.messenger.AndroidUtilities")
                AndroidUtilities.runOnUIThread(JRunnable(_do_initial_patch), 2000)
            except Exception as e:
                _log(f"Channel hook: delayed repatch schedule failed: {e}")
        except Exception as e:
            _log(f"_hook_channel_data error: {e}")

    def _hook_network(self):
        try:
            cm_class = get_connections_manager().getClass()
            try:
                self.hook_method(
                    cm_class.getMethod("sendRequest",
                                       jclass("org.telegram.tgnet.TLObject"),
                                       jclass("org.telegram.tgnet.RequestDelegate"),
                                       jclass("int")),
                    NetworkHook(self)
                )
                _log("Hooked sendRequest(TLObject, RequestDelegate, int)")
            except:
                self.hook_method(
                    cm_class.getMethod("sendRequest",
                                       jclass("org.telegram.tgnet.TLObject"),
                                       jclass("org.telegram.tgnet.RequestDelegate")),
                    NetworkHook(self)
                )
                _log("Hooked sendRequest(TLObject, RequestDelegate)")
        except Exception as e:
            _log(f"Hook Error: {e}\n{traceback.format_exc()}")

    def process_response(self, response, req_user_id=-1, req_name="", allow_inject=True):
        try:
            resp_name = response.getClass().getSimpleName()
            _log(f"process_response: {resp_name}, req={req_name}, req_user_id={req_user_id}, allow_inject={bool(allow_inject)}")

            gifts_list, sample_item = self._resolve_saved_gifts_list(response)
            if not gifts_list:
                _log(f"  No usable saved gifts list in {resp_name}")
                return

            gifts_size = gifts_list.size()
            _log(f"  gifts_list.size()={gifts_size}")
            manage_self = bool(self._should_manage_self_saved_gifts(req_user_id=req_user_id))

            try:
                removed_invalid = self._sanitize_saved_gifts_list(gifts_list)
                if removed_invalid:
                    _log(f"  Removed invalid saved gifts: {removed_invalid}")
            except Exception as e:
                _log(f"  Saved gifts sanitize error: {e}")

            if sample_item:
                item_cls = sample_item.getClass()
                self.cls_saved = item_cls
                try:
                    gift_val = item_cls.getField("gift").get(sample_item)
                    if gift_val and "unique" in gift_val.getClass().getSimpleName().lower():
                        self.cls_unique = gift_val.getClass()
                        _log(f"  Classes: saved={self.cls_saved.getName()}, unique={self.cls_unique.getName()}")
                except:
                    pass

            # Fix bogus "X ÃƒÂÃ‚Â¸ÃƒÂÃ‚Â· 0" ribbons for real saved gifts too (not only injected ones).
            try:
                try:
                    my_id = int(self._get_my_user_id() or 0)
                except:
                    my_id = 0
                try:
                    owner_user_id = int(self._get_list_owner_user_id(gifts_list) or 0)
                except:
                    owner_user_id = 0
                try:
                    target_user_id = int(self._resolve_saved_gifts_target_user_id(req_user_id, owner_user_id) or 0)
                except:
                    target_user_id = 0
                manage_self = bool(self._should_manage_self_saved_gifts(req_user_id=req_user_id, owner_user_id=owner_user_id, target_user_id=target_user_id))
                if not manage_self:
                    try:
                        remote_uid = int(target_user_id or owner_user_id or req_user_id or 0)
                    except:
                        remote_uid = 0
                    if remote_uid > 0 and remote_uid != my_id:
                        # Honor remote owner's "hide official gifts" toggle:
                        # if the foreign user enabled it locally, their snapshot
                        # carries hide_official_gifts=True, and we strip all
                        # server-returned (= real Telegram) gifts before our
                        # _sync_inject_remote_gifts re-populates the list with
                        # only the plugin/synced ones. This makes the hide
                        # toggle visible to other plugin users, not just to
                        # the owner.
                        try:
                            self._sync_apply_remote_hide_official(gifts_list, remote_uid)
                        except Exception as _hoe:
                            _log(f"  Remote sync hide-official error: {_hoe}")
                        try:
                            inj = self._sync_inject_remote_gifts(gifts_list, remote_uid)
                            if inj > 0:
                                _log(f"  Remote sync inject for uid={remote_uid}: +{inj}")
                        except Exception as _re:
                            _log(f"  Remote sync inject error: {_re}")
                        try:
                            self._sync_schedule_remote_user_patch(remote_uid)
                        except Exception as _re2:
                            _log(f"  Remote sync schedule error: {_re2}")
                        # Bump response.count >= max(3, gifts_list.size()). Telegram's
                        # ProfileGiftsContainer$Page.fillItems() computes the grid
                        # spanCount as Math.min(3, list.totalCount), and totalCount is
                        # later assigned from rez.count in StarsController.GiftsList.
                        # Without this bump a foreign profile with 1 real gift renders
                        # injected gifts as full-width banners (1 column) instead of
                        # the expected 3x3 grid.
                        try:
                            try:
                                _gs = int(gifts_list.size() or 0)
                            except Exception:
                                _gs = 0
                            _desired_count = max(3, _gs)
                            self._sync_saved_gifts_owner_count_fields(
                                response,
                                gifts_list=gifts_list,
                                field_names=["count"],
                                desired_min=_desired_count,
                            )
                        except Exception as _ce:
                            _log(f"  Remote sync count bump error: {_ce}")
                        # Belt-and-suspenders: also bump totalCount on any cached
                        # StarsController.GiftsList for this dialog so a fillItems()
                        # racing the response delivery still gets spanCount=3.
                        try:
                            self._bump_remote_gifts_list_total_count(remote_uid, desired_min=_desired_count)
                        except Exception as _be:
                            _log(f"  Remote GiftsList totalCount bump error: {_be}")
                    _log(f"  Skip saved gifts patch: req_uid={req_user_id}, owner_uid={owner_user_id}, target_uid={target_user_id}, my_id={my_id}")
                    return

                try:
                    if bool(getattr(self, "hide_official_gifts_local", False)):
                        removed_local = int(self._filter_official_saved_gifts(gifts_list) or 0)
                        if removed_local:
                            _log(f"  Locally hid official gifts: {removed_local}")
                except Exception as e:
                    _log(f"  Local hide official gifts error: {e}")

                scan_n = min(int(gifts_list.size() or 0), 24)
                for i in range(scan_n):
                    try:
                        it = gifts_list.get(i)
                        g = get_val(it, "gift", None)
                        if g is not None:
                            self._ensure_unique_gift_availability(g, base_gift_id=0)
                    except:
                        continue
            except:
                pass

            if allow_inject and self.inject_active and self.injection_payloads:
                try:
                    my_id = 0
                    owner_user_id = self._get_list_owner_user_id(gifts_list)
                    target_user_id = self._resolve_saved_gifts_target_user_id(req_user_id, owner_user_id)
                    try:
                        self._debug_state_snapshot(
                            "process_response:inject_start",
                            f"req={req_name} req_uid={req_user_id} owner_uid={owner_user_id} target_uid={target_user_id} gifts_size={gifts_size}",
                        )
                    except:
                        pass

                    if my_id > 0 and req_user_id > 0 and req_user_id != my_id:
                        _log(f"  Skip inject: Ãƒâ€˜Ã¢â‚¬Â¡Ãƒâ€˜Ã†â€™ÃƒÂÃ‚Â¶ÃƒÂÃ‚Â¾ÃƒÂÃ‚Â¹ ÃƒÂÃ‚Â¿Ãƒâ€˜Ã¢â€šÂ¬ÃƒÂÃ‚Â¾Ãƒâ€˜Ã¢â‚¬Å¾ÃƒÂÃ‚Â¸ÃƒÂÃ‚Â»Ãƒâ€˜Ã…â€™ req_user_id={req_user_id}, my_id={my_id}")
                        return

                    if my_id > 0 and owner_user_id > 0 and owner_user_id != my_id:
                        _log(f"  Skip inject: Ãƒâ€˜Ã‚ÂÃƒÂÃ‚Â¿ÃƒÂÃ‚Â¸Ãƒâ€˜Ã‚ÂÃƒÂÃ‚Â¾ÃƒÂÃ‚Âº Ãƒâ€˜Ã¢â‚¬Â¡Ãƒâ€˜Ã†â€™ÃƒÂÃ‚Â¶ÃƒÂÃ‚Â¾ÃƒÂÃ‚Â³ÃƒÂÃ‚Â¾ ÃƒÂÃ‚Â²ÃƒÂÃ‚Â»ÃƒÂÃ‚Â°ÃƒÂÃ‚Â´ÃƒÂÃ‚ÂµÃƒÂÃ‚Â»Ãƒâ€˜Ã…â€™Ãƒâ€˜Ã¢â‚¬Â ÃƒÂÃ‚Â° owner_user_id={owner_user_id}, my_id={my_id}")
                        return

                    if my_id > 0 and target_user_id > 0 and target_user_id != my_id:
                        _log(f"  Skip inject: resolved target_user_id={target_user_id}, my_id={my_id}")
                        return

                    if (not manage_self) and req_user_id < 0 and owner_user_id == 0 and target_user_id == 0:
                        _log("  Skip inject: target user unresolved")
                        return

                    try:
                        now_sync = time.time()
                        do_sync_wrappers = (now_sync - float(getattr(self, "_profile_gifts_sync_last_ts", 0.0) or 0.0)) >= 4.0
                    except:
                        do_sync_wrappers = False
                    for w in []:
                        try:
                            if not self._is_valid_saved_gift_wrapper(w):
                                continue
                            # Respect user's pin/unpin/order changes.
                            self._normalize_saved_gift_for_actions(
                                w,
                                force_pin=False,
                                update_date=False,
                                touch_unsaved=False,
                                touch_restrictions=False,
                            )
                            try:
                                gift = self._extract_wrapper_gift(w)
                                if gift is not None:
                                    # Keep availability totals sane for UI ("X ÃƒÂÃ‚Â¸ÃƒÂÃ‚Â· Y" ribbon).
                                    self._ensure_unique_gift_availability(gift, base_gift_id=0)
                                    try:
                                        gid = int(get_val(gift, "id", 0) or 0)
                                    except:
                                        gid = 0
                                    if gid > 0:
                                        wrapper_gift_ids.add(gid)
                            except:
                                pass
                            wrappers.append(w)
                        except:
                            pass

                    wrappers, wrapper_gift_ids, desired_ids = self._build_injection_wrappers_bundle(target_entity_id=target_user_id)
                    if not wrappers:
                        _log(f"  Skip inject: no local gifts for target={target_user_id}")
                        return

                    try:
                        current_ids, has_duplicates = self._collect_plugin_gift_ids_in_order(gifts_list, wrapper_gift_ids)
                    except:
                        current_ids, has_duplicates = [], True

                    try:
                        if wrapper_gift_ids and (has_duplicates or current_ids != desired_ids):
                            self._remove_existing_gifts_by_ids(gifts_list, wrapper_gift_ids)
                    except:
                        pass

                    if do_sync_wrappers:
                        for w in list(wrappers or []):
                            try:
                                self._sync_library_entry_from_wrapper(w)
                            except:
                                pass
                        try:
                            self._profile_gifts_sync_last_ts = time.time()
                        except:
                            pass

                    inserted = 0
                    try:
                        list_size_now = int(gifts_list.size() or 0)
                    except:
                        list_size_now = 0
                    if (not has_duplicates) and current_ids == desired_ids:
                        inserted = 0
                    elif list_size_now <= 0:
                        for w in wrappers:
                            try:
                                gifts_list.add(w)
                                inserted += 1
                            except:
                                pass
                    else:
                        for w in wrappers:
                            try:
                                idx = self._find_insert_index_by_sort(gifts_list, w)
                                gifts_list.add(idx, w)
                                inserted += 1
                            except:
                                pass

                    self._flush_library_if_dirty()
                    _log(f"  Injection applied. count={inserted}")
                    try:
                        self._debug_state_snapshot(
                            "process_response:inject_end",
                            f"req={req_name} inserted={inserted} wrappers={len(wrappers or [])} list_now={int(gifts_list.size() or 0)}",
                        )
                    except:
                        pass
                except Exception as e:
                    _log(f"  Inject Error: {e}")

            try:
                my_id = int(self._get_my_user_id() or 0)
            except:
                my_id = 0
            try:
                owner_user_id = int(self._get_list_owner_user_id(gifts_list) or 0)
            except:
                owner_user_id = 0
            try:
                target_user_id = int(self._resolve_saved_gifts_target_user_id(req_user_id, owner_user_id) or 0)
            except:
                target_user_id = 0
            try:
                desired_total = int(self._get_local_profile_gifts_count(target_user_id) or 0)
            except:
                desired_total = 0
            try:
                self._sync_saved_gifts_owner_count_fields(
                    response,
                    gifts_list=gifts_list,
                    field_names=["count"],
                    desired_min=desired_total,
                )
            except:
                pass
            try:
                should_refresh_profile = bool(
                    my_id > 0
                    and self._is_my_profile_activity()
                    and (
                        target_user_id == my_id
                        or owner_user_id == my_id
                        or req_user_id == my_id
                        or req_user_id == 0
                    )
                )
            except:
                should_refresh_profile = False
            try:
                if should_refresh_profile:
                    self._schedule_profile_gifts_refresh([120, 420], min_interval=0.55, force=False)
            except:
                pass

        except Exception as e:
            _log(f"Process Error: {e}\n{traceback.format_exc()}")

    def activate_injection(self, wrapper, wear_override=None):
        try:
            owner_uid = self._sanitize_identity_config(getattr(self, "identity_config", None)).get("owner_user_id", 0)
        except:
            owner_uid = 0
        force_pin = False
        try:
            existing_entry = self._library_find_entry(self.editing_gift_key) if getattr(self, "editing_gift_key", None) else None
        except:
            existing_entry = None
        try:
            if existing_entry is not None and existing_entry.get("pinned_override", None) is not None:
                force_pin = bool(existing_entry.get("pinned_override"))
            elif self.stolen_gift_wrapper is not None:
                has_pin, pin_val = self._saved_gift_pinned_value(self.stolen_gift_wrapper)
                if has_pin:
                    force_pin = bool(pin_val)
        except:
            force_pin = False
        self._normalize_saved_gift_for_actions(wrapper, force_pin=force_pin, update_date=True, owner_user_id=owner_uid)
        entry_key = self._library_upsert_wrapper(
            wrapper,
            base_gift_id=self.cached_gift_id or 0,
            key=self.editing_gift_key,
            inject=True,
            make_active=True,
            wear_override=wear_override,
            build_config=(self.build_config.copy() if isinstance(self.build_config, dict) else None),
            identity_config=(self.identity_config.copy() if isinstance(self.identity_config, dict) else None),
            value_config=(self.value_config.copy() if isinstance(self.value_config, dict) else None),
            gift_stars_config=(self.gift_stars_config.copy() if isinstance(self.gift_stars_config, dict) else None),
        )
        try:
            pending_key = str(getattr(self, "_pending_local_upgrade_key", None) or "")
        except:
            pending_key = ""
        try:
            entry_key_s = str(entry_key or "")
        except:
            entry_key_s = ""
        if entry_key_s and pending_key and pending_key == entry_key_s:
            try:
                self._annotate_library_entry_kind(
                    entry_key_s,
                    gift_kind=GIFT_KIND_LOCAL_UPGRADED,
                    official_import=False,
                    local_only=True,
                    original_b64=str(getattr(self, "_pending_local_upgrade_source_b64", "") or ""),
                    animation_style="telegram_upgrade",
                )
            except:
                pass
        self._clear_pending_local_upgrade()
        self.editing_gift_key = None
        self._save_cache()
        self._save_injection_cache()
        try:
            self._refresh_local_profile_gifts_section(reason="activate_injection")
        except Exception as e:
            _log(f"Local profile gifts reveal error: {e}")
        _log("Injection activated and cached to disk")
        BulletinHelper.show_success("\u0413\u043e\u0442\u043e\u0432\u043e! NFT \u0441\u043e\u0445\u0440\u0430\u043d\u0435\u043d \u0432 \u0431\u0438\u0431\u043b\u0438\u043e\u0442\u0435\u043a\u0435 \u0438 \u043f\u0440\u043e\u0444\u0438\u043b\u044c \u043e\u0431\u043d\u043e\u0432\u043b\u0435\u043d.")

    def _open_gift_actions_menu(self, key):
        e = self._library_find_entry(key)
        if not e:
            BulletinHelper.show_error("Подарок не найден")
            return
        t = self._ui_text(e.get("title", "NFT"), "NFT")
        n = int(e.get("num", 0) or 0)
        title = f"{t} #{n}" if n > 0 else t
        ton_cfg = self._sanitize_ton_display_config(e.get("ton_display_config", None))
        actions = [
            ("Открыть в конструкторе", lambda: self._open_constructor_for_library_key(key)),
            (f"TON блокчейн • {self._state_short_text(bool(ton_cfg.get('enabled', False)))}", lambda: self._toggle_library_ton_display(key)),
        ]
        if bool(ton_cfg.get("enabled", False)):
            actions.insert(2, (f"Владелец TON • {self._format_visual_ton_owner_text(e, ton_cfg)}", lambda: self._open_library_ton_owner_menu(key)))
        actions.append(("Удалить из библиотеки", lambda: self._delete_library_gift_key(key)))
        self._show_action_menu(title, actions, negative_text="Назад")

