class LocalStarsBalanceHook(MethodHook):
    def __init__(self, plugin):
        super().__init__()
        self.plugin = plugin

    def before_hooked_method(self, param):
        try:
            if self.plugin._is_local_stars_balance_active() and param.method.getName() == "updateBalance":
                local_amount = self.plugin._create_local_stars_amount()
                if local_amount is not None and param.args and len(param.args) > 0:
                    param.args[0] = local_amount
        except:
            pass

    def after_hooked_method(self, param):
        try:
            if not self.plugin._is_local_stars_balance_active():
                return
            ctrl = getattr(param, "thisObject", None)
            if ctrl is not None:
                self.plugin._apply_local_stars_balance_to_controller(ctrl)
            name = str(param.method.getName() or "")
            if name == "balanceAvailable":
                param.setResult(True)
                return
            if name == "getBalanceAmount":
                amount = self.plugin._create_local_stars_amount_value()
                if amount is not None:
                    param.setResult(amount)
                return
            if "getBalance" not in name:
                return
            try:
                ret_name = str(param.method.getReturnType().getName() or "")
            except:
                ret_name = ""
            if ret_name in ["long", "int"]:
                param.setResult(int(self.plugin._get_local_stars_balance_value() or 0))
                return
            local_amount = self.plugin._create_local_stars_amount()
            if local_amount is not None:
                param.setResult(local_amount)
        except:
            pass

