class ChannelGiftWrapperDelegate(dynamic_proxy(RequestDelegate)):
    """Intercepts getSavedStarGifts response for a channel and injects local gifts."""
    def __init__(self, plugin, original, channel_key, req_name=""):
        super().__init__()
        self.plugin = plugin
        self.original = original
        self.channel_key = str(channel_key or "")
        self.req_name = req_name

    def run(self, response, error):
        if not error and response:
            try:
                self.plugin._inject_channel_gifts_into_response(response, self.channel_key)
            except Exception as e:
                _log(f"ChannelGiftWrapper error: {e}")
        try:
            if self.original:
                self.original.run(response, error)
        except:
            pass


class ChannelFullWrapperDelegate(dynamic_proxy(RequestDelegate)):
    """Intercepts getFullChannel / getFullChat response and patches participants_count."""
    def __init__(self, plugin, original, channel_key, req_name=""):
        super().__init__()
        self.plugin = plugin
        self.original = original
        self.channel_key = str(channel_key or "")
        self.req_name = req_name

    def run(self, response, error):
        if not error and response:
            try:
                # Walk the response object looking for ChannelFull / ChatFull
                resp_cls = str(response.getClass().getSimpleName()).lower()
                if "full" in resp_cls or "messages" in resp_cls:
                    # Try direct patch
                    self.plugin._apply_channel_overrides_to_full(response)
                    # Also walk fields for nested Full objects
                    for fname in ["full_chat", "fullChat", "chat_full", "chatFull",
                                  "full", "channel_full", "channelFull"]:
                        try:
                            sub = get_val(response, fname, None)
                            if sub is not None:
                                self.plugin._apply_channel_overrides_to_full(sub)
                        except:
                            pass
            except Exception as e:
                _log(f"ChannelFullWrapper error: {e}")
        try:
            if self.original:
                self.original.run(response, error)
        except:
            pass


class NetworkHook(MethodHook):
    def __init__(self, plugin):
        self.plugin = plugin

    def before_hooked_method(self, param):
        try:
            try:
                self.plugin._ensure_user_context(force=False)
            except:
                pass
            req = param.args[0]
            req_name = req.getClass().getSimpleName()
            req_name_l = str(req_name).lower()

            if "gift" in req_name_l and "get" in req_name_l:
                req_user_id = self.plugin._extract_request_user_id(req)
                is_self = bool(self.plugin._should_manage_self_saved_gifts(req_user_id=req_user_id))
                has_local_overrides = bool(self.plugin._has_local_gifts_overrides())
                sync_enabled = bool(getattr(self.plugin, "_eblannft_sync_client", None) is not None)
                # Self profile + own NFTs → original behaviour.
                # Any saved-gifts response → also wrap so we can inject remote
                # NFTs of *other* users when the sync client is alive.
                if (is_self and has_local_overrides) or (sync_enabled and "saved" in req_name_l):
                    allow_inject = True
                    try:
                        if self.plugin._is_non_first_saved_gifts_page(req):
                            allow_inject = False
                    except:
                        allow_inject = True
                    _log(f">>> Hooking: {req_name}, req_user_id={req_user_id}, is_self={is_self}, has_local={has_local_overrides}, sync={sync_enabled}")
                    param.args[1] = WrapperDelegate(self.plugin, param.args[1], req_user_id, req_name, allow_inject)

            # Channel gifts injection: getSavedStarGifts for a channel peer
            if "gift" in req_name_l and "get" in req_name_l and "saved" in req_name_l:
                try:
                    req_entity_id = self.plugin._extract_request_user_id(req)
                    if req_entity_id is not None and int(req_entity_id or 0) < 0:
                        ch_key = self.plugin._get_channel_key(int(req_entity_id))
                        if ch_key and self.plugin._has_channel_gifts(ch_key):
                            _log(f">>> Hooking CHANNEL GIFT: {req_name}, channel_key={ch_key}")
                            param.args[1] = ChannelGiftWrapperDelegate(self.plugin, param.args[1], ch_key, req_name)
                except:
                    pass

            # Channel full info: patch subscribers count in getFullChannel / getFullChat
            if ("full" in req_name_l and ("channel" in req_name_l or "chat" in req_name_l)):
                try:
                    req_entity_id = self.plugin._extract_request_user_id(req)
                    ch_key = None
                    if req_entity_id is not None and int(req_entity_id or 0) < 0:
                        ch_key = self.plugin._get_channel_key(int(req_entity_id))
                    if ch_key is None and req_entity_id is not None and int(req_entity_id or 0) > 0:
                        ch_key = str(int(req_entity_id))
                    if ch_key:
                        cd = self.plugin._get_channel_data(ch_key)
                        if cd.get("subscribers"):
                            _log(f">>> Hooking CHANNEL FULL: {req_name}, key={ch_key}")
                            param.args[1] = ChannelFullWrapperDelegate(
                                self.plugin, param.args[1], ch_key, req_name
                            )
                except:
                    pass

            # Actions on saved gifts: hide/unhide/reorder/pin. For injected gifts we fake success to avoid UI errors.
            is_local_upgrade_action = ("upgrade" in req_name_l and "get" not in req_name_l)
            if is_local_upgrade_action:
                try:
                    entry = self.plugin._resolve_library_entry_for_saved_action(req)
                    entry_key = str(entry.get("key")) if isinstance(entry, dict) and entry.get("key") else None
                    if not entry_key:
                        try:
                            entry_key = getattr(self.plugin, "_active_gift_sheet_entry_key", None) or self.plugin._resolve_library_key_from_gift_sheet(getattr(self.plugin, "_active_gift_sheet_ref", None))
                        except:
                            entry_key = None
                    if entry is None and entry_key:
                        try:
                            entry = self.plugin._library_find_entry(entry_key)
                        except:
                            entry = None
                    if entry_key and self.plugin._entry_can_local_upgrade(entry):
                        _log(f">>> Hooking LOCAL GIFT UPGRADE: {req_name} key={entry_key}")
                        try:
                            run_on_ui_thread(lambda ek=entry_key: self.plugin._local_upgrade_entry_runnable(ek))
                        except:
                            pass
                        param.args[1] = SavedGiftActionDelegate(self.plugin, param.args[1], entry_key, req_name)
                except:
                    pass

            is_saved_action = ("saved" in req_name_l and "gift" in req_name_l)
            # payments.saveStarGift(stargift, unsave=true/false) is what TG's
            # "Hide from profile" / "Show on profile" button fires. Its
            # lowercased name is "savestargift" — no "saved" substring,
            # no "hide" token — the original heuristic missed it entirely,
            # so plugin entries kept being re-injected after the user hid
            # them. Detect this overload explicitly.
            if (not is_saved_action) and ("savestargift" in req_name_l or "savestar" in req_name_l):
                is_saved_action = True
            if (not is_saved_action) and ("gift" in req_name_l) and ("get" not in req_name_l):
                for tok in ["hide", "unhide", "pin", "pinned", "unpin", "order", "reorder", "sort", "unsave", "remove", "visible", "show"]:
                    if tok in req_name_l:
                        is_saved_action = True
                        break
            if is_saved_action and ("get" not in req_name_l):
                try:
                    batch_changed_keys = []
                    if ("toggle" in req_name_l) and ("pin" in req_name_l):
                        batch_changed_keys = self.plugin._apply_pinned_overrides_from_toggle_req(req, req_name_l=req_name_l)
                        if batch_changed_keys:
                            _log(f">>> Hooking SAVED_GIFTS BATCH ACTION: {req_name} keys={len(batch_changed_keys)}")
                            param.args[1] = SavedGiftsBatchActionDelegate(self.plugin, param.args[1], batch_changed_keys, req_name)
                    entry = self.plugin._resolve_library_entry_for_saved_action(req)
                    entry_key = None
                    if entry is not None:
                        entry_key = self.plugin._apply_saved_action_from_req(req, entry, req_name_l=req_name_l)
                    if entry_key:
                        _log(f">>> Hooking SAVED_GIFT ACTION: {req_name} key={entry_key}")
                        param.args[1] = SavedGiftActionDelegate(self.plugin, param.args[1], entry_key, req_name)
                except:
                    pass

            # payments.upgradeStarGift safety net. The method-level intercept
            # (StarGiftUpgradeInterceptHook) catches button clicks before they
            # turn into RPCs, but if it misses — e.g. obfuscated method names
            # in a future client build, or a code path that goes straight to
            # ConnectionsManager — Telegram replies with STARGIFT_ALREADY_CONVERTED
            # / STARGIFT_NOT_FOUND and shows an "Unknown error" toast. Here we
            # catch those terminal errors and reroute into the local upgrade.
            if ("upgrade" in req_name_l) and ("stargift" in req_name_l):
                entry_key = ""
                try:
                    entry = self.plugin._resolve_library_entry_for_saved_action(req)
                    if entry is not None:
                        entry_key = str(entry.get("key", "") or "")
                except Exception as e:
                    _log(f"Upgrade hook resolve entry failed: {e}")
                _log(f">>> Hooking UPGRADE_STARGIFT: {req_name} entry_key='{entry_key}'")
                param.args[1] = UpgradeStarGiftDelegate(self.plugin, param.args[1], req_name, entry_key)

            if "emojistatus" in req_name_l and "update" in req_name_l:
                cid = self.plugin._on_update_emoji_status_request(req)
                _log(f">>> Hooking STATUS: {req_name}, collectible_id={cid}")
                param.args[1] = StatusWrapperDelegate(self.plugin, param.args[1], cid, req_name)

            sync_active = bool(getattr(self.plugin, "_eblannft_sync_client", None) is not None)
            if (self.plugin._has_profile_overrides() or self.plugin._is_local_rating_active() or sync_active) and (("getfulluser" in req_name_l) or ("getusers" in req_name_l) or ("getuser" in req_name_l and "gift" not in req_name_l)):
                req_user_id = self.plugin._extract_request_user_id(req)
                should_hook_user = False
                if self.plugin._has_profile_overrides() and self.plugin._should_manage_self_saved_gifts(req_user_id=req_user_id):
                    should_hook_user = True
                elif self.plugin._should_apply_local_rating_for_target(req_user_id):
                    should_hook_user = True
                elif self.plugin._is_local_rating_active() and ("getfulluser" in req_name_l) and int(req_user_id or -1) <= 0:
                    should_hook_user = True
                elif sync_active and int(req_user_id or 0) > 0:
                    # Foreign profile + sync: wrap so we can patch wear status
                    # using the remote record fetched from the VPS.
                    should_hook_user = True
                if should_hook_user:
                    _log(f">>> Hooking USER: {req_name}")
                    param.args[1] = UserWrapperDelegate(self.plugin, param.args[1], req_name, req_user_id)

            if self.plugin._is_nft_username_active() or self.plugin._is_nft_number_active():
                if ("collectible" in req_name_l and ("info" in req_name_l or "username" in req_name_l or "phone" in req_name_l or "number" in req_name_l)) or ("fragment" in req_name_l and "collectible" in req_name_l):
                    kind, tok = self.plugin._extract_collectible_request_kind_and_token(req)
                    if (not kind or not tok) and self.plugin._is_my_profile_activity():
                        if ("phone" in req_name_l or "number" in req_name_l) and self.plugin._is_nft_number_active():
                            kind, tok = ("number", self.plugin._get_primary_nft_number())
                        elif self.plugin._is_nft_username_active():
                            kind, tok = ("username", self.plugin._get_primary_nft_username())
                        elif self.plugin._is_nft_number_active():
                            kind, tok = ("number", self.plugin._get_primary_nft_number())
                    if kind and tok:
                        # Do not interfere with other people's collectible info. Only patch/fake our managed tokens.
                        if kind == "number":
                            norm = self.plugin._normalize_nft_number(tok)
                            if norm and (not self.plugin._is_managed_nft_number(norm)):
                                kind = ""
                        elif kind == "username":
                            norm = self.plugin._normalize_nft_username(tok)
                            if norm and (not self.plugin._is_managed_nft_username(norm)):
                                kind = ""
                        if kind:
                            _log(f">>> Hooking COLLECTIBLE INFO: {req_name} kind={kind}")
                            param.args[1] = CollectibleInfoDelegate(self.plugin, param.args[1], req_name, kind, tok)

            if "uniquestargift" in req_name_l and "get" in req_name_l:
                if self.plugin.wear_active and (self.plugin.injection_payloads or self.plugin.injection_payload):
                    try:
                        req_slug = str(get_val(req, "slug", ""))
                        candidates = []
                        if self.plugin.injection_payloads:
                            candidates.extend(list(self.plugin.injection_payloads))
                        if self.plugin.injection_payload:
                            candidates.append(self.plugin.injection_payload)
                        for w in candidates:
                            cached_gift = get_val(w, "gift", None)
                            cached_slug = str(get_val(cached_gift, "slug", "")) if cached_gift else ""
                            if req_slug and cached_slug and req_slug == cached_slug:
                                _log(f">>> Hooking GIFT LOOKUP: {req_name}, slug={req_slug} -> returning cached gift")
                                param.args[1] = GiftLookupDelegate(self.plugin, param.args[1], cached_gift)
                                break
                    except Exception as e:
                        _log(f"Gift lookup hook error: {e}")
        except Exception as e:
            _log(f"NetworkHook error: {e}")

class WrapperDelegate(dynamic_proxy(RequestDelegate)):
    def __init__(self, plugin, original, req_user_id=-1, req_name="", allow_inject=True):
        super().__init__()
        self.plugin = plugin
        self.original = original
        self.req_user_id = req_user_id
        self.req_name = req_name
        self.allow_inject = bool(allow_inject)

    def run(self, response, error):
        if not error and response:
            try:
                self.plugin.process_response(response, self.req_user_id, self.req_name, self.allow_inject)
            except Exception as e:
                _log(f"WrapperDelegate error: {e}")
        if self.original:
            self.original.run(response, error)

class UpgradeStarGiftDelegate(dynamic_proxy(RequestDelegate)):
    """Network-level safety net for payments.upgradeStarGift.

    The method-level StarGiftSheet intercept (1.0.44) catches button clicks
    before they become RPCs in most cases. This delegate is the fallback for
    paths that slip past it: when Telegram replies with STARGIFT_ALREADY_CONVERTED
    or other terminal upgrade errors, we suppress the error toast (so the user
    doesn't see "Unknown error: STARGIFT_ALREADY_CONVERTED") and reroute into
    the local visual upgrade flow on the matching library entry, when we have
    one. Successful real upgrades pass through unchanged.
    """
    _UPGRADE_REROUTE_TOKENS = (
        "STARGIFT_ALREADY_CONVERTED",
        "STARGIFT_NOT_FOUND",
        "STARGIFT_NOT_MODIFIED",
        "STARGIFT_UPGRADE_UNAVAILABLE",
        "STARGIFT_RESELLABLE",
    )

    def __init__(self, plugin, original, req_name="", entry_key=""):
        super().__init__()
        self.plugin = plugin
        self.original = original
        self.req_name = str(req_name or "")
        self.entry_key = str(entry_key or "")

    def run(self, response, error):
        # NB: must return None (Java void). Never `return some_bool` here —
        # Chaquopy's PyInvocationHandler will throw
        # "Cannot convert bool object to void" on the proxy boundary.
        try:
            err_text = ""
            if error is not None:
                try:
                    err_text = str(getattr(error, "text", "") or "")
                except:
                    err_text = ""
            should_local = False
            if error is not None:
                up = err_text.upper()
                for tok in self._UPGRADE_REROUTE_TOKENS:
                    if tok in up:
                        should_local = True
                        break
            if should_local:
                key = self.entry_key
                def _open():
                    try:
                        opened = False
                        if key:
                            opened = bool(self.plugin._open_local_upgrade_for_entry(key))
                        if not opened:
                            BulletinHelper.show_info(
                                "Подарок уже сконвертирован в звёзды — используй локальный апгрейд из меню eblanNFT"
                            )
                    except Exception as e:
                        _log(f"UpgradeStarGiftDelegate reroute open failed: {e}")
                    # explicit: Runnable.run -> void
                    return None
                try:
                    run_on_ui_thread(_open)
                except Exception as e:
                    _log(f"UpgradeStarGiftDelegate run_on_ui_thread failed: {e}")
                _log(f"UpgradeStarGiftDelegate: rerouted to local upgrade (err='{err_text}', key='{key}')")
                # Suppress the original delegate entirely. Calling
                # original.run(None, None) is unsafe — Telegram's gift-sheet
                # handler may dereference response without null-checks. We
                # already dismissed/overlaid the sheet via the local upgrade
                # flow, so swallowing the callback is the safe path.
                return None
        except Exception as e:
            _log(f"UpgradeStarGiftDelegate error: {e}")
        if self.original is not None:
            try:
                self.original.run(response, error)
            except Exception as e:
                _log(f"UpgradeStarGiftDelegate original.run failed: {e}")
        return None


class StatusWrapperDelegate(dynamic_proxy(RequestDelegate)):
    def __init__(self, plugin, original, collectible_id=0, req_name=""):
        super().__init__()
        self.plugin = plugin
        self.original = original
        self.collectible_id = collectible_id
        self.req_name = req_name

    def run(self, response, error):
        try:
            if error and self.collectible_id and self.collectible_id > 0:
                try:
                    BoolTrue = jclass("org.telegram.tgnet.TLRPC$TL_boolTrue")
                    response = BoolTrue()
                    error = None
                    _log(f"STATUS faked success for collectible_id={self.collectible_id}")
                except Exception as e:
                    _log(f"STATUS fake success failed: {e}")
                    error = None

            self.plugin._patch_my_cached_user(patch_userconfig=False)
            try:
                self.plugin._patch_userconfig_current_user(force=True)
            except:
                pass
        except Exception as e:
            _log(f"StatusWrapperDelegate error: {e}")

        if self.original:
            self.original.run(response, error)

        if (self.plugin.wear_active and self.plugin.wear_collectible_id > 0) or self.plugin._is_nft_username_active() or self.plugin._is_nft_number_active():
            try:
                # The previous gate skipped rescheduling whenever the early-
                # profile fastpatch path was active — but the early-profile
                # mode is *exactly* when the loadFullUser response is about to
                # overwrite our patched cached User. Without a follow-up
                # schedule, identity/wear silently drops on the next render.
                # Always schedule; the dedupe inside _schedule_cached_user_patch
                # takes care of coalescing.
                self.plugin._schedule_cached_user_patch([180, 420], patch_userconfig=False, key="status_wrapper_delegate")
            except:
                pass

class SavedGiftActionDelegate(dynamic_proxy(RequestDelegate)):
    """
    Fake success for actions on injected (plugin) gifts so official TG UI doesn't show errors
    like SAVED_ID_EMPTY / NOT_FOUND. Also persists wrapper changes into library cache.
    """
    def __init__(self, plugin, original, entry_key=None, req_name=""):
        super().__init__()
        self.plugin = plugin
        self.original = original
        self.entry_key = entry_key
        self.req_name = req_name

    def run(self, response, error):
        try:
            err_text = ""
            try:
                err_text = str(getattr(error, "text", "") or "")
            except:
                err_text = ""
            active_key = self.entry_key
            if not active_key:
                try:
                    active_key = getattr(self.plugin, "_active_gift_sheet_entry_key", None) or self.plugin._resolve_library_key_from_gift_sheet(getattr(self.plugin, "_active_gift_sheet_ref", None))
                except:
                    active_key = None
            if error and active_key:
                try:
                    entry = self.plugin._library_find_entry(active_key)
                except:
                    entry = None
                try:
                    req_name_l = str(self.req_name or "").lower()
                except:
                    req_name_l = ""
                try:
                    should_local_upgrade = bool(
                        entry is not None
                        and self.plugin._entry_can_local_upgrade(entry)
                        and "upgrade" in req_name_l
                    )
                except:
                    should_local_upgrade = False
                try:
                    if should_local_upgrade:
                        run_on_ui_thread(lambda ek=str(active_key): self.plugin._local_upgrade_entry_runnable(ek))
                except:
                    pass
            if error and active_key:
                try:
                    BoolTrue = jclass("org.telegram.tgnet.TLRPC$TL_boolTrue")
                    response = BoolTrue()
                    error = None
                    _log(f"SAVED_GIFT action faked success key={active_key} req={self.req_name} err={err_text}")
                except Exception as e:
                    _log(f"SAVED_GIFT fake success failed: {e}")
                    error = None

            try:
                self.plugin._flush_library_if_dirty(min_interval_sec=0.0)
            except:
                pass
        except:
            pass

        if self.original:
            self.original.run(response, error)

