class ProfileActivityNotificationPatchHook(MethodHook):
    def __init__(self, plugin):
        self.plugin = plugin

    def _get_watched_ids(self, p):
        watched = set()
        try:
            watched.add(int(NotificationCenter.userInfoDidLoad))
        except:
            pass
        try:
            watched.add(int(NotificationCenter.chatInfoDidLoad))
        except:
            pass
        try:
            watched.add(int(NotificationCenter.botInfoDidLoad))
        except:
            pass
        try:
            watched.add(int(p._get_notification_center_event_id(
                jclass("org.telegram.messenger.NotificationCenter"), "mainUserInfoChanged") or 0))
        except:
            pass
        watched.discard(0)
        return watched

    def before_hooked_method(self, param):
        """Patch notification args BEFORE ProfileActivity reads them.
        This ensures the patched user/full-user object is what gets stored in
        pa.user / pa.userInfo / pa.userFull -- eliminating the window where real
        server data would briefly overwrite wear / NFT username / NFT number."""
        try:
            p = self.plugin
            if not (p._has_profile_overrides() or p._is_local_rating_active()):
                return
            pa = getattr(param, "thisObject", None)
            if pa is None or not p._is_my_profile_activity(pa):
                return
            raw_args = param.args if param.args is not None else []
            if not raw_args:
                return
            try:
                notification_id = int(raw_args[0] or 0)
            except:
                notification_id = 0
            if notification_id not in self._get_watched_ids(p):
                return
            # Patch every TLRPC object in the notification args so ProfileActivity
            # receives already-overridden data (wear status, NFT username, phone).
            for i in range(1, len(raw_args)):
                try:
                    obj = raw_args[i]
                    if obj is None:
                        continue
                    try:
                        obj.getClass()
                    except:
                        continue
                    p._apply_profile_overrides_to_obj(obj)
                    try:
                        nested = get_val(obj, "user", None)
                        if nested is not None:
                            p._apply_profile_overrides_to_obj(nested)
                    except:
                        pass
                except:
                    pass
        except Exception as e:
            _log(f"ProfileActivityNotificationPatchHook(before) error: {e}")

    def after_hooked_method(self, param):
        try:
            p = self.plugin
            # Guard now covers all profile overrides -- wear, NFT username, NFT number,
            # and local verification/rating -- not just verification/rating.
            if not (p._has_profile_overrides() or p._is_local_rating_active()):
                return
            pa = getattr(param, "thisObject", None)
            if pa is None or not p._is_my_profile_activity(pa):
                return
            raw_args = param.args if param.args is not None else []
            if not raw_args:
                return
            try:
                notification_id = int(raw_args[0] or 0)
            except:
                notification_id = 0
            if notification_id not in self._get_watched_ids(p):
                return
            try:
                frag_key = int(pa.hashCode())
            except:
                frag_key = 0
            if frag_key > 0:
                try:
                    now = time.time()
                    last_key = int(getattr(p, "_profile_notification_repatch_frag_key", 0) or 0)
                    last_ts = float(getattr(p, "_profile_notification_repatch_last_ts", 0.0) or 0.0)
                    if last_key == frag_key and (now - last_ts) < 0.24:
                        return
                    p._profile_notification_repatch_frag_key = frag_key
                    p._profile_notification_repatch_last_ts = now
                except:
                    pass
            try:
                if p._should_use_early_profile_data_mode(p._get_profile_activity_user_id(pa)):
                    return
            except:
                pass
            try:
                _log(f"ProfileActivity notification repatch: id={notification_id}")
            except:
                pass
            # Patch pa.user/userFull fields in-place, then also update the
            # MessagesController cache so all subsequent getUser calls are consistent.
            try:
                p._patch_profile_activity_in_place(pa, notify=False, include_major_views=False)
            except:
                pass
            try:
                p._patch_my_cached_user(patch_userconfig=False)
            except:
                pass
            try:
                if p._should_use_early_profile_data_mode(p._get_profile_activity_user_id(pa)):
                    return
            except:
                pass
            try:
                p._schedule_profile_ui_repatch(pa, [0, 180])
            except:
                pass
        except Exception as e:
            _log(f"ProfileActivityNotificationPatchHook error: {e}")

class LoadFullUserWearHook(MethodHook):
    """Re-apply local profile overrides after Telegram refreshes full user info."""
    def __init__(self, plugin):
        self.plugin = plugin

    def before_hooked_method(self, param):
        try:
            plugin_ref = self.plugin
            try:
                method_name = str(param.method.getName() or "")
            except:
                method_name = ""
            if method_name != "loadFullUser":
                return
            if not param.args or len(param.args) < 1:
                return
            user_obj = param.args[0]
            try:
                uid = int(plugin_ref._extract_user_id_from_obj(user_obj) or 0)
            except:
                uid = 0
            if not plugin_ref._should_use_early_profile_data_mode(uid):
                return
            ctrl = getattr(param, "thisObject", None)
            if ctrl is None:
                return
            try:
                full_obj = ctrl.getUserFull(uid)
            except:
                full_obj = None
            if full_obj is None:
                try:
                    full_obj = plugin_ref._create_placeholder_self_user_full(user_obj)
                except:
                    full_obj = None
                if full_obj is not None and user_obj is not None:
                    try:
                        ctrl.loadUserInfo(user_obj, False, 0)
                    except:
                        pass
            if full_obj is None:
                return
            try:
                plugin_ref._apply_profile_overrides_to_obj(user_obj)
            except:
                pass
            try:
                plugin_ref._apply_profile_overrides_to_obj(full_obj)
            except:
                pass
            try:
                nested_user = get_val(full_obj, "user", None)
            except:
                nested_user = None
            if nested_user is None and user_obj is not None:
                try:
                    plugin_ref._set_field(full_obj, "user", user_obj)
                except:
                    pass
            try:
                if user_obj is not None:
                    try:
                        ctrl.putUser(user_obj, False, True)
                    except Exception:
                        ctrl.putUser(user_obj, False)
            except:
                pass
            try:
                plugin_ref._touch_local_full_user_loaded_state(ctrl, uid, full_obj)
            except:
                pass
            try:
                plugin_ref._last_load_full_user_short_circuit_uid = uid
            except:
                pass

            def _dispatch():
                try:
                    if len(param.args) >= 4 and param.args[3] is not None:
                        param.args[3].run(full_obj)
                except:
                    pass
                try:
                    account = int(get_user_config().selectedAccount or 0)
                except:
                    account = 0
                try:
                    NC = jclass("org.telegram.messenger.NotificationCenter")
                    nc = NC.getInstance(to_java_int(account))
                    if nc is not None:
                        nc.postNotificationName(to_java_int(int(NotificationCenter.userInfoDidLoad)), uid, full_obj)
                except:
                    pass

            try:
                run_on_ui_thread(_dispatch)
            except:
                try:
                    _dispatch()
                except:
                    pass
            param.setResult(None)
        except Exception as e:
            _log(f"LoadFullUserWearHook(before) error: {e}")

    def after_hooked_method(self, param):
        try:
            plugin_ref = self.plugin
            try:
                method_name = str(param.method.getName() or "")
            except:
                method_name = ""
            if method_name == "loadFullUser":
                try:
                    uid = int(plugin_ref._extract_user_id_from_obj(param.args[0]) or 0) if param.args else 0
                except:
                    uid = 0
                try:
                    short_uid = int(getattr(plugin_ref, "_last_load_full_user_short_circuit_uid", 0) or 0)
                except:
                    short_uid = 0
                if short_uid > 0 and short_uid == uid:
                    try:
                        plugin_ref._last_load_full_user_short_circuit_uid = 0
                    except:
                        pass
                    return
            if not (plugin_ref._has_profile_overrides() or plugin_ref._is_local_rating_active()):
                return
            def _restore():
                try:
                    plugin_ref._patch_my_cached_user(patch_userconfig=False)
                except:
                    pass
                try:
                    plugin_ref._patch_my_cached_user_full()
                except:
                    pass
                try:
                    plugin_ref._patch_userconfig_current_user(force=True)
                except:
                    pass
            AndroidUtilities.runOnUIThread(JRunnable(_restore), 300)
        except Exception as e:
            _log(f"LoadFullUserWearHook error: {e}")

class GetAnyWearHook(MethodHook):
    def __init__(self, plugin):
        self.plugin = plugin

    def after_hooked_method(self, param):
        try:
            # Master-switch fast-path: skip reflection when there is nothing
            # to override. getUser / getUserFull fire extremely frequently
            # (per cell bind, per notification) - this is the single
            # biggest CPU win in the plugin when all overrides are off.
            try:
                if not self.plugin._has_profile_overrides():
                    return
            except:
                pass
            try:
                my_id = int(self.plugin._get_my_user_id() or 0)
            except:
                my_id = 0
            if my_id <= 0:
                return
            try:
                req_obj = param.args[0] if param.args and len(param.args) > 0 else None
            except:
                req_obj = None
            if req_obj is not None:
                try:
                    req_uid = int(self.plugin._extract_user_id_from_obj(req_obj) or 0)
                except:
                    req_uid = 0
                # Fast reject: getUser/getUserFull/getUserOrChat for any entity
                # except our own profile should never enter the heavy override
                # pipeline.
                if req_uid != 0 and req_uid != my_id:
                    return
            user_obj = param.getResult()
            if user_obj is None:
                return
            try:
                result_uid = int(self.plugin._extract_user_id_from_obj(user_obj) or 0)
            except:
                result_uid = 0
            if result_uid > 0 and result_uid != my_id:
                return
            try:
                should_skip, state_sig = self.plugin._should_skip_hot_get_override(user_obj, ttl=0.55)
            except:
                should_skip, state_sig = False, None
            if should_skip:
                return
            changed = False
            try:
                changed = bool(self.plugin._apply_profile_overrides_to_obj(user_obj))
            finally:
                try:
                    self.plugin._mark_hot_get_override(user_obj, state_sig)
                except:
                    pass
            if changed:
                param.setResult(user_obj)
        except Exception as e:
            _log(f"GetAnyWearHook error: {e}")

class GetUserFullForeignSyncHook(MethodHook):
    """Patch foreign UserFull on every getUserFull read with synced rating
    and stargifts_count. Catches cases where the response-wrapper patch
    (_sync_apply_remote_user_overrides) didn't fire — e.g. cache hit, no
    fresh network round-trip."""

    def __init__(self, plugin):
        self.plugin = plugin

    def after_hooked_method(self, param):
        try:
            full_obj = param.getResult()
            if full_obj is None:
                return
            try:
                args = param.args
            except Exception:
                args = None
            if not args or len(args) < 1:
                return
            try:
                uid = int(args[0] or 0)
            except Exception:
                uid = 0
            if uid <= 0:
                return
            try:
                my_id = int(self.plugin._get_my_user_id() or 0)
            except Exception:
                my_id = 0
            if uid == my_id:
                return
            client = getattr(self.plugin, "_eblannft_sync_client", None)
            if client is None:
                return
            record = None
            try:
                record = client.get_cached(uid)
            except Exception:
                record = None
            if not isinstance(record, dict):
                return
            changed = False
            # stargifts_count bump for tab visibility
            try:
                gifts_count = int(self.plugin._sync_get_remote_gifts_count(record) or 0)
                if gifts_count > 0:
                    if self.plugin._apply_remote_stargifts_count_to_obj(full_obj, gifts_count):
                        changed = True
            except Exception:
                pass
            # stars_rating
            try:
                rs = record.get("rating_state") or {}
                if isinstance(rs, dict) and rs.get("enabled") and int(rs.get("value", 0) or 0) > 0:
                    rating_args = (
                        int(rs.get("value", 0) or 0),
                        int(rs.get("level", 1) or 1),
                        int(rs.get("next_goal", 0) or 0),
                    )
                    if self.plugin._apply_remote_rating_to_full_user(full_obj, *rating_args):
                        changed = True
            except Exception:
                pass
            if changed:
                try:
                    param.setResult(full_obj)
                    _log(f"GetUserFullForeignSync patched uid={uid}")
                except Exception:
                    pass
        except Exception as e:
            try:
                _log(f"GetUserFullForeignSyncHook error: {e}")
            except Exception:
                pass


class PutAnyWearHook(MethodHook):
    def __init__(self, plugin):
        self.plugin = plugin

    def before_hooked_method(self, param):
        try:
            # Master-switch fast-path: when no local override is enabled there
            # is literally nothing to do - skip reflection on every single
            # putUser call from MessagesController. This is the hottest path
            # during chat/contact sync and accounts for most JNI traffic.
            try:
                if not self.plugin._has_profile_overrides():
                    return
            except:
                pass
            if not param.args or len(param.args) < 1:
                return
            user_obj = param.args[0]
            if user_obj is None:
                return
            try:
                my_id = int(self.plugin._get_my_user_id() or 0)
            except:
                my_id = 0
            if my_id <= 0:
                return
            try:
                uid = int(self.plugin._extract_user_id_from_obj(user_obj) or 0)
            except:
                uid = 0
            if uid > 0 and uid != my_id:
                return
            self.plugin._apply_profile_overrides_to_obj(user_obj)
        except Exception as e:
            _log(f"PutAnyWearHook error: {e}")

    def after_hooked_method(self, param):
        # After Telegram's internal merge runs (putUser merges incoming user
        # into the cached User in MessagesController.users), the cached User
        # may have a *fresh* usernames ArrayList that reflects only the server
        # state — discarding our pre-merge patches. Re-apply against the
        # post-merge cached User so wear AND identity stay in sync, eliminating
        # the "wear shows / usernames revert" alternation users see when the
        # merge replaces the list reference.
        try:
            p = self.plugin
            try:
                if not p._has_profile_overrides():
                    return
            except:
                pass
            if not param.args or len(param.args) < 1:
                return
            user_obj = param.args[0]
            if user_obj is None:
                return
            try:
                my_id = int(p._get_my_user_id() or 0)
            except:
                my_id = 0
            if my_id <= 0:
                return
            try:
                uid = int(p._extract_user_id_from_obj(user_obj) or 0)
            except:
                uid = 0
            if uid > 0 and uid != my_id:
                return
            try:
                # Re-apply on the obj passed to putUser (typically the same
                # ref that ends up in MessagesController.users on first put).
                p._apply_profile_overrides_to_obj(user_obj)
            except:
                pass
            try:
                # Then also re-apply on whatever MessagesController stored,
                # in case it kept the previous cached User and merged fields
                # into it instead of swapping refs.
                account = get_user_config().selectedAccount
                MC = jclass("org.telegram.messenger.MessagesController")
                ctrl = MC.getInstance(to_java_int(account))
                cached = ctrl.getUser(my_id)
                if cached is not None and cached is not user_obj:
                    p._apply_profile_overrides_to_obj(cached)
            except:
                pass
        except Exception as e:
            _log(f"PutAnyWearHook(after) error: {e}")

class PutUsersWearHook(MethodHook):
    def __init__(self, plugin):
        self.plugin = plugin

    def before_hooked_method(self, param):
        try:
            # Master-switch fast-path (see PutAnyWearHook comment).
            # Without this guard, every incoming user batch would spin up
            # the per-item override pipeline even when the user has all
            # local overrides disabled.
            try:
                if not self.plugin._has_profile_overrides():
                    return
            except:
                pass
            if not param.args or len(param.args) < 1:
                return
            lst = param.args[0]
            if lst is None:
                return
            try:
                size = int(lst.size() or 0)
            except:
                return
            if size <= 0:
                return
            try:
                my_id = int(self.plugin._get_my_user_id() or 0)
            except:
                my_id = 0
            if my_id <= 0:
                return
            apply = self.plugin._apply_profile_overrides_to_obj
            for i in range(size):
                try:
                    item = lst.get(i)
                except:
                    continue
                if item is None:
                    continue
                try:
                    uid = int(self.plugin._extract_user_id_from_obj(item) or 0)
                except:
                    uid = 0
                if uid > 0 and uid != my_id:
                    continue
                try:
                    apply(item)
                except:
                    continue
                if uid == my_id:
                    break
        except Exception as e:
            _log(f"PutUsersWearHook error: {e}")

    def after_hooked_method(self, param):
        # Mirrors PutAnyWearHook.after_hooked_method: after Telegram's bulk
        # merge runs, the cached self-User in MessagesController.users may
        # have its usernames / emoji_status fields swapped to whatever the
        # server batch contained, dropping our pre-merge patches. Re-apply
        # against the now-cached User so wear and identity stay in sync,
        # eliminating the alternation users observe between profile renders.
        try:
            p = self.plugin
            try:
                if not p._has_profile_overrides():
                    return
            except:
                pass
            try:
                my_id = int(p._get_my_user_id() or 0)
            except:
                my_id = 0
            if my_id <= 0:
                return
            try:
                account = get_user_config().selectedAccount
                MC = jclass("org.telegram.messenger.MessagesController")
                ctrl = MC.getInstance(to_java_int(account))
                cached = ctrl.getUser(my_id)
            except:
                cached = None
            if cached is None:
                return
            try:
                p._apply_profile_overrides_to_obj(cached)
            except:
                pass
        except Exception as e:
            _log(f"PutUsersWearHook(after) error: {e}")

class ProcessUserInfoCacheHook(MethodHook):
    def __init__(self, plugin):
        self.plugin = plugin

    def before_hooked_method(self, param):
        try:
            if not param.args or len(param.args) < 2:
                return
            ctrl = getattr(param, "thisObject", None)
            user_obj = param.args[0]
            info_obj = param.args[1]
            try:
                uid = int(self.plugin._extract_user_id_from_obj(user_obj) or 0)
            except:
                uid = 0
            if not self.plugin._should_use_early_profile_data_mode(uid):
                return
            try:
                if user_obj is not None:
                    self.plugin._apply_profile_overrides_to_obj(user_obj)
                    if ctrl is not None:
                        try:
                            try:
                                ctrl.putUser(user_obj, False, True)
                            except Exception:
                                ctrl.putUser(user_obj, False)
                        except:
                            pass
            except:
                pass
            if info_obj is None and ctrl is not None:
                try:
                    info_obj = ctrl.getUserFull(uid)
                except:
                    info_obj = None
                if info_obj is not None:
                    try:
                        param.args[1] = info_obj
                    except:
                        pass
            if info_obj is not None:
                try:
                    self.plugin._apply_profile_overrides_to_obj(info_obj)
                except:
                    pass
                try:
                    nested_user = get_val(info_obj, "user", None)
                except:
                    nested_user = None
                if nested_user is None and user_obj is not None:
                    try:
                        self.plugin._set_field(info_obj, "user", user_obj)
                    except:
                        pass
                try:
                    self.plugin._touch_local_full_user_loaded_state(ctrl, uid, info_obj)
                except:
                    pass
        except Exception as e:
            _log(f"ProcessUserInfoCacheHook error: {e}")

class ProcessUpdatesWearHook(MethodHook):
    def __init__(self, plugin):
        self.plugin = plugin

    def before_hooked_method(self, param):
        try:
            has_wear = bool(self.plugin.wear_active and self.plugin.wear_collectible_id > 0)
            has_identity = bool(self.plugin._is_nft_username_active() or self.plugin._is_nft_number_active())
            if not has_wear and not has_identity:
                return
            if not param.args:
                return
            total = 0
            for a in param.args:
                if a is None:
                    continue
                try:
                    _ = a.getClass()
                except:
                    continue
                if has_wear:
                    total += self.plugin._patch_wear_in_updates_container(a)
                if has_identity:
                    total += self.plugin._patch_identity_in_updates_container(a)
            if total:
                _log(f"Updates patched before apply: {total}")
        except Exception as e:
            _log(f"ProcessUpdatesWearHook error: {e}")

    def after_hooked_method(self, param):
        try:
            has_wear = bool(self.plugin.wear_active and self.plugin.wear_collectible_id > 0)
            has_identity = bool(self.plugin._is_nft_username_active() or self.plugin._is_nft_number_active())
            if not has_wear and not has_identity:
                return
            # Re-patch our cached user right after Telegram applies the update batch.
            # This catches any cases where wear/identity state was overwritten by the
            # incoming update (e.g. server pushed TL_updateUserEmojiStatus with empty status).
            try:
                self.plugin._schedule_cached_user_patch([80], patch_userconfig=False, key="post_updates_wear_patch")
            except:
                pass
        except Exception as e:
            _log(f"ProcessUpdatesWearHook(after) error: {e}")

class EmojiStatusCallbackHook(MethodHook):
    def __init__(self, plugin):
        self.plugin = plugin

    def after_hooked_method(self, param):
        try:
            try:
                self.plugin._patch_my_cached_user(patch_userconfig=False)
            except:
                pass
            try:
                self.plugin._patch_my_cached_user_full()
            except:
                pass
            try:
                self.plugin._patch_userconfig_current_user(force=True)
            except:
                pass
            try:
                # Extended schedule: patch at 0 ms (immediate), 180 ms, 600 ms, and 1800 ms
                # to ensure the wear/identity state survives any delayed UI updates from the server
                self.plugin._schedule_cached_user_patch([0, 180, 600, 1800], patch_userconfig=True, key="status_cached_user_patch")
            except:
                pass
        except Exception as e:
            _log(f"EmojiStatusCallbackHook error: {e}")

class UpdateEmojiStatusHardLockHook(MethodHook):
    """Block local clear of the worn collectible before Telegram mutates currentUser."""
    def __init__(self, plugin):
        self.plugin = plugin

    def before_hooked_method(self, param):
        try:
            p = self.plugin
            active_cid = int(p.wear_collectible_id or 0)
            if not p.wear_active or active_cid <= 0:
                return

            args = list(param.args or [])
            if len(args) >= 3:
                try:
                    dialog_id = int(args[0] or 0)
                except:
                    dialog_id = 0
                try:
                    my_id = int(p._get_my_user_id() or 0)
                except:
                    my_id = 0
                if dialog_id not in [0, my_id]:
                    return

            requested_cid = 0
            for arg in args:
                try:
                    requested_cid = int(p._extract_collectible_id(arg) or 0)
                except:
                    requested_cid = 0
                if requested_cid > 0:
                    return

            try:
                p._ensure_current_wear_status_data(active_cid, force=False)
            except:
                pass
            try:
                p._patch_my_cached_user(patch_userconfig=False)
            except:
                pass
            try:
                p._patch_userconfig_current_user(force=True)
            except:
                pass
            try:
                p._post_local_profile_notifications(reason="wear_hardlock_block_clear", cooldown=0.12)
            except:
                pass
            try:
                p._schedule_cached_user_patch([0, 120, 360, 900], patch_userconfig=True, key="wear_hardlock_block_clear")
            except:
                pass
            try:
                _log(f"WEAR HARDLOCK: blocked local clear, kept collectible_id={active_cid}")
            except:
                pass
            param.setResult(None)
        except Exception as e:
            _log(f"UpdateEmojiStatusHardLockHook error: {e}")

