class GetCurrentUserOverrideHook(MethodHook):
    """Re-apply identity / wear / rating overrides on every getCurrentUser
    read. The drawer header, account list and several profile rows pull
    from this getter — patching here guarantees they never see a non-spoofed
    snapshot, regardless of what update path raced our scheduled patches.
    """
    def __init__(self, plugin):
        self.plugin = plugin
        self._reentry_guard = False

    def after_hooked_method(self, param):
        try:
            if self._reentry_guard:
                return
            p = self.plugin
            try:
                if (not p._has_profile_overrides()) and (not p._is_local_rating_active()):
                    return
            except Exception:
                return
            user_obj = None
            try:
                user_obj = param.getResult()
            except Exception:
                user_obj = None
            if user_obj is None:
                return
            try:
                uid = int(p._extract_user_id_from_obj(user_obj) or 0)
            except Exception:
                uid = 0
            try:
                my_id = int(p._get_my_user_id() or 0)
            except Exception:
                my_id = 0
            if my_id <= 0 or (uid > 0 and uid != my_id):
                return
            self._reentry_guard = True
            try:
                p._apply_profile_overrides_to_obj(user_obj)
            finally:
                self._reentry_guard = False
        except Exception as e:
            try:
                _log(f"GetCurrentUserOverrideHook error: {e}")
            except Exception:
                pass

class AttrLoader:
    def __init__(self, plugin, gift_id, allow_generic_fallback=False):
        self.plugin = plugin
        self.base_gift_id = int(gift_id or 0)
        self.gift_id = int(gift_id or 0)
        self.req_callback = None
        self.allow_generic_fallback = bool(allow_generic_fallback)
        self._fallback_requested = False

    def start(self):
        # Fast path: if the upgrade-attribute pool was already populated
        # by a previous load (any gift's attrs fill the generic model /
        # pattern / backdrop pools), open the builder immediately. Saves
        # the 5-10s server round-trip every time the user re-enters the
        # constructor.
        try:
            if self.allow_generic_fallback and self.plugin._has_generic_upgrade_attrs():
                _log(f"AttrLoader: cache hit, opening builder immediately gift_id={self.gift_id}")
                run_on_ui_thread(lambda: NftBuilderSheet(self.plugin, self.base_gift_id, None).show())
                # Refresh attrs in the background so the pool tracks new
                # gifts released on the server without making the user wait.
                def _bg_refresh(response, error):
                    if error or response is None:
                        return None
                    try:
                        self.plugin._remember_upgrade_attrs(self.gift_id, response)
                    except Exception:
                        pass
                    return None
                try:
                    bg_req = jclass("org.telegram.tgnet.tl.TL_stars$getStarGiftUpgradeAttributes")()
                    bg_req.gift_id = self.gift_id
                    self.req_callback = JRequestDelegate(_bg_refresh)
                    get_connections_manager().sendRequest(bg_req, self.req_callback)
                except Exception:
                    pass
                return
        except Exception:
            pass

        try:
            req = jclass("org.telegram.tgnet.tl.TL_stars$getStarGiftUpgradeAttributes")()
            req.gift_id = self.gift_id
            self.req_callback = JRequestDelegate(self.on_done)
            get_connections_manager().sendRequest(req, self.req_callback)
            _log(f"AttrLoader: requesting gift_id={self.gift_id}")
            BulletinHelper.show_info("\u0417\u0430\u0433\u0440\u0443\u0437\u043a\u0430 \u0430\u0442\u0440\u0438\u0431\u0443\u0442\u043e\u0432...")
        except Exception as e:
            _log(f"AttrLoader error: {e}\n{traceback.format_exc()}")
            BulletinHelper.show_error(f"\u041e\u0448\u0438\u0431\u043a\u0430 \u0437\u0430\u043f\u0440\u043e\u0441\u0430: {e}")

    def on_done(self, response, error):
        if error:
            _log(f"AttrLoader net error: {error.text}")
            if self.allow_generic_fallback:
                try:
                    if self.plugin._has_generic_upgrade_attrs():
                        run_on_ui_thread(lambda: NftBuilderSheet(self.plugin, self.base_gift_id, None).show())
                        return
                except:
                    pass
                try:
                    if not self._fallback_requested:
                        seed_id = int(self.plugin._get_fallback_upgrade_seed_gift_id(exclude_gift_id=self.gift_id) or 0)
                        if seed_id > 0:
                            self._fallback_requested = True
                            self.gift_id = int(seed_id)
                            self.start()
                            return
                except:
                    pass
            run_on_ui_thread(lambda: BulletinHelper.show_error(f"\u041e\u0448\u0438\u0431\u043a\u0430 \u0441\u0435\u0442\u0438: {error.text}"))
            return
        _log("AttrLoader: attributes received")
        try:
            self.plugin._remember_upgrade_attrs(self.gift_id, response)
        except:
            pass
        run_on_ui_thread(lambda: NftBuilderSheet(self.plugin, self.base_gift_id, response).show())


# ---------------------------------------------------------------------------
# «Мои подарки» V3 — MD3 card-style screen
# ---------------------------------------------------------------------------
class MyGiftsCardSheet:
    """Full-screen BottomSheet that renders the user's gift library as a
    vertical list of MD3-style cards. Two card variants:

      - Regular (gift_kind='standard'): animated sticker preview on the left,
        inline editable rows for «От кого» / «Дата» / «Комментарий», and a
        single red «Удалить» button.
      - NFT (gift_kind not standard): sticker preview on the left, attribute
        rows (Model / Symbol / Backdrop with rarity %), and two pill buttons:
        blue «Изменить» (opens the existing constructor) + red «Удалить».

    Tap on any editable row in a regular card opens the existing
    _show_text_input_dialog. All state mutation routes through the existing
    _my_gifts_set_field / _my_gifts_delete helpers so persistence, wrapper
    invalidation, and injection rebuild stay unified with V1's list view.
    """

    def __init__(self, plugin):
        self.plugin = plugin
        self.sheet = None
        self.scroll_root = None
        self.empty_view = None

    def show(self):
        try:
            fragment = get_last_fragment()
            if not fragment:
                return
            ctx = fragment.getParentActivity()
            if not ctx:
                return
            BottomSheetCls = jclass("org.telegram.ui.ActionBar.BottomSheet")
            self.sheet = BottomSheetCls(ctx, False)
            try:
                # Full-height sheet — the cards scroll independently.
                self.sheet.setUseFullWidth(False)
            except:
                pass
            # Disable swipe-to-dismiss: BottomSheet's swipe handler captures
            # vertical drags from the top of the scroll area, so the user
            # can't scroll up after scrolling down (the sheet starts to
            # collapse instead of the ScrollView scrolling). Keep the back
            # arrow as the only close path — gestures stay with ScrollView.
            try:
                self.sheet.setCanDismissWithSwipe(False)
            except:
                pass
            root = self._build_root(ctx)
            try:
                self.sheet.setCustomView(root)
            except Exception as _e:
                _log(f"MyGiftsCardSheet setCustomView fail: {_e}")
            try:
                self.sheet.show()
            except Exception as _e:
                _log(f"MyGiftsCardSheet show fail: {_e}")
        except Exception as e:
            _log(f"MyGiftsCardSheet.show error: {e}")
            try:
                BulletinHelper.show_error(f"Карточный вид: {e}")
            except:
                pass

    def _dismiss(self):
        try:
            if self.sheet is not None:
                self.sheet.dismiss()
        except:
            pass
        self.sheet = None
        self.scroll_root = None
        self.empty_view = None

    def refresh(self):
        """Rebuild the content list after add/delete/edit so the sheet
        reflects current state without dismissing."""
        try:
            ctx = self.scroll_root.getContext() if self.scroll_root is not None else None
        except:
            ctx = None
        if ctx is None or self.scroll_root is None:
            return
        try:
            self.scroll_root.removeAllViews()
        except:
            pass
        try:
            self._fill_cards(ctx, self.scroll_root)
        except Exception as e:
            _log(f"MyGiftsCardSheet refresh error: {e}")

    # -----------------------------------------------------------------------
    # Layout builders
    # -----------------------------------------------------------------------

    def _build_root(self, ctx):
        screen_h = AndroidUtilities.displaySize.y
        sheet_h = int(screen_h * 0.92)

        outer = LinearLayout(ctx)
        outer.setOrientation(LinearLayout.VERTICAL)
        outer.setBackgroundColor(Theme.getColor(Theme.key_windowBackgroundGray))
        try:
            outer.setLayoutParams(FrameLayout.LayoutParams(-1, sheet_h))
        except:
            pass

        # ---- Top bar: back arrow + title + (+) add button -----------------
        bar = LinearLayout(ctx)
        bar.setOrientation(LinearLayout.HORIZONTAL)
        bar.setGravity(Gravity.CENTER_VERTICAL)
        bar.setPadding(AndroidUtilities.dp(8), AndroidUtilities.dp(8),
                       AndroidUtilities.dp(8), AndroidUtilities.dp(8))
        bar.setBackgroundColor(Theme.getColor(Theme.key_dialogBackground))

        back_btn = self._build_icon_button(
            ctx, "ic_ab_back", Theme.getColor(Theme.key_dialogTextBlack),
            on_click=lambda v: self._dismiss(),
        )
        bar.addView(back_btn, LinearLayout.LayoutParams(AndroidUtilities.dp(44), AndroidUtilities.dp(44)))

        title = TextView(ctx)
        title.setText("Мои подарки")
        title.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 18)
        try:
            title.setTypeface(AndroidUtilities.bold())
        except:
            pass
        title.setTextColor(Theme.getColor(Theme.key_dialogTextBlack))
        lp_title = LinearLayout.LayoutParams(0, -2, 1.0)
        lp_title.leftMargin = AndroidUtilities.dp(12)
        bar.addView(title, lp_title)

        add_btn = self._build_icon_button(
            ctx, "msg_add", Theme.getColor(Theme.key_featuredStickers_addButton),
            on_click=lambda v: self._on_add_clicked(),
        )
        bar.addView(add_btn, LinearLayout.LayoutParams(AndroidUtilities.dp(44), AndroidUtilities.dp(44)))

        outer.addView(bar, LinearLayout.LayoutParams(-1, AndroidUtilities.dp(56)))

        # ---- Scrollable cards container -----------------------------------
        scroll = ScrollView(ctx)
        try:
            scroll.setFillViewport(True)
        except:
            pass
        cards = LinearLayout(ctx)
        cards.setOrientation(LinearLayout.VERTICAL)
        cards.setPadding(AndroidUtilities.dp(12), AndroidUtilities.dp(8),
                         AndroidUtilities.dp(12), AndroidUtilities.dp(24))
        self.scroll_root = cards
        self._fill_cards(ctx, cards)
        scroll.addView(cards, FrameLayout.LayoutParams(-1, -2))
        outer.addView(scroll, LinearLayout.LayoutParams(-1, 0, 1.0))
        return outer

    def _fill_cards(self, ctx, cards):
        entries = self.plugin._my_gifts_list_entries()
        # Newest first: sort by custom_date_ts (user-set date) primarily,
        # then fall back to created_at / updated_at so freshly-added gifts
        # without a custom date still surface at the top.
        def _entry_sort_key(item):
            _, entry = item
            try:
                ts = int(entry.get("custom_date_ts", 0) or 0)
            except:
                ts = 0
            if ts > 0:
                return ts
            try:
                return int(entry.get("created_at", 0) or entry.get("updated_at", 0) or 0)
            except:
                return 0
        try:
            entries.sort(key=_entry_sort_key, reverse=True)
        except Exception as _se:
            _log(f"MyGiftsCardSheet sort fail: {_se}")
        if not entries:
            empty = TextView(ctx)
            empty.setText("Пусто.\nНажмите + чтобы добавить подарок.")
            empty.setTextColor(Theme.getColor(Theme.key_windowBackgroundWhiteGrayText2))
            empty.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 15)
            empty.setGravity(Gravity.CENTER)
            empty.setPadding(0, AndroidUtilities.dp(48), 0, 0)
            cards.addView(empty, LinearLayout.LayoutParams(-1, -2))
            self.empty_view = empty
            return
        self.empty_view = None
        for source, entry in entries:
            try:
                key = str(entry.get("key", "") or "")
            except:
                key = ""
            if not key:
                continue
            try:
                card = self._build_card(ctx, source, entry, key)
            except Exception as e:
                _log(f"MyGiftsCardSheet build_card fail key={key}: {e}")
                continue
            if card is None:
                continue
            lp = LinearLayout.LayoutParams(-1, -2)
            lp.topMargin = AndroidUtilities.dp(10)
            cards.addView(card, lp)

    def _build_card(self, ctx, source, entry, key):
        card = LinearLayout(ctx)
        card.setOrientation(LinearLayout.VERTICAL)
        card.setPadding(AndroidUtilities.dp(12), AndroidUtilities.dp(12),
                        AndroidUtilities.dp(12), AndroidUtilities.dp(12))
        card_bg = GradientDrawable()
        card_bg.setCornerRadius(AndroidUtilities.dp(18))
        card_bg.setColor(Theme.getColor(Theme.key_dialogBackground))
        card.setBackground(card_bg)

        # ---- Top row: preview (square) + info block ------------------------
        top = LinearLayout(ctx)
        top.setOrientation(LinearLayout.HORIZONTAL)

        preview = self._build_preview(ctx, source, entry)
        lp_prev = LinearLayout.LayoutParams(AndroidUtilities.dp(108), AndroidUtilities.dp(108))
        top.addView(preview, lp_prev)

        info = LinearLayout(ctx)
        info.setOrientation(LinearLayout.VERTICAL)
        lp_info = LinearLayout.LayoutParams(0, -2, 1.0)
        lp_info.leftMargin = AndroidUtilities.dp(12)

        title_view = TextView(ctx)
        title_view.setText(self.plugin._my_gifts_entry_title(source, entry))
        title_view.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 17)
        try:
            title_view.setTypeface(AndroidUtilities.bold())
        except:
            pass
        title_view.setTextColor(Theme.getColor(Theme.key_dialogTextBlack))
        info.addView(title_view, LinearLayout.LayoutParams(-1, -2))

        if source == "nft":
            self._build_nft_attribute_rows(ctx, info, entry)
        else:
            self._build_regular_inline_rows(ctx, info, entry, key, source)

        top.addView(info, lp_info)
        card.addView(top, LinearLayout.LayoutParams(-1, -2))

        # ---- Action buttons row -------------------------------------------
        actions = LinearLayout(ctx)
        actions.setOrientation(LinearLayout.HORIZONTAL)
        lp_actions = LinearLayout.LayoutParams(-1, -2)
        lp_actions.topMargin = AndroidUtilities.dp(12)

        if source == "nft":
            edit_btn = self._build_pill_button(
                ctx, "msg_edit", "Изменить",
                tint=Theme.getColor(Theme.key_featuredStickers_addButton),
                on_click=lambda v, k=key: self._on_edit_clicked(k),
            )
            lp_edit = LinearLayout.LayoutParams(0, AndroidUtilities.dp(44), 1.0)
            lp_edit.rightMargin = AndroidUtilities.dp(8)
            actions.addView(edit_btn, lp_edit)

        delete_btn = self._build_pill_button(
            ctx, "msg_delete", "Удалить",
            tint=Theme.getColor(Theme.key_text_RedRegular),
            on_click=lambda v, k=key, s=source: self._on_delete_clicked(k, s),
        )
        actions.addView(delete_btn, LinearLayout.LayoutParams(0, AndroidUtilities.dp(44), 1.0))

        card.addView(actions, lp_actions)
        return card

    def _build_preview(self, ctx, source, entry):
        """108dp rounded-corner preview. For regular gifts: just the animated
        gift sticker. For NFT gifts: backdrop radial gradient (center→edge
        from TL_starGiftAttributeBackdrop) + pattern document overlay +
        centered model sticker — same visual style Telegram uses in the
        profile gift grid."""
        wrap = FrameLayout(ctx)
        bg = GradientDrawable()
        bg.setCornerRadius(AndroidUtilities.dp(14))
        try:
            bg.setColor(Theme.getColor(Theme.key_windowBackgroundGray))
        except:
            bg.setColor(0xFF222222)
        try:
            wrap.setBackground(bg)
        except:
            pass
        try:
            wrap.setClipToOutline(True)
        except:
            pass

        # Resolve wrapper + inner gift once; reused for sticker/backdrop/pattern.
        wrapper = None
        gift = None
        try:
            key = str(entry.get("key", "") or "")
            wrapper = self.plugin._library_get_wrapper(key) if key else None
            gift = self.plugin._extract_wrapper_gift(wrapper) if wrapper is not None else None
        except:
            wrapper, gift = None, None

        # NFT-only: backdrop gradient + pattern overlay (only if attributes
        # carry a Backdrop). Fall through to sticker render below for the
        # model layer regardless.
        if source == "nft" and gift is not None:
            try:
                self._apply_nft_backdrop_and_pattern(ctx, wrap, gift)
            except Exception as _e:
                _log(f"MyGiftsCardSheet backdrop/pattern fail: {_e}")

        # Sticker / model layer: regular = gift.sticker, NFT = model.document
        # if available (model attribute), else gift.sticker as fallback.
        document = None
        if source == "nft" and gift is not None:
            try:
                document = self._resolve_nft_model_document(gift)
            except:
                document = None
        if document is None and gift is not None:
            try:
                document = get_val(gift, "sticker", None)
            except:
                document = None

        if document is not None:
            try:
                img = BackupImageView(ctx)
                # NFT model should leave the backdrop gradient and pattern
                # symbols visible around it — 72dp inside a 108dp tile is
                # roughly two thirds, matching the prototype proportions.
                # Regular gifts have no backdrop so we keep the sticker
                # slightly bigger (84dp) but still leave some inset breathing
                # room around the rounded edges.
                model_size_dp = 72 if source == "nft" else 84
                try:
                    img.setRoundRadius(AndroidUtilities.dp(model_size_dp // 2))
                except:
                    pass
                try:
                    size_tag = f"{model_size_dp}_{model_size_dp}"
                    image_location = ImageLocation.getForDocument(document)
                    if image_location is not None:
                        img.setImage(image_location, size_tag, None, 0, document)
                except Exception as _e:
                    _log(f"MyGiftsCardSheet sticker load fail: {_e}")
                try:
                    if hasattr(img, "startAnimation"):
                        img.startAnimation()
                except:
                    pass
                lp_img = FrameLayout.LayoutParams(
                    AndroidUtilities.dp(model_size_dp),
                    AndroidUtilities.dp(model_size_dp),
                    Gravity.CENTER,
                )
                wrap.addView(img, lp_img)
                return wrap
            except Exception as _e:
                _log(f"MyGiftsCardSheet BackupImageView fail: {_e}")

        # Final fallback: blank rounded tile.
        fallback = ImageView(ctx)
        wrap.addView(fallback, FrameLayout.LayoutParams(-2, -2, Gravity.CENTER))
        return wrap

    def _apply_nft_backdrop_and_pattern(self, ctx, wrap, gift):
        """Apply backdrop radial gradient and pattern document overlay onto
        the preview FrameLayout. Reads from TL_starGiftAttributeBackdrop
        (center_color, edge_color, pattern_color) and TL_starGiftAttributePattern
        (document) inside gift.attributes."""
        attrs = get_val(gift, "attributes", None)
        if attrs is None:
            return
        try:
            size = int(attrs.size() or 0)
        except:
            return

        center_color = None
        edge_color = None
        pattern_color = None
        pattern_doc = None
        for i in range(size):
            try:
                a = attrs.get(i)
            except:
                continue
            if a is None:
                continue
            try:
                cls_low = str(a.getClass().getSimpleName() or "").lower()
            except:
                cls_low = ""
            if "backdrop" in cls_low:
                try:
                    center_color = int(get_val(a, "center_color", 0) or 0) | 0xFF000000
                except:
                    pass
                try:
                    edge_color = int(get_val(a, "edge_color", 0) or 0) | 0xFF000000
                except:
                    pass
                try:
                    pattern_color = int(get_val(a, "pattern_color", 0) or 0) | 0xFF000000
                except:
                    pass
            elif "pattern" in cls_low or "symbol" in cls_low:
                try:
                    pattern_doc = get_val(a, "document", None)
                except:
                    pattern_doc = None

        # Backdrop: radial gradient from center to edge.
        if center_color is not None and edge_color is not None:
            try:
                grad = GradientDrawable()
                grad.setShape(GradientDrawable.RECTANGLE)
                grad.setCornerRadius(AndroidUtilities.dp(14))
                grad.setGradientType(GradientDrawable.RADIAL_GRADIENT)
                try:
                    grad.setGradientCenter(0.5, 0.5)
                except:
                    pass
                try:
                    grad.setGradientRadius(AndroidUtilities.dp(80))
                except:
                    pass
                try:
                    # API 16+: setColors([center, edge])
                    grad.setColors([to_java_int(center_color), to_java_int(edge_color)])
                except:
                    # Fallback if setColors not available.
                    try:
                        grad.setColor(to_java_int(center_color))
                    except:
                        pass
                wrap.setBackground(grad)
            except Exception as _e:
                _log(f"NFT backdrop gradient fail: {_e}")

        # Pattern overlay: scatter pattern doc instances around the 72dp
        # centered model so they remain visible (model occupies dp 18..90
        # of the 108dp tile). Positions hand-picked to hit corners + edge
        # midpoints — mimics Telegram's "scattered pattern" effect.
        if pattern_doc is not None:
            try:
                pat_color = pattern_color if pattern_color is not None else 0x66FFFFFF
                # (left_dp, top_dp, size_dp) inside a 108dp square.
                positions = (
                    (4, 4, 16),     # top-left corner
                    (88, 4, 16),    # top-right corner
                    (4, 88, 16),    # bottom-left corner
                    (88, 88, 16),   # bottom-right corner
                    (47, 2, 14),    # top edge midpoint
                    (47, 92, 14),   # bottom edge midpoint
                    (2, 47, 14),    # left edge midpoint
                    (92, 47, 14),   # right edge midpoint
                )
                for left_dp, top_dp, sz_dp in positions:
                    try:
                        piv = BackupImageView(ctx)
                        try:
                            image_location = ImageLocation.getForDocument(pattern_doc)
                            if image_location is not None:
                                piv.setImage(image_location, f"{sz_dp}_{sz_dp}", None, 0, pattern_doc)
                        except:
                            continue
                        try:
                            piv.setColorFilter(to_java_int(pat_color))
                        except:
                            pass
                        try:
                            piv.setAlpha(0.55)
                        except:
                            pass
                        lp = FrameLayout.LayoutParams(AndroidUtilities.dp(sz_dp), AndroidUtilities.dp(sz_dp))
                        lp.leftMargin = AndroidUtilities.dp(left_dp)
                        lp.topMargin = AndroidUtilities.dp(top_dp)
                        wrap.addView(piv, lp)
                    except Exception as _e:
                        _log(f"NFT pattern dot fail: {_e}")
                        continue
            except Exception as _e:
                _log(f"NFT pattern overlay fail: {_e}")

    def _resolve_nft_model_document(self, gift):
        """For a TL_starGiftUnique, return the model attribute's document
        (the actual 3D-style upgraded sticker), falling back to None so the
        caller can use gift.sticker as a backup."""
        try:
            attrs = get_val(gift, "attributes", None)
            if attrs is None:
                return None
            try:
                size = int(attrs.size() or 0)
            except:
                return None
            for i in range(size):
                try:
                    a = attrs.get(i)
                except:
                    continue
                if a is None:
                    continue
                try:
                    cls_low = str(a.getClass().getSimpleName() or "").lower()
                except:
                    cls_low = ""
                if "model" in cls_low:
                    try:
                        return get_val(a, "document", None)
                    except:
                        return None
        except:
            pass
        return None

    def _build_nft_attribute_rows(self, ctx, info, entry):
        """Three attribute rows (Model / Symbol / Backdrop) with rarity %,
        wrapped in an inner MD3-style tonal container (rounded, slightly
        darker than the parent card, hairline dividers between rows)."""
        attrs = self._read_nft_attributes(entry)
        labels = (
            ("model", "Model"),
            ("pattern", "Symbol"),
            ("backdrop", "Backdrop"),
        )

        inner = LinearLayout(ctx)
        inner.setOrientation(LinearLayout.VERTICAL)
        inner_bg = GradientDrawable()
        inner_bg.setCornerRadius(AndroidUtilities.dp(14))
        try:
            inner_bg.setColor(Theme.getColor(Theme.key_windowBackgroundGray))
        except:
            inner_bg.setColor(0x33000000)
        try:
            inner.setBackground(inner_bg)
        except:
            pass
        inner.setPadding(AndroidUtilities.dp(12), AndroidUtilities.dp(8),
                         AndroidUtilities.dp(12), AndroidUtilities.dp(8))

        for idx, (attr_key, attr_label) in enumerate(labels):
            name, rarity = attrs.get(attr_key, ("—", 0))
            self._add_attribute_row(ctx, inner, attr_label, name, rarity)
            if idx < len(labels) - 1:
                # Hairline divider between rows.
                div = View(ctx)
                try:
                    div.setBackgroundColor(Theme.getColor(Theme.key_divider))
                except:
                    div.setBackgroundColor(0x22FFFFFF)
                lp_div = LinearLayout.LayoutParams(-1, 1)
                lp_div.topMargin = AndroidUtilities.dp(6)
                lp_div.bottomMargin = AndroidUtilities.dp(0)
                inner.addView(div, lp_div)

        lp_inner = LinearLayout.LayoutParams(-1, -2)
        lp_inner.topMargin = AndroidUtilities.dp(8)
        info.addView(inner, lp_inner)

    def _read_nft_attributes(self, entry):
        out = {"model": ("—", 0), "pattern": ("—", 0), "backdrop": ("—", 0)}
        try:
            key = str(entry.get("key", "") or "")
            wrapper = self.plugin._library_get_wrapper(key) if key else None
            gift = self.plugin._extract_wrapper_gift(wrapper) if wrapper is not None else None
            if gift is None:
                return out
            attrs = get_val(gift, "attributes", None)
            if attrs is None:
                return out
            try:
                size = int(attrs.size() or 0)
            except:
                size = 0
            for i in range(size):
                try:
                    a = attrs.get(i)
                except:
                    continue
                if a is None:
                    continue
                try:
                    cls_low = str(a.getClass().getSimpleName() or "").lower()
                except:
                    cls_low = ""
                name = str(get_val(a, "name", "") or "")
                try:
                    rar = int(get_val(a, "rarity_per_mille", 0) or 0)
                except:
                    rar = 0
                if "model" in cls_low and out["model"][0] == "—":
                    out["model"] = (name or "—", rar)
                elif ("pattern" in cls_low or "symbol" in cls_low) and out["pattern"][0] == "—":
                    out["pattern"] = (name or "—", rar)
                elif "backdrop" in cls_low and out["backdrop"][0] == "—":
                    out["backdrop"] = (name or "—", rar)
        except:
            pass
        return out

    def _add_attribute_row(self, ctx, info, label, value, rarity_per_mille):
        row = LinearLayout(ctx)
        row.setOrientation(LinearLayout.HORIZONTAL)
        row.setGravity(Gravity.CENTER_VERTICAL)
        lp_row = LinearLayout.LayoutParams(-1, -2)
        lp_row.topMargin = AndroidUtilities.dp(6)

        label_tv = TextView(ctx)
        label_tv.setText(str(label))
        label_tv.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 13)
        label_tv.setTextColor(Theme.getColor(Theme.key_windowBackgroundWhiteGrayText2))
        lp_l = LinearLayout.LayoutParams(0, -2, 0.45)
        row.addView(label_tv, lp_l)

        value_tv = TextView(ctx)
        value_tv.setText(str(value))
        value_tv.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 13)
        value_tv.setTextColor(Theme.getColor(Theme.key_dialogTextBlack))
        try:
            value_tv.setSingleLine(True)
        except:
            pass
        lp_v = LinearLayout.LayoutParams(0, -2, 0.45)
        row.addView(value_tv, lp_v)

        rar_tv = TextView(ctx)
        rar_tv.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 12)
        rar_tv.setTextColor(Theme.getColor(Theme.key_windowBackgroundWhiteGrayText2))
        rar_tv.setGravity(Gravity.RIGHT)
        try:
            rmille = int(rarity_per_mille or 0)
        except:
            rmille = 0
        if rmille > 0:
            pct = rmille / 10.0
            rar_tv.setText(f"{pct:.1f}%".replace(".0%", "%"))
        else:
            rar_tv.setText("")
        lp_r = LinearLayout.LayoutParams(0, -2, 0.10)
        row.addView(rar_tv, lp_r)

        info.addView(row, lp_row)

    def _build_regular_inline_rows(self, ctx, info, entry, key, source):
        """Three tappable rows for regular gifts: From / Date / Comment.
        Each opens _show_text_input_dialog routed through _my_gifts_set_field
        so persistence + injection rebuild + wrapper invalidation happens
        through the V5 pipeline."""
        cf = str(entry.get("custom_from", "") or "")
        cd = str(entry.get("custom_date", "") or "")
        cc = str(entry.get("custom_comment", "") or "")
        rows = (
            ("От", cf if cf else "не указано", "custom_from", "От кого"),
            ("Дата", cd if cd else "не указана", "custom_date", "Дата (например 23.03.2026)"),
            ("Комментарий", cc if cc else "не указан", "custom_comment", "Комментарий"),
        )
        for label, value, field_name, prompt in rows:
            row = self._build_editable_row(ctx, label, value)
            row.setOnClickListener(JOnClickListener(
                lambda v, _key=key, _src=source, _fn=field_name, _prompt=prompt, _cur=str(value if value not in ("не указано", "не указана", "не указан") else ""):
                    self._on_field_tap(_key, _src, _fn, _prompt, _cur)
            ))
            lp_row = LinearLayout.LayoutParams(-1, -2)
            lp_row.topMargin = AndroidUtilities.dp(6)
            info.addView(row, lp_row)

    def _build_editable_row(self, ctx, label, value):
        row = LinearLayout(ctx)
        row.setOrientation(LinearLayout.HORIZONTAL)
        row.setGravity(Gravity.CENTER_VERTICAL)
        row.setPadding(0, AndroidUtilities.dp(2), 0, AndroidUtilities.dp(2))
        try:
            row.setBackground(Theme.createSelectorDrawable(Theme.getColor(Theme.key_listSelector), 7))
        except:
            pass

        label_tv = TextView(ctx)
        label_tv.setText(str(label))
        label_tv.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 13)
        label_tv.setTextColor(Theme.getColor(Theme.key_windowBackgroundWhiteGrayText2))
        row.addView(label_tv, LinearLayout.LayoutParams(0, -2, 0.4))

        value_tv = TextView(ctx)
        value_tv.setText(str(value))
        value_tv.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 13)
        value_tv.setTextColor(Theme.getColor(Theme.key_dialogTextBlack))
        try:
            value_tv.setSingleLine(True)
        except:
            pass
        row.addView(value_tv, LinearLayout.LayoutParams(0, -2, 0.6))
        return row

    def _build_icon_button(self, ctx, icon_name, tint_color, on_click):
        btn = ImageView(ctx)
        try:
            res_id = ctx.getResources().getIdentifier(str(icon_name), "drawable", ctx.getPackageName())
            if res_id > 0:
                btn.setImageResource(res_id)
        except:
            pass
        try:
            btn.setColorFilter(int(tint_color))
        except:
            pass
        btn.setScaleType(ImageView.ScaleType.CENTER_INSIDE)
        try:
            btn.setBackground(Theme.createSelectorDrawable(Theme.getColor(Theme.key_listSelector), 1))
        except:
            pass
        if on_click is not None:
            btn.setOnClickListener(JOnClickListener(on_click))
        return btn

    def _build_pill_button(self, ctx, icon_name, label, tint, on_click):
        """MD3-style pill button: rounded background with the tint colour at
        12% opacity, an icon and a label in the full tint colour."""
        wrap = LinearLayout(ctx)
        wrap.setOrientation(LinearLayout.HORIZONTAL)
        wrap.setGravity(Gravity.CENTER)

        tint_int = int(tint)
        # 0x1F (~12%) alpha tint background.
        bg_color = (0x1F << 24) | (tint_int & 0x00FFFFFF)
        bg = GradientDrawable()
        bg.setCornerRadius(AndroidUtilities.dp(22))
        bg.setColor(bg_color)
        try:
            ripple = Theme.createSimpleSelectorRoundRectDrawable(
                AndroidUtilities.dp(22), bg_color, (0x33 << 24) | (tint_int & 0x00FFFFFF)
            )
            wrap.setBackground(ripple)
        except:
            wrap.setBackground(bg)

        icon = ImageView(ctx)
        try:
            res_id = ctx.getResources().getIdentifier(str(icon_name), "drawable", ctx.getPackageName())
            if res_id > 0:
                icon.setImageResource(res_id)
        except:
            pass
        try:
            icon.setColorFilter(tint_int)
        except:
            pass
        icon.setScaleType(ImageView.ScaleType.CENTER_INSIDE)
        lp_icon = LinearLayout.LayoutParams(AndroidUtilities.dp(20), AndroidUtilities.dp(20))
        lp_icon.rightMargin = AndroidUtilities.dp(6)
        wrap.addView(icon, lp_icon)

        text = TextView(ctx)
        text.setText(str(label))
        text.setTextSize(TypedValue.COMPLEX_UNIT_DIP, 14)
        text.setTextColor(tint_int)
        try:
            text.setTypeface(AndroidUtilities.bold())
        except:
            pass
        wrap.addView(text, LinearLayout.LayoutParams(-2, -2))

        if on_click is not None:
            wrap.setOnClickListener(JOnClickListener(on_click))
        return wrap

    # -----------------------------------------------------------------------
    # Action handlers — delegate to existing plugin methods so logic stays
    # unified with the V1 list view and V5 persistence.
    # -----------------------------------------------------------------------

    def _on_add_clicked(self):
        # Build the 2-option chooser ourselves (instead of delegating to
        # plugin._open_my_gifts_add_menu) so each option can dismiss this
        # card sheet *before* presenting the catalog fragment. Otherwise
        # the sheet stays alive under the catalog and the user has to back
        # out twice.
        def _open_nft():
            self._dismiss()
            try:
                self.plugin._open_catalog_nft_sheet()
            except Exception as e:
                try:
                    BulletinHelper.show_error(f"Каталог NFT: {e}")
                except:
                    pass

        def _open_regular():
            self._dismiss()
            try:
                self.plugin._add_regular_gift_via_template()
            except Exception as e:
                try:
                    BulletinHelper.show_error(f"Каталог: {e}")
                except:
                    pass

        try:
            self.plugin._show_action_menu(
                "Добавить подарок",
                [
                    ("NFT-подарок (с улучшениями)", _open_nft),
                    ("Обычный подарок (без улучшений)", _open_regular),
                ],
                negative_text="Отмена",
            )
        except Exception as e:
            try:
                BulletinHelper.show_error(f"Меню: {e}")
            except:
                pass

    def _on_edit_clicked(self, key):
        # Dismiss before opening the constructor fragment so we don't leave
        # this BottomSheet stranded under the new screen.
        self._dismiss()
        try:
            self.plugin._open_constructor_for_library_key(key)
        except Exception as e:
            try:
                BulletinHelper.show_error(f"Конструктор: {e}")
            except:
                pass

    def _on_delete_clicked(self, key, source):
        # Reuse the existing confirmation menu so the destructive UX matches
        # the rest of the plugin. After the user confirms, refresh the sheet.
        try:
            actions = [
                ("Да, удалить", lambda: self._do_delete(key, source)),
            ]
            self.plugin._show_action_menu("Удалить подарок?", actions, negative_text="Отмена")
        except Exception as e:
            try:
                BulletinHelper.show_error(f"Ошибка: {e}")
            except:
                pass

    def _do_delete(self, key, source):
        try:
            self.plugin._my_gifts_delete(key, source)
        except Exception as e:
            try:
                BulletinHelper.show_error(f"Удаление: {e}")
            except:
                pass
        try:
            run_on_ui_thread(self.refresh)
        except:
            pass

    def _on_field_tap(self, key, source, field, prompt, current):
        try:
            def _submit(value, _k=key, _s=source, _f=field):
                try:
                    self.plugin._my_gifts_set_field(_k, _s, _f, value)
                except Exception as e:
                    try:
                        BulletinHelper.show_error(f"Сохранение: {e}")
                    except:
                        pass
                try:
                    run_on_ui_thread(self.refresh)
                except:
                    pass
            self.plugin._show_text_input_dialog(prompt, current, _submit)
        except Exception as e:
            try:
                BulletinHelper.show_error(f"Ввод: {e}")
            except:
                pass


class ResaleGridController:
    # `mode` selects per-click behavior and item filtering:
    #   "default"     — legacy popup ("Обычный подарок?" / "Локально улучшить")
    #                   for non-unique items; constructor for unique. Catalog
    #                   shows every TL_starGift (no extra filter).
    #   "nft_only"    — show only gifts whose upgrades have already been
    #                   released (availability_resale > 0 OR resell_min_stars
    #                   > 0 OR looks unique). Click → constructor immediately.
    #   "regular_only"— show all non-unique catalog gifts (both upgradable
    #                   templates and plain ones). Click → add to gift_library
    #                   as gift_kind='standard' immediately, then close.
    def __init__(self, plugin, is_catalog=False, mode="default"):
        self.plugin = plugin
        self.is_catalog = is_catalog
        self.mode = str(mode or "default")
        self.fragment = None
        self.my_adapter = None
        self.items = []
        self.filtered_items = []
        self.filter_model = None
        self.filter_pattern = None
        self.filter_backdrop = None

    def _release(self):
        try:
            ctrls = list(getattr(self.plugin, "active_controllers", None) or [])
            self.plugin.active_controllers = [c for c in ctrls if c is not self]
            self.plugin.active_catalog_controllers = self.plugin.active_controllers
        except:
            pass
        self.fragment = None
        self.my_adapter = None
        self.items = []
        self.filtered_items = []
        self.btn_model = None
        self.btn_pattern = None
        self.btn_backdrop = None
        self.btn_clear = None
        self.btn_sort = None
        try:
            self.plugin._prune_active_controller_refs()
        except:
            pass

    def show(self):
        title = (
            "Каталог подарков" if self.mode == "regular_only"
            else ("Каталог NFT" if (self.mode == "nft_only" or self.is_catalog) else "Мои NFT")
        )
        try:
            user_id = get_user_config().clientUserId
            ResaleGiftsFragment = jclass("org.telegram.ui.Gifts.ResaleGiftsFragment")
            self.fragment = ResaleGiftsFragment(user_id, title, 0, None)
            ctrls = getattr(self.plugin, "active_controllers", None)
            if ctrls is None:
                self.plugin.active_controllers = []
                ctrls = self.plugin.active_controllers
            else:
                try:
                    ctrls[:] = [c for c in list(ctrls) if c is not None and getattr(c, "fragment", None) is not None]
                except:
                    pass
            try:
                self.plugin._prune_active_controller_refs()
            except:
                pass
            ctrls.append(self)
            self.plugin.active_catalog_controllers = ctrls
            get_last_fragment().presentFragment(self.fragment)
            AndroidUtilities.runOnUIThread(JRunnable(self._init_ui), 150)
        except Exception as e:
            BulletinHelper.show_error(f"ÃƒÂÃ…Â¾Ãƒâ€˜Ã‹â€ ÃƒÂÃ‚Â¸ÃƒÂÃ‚Â±ÃƒÂÃ‚ÂºÃƒÂÃ‚Â° ÃƒÂÃ‚Â¾Ãƒâ€˜Ã¢â‚¬Å¡ÃƒÂÃ‚ÂºÃƒâ€˜Ã¢â€šÂ¬Ãƒâ€˜Ã¢â‚¬Â¹Ãƒâ€˜Ã¢â‚¬Å¡ÃƒÂÃ‚Â¸Ãƒâ€˜Ã‚Â: {e}")

    def _init_ui(self):
        try:
            list_view = get_val(self.fragment, "listView")
            empty_view = get_val(self.fragment, "emptyView")
            if empty_view:
                try:
                    empty_view.setVisibility(8)
                    empty_view.setAlpha(0.0)
                except:
                    pass
            if not list_view:
                return

            self.my_adapter = get_val(list_view, "adapter")
            self.btn_model = get_val(self.fragment, "modelButton")
            self.btn_pattern = get_val(self.fragment, "patternButton")
            self.btn_backdrop = get_val(self.fragment, "backdropButton")
            self.btn_clear = get_val(self.fragment, "clearFiltersButton")
            self.btn_sort = get_val(self.fragment, "sortButton")

            if self.btn_model:
                self.btn_model.setOnClickListener(JOnClickListener(lambda v: self._open_filter("model", "\u041c\u043e\u0434\u0435\u043b\u044c")))
            if self.btn_pattern:
                self.btn_pattern.setOnClickListener(JOnClickListener(lambda v: self._open_filter("pattern", "\u0423\u0437\u043e\u0440")))
            if self.btn_backdrop:
                self.btn_backdrop.setOnClickListener(JOnClickListener(lambda v: self._open_filter("backdrop", "\u0424\u043e\u043d")))
            if self.btn_clear:
                self.btn_clear.setOnClickListener(JOnClickListener(lambda v: self._clear_filters()))
            if self.btn_sort:
                try:
                    self.btn_sort.setVisibility(8)
                except:
                    pass

            if self.is_catalog:
                self.plugin._force_load_catalog()
                self.items = self._mode_filtered_catalog()
                self._update_ui()
                if not self.items:
                    BulletinHelper.show_info("\u0417\u0430\u0433\u0440\u0443\u0437\u043a\u0430 \u043a\u0430\u0442\u0430\u043b\u043e\u0433\u0430...")
                    self._retry_attempts = 0
                    AndroidUtilities.runOnUIThread(JRunnable(self._retry_catalog_load), 1000)
            else:
                self.items = []
                self._update_ui()
        except Exception as e:
            _log(f"Init UI Error: {e}\n{traceback.format_exc()}")

    def _mode_filtered_catalog(self):
        """Pull the raw catalog list, then narrow it according to self.mode.
        Cached underlying list — call is cheap on hot path."""
        try:
            raw = list(self.plugin._get_catalog_nft_gifts() or [])
        except:
            raw = []
        mode = getattr(self, "mode", "default") or "default"
        if mode == "regular_only":
            # All catalog templates (TL_starGift), excluding already-rolled
            # unique variants — those don't belong in the "add as regular" path.
            out = []
            for g in raw:
                try:
                    if self.plugin._looks_like_unique_gift(g):
                        continue
                except:
                    pass
                out.append(g)
            return out
        if mode == "nft_only":
            # Only gifts whose upgrades have been released — i.e. unique
            # variants exist in the wild (availability_resale > 0 or the
            # resell market has a min-price). Already-unique items also pass.
            out = []
            for g in raw:
                try:
                    if self.plugin._looks_like_unique_gift(g):
                        out.append(g)
                        continue
                except:
                    pass
                try:
                    ar = int(get_val(g, "availability_resale", 0) or 0)
                except:
                    ar = 0
                if ar > 0:
                    out.append(g)
                    continue
                try:
                    rms = int(get_val(g, "resell_min_stars", 0) or 0)
                except:
                    rms = 0
                if rms > 0:
                    out.append(g)
                    continue
            return out
        return raw

    def _retry_catalog_load(self):
        if not self.fragment:
            return
        if self.is_catalog and not self.items:
            self.items = self._mode_filtered_catalog()
            self._update_ui()
            if not self.items:
                self._retry_attempts = int(getattr(self, "_retry_attempts", 0) or 0) + 1
                if self._retry_attempts < 10:
                    AndroidUtilities.runOnUIThread(JRunnable(self._retry_catalog_load), 1000)
                else:
                    BulletinHelper.show_error("\u041e\u0448\u0438\u0431\u043a\u0430 \u0437\u0430\u0433\u0440\u0443\u0437\u043a\u0438 (\u0442\u0430\u0439\u043c\u0430\u0443\u0442)")
            else:
                BulletinHelper.show_success("\u041a\u0430\u0442\u0430\u043b\u043e\u0433 \u0437\u0430\u0433\u0440\u0443\u0436\u0435\u043d!")

    def _extract_attr_name(self, gift, attr_type):
        try:
            attrs = get_val(gift, "attributes")
            if attrs:
                for i in range(attrs.size()):
                    a = attrs.get(i)
                    if attr_type in str(a.getClass().getSimpleName()).lower():
                        return str(get_val(a, "name", ""))
        except:
            pass
        return None

    def _open_filter(self, attr_type, title):
        seen = set()
        values = []
        for gift in list(self.items or []):
            name = self._extract_attr_name(gift, attr_type)
            if name and name not in seen:
                seen.add(name)
                values.append(name)
        values.sort()

        if not values:
            BulletinHelper.show_info(f"\u041d\u0435\u0442 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432 \u0434\u043b\u044f {self.plugin._ui_text(title, str(title)).lower()}")
            return

        def _on_selected(index):
            chosen = None if index == 0 else values[index - 1]
            if attr_type == "model":
                self.filter_model = chosen
            elif attr_type == "pattern":
                self.filter_pattern = chosen
            elif attr_type == "backdrop":
                self.filter_backdrop = chosen
            self._update_ui()

        LiveSelectorDialog(self.plugin._ui_text(title, "NFT"), ["\u0412\u0441\u0435"] + values, _on_selected, lambda obj, _: (self.plugin._ui_text(obj, str(obj)), False)).show()

    def _clear_filters(self):
        self.filter_model = None
        self.filter_pattern = None
        self.filter_backdrop = None
        self._update_ui()

    def _update_ui(self):
        self.filtered_items = []
        has_filters = bool(self.filter_model or self.filter_pattern or self.filter_backdrop)

        for gift in list(self.items or []):
            m_match = self.filter_model is None or self._extract_attr_name(gift, "model") == self.filter_model
            p_match = self.filter_pattern is None or self._extract_attr_name(gift, "pattern") == self.filter_pattern
            b_match = self.filter_backdrop is None or self._extract_attr_name(gift, "backdrop") == self.filter_backdrop
            if m_match and p_match and b_match:
                self.filtered_items.append(gift)

        try:
            String = jclass("java.lang.String")
            if self.btn_model:
                self.btn_model.setValue(String(f"ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â¢ {self.filter_model}" if self.filter_model else "ÃƒÂÃ…â€œÃƒÂÃ‚Â¾ÃƒÂÃ‚Â´ÃƒÂÃ‚ÂµÃƒÂÃ‚Â»Ãƒâ€˜Ã…â€™"))
            if self.btn_pattern:
                self.btn_pattern.setValue(String(f"ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â¢ {self.filter_pattern}" if self.filter_pattern else "ÃƒÂÃ‚Â£ÃƒÂÃ‚Â·ÃƒÂÃ‚Â¾Ãƒâ€˜Ã¢â€šÂ¬"))
            if self.btn_backdrop:
                self.btn_backdrop.setValue(String(f"ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â¢ {self.filter_backdrop}" if self.filter_backdrop else "ÃƒÂÃ‚Â¤ÃƒÂÃ‚Â¾ÃƒÂÃ‚Â½"))
        except:
            pass

        clear_container = get_val(self.fragment, "clearFiltersContainer")
        if clear_container:
            try:
                clear_container.setVisibility(0 if has_filters else 8)
            except:
                pass

        action_bar = get_val(self.fragment, "actionBar")
        if action_bar:
            try:
                count = len(self.filtered_items or [])
                action_bar.setSubtitle(f"{count} NFT" if count > 0 else "ÃƒÂÃ‚ÂÃƒÂÃ‚ÂµÃƒâ€˜Ã¢â‚¬Å¡ NFT")
            except:
                pass

        if self.my_adapter:
            try:
                self.my_adapter.update(True)
            except:
                pass
            try:
                list_view = get_val(self.fragment, "listView")
                if list_view:
                    list_view.scrollToPosition(0)
            except:
                pass

    def _fill_items(self, items, adapter):
        try:
            GiftCellFactory = jclass("org.telegram.ui.Gifts.GiftSheet$GiftCell$Factory")
        except:
            GiftCellFactory = None

        if not self.filtered_items:
            empty = UItem.asShadow("ÃƒÂÃ‚ÂÃƒÂÃ‚Â¸Ãƒâ€˜Ã¢â‚¬Â¡ÃƒÂÃ‚ÂµÃƒÂÃ‚Â³ÃƒÂÃ‚Â¾ ÃƒÂÃ‚Â½ÃƒÂÃ‚Âµ ÃƒÂÃ‚Â½ÃƒÂÃ‚Â°ÃƒÂÃ‚Â¹ÃƒÂÃ‚Â´ÃƒÂÃ‚ÂµÃƒÂÃ‚Â½ÃƒÂÃ‚Â¾")
            try:
                empty.spanCount = 3
            except:
                pass
            items.add(empty)
            return

        for gift in list(self.filtered_items or []):
            try:
                if GiftCellFactory:
                    item = GiftCellFactory.asStarGift(0, gift, False, False, False, False, False)
                    if item:
                        item.object = gift
                        items.add(item)
                        continue
            except:
                pass

            fallback = UItem.asButton(int(get_val(gift, "id", 0)), str(get_val(gift, "title", "NFT")), f"#{get_val(gift, 'num', 1)}")
            try:
                fallback.object = gift
            except:
                pass
            items.add(fallback)

    def _on_click_uitem(self, item, view, pos, x, y):
        try:
            gift = getattr(item, "object", None)
            if not gift:
                return
            mode = getattr(self, "mode", "default") or "default"

            # regular_only: tap → add as standard gift immediately, no popup.
            if mode == "regular_only":
                try:
                    self.fragment.finishFragment()
                except:
                    pass
                self._release()
                try:
                    self.plugin._add_regular_gift_from_template(gift)
                except Exception as add_e:
                    try:
                        BulletinHelper.show_error(f"Добавление: {add_e}")
                    except:
                        pass
                return

            # nft_only: tap → constructor (AttrLoader) for ANY shown gift,
            # including non-unique templates with upgrade_stars > 0. The
            # «Обычный подарок?» / «Локально улучшить» popup is skipped.
            if mode == "nft_only":
                self.plugin.stolen_gift_inner = gift
                try:
                    self.plugin.cached_gift_id = int(self.plugin._get_gift_base_id(gift, fallback=int(get_val(gift, "id", 0) or 0)) or 0)
                except:
                    self.plugin.cached_gift_id = 0
                if int(self.plugin.cached_gift_id or 0) <= 0:
                    BulletinHelper.show_error("Не удалось определить gift_id")
                    return
                try:
                    self.fragment.finishFragment()
                except:
                    pass
                self._release()
                AttrLoader(self.plugin, self.plugin.cached_gift_id, allow_generic_fallback=True).start()
                return

            # default: legacy two-step popup for non-unique items.
            try:
                is_unique = bool(self.plugin._looks_like_unique_gift(gift))
            except:
                is_unique = False
            if not is_unique:
                self.plugin._show_action_menu(
                    "Обычный подарок",
                    [
                        ("Добавить как обычный", lambda: self.plugin._import_gift_to_library(gift=gift, wrapper=None, inject=True, official_import=False, gift_kind=GIFT_KIND_NORMAL, local_only=False)),
                        (f"Локально улучшить • {LOCAL_VISUAL_UPGRADE_STARS}★", lambda: self.plugin._open_local_upgrade_for_gift(gift)),
                    ],
                    negative_text="Назад",
                )
                return
            self.plugin.stolen_gift_inner = gift
            try:
                self.plugin.cached_gift_id = int(self.plugin._get_gift_base_id(gift, fallback=int(get_val(gift, "id", 0) or 0)) or 0)
            except:
                self.plugin.cached_gift_id = 0
            if int(self.plugin.cached_gift_id or 0) <= 0:
                BulletinHelper.show_error("ÃƒÂÃ‚ÂÃƒÂÃ‚Âµ Ãƒâ€˜Ã†â€™ÃƒÂÃ‚Â´ÃƒÂÃ‚Â°ÃƒÂÃ‚Â»ÃƒÂÃ‚Â¾Ãƒâ€˜Ã‚ÂÃƒâ€˜Ã…â€™ ÃƒÂÃ‚Â¾ÃƒÂÃ‚Â¿Ãƒâ€˜Ã¢â€šÂ¬ÃƒÂÃ‚ÂµÃƒÂÃ‚Â´ÃƒÂÃ‚ÂµÃƒÂÃ‚Â»ÃƒÂÃ‚Â¸Ãƒâ€˜Ã¢â‚¬Å¡Ãƒâ€˜Ã…â€™ gift_id")
                return
            try:
                self.fragment.finishFragment()
            except:
                pass
            self._release()
            AttrLoader(self.plugin, self.plugin.cached_gift_id, allow_generic_fallback=True).start()
        except Exception as e:
            _log(f"ResaleGridController click error: {e}")

class CatalogGridController:
    def __init__(self, plugin):
        self.plugin = plugin
        self.fragment = None
        self.my_adapter = None
        self.use_official_render = False
