    def _catalog_signature(self, lst):
        if not lst:
            return ""
        parts = []
        try:
            for g in list(lst)[:10]:
                try:
                    parts.append(str(get_val(g, "id", "") or ""))
                except:
                    continue
        except:
            return ""
        return "|".join(parts)

    def _kick_adapter(self, full=True, min_interval=0.18):
        now = time.time()
        want_full = bool(full)
        try:
            last_ts = float(getattr(self, "_last_adapter_kick_ts", 0.0) or 0.0)
            last_full = bool(getattr(self, "_last_adapter_kick_full", False))
            if float(min_interval or 0.0) > 0.0 and (now - last_ts) < float(min_interval) and ((not want_full) or last_full):
                return False
        except:
            pass
        try:
            if self.my_adapter:
                self.my_adapter.update(want_full)
                try:
                    self._last_adapter_kick_ts = now
                    self._last_adapter_kick_full = want_full
                except:
                    pass
                try:
                    if want_full and hasattr(self.my_adapter, "notifyDataSetChanged"):
                        self.my_adapter.notifyDataSetChanged()
                except:
                    pass
                return True
        except:
            pass
        return False

    def _hide_view_quietly(self, view):
        if not view:
            return
        try:
            view.setVisibility(8)
        except:
            pass
        try:
            view.setAlpha(0.0)
        except:
            pass

    def _suppress_native_loading_state(self):
        placeholder_text = "\u0417\u0430\u0433\u0440\u0443\u0437\u043a\u0430 \u043a\u0430\u0442\u0430\u043b\u043e\u0433\u0430..." if bool(getattr(self, "_loading_catalog", False)) else "\u0421\u043f\u0438\u0441\u043e\u043a \u043f\u0443\u0441\u0442"
        broken_tokens = ("Ã", "Ð", "Ñ", "â", "€", "™")

        def _is_broken_text(text):
            try:
                s = str(text or "")
            except:
                s = ""
            if not s:
                return False
            for token in broken_tokens:
                if token in s:
                    return True
            return False

        def _fix_texts(view, depth=0):
            if view is None or depth > 3:
                return
            try:
                cls_name = str(view.getClass().getSimpleName() or "")
            except:
                cls_name = ""
            try:
                if "TextView" in cls_name:
                    cur = view.getText()
                    if _is_broken_text(cur):
                        view.setText(placeholder_text)
            except:
                pass
            try:
                count = int(view.getChildCount() or 0)
            except:
                count = 0
            for i in range(count):
                try:
                    _fix_texts(view.getChildAt(i), depth + 1)
                except:
                    continue

        for name in ["emptyView", "progressView", "loadingView", "emptyTextView", "emptyTitleTextView", "emptySubtitleTextView", "progressLayout", "loadingLayout"]:
            try:
                obj = get_val(self.fragment, name, None)
            except:
                obj = None
            if obj is None:
                continue
            try:
                _fix_texts(obj, 0)
            except:
                pass
            try:
                self._hide_view_quietly(obj)
            except:
                pass
        try:
            root = get_val(self.fragment, "fragmentView", None)
        except:
            root = None
        if root is None:
            try:
                root = self.fragment.getFragmentView()
            except:
                root = None
        try:
            _fix_texts(root, 0)
        except:
            pass
        return
        # ÃƒÂÃ‚Â ÃƒÂÃ‚Â°ÃƒÂÃ‚Â±ÃƒÂÃ‚Â¾Ãƒâ€˜Ã¢â‚¬Â¡ÃƒÂÃ‚Â°Ãƒâ€˜Ã‚Â ÃƒÂÃ‚Â²ÃƒÂÃ‚ÂµÃƒâ€˜Ã¢â€šÂ¬Ãƒâ€˜Ã‚ÂÃƒÂÃ‚Â¸Ãƒâ€˜Ã‚Â ÃƒÂÃ‚ÂºÃƒÂÃ‚Â°Ãƒâ€˜Ã¢â‚¬Å¡ÃƒÂÃ‚Â°ÃƒÂÃ‚Â»ÃƒÂÃ‚Â¾ÃƒÂÃ‚Â³ÃƒÂÃ‚Â° Ãƒâ€˜Ã‚ÂÃƒÂÃ‚ÂºÃƒâ€˜Ã¢â€šÂ¬Ãƒâ€˜Ã¢â‚¬Â¹ÃƒÂÃ‚Â²ÃƒÂÃ‚Â°ÃƒÂÃ‚Â»ÃƒÂÃ‚Â° Ãƒâ€˜Ã¢â‚¬Å¡ÃƒÂÃ‚Â¾ÃƒÂÃ‚Â»Ãƒâ€˜Ã…â€™ÃƒÂÃ‚ÂºÃƒÂÃ‚Â¾ emptyView. ÃƒÂÃ¢â‚¬Å“ÃƒÂÃ‚Â»Ãƒâ€˜Ã†â€™ÃƒÂÃ‚Â±ÃƒÂÃ‚Â¾ÃƒÂÃ‚ÂºÃƒÂÃ‚Â¸ÃƒÂÃ‚Â¹ ÃƒÂÃ‚Â¾ÃƒÂÃ‚Â±Ãƒâ€˜Ã¢â‚¬Â¦ÃƒÂÃ‚Â¾ÃƒÂÃ‚Â´
        # loading/progress-ÃƒÂÃ‚Â¿ÃƒÂÃ‚Â¾ÃƒÂÃ‚Â»ÃƒÂÃ‚ÂµÃƒÂÃ‚Â¹ ÃƒÂÃ‚Â² Ãƒâ€˜Ã¢â‚¬Å¡ÃƒÂÃ‚ÂµÃƒÂÃ‚ÂºÃƒâ€˜Ã†â€™Ãƒâ€˜Ã¢â‚¬Â°ÃƒÂÃ‚ÂµÃƒÂÃ‚Â¹ Ãƒâ€˜Ã‚ÂÃƒÂÃ‚Â±ÃƒÂÃ‚Â¾Ãƒâ€˜Ã¢â€šÂ¬ÃƒÂÃ‚ÂºÃƒÂÃ‚Âµ ÃƒÂÃ‚Â»ÃƒÂÃ‚Â¾ÃƒÂÃ‚Â¼ÃƒÂÃ‚Â°ÃƒÂÃ‚Â» Ãƒâ€˜Ã¢â‚¬Â¡ÃƒÂÃ‚Â°Ãƒâ€˜Ã‚ÂÃƒâ€˜Ã¢â‚¬Å¡Ãƒâ€˜Ã…â€™ ÃƒÂÃ‚Â½ÃƒÂÃ‚Â°Ãƒâ€˜Ã¢â‚¬Å¡ÃƒÂÃ‚Â¸ÃƒÂÃ‚Â²ÃƒÂÃ‚Â½ÃƒÂÃ‚Â¾ÃƒÂÃ‚Â³ÃƒÂÃ‚Â¾ layout.
        try:
            empty_view = get_val(self.fragment, "emptyView")
            if empty_view:
                self._hide_view_quietly(empty_view)
        except:
            pass

    def _poll_catalog_loaded(self, timeout_sec=12.0, interval_ms=280):
        try:
            self._poll_token = int(self._poll_token or 0) + 1
        except:
            self._poll_token = 1
        token = int(self._poll_token or 0)
        started = time.time()
        base_sig = self._catalog_signature(self.items)
        try:
            base_len = len(self.items or [])
        except:
            base_len = 0

        def _ui_apply(new_items, sig):
            try:
                if int(getattr(self, "_poll_token", 0) or 0) != token:
                    return
                if not self.fragment:
                    return
                self.items = new_items
                self._last_catalog_sig = sig
                self._suppress_native_loading_state()
                self._update_ui()
                self._kick_adapter(full=True)
            except:
                pass

        def _ui_timeout():
            try:
                if int(getattr(self, "_poll_token", 0) or 0) != token:
                    return
                if not self.fragment:
                    return
                self._refresh_catalog_items()
                self._suppress_native_loading_state()
                self._update_ui()
                self._kick_adapter(full=True)
            except:
                pass

        def _bg_loop():
            try:
                while True:
                    if int(getattr(self, "_poll_token", 0) or 0) != token:
                        return
                    if not self.fragment:
                        return
                    if (time.time() - started) > float(timeout_sec):
                        try:
                            AndroidUtilities.runOnUIThread(JRunnable(_ui_timeout))
                        except:
                            pass
                        return

                    new_items = self.plugin._get_catalog_nft_gifts()
                    sig = self._catalog_signature(new_items)
                    try:
                        new_len = len(new_items or [])
                    except:
                        new_len = 0

                    if (sig and sig != base_sig) or (new_len > 0 and new_len != base_len):
                        _log(f"CatalogGrid.poll: detected update len={new_len} sig={sig}")
                        try:
                            AndroidUtilities.runOnUIThread(JRunnable(lambda: _ui_apply(new_items, sig)))
                        except:
                            pass
                        return
                    if new_len > 0 and (time.time() - started) > 1.2:
                        _log(f"CatalogGrid.poll: taking loaded items len={new_len} after wait")
                        try:
                            AndroidUtilities.runOnUIThread(JRunnable(lambda: _ui_apply(new_items, sig)))
                        except:
                            pass
                        return
                    try:
                        time.sleep(float(interval_ms) / 1000.0)
                    except:
                        return
            except:
                return

        try:
            Thread = jclass("java.lang.Thread")
            t = Thread(JRunnable(_bg_loop))
            try:
                t.setDaemon(True)
            except:
                pass
            t.start()
        except:
            try:
                self.plugin._bg_submit(_bg_loop, delay_ms=0)
            except:
                pass

    def _init_ui(self):
        try:
            list_view = get_val(self.fragment, "listView")
            if not list_view:
                _log("CatalogGrid.init: listView not found")
                return

            self.my_adapter = get_val(list_view, "adapter")
            _log(f"CatalogGrid.init: adapter={'ok' if self.my_adapter else 'missing'}")
            self._suppress_native_loading_state()

            empty_view = get_val(self.fragment, "emptyView")
            if empty_view:
                try:
                    empty_view.setVisibility(8)
                    empty_view.setAlpha(0.0)
                except:
                    pass
            self.btn_model = get_val(self.fragment, "modelButton")
            self.btn_pattern = get_val(self.fragment, "patternButton")
            self.btn_backdrop = get_val(self.fragment, "backdropButton")
            self.btn_clear = get_val(self.fragment, "clearFiltersButton")
            self.btn_sort = get_val(self.fragment, "sortButton")

            if self.btn_model:
                self.btn_model.setOnClickListener(JOnClickListener(lambda v: self._open_filter("model", "\u041c\u043e\u0434\u0435\u043b\u044c")))
            if self.btn_pattern:
                self.btn_pattern.setOnClickListener(JOnClickListener(lambda v: self._open_filter("pattern", "\u0423\u0437\u043e\u0440")))
            if self.btn_backdrop:
                self.btn_backdrop.setOnClickListener(JOnClickListener(lambda v: self._open_filter("backdrop", "\u0424\u043e\u043d")))
            if self.btn_clear:
                self.btn_clear.setOnClickListener(JOnClickListener(lambda v: self._clear_filters()))
            if self.btn_sort:
                try:
                    self.btn_sort.setVisibility(8)
                except:
                    pass

            try:
                self.plugin._force_load_catalog()
            except:
                pass
            self._refresh_catalog_items()
            self._last_catalog_sig = self._catalog_signature(self.items)
            self._update_ui()
            if not self.items:
                _log("CatalogGrid.init: catalog empty, starting retries")
                BulletinHelper.show_info("\u0417\u0430\u0433\u0440\u0443\u0437\u043a\u0430 \u043a\u0430\u0442\u0430\u043b\u043e\u0433\u0430...")
                self._retry_attempts = 0
                self._poll_catalog_loaded(timeout_sec=14.0, interval_ms=280)
                AndroidUtilities.runOnUIThread(JRunnable(self._retry_catalog_load), 1000)
            else:
                _log(f"CatalogGrid.init: initial items={len(self.items or [])}")
        except Exception as e:
            _log(f"CatalogGrid init error: {e}\n{traceback.format_exc()}")

    def _retry_catalog_load(self):
        if not self.fragment:
            return
        if not self.items:
            self._refresh_catalog_items()
            self._suppress_native_loading_state()
            self._update_ui()
            if not self.items:
                self._retry_attempts = int(getattr(self, "_retry_attempts", 0) or 0) + 1
                _log(f"CatalogGrid.retry: attempt={self._retry_attempts} items=0")
                if self._retry_attempts < 10:
                    AndroidUtilities.runOnUIThread(JRunnable(self._retry_catalog_load), 1000)
                else:
                    BulletinHelper.show_error("\u041e\u0448\u0438\u0431\u043a\u0430 \u0437\u0430\u0433\u0440\u0443\u0437\u043a\u0438 \u043a\u0430\u0442\u0430\u043b\u043e\u0433\u0430 (\u0442\u0430\u0439\u043c\u0430\u0443\u0442)")

    def _extract_attr_name(self, gift, attr_type):
        try:
            attrs = get_val(gift, "attributes")
            if attrs:
                for i in range(attrs.size()):
                    a = attrs.get(i)
                    if attr_type in str(a.getClass().getSimpleName()).lower():
                        return str(get_val(a, "name", ""))
        except:
            pass
        return None

    def _open_filter(self, attr_type, title):
        seen = set()
        values = []
        for gift in list(self.items or []):
            name = self._extract_attr_name(gift, attr_type)
            if name and name not in seen:
                seen.add(name)
                values.append(name)
        values.sort()

        if not values:
            BulletinHelper.show_info(f"\u041d\u0435\u0442 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432 \u0434\u043b\u044f {self.plugin._ui_text(title, str(title)).lower()}")
            return

        def _on_selected(index):
            chosen = None if index == 0 else values[index - 1]
            if attr_type == "model":
                self.filter_model = chosen
            elif attr_type == "pattern":
                self.filter_pattern = chosen
            elif attr_type == "backdrop":
                self.filter_backdrop = chosen
            self._update_ui()

        LiveSelectorDialog(self.plugin._ui_text(title, "NFT"), ["\u0412\u0441\u0435"] + values, _on_selected, lambda obj, _: (self.plugin._ui_text(obj, str(obj)), False)).show()

    def _clear_filters(self):
        self.filter_model = None
        self.filter_pattern = None
        self.filter_backdrop = None
        self._update_ui()

    def _update_ui(self):
        self.filtered_items = []
        has_filters = bool(self.filter_model or self.filter_pattern or self.filter_backdrop)
        self._suppress_native_loading_state()

        for gift in list(self.items or []):
            m_match = self.filter_model is None or self._extract_attr_name(gift, "model") == self.filter_model
            p_match = self.filter_pattern is None or self._extract_attr_name(gift, "pattern") == self.filter_pattern
            b_match = self.filter_backdrop is None or self._extract_attr_name(gift, "backdrop") == self.filter_backdrop
            if m_match and p_match and b_match:
                self.filtered_items.append(gift)

        try:
            String = jclass("java.lang.String")
        except:
            String = None

        def _set_btn(btn, value, fallback):
            if not btn:
                return
            try:
                txt = value if value else fallback
                if String is not None:
                    btn.setValue(String(txt))
                else:
                    btn.setValue(txt)
            except:
                pass

        _set_btn(self.btn_model, f"ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â¢ {self.filter_model}" if self.filter_model else None, "ÃƒÂÃ…â€œÃƒÂÃ‚Â¾ÃƒÂÃ‚Â´ÃƒÂÃ‚ÂµÃƒÂÃ‚Â»Ãƒâ€˜Ã…â€™")
        _set_btn(self.btn_pattern, f"ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â¢ {self.filter_pattern}" if self.filter_pattern else None, "ÃƒÂÃ‚Â£ÃƒÂÃ‚Â·ÃƒÂÃ‚Â¾Ãƒâ€˜Ã¢â€šÂ¬")
        _set_btn(self.btn_backdrop, f"ÃƒÂ¢Ã¢â€šÂ¬Ã‚Â¢ {self.filter_backdrop}" if self.filter_backdrop else None, "ÃƒÂÃ‚Â¤ÃƒÂÃ‚Â¾ÃƒÂÃ‚Â½")

        clear_container = get_val(self.fragment, "clearFiltersContainer")
        if clear_container:
            try:
                clear_container.setVisibility(0 if has_filters else 8)
            except:
                pass

        action_bar = get_val(self.fragment, "actionBar")
        if action_bar:
            try:
                count = len(self.filtered_items or [])
                action_bar.setSubtitle(f"{count} NFT" if count > 0 else "ÃƒÂÃ‚ÂÃƒÂÃ‚ÂµÃƒâ€˜Ã¢â‚¬Å¡ NFT")
            except:
                pass

        try:
            filtered_sig = (
                f"{self._catalog_signature(self.filtered_items)}|"
                f"{self.filter_model or '-'}|{self.filter_pattern or '-'}|{self.filter_backdrop or '-'}"
            )
        except:
            filtered_sig = ""
        try:
            needs_full_update = bool(filtered_sig != getattr(self, "_last_filtered_sig", ""))
        except:
            needs_full_update = True
        try:
            self._last_filtered_sig = filtered_sig
        except:
            pass
        if self.my_adapter:
            try:
                self._kick_adapter(full=needs_full_update, min_interval=0.0 if needs_full_update else 0.18)
            except:
                pass
            try:
                list_view = get_val(self.fragment, "listView")
                if list_view and needs_full_update and filtered_sig and filtered_sig != getattr(self, "_last_scroll_sig", ""):
                    list_view.scrollToPosition(0)
                    self._last_scroll_sig = filtered_sig
            except:
                pass
        try:
            sig = (
                f"{len(self.items or [])}:{len(self.filtered_items or [])}:"
                f"{self.filter_model or '-'}:{self.filter_pattern or '-'}:{self.filter_backdrop or '-'}"
            )
            if sig != self._last_update_log_sig:
                self._last_update_log_sig = sig
                _log(
                    f"CatalogGrid.update: all={len(self.items or [])} filtered={len(self.filtered_items or [])} "
                    f"filters=model:{self.filter_model or '-'} pattern:{self.filter_pattern or '-'} backdrop:{self.filter_backdrop or '-'}"
                )
        except:
            pass

    def _make_star_gift_item(self, GiftCellFactory, gift):
        if not GiftCellFactory or not gift:
            return None

        attempts = [
            ("sig7_idx_first", lambda: GiftCellFactory.asStarGift(0, gift, False, False, False, False, False)),
            ("sig7_gift_first", lambda: GiftCellFactory.asStarGift(gift, 0, False, False, False, False, False)),
            ("sig6_gift_first", lambda: GiftCellFactory.asStarGift(gift, False, False, False, False, False)),
            ("sig7_gift_only", lambda: GiftCellFactory.asStarGift(gift, False, False, False, False, False, False)),
            ("sig8_idx_first", lambda: GiftCellFactory.asStarGift(0, gift, False, False, False, False, False, False)),
        ]

        last_err = None
        for sig_name, fn in attempts:
            try:
                item = fn()
                if item:
                    try:
                        logged = getattr(self, "_gift_factory_sig_logged", None)
                    except:
                        logged = None
                    if logged != sig_name:
                        try:
                            self._gift_factory_sig_logged = sig_name
                        except:
                            pass
                        _log(f"CatalogGrid.fill: GiftCellFactory success via {sig_name}")
                    return item
            except Exception as e:
                last_err = e
                continue

        try:
            _log(f"CatalogGrid.fill: GiftCellFactory failed for cls={gift.getClass().getName()} err={last_err}")
        except:
            pass
        return None

    def _fill_items(self, items, adapter):
        try:
            GiftCellFactory = jclass("org.telegram.ui.Gifts.GiftSheet$GiftCell$Factory")
        except:
            GiftCellFactory = None

        try:
            fill_sig = f"{len(self.filtered_items or [])}:{self._catalog_signature(self.filtered_items)}"
        except:
            fill_sig = ""
        try:
            if fill_sig != self._last_logged_fill_sig:
                self._last_logged_fill_sig = fill_sig
                _log(f"CatalogGrid.fill: filtered={len(self.filtered_items or [])} factory={'ok' if GiftCellFactory else 'missing'}")
        except:
            pass

        if not self.filtered_items:
            empty = UItem.asShadow("ÃƒÂÃ‚ÂÃƒÂÃ‚Â¸Ãƒâ€˜Ã¢â‚¬Â¡ÃƒÂÃ‚ÂµÃƒÂÃ‚Â³ÃƒÂÃ‚Â¾ ÃƒÂÃ‚Â½ÃƒÂÃ‚Âµ ÃƒÂÃ‚Â½ÃƒÂÃ‚Â°ÃƒÂÃ‚Â¹ÃƒÂÃ‚Â´ÃƒÂÃ‚ÂµÃƒÂÃ‚Â½ÃƒÂÃ‚Â¾")
            try:
                empty.spanCount = 3
            except:
                pass
            items.add(empty)
            return

        for gift in list(self.filtered_items or []):
            try:
                self.plugin._normalize_catalog_gift_availability(gift)
            except:
                pass
            try:
                bg = int(get_val(gift, "gift_id", 0) or get_val(gift, "id", 0) or 0)
            except:
                bg = 0
            if bg > 0:
                try:
                    self.plugin._ensure_unique_gift_availability(gift, base_gift_id=bg)
                except:
                    pass

            try:
                item = self._make_star_gift_item(GiftCellFactory, gift)
                if item:
                    item.object = gift
                    items.add(item)
                    continue
            except:
                pass

            fallback = UItem.asButton(int(get_val(gift, "id", 0)), str(get_val(gift, "title", "NFT")), f"#{get_val(gift, 'num', 1)}")
            try:
                fallback.spanCount = 3
            except:
                pass
            fallback.object = gift
            items.add(fallback)

