    def show(self):
        self.fragment = get_last_fragment()
        self.activity = self.fragment.getParentActivity() if self.fragment else None
        if not self.activity:
            try:
                self.activity = self.plugin._get_menu_activity(None)
            except:
                self.activity = None
            if self.activity and not self.fragment:
                try:
                    self.fragment = get_last_fragment()
                except:
                    pass
        self.sheet = None
        self.recycler = None
        self.top_view = None
        self.crop_container = None
        self.layout_listener = None
        self.native_preview_sheet = None
        self.is_refreshing = False
        try:
            self._refresh_gen = int(self._refresh_gen or 0) + 1
        except:
            self._refresh_gen = 1
        try:
            self._refresh_started_ts = time.time()
        except:
            self._refresh_started_ts = 0.0

        if not self.activity:
            BulletinHelper.show_error("Не удалось открыть конструктор NFT")
            self._on_dismiss()
            return

        try:
            if self._show_native_preview_selector("model"):
                return
        except Exception as e:
            _log(f"Hooked constructor open error: {e}")

        try:
            if self._show_compact_hooked_sheet():
                BulletinHelper.show_info("Открываю конструктор NFT...")
                return
        except Exception as e:
            _log(f"Compact constructor fallback error: {e}")

        BulletinHelper.show_error("Не удалось открыть конструктор NFT")
        self._on_dismiss()

    def _on_dismiss(self):
        # Cleanup references and listeners to reduce leaks.
        try:
            if self.top_view and self.layout_listener:
                try:
                    self.top_view.getViewTreeObserver().removeOnGlobalLayoutListener(self.layout_listener)
                except:
                    pass
        except:
            pass
        try:
            self._detach_number_controls()
        except:
            pass
        try:
            self._detach_value_controls()
        except:
            pass
        self.is_refreshing = False
        try:
            self._refresh_gen = int(self._refresh_gen or 0) + 1
        except:
            pass
        self.sheet = None
        self.recycler = None
        self.top_view = None
        self.crop_container = None
        self.layout_listener = None
        self.native_preview_sheet = None
        self.activity = None
        self.fragment = None

